// ¿El usuario tiene acceso a esta feature?
function tieneFeature(featureName) {
  // Vista previa de plan (dueño): fuerza el set de features del plan simulado.
  if (window._previewPlan) return (PLAN_FEATURES[window._previewPlan] || []).indexOf(featureName) !== -1;
  // Durante trial activo (no expirado), TODAS las features están desbloqueadas
  if (PLAN_INFO.status === 'trial' && PLAN_INFO.trial_until) {
    var trialEnd = new Date(PLAN_INFO.trial_until);
    if (trialEnd > new Date()) return true;
  }
  var plan = PLAN_INFO.plan || 'basico';
  return (PLAN_FEATURES[plan] || []).indexOf(featureName) !== -1;
}

// ¿El plan del usuario es ≥ al requerido? (basico < pro < top)
function tienePlan(planRequerido) {
  return (PLAN_TIER[PLAN_INFO.plan] || 1) >= (PLAN_TIER[planRequerido] || 1);
}
// Límite de clientes por plan (trial = sin límite, como las features)
function _limiteClientes() {
  if (PLAN_INFO.status === 'trial' && PLAN_INFO.trial_until && new Date(PLAN_INFO.trial_until) > new Date()) return Infinity;
  return ((PLAN_LIMITS[PLAN_INFO.plan] || PLAN_LIMITS.basico).clientes) || Infinity;
}
function _puedeAnadirCliente() {
  var lim = _limiteClientes();
  if ((DB.clis || []).length >= lim) {
    try { toast(T('lim.clientes').replace('{n}', lim), 'err'); } catch(e){}
    mostrarModalUpgrade('clientes', (PLAN_INFO.plan === 'basico') ? 'pro' : 'premium');
    return false;
  }
  return true;
}

// Días restantes de trial / próximo cobro (floor para que 14.99 = 14, no 15)
function planDiasRestantes() {
  var fecha = PLAN_INFO.status === 'trial' ? PLAN_INFO.trial_until : PLAN_INFO.plan_until;
  if (!fecha) return null;
  return Math.max(0, Math.floor((new Date(fecha) - new Date()) / 86400000));
}

// Decodifica el payload de un JWT (base64url) sin verificar firma. {} si ilegible.
function _jwtClaims(t) {
  try { return JSON.parse(atob(String(t).split('.')[1].replace(/-/g, '+').replace(/_/g, '/'))); }
  catch (e) { return {}; }
}

// Las sesiones abiertas antes del sellado RLS (jun-2026) llevan un JWT sin `tienda_id`,
// y la nube rechaza sus writes en silencio. Canjeamos el token de sesión (ya guardado)
// por un JWT fresco con tienda_id y recargamos una vez. Anti-bucle por pestaña.
function _autoRenovarJWT(sess) {
  try {
    if (!JWT_TOKEN || !sess || !sess.token) return;
    var claims = _jwtClaims(JWT_TOKEN);
    if (claims && claims.tienda_id) return;                  // JWT ya correcto
    if (sessionStorage.getItem('tk_jwt_renew_try')) return;  // ya intentado esta sesión
    sessionStorage.setItem('tk_jwt_renew_try', '1');
    fetch('/api/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action: 'renovar-jwt', token: sess.token })
    }).then(function (r) { return r.json(); }).then(function (j) {
      if (j && j.jwt_token) {
        var s = JSON.parse(localStorage.getItem('tk_sess') || '{}');
        s.jwt_token = j.jwt_token;
        if (j.tienda_id) s.tienda_id = j.tienda_id;
        localStorage.setItem('tk_sess', JSON.stringify(s));
        location.reload();
      } else {
        // No se renovó: permitir reintento en la próxima carga (no dejar la sesión coja en silencio)
        try { sessionStorage.removeItem('tk_jwt_renew_try'); } catch (e) {}
      }
    }).catch(function () { try { sessionStorage.removeItem('tk_jwt_renew_try'); } catch (e) {} });
  } catch (e) {}
}

// Refrescar plan desde /api/me (llamado al cargar)
async function refrescarPlan() {
  if (!PLAN_INFO.token) return;
  try {
    var r = await fetch('/api/login', {
      method: 'POST',
      headers: {'Content-Type':'application/json'},
      body: JSON.stringify({action: 'me', token: PLAN_INFO.token})
    });
    var data = await r.json();
    if (data.ok) {
      PLAN_INFO.plan = data.plan;
      PLAN_INFO.status = data.plan_status;
      PLAN_INFO.trial_until = data.trial_until;
      PLAN_INFO.plan_until = data.plan_until;
      // Update session storage
      var sess = JSON.parse(localStorage.getItem('tk_sess') || '{}');
      sess.plan = data.plan;
      sess.plan_status = data.plan_status;
      sess.trial_until = data.trial_until;
      sess.plan_until = data.plan_until;
      localStorage.setItem('tk_sess', JSON.stringify(sess));
      // Re-render banners y bloqueos
      renderPlanBanner();
      aplicarBloqueosPlan();
      // Primer login (sin plan cacheado): si ahora sabemos que es Premium y se le había
      // mandado al Clásico automáticamente, devolverlo al Inicio nuevo (solo si sigue ahí).
      if (typeof tieneFeature === 'function' && tieneFeature('inicio_avanzado') && window._inicioAutoRedirect) {
        var pd = document.getElementById('pDash');
        // F70: no pisar una navegación por hash (#citas, #catalogo…) explícita del usuario
        if (pd && pd.classList.contains('active') && !location.hash) navTo('pInicioNuevo');
      }
      window._inicioAutoRedirect = false;
    }
  } catch(e) { console.warn('refrescarPlan error', e); }
}

// Mostrar modal de upgrade
function mostrarModalUpgrade(featureName, planRequerido) {
  var feat = ({
    citas: '📅 Citas online',
    kanban: '🔧 Vista Kanban',
    auditoria: '📜 Historial de actividad',
    backup: '💾 Backup completo',
    reportes_pdf: T('gen.pdf_para_gestor'),
    importar_pdf: '📤 Importar facturas PDF',
    catalogo_servicios: '🛠️ Catálogo de servicios',
    plantillas_rep: '📋 Plantillas de reparación',
    permisos_usuarios: '👥 Permisos por usuario',
    multi_tienda: '🏪 Multi-tienda',
    fotos_rep: '📸 Fotos en reparaciones',
    clientes: '👥 Más clientes',
    ubicaciones: '📍 Ubicaciones múltiples',
    analitica: '📊 Analítica avanzada',
    financiado: '💰 Financiación a plazos',
    inicio_avanzado: '🆕 Inicio nuevo con Tablero',
    ia: '🤖 Funciones con IA (pegar pedido, factura con foto)'
  })[featureName] || featureName;
  var planLabel = ({basico:'Básico', pro:'Pro', premium:'Premium', top:'Premium'})[planRequerido] || planRequerido;
  document.getElementById('upgFeatName').textContent = feat;
  document.getElementById('upgPlanReq').textContent = planLabel;
  // Resaltar el plan recomendado
  document.querySelectorAll('.upg-plan').forEach(function(el){ el.classList.remove('recommended'); });
  var recCard = document.querySelector('.upg-plan[data-plan="' + planRequerido + '"]');
  if (recCard) recCard.classList.add('recommended');
  openM('mUpgrade');
}

// Función central: bloquea o muestra modal si la feature no está disponible
function checkFeature(featureName) {
  if (tieneFeature(featureName)) return true;
  // Determinar el plan mínimo para esta feature
  var planMin = 'pro';
  if (PLAN_FEATURES.pro.indexOf(featureName) === -1) planMin = 'premium';
  mostrarModalUpgrade(featureName, planMin);
  return false;
}

// ═══ NOVEDADES: banner de mejoras para las tiendas (se muestra 1 vez por versión) ═══
var NOVEDADES_VERSION = '2026-06-28';
// Changelog por fecha (lo más nuevo primero). El banner automático muestra solo el
// último lanzamiento; en Ajustes › Novedades se ve el historial completo.
var CHANGELOG = [
  { fecha: '2026-06-28', items: ['nov.h1', 'nov.h2', 'nov.h3', 'nov.h4', 'nov.h5', 'nov.h6'] },
  { fecha: '2026-06-21', items: ['nov.g1', 'nov.g2', 'nov.g3', 'nov.g4', 'nov.g5', 'nov.g6'] },
  { fecha: '2026-06-14', items: ['nov.f6', 'nov.f7', 'nov.f1', 'nov.f2', 'nov.f3', 'nov.f4', 'nov.f5'] }
];
function _novFechaLbl(iso) {
  try { return new Date(iso + 'T00:00:00').toLocaleDateString((typeof TEKPAIR_LANG === 'string' ? TEKPAIR_LANG : 'es'), { year: 'numeric', month: 'long' }); }
  catch (e) { return iso; }
}
function renderNovedades(soloUltima) {
  var el = document.getElementById('novedadesBody'); if (!el) return;
  var releases = soloUltima ? CHANGELOG.slice(0, 1) : CHANGELOG;
  el.innerHTML = releases.map(function(rel, i) {
    var head = soloUltima ? '' : '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:var(--orange);margin:' + (i ? '18px' : '2px') + ' 0 6px">' + _novFechaLbl(rel.fecha) + '</div>';
    var body = rel.items.map(function(k) { return '<div style="padding:9px 2px;border-bottom:1px solid var(--border);font-size:13px;line-height:1.5">' + T(k) + '</div>'; }).join('');
    return head + body;
  }).join('');
}
// Desde Ajustes: historial completo. Banner automático: solo lo último.
function abrirNovedades() { renderNovedades(false); openM('mNovedades'); }
function cerrarNovedades() { try { localStorage.setItem('tk_novedades', NOVEDADES_VERSION); } catch(e){} closeM('mNovedades'); }
function mostrarNovedadesSiNuevo() {
  try { if (localStorage.getItem('tk_novedades') === NOVEDADES_VERSION) return; } catch(e) { return; }
  renderNovedades(true);
  openM('mNovedades');
}
// Renderizar banner de plan (trial, próximo cobro, expirado, etc.)
function renderPlanBanner() {
  var box = document.getElementById('planBanner');
  if (!box) return;
  var dias = planDiasRestantes();
  var html = '';

  if (PLAN_INFO.status === 'trial') {
    if (dias !== null && dias <= 3) {
      html = '<div class="plan-banner urgent">🔥 <strong>Tu prueba gratis termina en ' + dias + ' día' + (dias===1?'':'s') + '</strong>. Añade tu método de pago para no perder el acceso. <button onclick="abrirStripePortal()">Gestionar →</button></div>';
    } else if (dias !== null) {
      html = '<div class="plan-banner info">🎁 Te quedan <strong>' + dias + ' días</strong> de prueba gratis (plan ' + (PLAN_INFO.plan||'').charAt(0).toUpperCase() + (PLAN_INFO.plan||'').slice(1) + '). <a onclick="abrirStripePortal()">Añadir método de pago</a></div>';
    }
  } else if (PLAN_INFO.status === 'past_due') {
    html = '<div class="plan-banner urgent">⚠️ <strong>Problema con tu pago</strong>. Actualiza tu método antes de que se bloquee la cuenta. <button onclick="abrirStripePortal()">Solucionar →</button></div>';
  } else if (PLAN_INFO.status === 'cancelled') {
    if (dias !== null && dias > 0) {
      html = '<div class="plan-banner warning">⏳ Tu suscripción se cancelará el ' + new Date(PLAN_INFO.plan_until).toLocaleDateString('es') + '. <a onclick="abrirStripePortal()">Reactivar</a></div>';
    } else {
      html = '<div class="plan-banner urgent">❌ Tu suscripción ha terminado. <button onclick="abrirStripePortal()">Renovar →</button></div>';
    }
  }
  // Plan activo: invitar a mejorar (Básico → Pro, Pro → Premium)
  if (!html && PLAN_INFO.status !== 'trial' && PLAN_INFO.status !== 'past_due' && PLAN_INFO.status !== 'cancelled') {
    if (PLAN_INFO.plan === 'basico') {
      html = '<div class="plan-banner info">🚀 <strong>Mejora a Pro</strong> y desbloquea analítica avanzada, financiación a plazos y más. <button onclick="mostrarModalUpgrade(\'analitica\',\'pro\')">Ver planes →</button></div>';
    } else if (PLAN_INFO.plan === 'pro') {
      html = '<div class="plan-banner info">✨ <strong>Pásate a Premium</strong>: Inicio nuevo con Tablero, citas, multi-tienda y más. <button onclick="mostrarModalUpgrade(\'inicio_avanzado\',\'premium\')">Ver planes →</button></div>';
    }
  }
  box.innerHTML = html;
}

// Aplicar bloqueos: ocultar/marcar items de sidebar y botones según plan
function aplicarBloqueosPlan() {
  // Items del sidebar a bloquear
  var sidebarLocks = [
    {selector: '[data-p="pCitas"]', feat: 'citas'},
    {selector: '[data-p="pPedidos"]', feat: 'pedidos'},
    {selector: '[data-p="pGastos"]', feat: 'gastos'},
    {selector: '[data-p="pServicios"]', feat: 'catalogo_servicios'},
    {selector: '[data-p="pCajas"]', feat: 'cajas_multiservicio'}
  ];
  var _noFotos = (typeof tieneFeature === 'function') && !tieneFeature('fotos_rep');
  ['repFotoRecepSec','repFotoEntSec'].forEach(function(id){ var e = document.getElementById(id); if (e) e.style.display = _noFotos ? 'none' : ''; });
  sidebarLocks.forEach(function(lock) {
    var el = document.querySelector(lock.selector);
    if (!el) return;
    if (tieneFeature(lock.feat)) {
      el.classList.remove('plan-locked');
      // quitar lock icon si estaba
      var oldIcon = el.querySelector('.plan-lock-icon');
      if (oldIcon) oldIcon.remove();
    } else {
      el.classList.add('plan-locked');
      // Asegurar que el lock icon está visible
      if (!el.querySelector('.plan-lock-icon')) {
        var lockIcon = document.createElement('span');
        lockIcon.className = 'plan-lock-icon';
        lockIcon.textContent = '🔒';
        lockIcon.style.cssText = 'margin-left:auto;font-size:11px;opacity:.7';
        el.appendChild(lockIcon);
      }
    }
  });

  // Mostrar/ocultar tarjeta auditoría en Ajustes (solo si plan permite)
  setTimeout(function(){
    var cardA = document.getElementById('cardAuditoria');
    if (cardA) {
      if (!tieneFeature('auditoria') || !U || U.rol !== 'admin') {
        cardA.style.display = 'none';
      }
    }
  }, 1100);

  // Inicio por plan: Básico/Pro ahora usan el Inicio moderno recortado (ya NO se redirige al Clásico).
}

// Override navTo para bloquear páginas
var _navToOriginal = null;
function setupNavToBlocker() {
  if (_navToOriginal) return; // ya parcheado
  if (typeof navTo !== 'function') { setTimeout(setupNavToBlocker, 200); return; }
  _navToOriginal = navTo;
  window.navTo = function(pageId) {
    // Páginas solo-admin: bloquear acceso de empleados aunque lleguen por otra vía
    try {
      var esAdmin = (typeof U !== 'undefined' && U) ? (U.rol === 'admin' || (U.permisos && U.permisos.todo)) : true;
      if (!esAdmin) {
        if (pageId === 'pUsuarios' || pageId === 'pComisiones') { if (typeof toast === 'function') toast(T('perm.solo_admin'), 'err'); return; }
        if (pageId === 'pAjustes' && !(typeof tienePerm === 'function' && tienePerm('ajustes_ver'))) { if (typeof toast === 'function') toast(T('perm.sin_acceso_ajustes'), 'err'); return; }
      }
    } catch(e) {}
    var pageFeatureMap = {
      pCitas: 'citas',
      pPedidos: 'pedidos',
      pGastos: 'gastos',
      pServicios: 'catalogo_servicios',
      pCajas: 'cajas_multiservicio'
    };
    var feat = pageFeatureMap[pageId];
    if (feat && !tieneFeature(feat)) {
      var planMin = 'pro';
      if (PLAN_FEATURES.pro.indexOf(feat) === -1) planMin = 'premium';
      mostrarModalUpgrade(feat, planMin);
      return;
    }
    return _navToOriginal.apply(this, arguments);
  };
}

// Abrir Stripe Customer Portal
async function abrirStripePortal() {
  if (!PLAN_INFO.token) { toast(T('gen.sesion_invalida'), 'err'); return; }
  toast(T('sub.abriendo_portal'), 'ok');
  try {
    var r = await fetch('/api/portal', {
      method: 'POST',
      headers: {'Content-Type':'application/json'},
      body: JSON.stringify({action: 'me', token: PLAN_INFO.token})
    });
    var data = await r.json();
    if (data.ok && data.url) {
      // Validar que la URL sea de Stripe para prevenir open redirect
      if (/^https:\/\/billing\.stripe\.com\//.test(data.url) ||
          /^https:\/\/checkout\.stripe\.com\//.test(data.url)) {
        window.location.href = data.url;
      } else {
        console.warn('URL de portal no válida:', data.url);
        toast(T('sub.url_invalida'), 'err');
      }
    } else {
      toast(data.error || 'No se pudo abrir el portal', 'err');
    }
  } catch(e) {
    toast(T('gen.error_conexion'), 'err');
  }
}

// Click manual en upgrade desde modal
function clickUpgradePlan(plan) {
  // Si ya tiene Stripe → abrir portal para cambiar plan
  // Si no → ir a registro con ese plan
  if (PLAN_INFO.status === 'trial' || PLAN_INFO.status === 'active' || PLAN_INFO.status === 'past_due') {
    abrirStripePortal();
  } else {
    window.location.href = '/registro.html?plan=' + plan;
  }
}

// Renderizar info de suscripción en Ajustes
function renderSuscripcionInfo() {
  var box = document.getElementById('suscripcionInfo');
  if (!box) return;
  var planLabel = ({basico:'Básico', pro:'Pro ⭐', premium:'Premium', top:'Premium'})[PLAN_INFO.plan] || PLAN_INFO.plan;
  var planPrecio = ({basico:'9,90', pro:'19,90', premium:'34,90', top:'34,90'})[PLAN_INFO.plan] || '—';
  var _tt = function(k, fb){ return (typeof T === 'function' ? T(k) : '') || fb; };
  var statusLabel = ({trial:'🎁 '+_tt('plan.st_trial','Periodo de prueba'), active:'✓ '+_tt('plan.st_active','Activa'), past_due:'⚠️ '+_tt('plan.st_pastdue','Pago pendiente'), cancelled:'❌ '+_tt('plan.st_cancelled','Cancelada')})[PLAN_INFO.status] || PLAN_INFO.status;
  var statusColor = ({trial:'var(--blue)', active:'var(--green)', past_due:'var(--orange)', cancelled:'var(--red)'})[PLAN_INFO.status] || 'var(--muted)';
  var dias = planDiasRestantes();
  var _loc = (typeof TEKPAIR_LANG === 'string' ? TEKPAIR_LANG : 'es');

  var html = '<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px">';
  html += '<div><div style="font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:.4px;font-weight:700;margin-bottom:4px">' + _tt('plan.plan_actual','Plan actual') + '</div>';
  html += '<div style="font-size:20px;font-weight:800">' + planLabel + '</div>';
  html += '<div style="font-size:13px;color:var(--muted)">' + planPrecio + ' ' + _tt('plan.mes','€/mes') + '</div></div>';
  html += '<div><div style="font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:.4px;font-weight:700;margin-bottom:4px">' + _tt('plan.estado','Estado') + '</div>';
  html += '<div style="font-size:14px;font-weight:700;color:' + statusColor + '">' + statusLabel + '</div>';
  if (dias !== null && dias >= 0 && dias <= 3650) {
    // Tope de cordura: >10 años = dato anómalo (cuenta test/vitalicia) → no mostramos el absurdo "26863 días".
    var label = PLAN_INFO.status === 'trial' ? _tt('plan.dias_prueba','días de prueba restantes') : _tt('plan.dias_cobro','días hasta próximo cobro');
    html += '<div style="font-size:13px;color:var(--muted)">' + dias + ' ' + label + '</div>';
  }
  html += '</div></div>';

  if (PLAN_INFO.trial_until || PLAN_INFO.plan_until) {
    var fecha = PLAN_INFO.status === 'trial' ? PLAN_INFO.trial_until : PLAN_INFO.plan_until;
    if (fecha) {
      var _fd = new Date(fecha);
      // Centinela de cuenta sin caducidad (test/vitalicia, p.ej. año 2100): no mostrar la fecha absurda.
      if (_fd.getFullYear() >= 2099) {
        html += '<div style="background:var(--light);border-radius:8px;padding:10px 14px;font-size:12px;color:var(--muted)">♾️ <strong style="color:var(--text)">' + _tt('plan.sin_caducidad','Cuenta sin caducidad') + '</strong></div>';
      } else {
        html += '<div style="background:var(--light);border-radius:8px;padding:10px 14px;font-size:12px;color:var(--muted)">';
        html += (PLAN_INFO.status === 'trial' ? '📅 ' + _tt('plan.prueba_termina','La prueba termina:') + ' ' : '📅 ' + _tt('plan.proximo_cobro','Próximo cobro:') + ' ');
        html += '<strong style="color:var(--text)">' + _fd.toLocaleDateString(_loc, {day:'numeric',month:'long',year:'numeric'}) + '</strong>';
        html += '</div>';
      }
    }
  }

  box.innerHTML = html;
}

