// ═══ VISTA ESCRITORIO (plegables/tablets): fuerza el ancho de viewport ═══
function _aplicarVistaEscritorio(on) {
  var m = document.querySelector('meta[name="viewport"]');
  // Sin maximum-scale: permitir pinch-zoom (WCAG 1.4.4 / #B79).
  if (m) m.setAttribute('content', on ? 'width=1100' : 'width=device-width, initial-scale=1.0');
  try { on ? localStorage.setItem('tk_vista_escritorio', '1') : localStorage.removeItem('tk_vista_escritorio'); } catch (e) {}
  var d = document.getElementById('vistaEscritorioDesc');
  if (d) d.textContent = on ? '✓ Activada — usando toda la pantalla' : 'Aprovecha toda la pantalla (tablets y plegables)';
  var b = document.getElementById('btnVistaEscritorio');
  if (b) b.style.boxShadow = on ? 'inset 0 0 0 2px var(--blue)' : '';
}

// #B7: el saludo (mañana/tarde/noche) y la fecha se calculaban una sola vez al cargar.
// Si la pestaña queda abierta y cambia la franja horaria o el día, quedaban obsoletos
// ("Good afternoon" a las 23h). Refrescamos al volver a la pestaña y cada 5 minutos.
function _refrescarSaludo() {
  try {
    if (typeof U === 'undefined' || !U) return;
    var h = new Date().getHours();
    var primer = (U.nombre || '').split(' ')[0] || '';
    var saludoSb = h < 6 ? T('dash.buena_madrugada') : h < 13 ? T('dash.buenos_dias') : (h < 21 ? T('dash.buenas_tardes') : T('dash.buenas_noches'));
    var dTiendaEl = document.getElementById('dTienda');
    if (dTiendaEl) dTiendaEl.textContent = primer ? saludoSb + ', ' + primer : saludoSb;
    var sa = document.getElementById('inv-saludo');
    if (sa) {
      var sal = h < 6 ? T('inicio.saludo_madrugada') : h < 13 ? T('inicio.saludo_manana') : (h < 21 ? T('inicio.saludo_tarde') : T('inicio.saludo_noche'));
      sa.textContent = sal + (primer ? ', ' + primer : '') + ' 👋';
    }
    var fe = document.getElementById('inv-fecha');
    if (fe) fe.textContent = new Date().toLocaleDateString((typeof TEKPAIR_LANG !== 'undefined' ? TEKPAIR_LANG : 'es'), { weekday: 'long', day: 'numeric', month: 'long' });
  } catch (e) {}
}
var _refrescoSaludoSet = false;
function _setupRefrescoSaludo() {
  if (_refrescoSaludoSet) return;
  _refrescoSaludoSet = true;
  document.addEventListener('visibilitychange', function(){ if (!document.hidden) _refrescarSaludo(); });
  setInterval(_refrescarSaludo, 300000);
}
function toggleVistaEscritorio() {
  var on = false;
  try { on = localStorage.getItem('tk_vista_escritorio') !== '1'; } catch (e) { on = true; }
  _aplicarVistaEscritorio(on);
  if (typeof toast === 'function') toast(on ? 'Vista escritorio activada' : 'Vista móvil restaurada', 'ok');
}

// ═══ INIT ═══
window.addEventListener('DOMContentLoaded', function() {
  U = JSON.parse(localStorage.getItem('tk_user') || 'null');
  if (!U) { window.location.href = 'app.html'; return; }

  var sess = JSON.parse(localStorage.getItem('tk_sess') || '{}');
  SB_KEY = sess.sb_key || '';
  JWT_TOKEN = sess.jwt_token || '';
  _autoRenovarJWT(sess); // si el JWT no trae tienda_id (sesión previa al sellado RLS), canjearlo y recargar
  try { _aplicarVistaEscritorio(localStorage.getItem('tk_vista_escritorio') === '1'); } catch (e) {}
  setTimeout(function(){ detectarAccesoComisiones(); }, 800);
  TIENDA_ID = sess.tienda_id || (U && U.tienda_id) || '';
  // Load permisos from session
  if (sess.usuario && sess.usuario.permisos) U.permisos = sess.usuario.permisos;
  else if (!U.permisos) U.permisos = {};
  // Refrescar permisos/rol desde el servidor: si el admin los cambió, el empleado
  // los recibe al recargar (sin tener que cerrar sesión y volver a entrar).
  refrescarPermisosSesion();

  // ═══ PLAN ═══
  PLAN_INFO.plan = sess.plan || 'basico';
  PLAN_INFO.status = sess.plan_status || 'trial';
  PLAN_INFO.trial_until = sess.trial_until || null;
  PLAN_INFO.plan_until = sess.plan_until || null;
  PLAN_INFO.token = sess.token || '';

  // Aplicar idioma guardado
  (function(){
    var lang = localStorage.getItem('tp_lang') || 'es';
    if (typeof setLang === 'function') setLang(lang);
  })();
  // VIS-17: sincronizar labels sidebar controles
  setTimeout(function(){ if (typeof actualizarSbControls === 'function') actualizarSbControls(); }, 200);
  // Banner de novedades (1 vez por versión)
  setTimeout(function(){ try { mostrarNovedadesSiNuevo(); } catch(e){} }, 1600);

  document.getElementById('uName').textContent = U.nombre || '';
  var tiendaLS = JSON.parse(localStorage.getItem('tk_tienda') || '{}');
  Object.assign(TIENDA, tiendaLS);
  if (!TIENDA.nombre) TIENDA.nombre = 'Mi Tienda';
  // VIS-1: header con saludo personalizado en lugar de nombre de tienda
  // El nombre de la tienda ya se muestra en el sidebar; aquí saludo más humano.
  _refrescarSaludo();
  _setupRefrescoSaludo();
  renderSidebarLogo();
  document.getElementById('dStr').textContent = new Date().toLocaleDateString((typeof TEKPAIR_LANG !== 'undefined' ? TEKPAIR_LANG : 'es'), {weekday:'long',day:'numeric',month:'long'});

  // Load ajustes
  var aj = JSON.parse(localStorage.getItem('tk_ajustes') || '{}');
  if (aj.moneda) AJUSTES.moneda = aj.moneda;
  if (aj.paisPrefijo) AJUSTES.paisPrefijo = aj.paisPrefijo;
  if (aj.cierre) AJUSTES.cierre = aj.cierre;
  if (aj.nombre) AJUSTES.nombre = aj.nombre;
  if (aj.iva) AJUSTES.iva = Object.assign({activo:false,modo:'incluido',tipoDefault:21,tiposPermitidos:[0,4,10,21],nombre:'IVA',tiposExtra:'21, 10, 4, 0'}, aj.iva);
  if (aj.notif) {
    AJUSTES.notif = AJUSTES.notif || {};
    AJUSTES.notif.activa = Object.assign({vencida:true,urgente:true,abandono:true,stock:true,cuotaVencida:true,cuotaProxima:true,recibidaHoy:true,cumple:true}, aj.notif.activa || {});
    AJUSTES.notif.plantillaCumple = aj.notif.plantillaCumple || AJUSTES.notif.plantillaCumple;
    if (aj.notif.diasAbandono != null) AJUSTES.notif.diasAbandono = parseInt(aj.notif.diasAbandono) || 90;
  }

  // Load local data
  cargarDatosLocal();
  renderDash();
  try { renderInicioNuevo(); } catch(e){}
  checkUrgentes();
  applyLang();

  // Load from Supabase
  if (SB_KEY && TIENDA_ID) {
    syncCompleto(true).then(function() { cargarNotas(); iniciarRefrescoNotas(); cargarModelosCustom(); _migrarCategoriasAccesorios(); });
    cargarModelosPre();
    try { _initRealtime(); } catch(e){}
    try { cargarMisTiendas(); } catch(e){}
    // Vuelta del pago de una tienda nueva (add-on): avisa y refresca el selector
    // (el webhook crea la tienda; damos un margen por si tarda en llegar).
    try {
      if (/[?&]tienda_creada=1/.test(location.search)) {
        history.replaceState(null, '', location.pathname + location.hash);
        setTimeout(function() { try { toast(T('mt.creada'), 'ok'); cargarMisTiendas(); } catch (e) {} }, 2000);
      }
    } catch (e) {}
    // Si hoy ya se cerró pero el envío a Cobrum falló, reintenta al abrir.
    setTimeout(function () { try { _enviarCierreCobrumPendiente(); } catch (e) {} }, 8000);
  }

  // Sync continua: cuando vuelves a la pestaña + red de seguridad cada 60s.
  // Con Realtime conectado (_rtReady) los cambios llegan al instante por websocket,
  // así que el poll de 60s solo se dispara como fallback si el websocket está caído.
  window.addEventListener('focus', function(){ syncCompleto(true); try { cargarConfirmacionesPend(); } catch(e){} });
  window.addEventListener('visibilitychange', function(){ if (!document.hidden) syncCompleto(true); });
  setInterval(function(){ if (!document.hidden && !_rtReady) syncCompleto(true); }, 60000);

  // Admin check
  if (!U.rol || U.rol !== 'admin') {
    document.getElementById('btnUsuarios').style.display = 'none';
  }

  // Auto backup
  setInterval(function() { guardarDatos(); }, 2 * 60 * 60 * 1000);
  setInterval(checkCierreAuto, 60000);
  // Notificaciones
  setTimeout(refreshNotifs, 500);
  setInterval(refreshNotifs, 60000);

  // PWA shortcuts: manejar parámetros URL
  (function handlePWAParams() {
    try {
      var params = new URLSearchParams(window.location.search);
      var page = params.get('page');
      var action = params.get('action');
      if (page) {
        setTimeout(function() { navTo(page); }, 300);
      } else if (action === 'new-rep') {
        setTimeout(function() { navTo('pReps'); abrirRep(); }, 300);
      } else if (action === 'new-pres') {
        setTimeout(function() { navTo('pPresupuestos'); abrirPresupuesto(); }, 300);
      }
      // Limpiar params de la URL sin recargar
      if (page || action) {
        window.history.replaceState({}, '', '/dashboard.html');
      }
    } catch(e) {}
  })();

  // Navegación por hash (#ventas, #reparaciones, #stock...) → enlaces directos a una sección.
  var _HASH_NAV = { inicio:'pInicioNuevo', dashboard:'pDash', dash:'pDash', ventas:'pVentas',
    reparaciones:'pReps', reps:'pReps', presupuestos:'pPresupuestos', stock:'pStock',
    clientes:'pClis', clis:'pClis', proveedores:'pProvs', provs:'pProvs', gastos:'pGastos',
    pedidos:'pPedidos', servicios:'pServicios', cajas:'pCajas', caja:'pCajas',
    ajustes:'pAjustes', tienda:'pTienda',
    // F52: faltaban → #reportes y otros dejaban la pantalla en blanco
    reportes:'pReportes', reports:'pReportes', comisiones:'pComisiones', facturas:'pFacturas',
    catalogo:'pCatalogo', usuarios:'pUsuarios', ayuda:'pAyuda', citas:'pCitas', mas:'pMas' };
  function _navFromHash() {
    try {
      var h = (location.hash || '').replace(/^#\/?/, '').toLowerCase().trim();
      // F648/F649: el TPV es una página aparte (tpv.html), no un .page del SPA. #tpv/#pos
      // deben llevar a esa página, no quedarse sin efecto en la vista actual.
      if (h === 'tpv' || h === 'pos') { window.location.href = 'tpv.html'; return; }
      if (h && _HASH_NAV[h] && typeof navTo === 'function') navTo(_HASH_NAV[h]);
    } catch(e) {}
  }
  window.addEventListener('hashchange', _navFromHash);
  // F211: un F5 sobre #reparaciones debe restaurar esa vista, no caer a Inicio.
  // El render de arranque puede pisar la navegación, así que reaplicamos el hash de
  // boot varias veces durante los primeros ~2,5s, y paramos en cuanto el usuario
  // navega manualmente (cualquier hashchange) o la vista ya coincide.
  var _bootHash = (location.hash || '').replace(/^#\/?/, '').toLowerCase().trim();
  // F648/F649: cargar dashboard.html#tpv (o #pos) directo debe ir a la página del TPV. Antes
  // este caso se perdía porque el boot solo miraba _HASH_NAV (que no incluye tpv/pos).
  if (_bootHash === 'tpv' || _bootHash === 'pos') { window.location.href = 'tpv.html'; return; }
  if (_bootHash && _HASH_NAV[_bootHash]) {
    var _bootTarget = _HASH_NAV[_bootHash];
    // Páginas de aterrizaje por defecto: si el arranque se queda aquí pero el hash pedía
    // otra cosa, es el bug F211; si el usuario ya está en otra sección, no le movemos.
    var _landing = { pInicioNuevo:1, pDash:1 };
    var _tries = 0;
    var _applyBoot = function(){
      var tg = document.getElementById(_bootTarget);
      if (tg && tg.classList.contains('active')) return;       // ya estamos donde toca
      var cur = document.querySelector('.page.active');
      if (cur && !_landing[cur.id]) return;                    // el usuario navegó a otra sección: no le pisamos
      if (typeof navTo === 'function') navTo(_bootTarget);
      if (++_tries < 6) setTimeout(_applyBoot, 350);
    };
    _applyBoot();
  }

  setInterval(fetchNotifRemotas, 30000);
  setTimeout(fetchNotifRemotas, 3000); // primera consulta a los 3s
  initDesktop();
  window.addEventListener('resize', initDesktop);
  setTimeout(function() {
    aplicarPermisos();
    aplicarOrdenWidgets();
  }, 200);

  // Pago select listener
  document.getElementById('vPago').addEventListener('change', function() {
    // Financiado es de plan Pro/Premium: si no lo tiene, avisar y volver a Efectivo
    if (this.value === 'Financiado' && typeof checkFeature === 'function' && !checkFeature('financiado')) {
      this.value = 'Efectivo';
      document.getElementById('finOpts').style.display = 'none';
      return;
    }
    document.getElementById('finOpts').style.display = this.value === 'Financiado' ? 'block' : 'none';
  });

  // Set today date for gasto
  document.getElementById('gFecha').value = hoyLocal();
});

function setSidebarActive(el) {
  document.querySelectorAll('.sidebar-ni').forEach(function(n) { n.classList.remove('active'); });
  el.classList.add('active');
}


function initDesktop() {
  var isDesktop = window.innerWidth >= 840;  // alineado al breakpoint CSS (plegables ~884px)
  var sidebar = document.getElementById('sidebar');
  var appContent = document.getElementById('app-content');
  if (isDesktop) {
    sidebar.style.display = 'flex';
    sidebar.style.flexDirection = 'column';
    appContent.style.display = 'flex';
    appContent.style.flexDirection = 'column';
    appContent.style.flex = '1';
    appContent.style.overflow = 'hidden';
    document.getElementById('sidebarName').textContent = U ? U.nombre : '';
    document.getElementById('sidebarTienda').textContent = TIENDA.nombre;
    if (!U.rol || U.rol !== 'admin') {
      var su = document.getElementById('sidebarUsuarios');
      if (su) su.style.display = 'none';
    }
  } else {
    sidebar.style.display = 'none';
    appContent.style.display = 'contents';
  }
}

