async function guardarPedido() {
  DB.pedidos = DB.pedidos || [];
  // EDITAR: un solo pedido
  if (SEL.editPedidoId) {
    var _emarca = (document.getElementById('pedMarca').value || '').trim();
    var _emodelo = (document.getElementById('pedPieza').value || '').trim();
    if (!_emodelo) { toast(T('pedidos.falta_pieza'), 'err'); return; }
    _aprenderModelo(_emarca, _emodelo, (document.getElementById('pedCat') && document.getElementById('pedCat').value));
    var _ecant = parseInt(document.getElementById('pedCant').value, 10) || 1;
    var _ecompra = parseFloat(document.getElementById('pedImporte').value) || 0;
    var _eventaEl = document.getElementById('pedVenta');
    var _eventa = _eventaEl ? (parseFloat(_eventaEl.value) || 0) : 0;
    var datos = {
      pieza: _pedNombreCompleto(_emarca, _emodelo),
      marca: _emarca || null,
      categoria: (document.getElementById('pedCat') && document.getElementById('pedCat').value) || null,
      calidad: (((document.getElementById('pedCat') || {}).value === 'Pantalla') ? ((document.getElementById('pedCalidad') || {}).value || null) : null),
      cantidad: _ecant,
      proveedor: (document.getElementById('pedProv').value || '').trim() || null,
      precio_compra: _ecompra,
      precio_venta: _eventa,
      importe: Math.round(_ecompra * _ecant * 100) / 100,
      fecha_pedido: document.getElementById('pedFechaPed').value || null,
      fecha_estimada: document.getElementById('pedFecha').value || null,
      metodo_pago: (document.getElementById('pedMetodo') || {}).value || 'transferencia',
      nota: (document.getElementById('pedNota').value || '').trim() || null,
      estado_pago: (document.getElementById('pedEstadoPago') || {}).value || 'pagado'
    };
    var p = DB.pedidos.find(function(x) { return x.id === SEL.editPedidoId; });
    if (p) { Object.assign(p, datos); if (SB_KEY) sbPatch('pedidos', 'id=eq.' + encodeURIComponent(p.id), datos); }
    closeM('mPedido'); renderPedidosWidget(); toast(T('pedidos.guardado'), 'ok');
    return;
  }
  // NUEVO: si hay una pieza escrita sin añadir, la añadimos
  if ((document.getElementById('pedPieza').value || '').trim()) pedAddItem();
  var items = window._pedItems || [];
  if (!items.length) { toast(T('pedidos.falta_pieza'), 'err'); return; }
  var prov = (document.getElementById('pedProv').value || '').trim() || null;
  var fest = document.getElementById('pedFecha').value || null;
  var nota = (document.getElementById('pedNota').value || '').trim() || null;
  var metPed = (document.getElementById('pedMetodo') || {}).value || 'transferencia';
  // Total real pagado + factura: nivel pedido (compartido por todas las líneas vía 'grupo')
  var grupo = 'pg' + Date.now() + '_' + Math.random().toString(36).slice(2, 6);
  var totalReal = parseFloat((document.getElementById('pedTotalReal') || {}).value) || 0;
  var pdfInfo = null;
  var pdfEl = document.getElementById('pedPdf');
  var pdfFile = (pdfEl && pdfEl.files && pdfEl.files[0]) ? pdfEl.files[0] : null;
  if (pdfFile) { toast(T('pedidos.subiendo_factura') || 'Subiendo factura…', 'ok'); pdfInfo = await _subirPdfPedido(pdfFile, grupo); }
  var estadoPago = (document.getElementById('pedEstadoPago') || {}).value || 'pagado';
  items.forEach(function(it) {
    var nuevo = { id: _uuidPed(), tienda_id: TIENDA_ID, estado: 'por_pedir', creado_por: (U ? U.nombre : null), pieza: it.pieza, marca: it.marca || null, categoria: it.categoria || null, calidad: it.calidad || null, cantidad: it.cantidad, precio_compra: it.precio_compra || 0, precio_venta: it.precio_venta || 0, importe: it.importe, proveedor: prov, fecha_pedido: null, fecha_estimada: fest, metodo_pago: metPed, nota: nota, grupo: grupo, total_real: totalReal || null, pdf_url: pdfInfo ? pdfInfo.path : null, pdf_nombre: pdfInfo ? pdfInfo.nombre : null, estado_pago: estadoPago, pagado_importe: 0 };
    DB.pedidos.unshift(nuevo);
    if (SB_KEY) sbPost('pedidos', nuevo);
  });
  window._pedItems = [];
  var _ptr = document.getElementById('pedTotalReal'); if (_ptr) _ptr.value = '';
  if (pdfEl) pdfEl.value = '';
  closeM('mPedido');
  renderPedidosWidget();
  toast(T('pedidos.guardado_n').replace('{n}', items.length), 'ok');
}
function avanzarPedido(id) {
  if (!tienePerm('stock_crear')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var p = (DB.pedidos || []).find(function(x) { return x.id === id; });
  if (!p) return;
  if (p.estado === 'por_pedir') {
    p.estado = 'pedido';
    var patch1 = { estado: 'pedido' };
    if (!p.fecha_pedido) { p.fecha_pedido = hoyLocal(); patch1.fecha_pedido = p.fecha_pedido; }   // auto: hoy
    if (SB_KEY) sbPatch('pedidos', 'id=eq.' + encodeURIComponent(p.id), patch1);
    toast(T('pedidos.marcado_pedido'), 'ok');
  } else if (p.estado === 'pedido') {
    p.estado = 'recibido';
    var patch = { estado: 'recibido' };
    p.fecha_recibido = hoyLocal();   // día de recepción (escritura best-effort, ver abajo)
    if (SB_KEY && typeof _sbPatchRaw === 'function') { try { _sbPatchRaw('pedidos', 'id=eq.' + encodeURIComponent(p.id), { fecha_recibido: p.fecha_recibido }); } catch (e) {} }
    var gid = _gastoAlRecibir(p);
    if (gid) { p.gasto_id = gid; patch.gasto_id = gid; toast(T('pedidos.recibido_gasto'), 'ok'); }
    else { toast(T('pedidos.marcado_recibido'), 'ok'); }
    if (SB_KEY) sbPatch('pedidos', 'id=eq.' + encodeURIComponent(p.id), patch);
    // Al recibir: registrar en stock. La categoría del pedido manda; si no
    // la tiene (pedidos antiguos), se usa la del item de stock que coincida.
    var uds = parseInt(p.cantidad, 10) || 1;
    var existe = _stockMatch(p.pieza);
    // No fusionar pantallas (u otros) de distinta calidad: si difiere, crear item aparte
    if (existe && p.calidad && (existe.calidad || '') !== p.calidad) existe = null;
    var cat = p.categoria || (existe ? existe.categoria : '');
    // F207: modal en vez de confirm() nativo (el nativo no se disparaba con la automatización
    // → quedaba el gasto registrado pero sin sumar el stock).
    if (_esImeiCat(cat)) {
      // IMEI: no se suma, se registran las unidades con su IMEI (modal de alta multi-IMEI)
      confirmar(T('pedidos.add_stock_imei').replace('{n}', uds).replace('{pieza}', p.pieza || ''), function () {
        _abrirAltaImeiDesdePedido(p, uds, existe, cat);
      }, { okLabel: _pedBtnLbl('imei') });
    } else {
      var msg = existe
        ? T('pedidos.add_stock_sumar').replace('{n}', uds).replace('{pieza}', p.pieza || '').replace('{cur}', parseInt(existe.unidades, 10) || 0)
        : T('pedidos.add_stock').replace('{n}', uds).replace('{pieza}', p.pieza || '');
      confirmar(msg, function () { tpWithBusy(T('pedidos.recibiendo') || 'Recibiendo…', function () { _recibirAStock(p, uds, existe, false, cat); }); }, { okLabel: _pedBtnLbl('stock') });
    }
  }
  renderPedidosWidget();
}
// Abre el alta de Stock pre-rellenada para registrar N unidades con IMEI.
// Funciona con un item de stock existente o con un pedido nuevo (sin stock aún).
function _abrirAltaImeiDesdePedido(p, uds, existe, cat) {
  if (typeof nuevoStock !== 'function') return;
  nuevoStock();
  var set = function(id, v) { var e = document.getElementById(id); if (e) e.value = v; };
  if (existe) {
    set('sCat', existe.categoria || cat || 'Telefono');
    set('sMarca', existe.marca || '');
    set('sModelo', existe.modelo || '');
    if (existe.capacidad) set('sCap', existe.capacidad);
    if (existe.precioC) set('sPrecioC', existe.precioC);
    var ventaUe = parseFloat(p.precio_venta) || 0;
    if (ventaUe > 0) set('sPrecioV', ventaUe.toFixed(2));
  } else {
    // Teléfono pedido que aún no estaba en stock: marca y modelo del pedido
    // van directos a sus campos → el nombre coincide con el del pedido.
    set('sCat', cat || 'Telefono');
    set('sMarca', p.marca || '');
    set('sModelo', _pedModeloDe(p));
    var costeU = (parseFloat(p.importe) || 0) > 0 ? (parseFloat(p.importe) / (uds || 1)) : (parseFloat(p.precio_compra) || 0);
    if (costeU > 0) set('sPrecioC', costeU.toFixed(2));
    var ventaU = parseFloat(p.precio_venta) || 0;
    if (ventaU > 0) set('sPrecioV', ventaU.toFixed(2));
  }
  try { renderStockMarcas(); } catch (e) {}
  try { toggleStockMulti(); } catch (e) {}
  setTimeout(function() {
    var w = document.getElementById('sImeiMultiWrap'), ta = document.getElementById('sImeiMulti');
    if (w && w.scrollIntoView) w.scrollIntoView({ behavior: 'smooth', block: 'center' });
    if (ta) ta.focus();
  }, 120);
  toast(T('pedidos.imei_hint').replace('{n}', uds), 'ok');
}
// Recibe un pedido al stock: suma a un item existente o crea uno nuevo (repuesto)
function _recibirAStock(p, uds, existe, silent, cat) {
  DB.stock = DB.stock || [];
  if (existe) {
    existe.unidades = (parseInt(existe.unidades, 10) || 0) + uds;
    if (SB_KEY && TIENDA_ID) sbPatch('stock', 'id=eq.' + encodeURIComponent(existe.id), { unidades: existe.unidades });
    _logMov('entrada', _stockNombre(existe), uds, p.proveedor || T('pedidos.pieza'));
    try { guardarDatos(); } catch(e){}
    try { if (typeof renderStock === 'function') renderStock(); } catch(e){}
    if (!silent) toast(T('pedidos.stock_sumado').replace('{n}', uds).replace('{total}', existe.unidades), 'ok');
    return;
  }
  var costeUnit = (parseFloat(p.importe) || 0) > 0 ? (parseFloat(p.importe) / (uds || 1)) : (parseFloat(p.precio_compra) || 0);
  var ventaUnit = parseFloat(p.precio_venta) || 0;  // PVP del pedido → precio venta del stock
  var item = {
    id: 's' + Date.now() + '_' + Math.random().toString(36).slice(2, 8),
    categoria: cat || p.categoria || 'Repuesto', marca: p.marca || '', modelo: _pedModeloDe(p), capacidad: '', color: '', imei: '',
    unidades: uds, precioC: costeUnit, precioV: ventaUnit, stockMin: 2, stockMax: 10,
    vendido: false, calidad: p.calidad || '', tipo: 'nuevo', garantiaMeses: 0, ubicacion: null
  };
  DB.stock.push(item);
  if (SB_KEY && TIENDA_ID) sbPost('stock', {
    id: item.id, tienda_id: TIENDA_ID, categoria: item.categoria, marca: item.marca,
    modelo: item.modelo, capacidad: item.capacidad, color: item.color, imei: item.imei,
    unidades: item.unidades, precio_c: item.precioC, precio_v: item.precioV,
    stock_min: item.stockMin, stock_max: item.stockMax, vendido: false,
    calidad: item.calidad || null, tipo: 'nuevo', garantia_meses: 0, ubicacion: null
  });
  _logMov('entrada', _eqNombre(item.marca, item.modelo), uds, p.proveedor || T('pedidos.pieza'));
  try { guardarDatos(); } catch(e){}
  try { if (typeof renderStock === 'function') renderStock(); } catch(e){}
  if (!silent) toast(T('pedidos.stock_anadido').replace('{n}', uds), 'ok');
}
// Crea un item de stock por cada IMEI (1 unidad) desde un pedido. Para "Recibir todos".
function _recibirImeisDePedido(p, imeis, cat) {
  DB.stock = DB.stock || [];
  var uds = parseInt(p.cantidad, 10) || 1;
  var costeUnit = (parseFloat(p.importe) || 0) > 0 ? (parseFloat(p.importe) / uds) : (parseFloat(p.precio_compra) || 0);
  var ventaUnit = parseFloat(p.precio_venta) || 0;
  imeis.forEach(function (imei, i) {
    var item = {
      id: 's' + Date.now() + '_' + i + '_' + Math.random().toString(36).slice(2, 6),
      categoria: cat || p.categoria || 'Telefono', marca: p.marca || '', modelo: _pedModeloDe(p), capacidad: '', color: '', imei: imei,
      unidades: 1, precioC: costeUnit, precioV: ventaUnit, stockMin: 2, stockMax: 10,
      vendido: false, calidad: p.calidad || '', tipo: 'nuevo', garantiaMeses: 0, ubicacion: null
    };
    DB.stock.push(item);
    if (SB_KEY && TIENDA_ID) sbPost('stock', {
      id: item.id, tienda_id: TIENDA_ID, categoria: item.categoria, marca: item.marca,
      modelo: item.modelo, capacidad: '', color: '', imei: item.imei,
      unidades: 1, precio_c: item.precioC, precio_v: item.precioV,
      stock_min: 2, stock_max: 10, vendido: false,
      calidad: item.calidad || null, tipo: 'nuevo', garantia_meses: 0, ubicacion: null
    });
    _logMov('entrada', _eqNombre(item.marca, item.modelo) + ' ' + imei, 1, p.proveedor || T('pedidos.pieza'));
  });
}
// Recibir TODOS los pedidos en estado 'pedido' de golpe. No-IMEI en bloque; IMEI pidiendo los códigos.
function recibirTodosPedidos() {
  if (!tienePerm('stock_crear')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var pend = (DB.pedidos || []).filter(function (p) { return p.estado === 'pedido'; });
  if (!pend.length) { toast(T('pedidos.nada_recibir') || 'No hay pedidos por recibir', 'err'); return; }
  confirmar((T('pedidos.recibir_todos_confirm') || '¿Marcar como recibidos los {n} pedidos y sumarlos al stock?').replace('{n}', pend.length), function () {
    _procesarRecibirLista(pend, 0, { recibidos: 0, saltados: 0 }, function (ctr) {
      toast((T('pedidos.recibidos_n') || '{n} pedidos recibidos').replace('{n}', ctr.recibidos) + (ctr.saltados ? ' · ' + ctr.saltados + ' ' + (T('pedidos.pendientes_resto') || 'sin IMEI, pendientes') : ''), 'ok');
    });
  }, { okLabel: _pedBtnLbl('recibir') });
}
// Recibir de golpe todos los productos «pedido» de un proveedor (no IMEI)
function recibirGrupo(encKey) {
  if (!tienePerm('stock_crear')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var key = decodeURIComponent(encKey);
  var sinProv = T('pedidos.sin_proveedor');
  var grp = (DB.pedidos || []).filter(function(p) { return p.estado === 'pedido' && (((p.proveedor || '').trim() || sinProv) === key); });
  if (!grp.length) return;
  confirmar(T('pedidos.confirmar_grupo_recibir').replace('{n}', grp.length).replace('{prov}', key), function () {
    _procesarRecibirLista(grp, 0, { recibidos: 0, saltados: 0 }, function (ctr) {
      toast((T('pedidos.recibidos_n') || '{n} pedidos recibidos').replace('{n}', ctr.recibidos) + (ctr.saltados ? ' · ' + ctr.saltados + ' ' + (T('pedidos.pendientes_resto') || 'pendientes') : ''), 'ok');
    });
  }, { okLabel: _pedBtnLbl('recibir') });
}
function eliminarPedido(id) {
  if (!tienePerm('stock_eliminar')) { toast(T('gen.sin_permiso'), 'err'); return; }
  if (!confirm(T('pedidos.confirmar_borrar'))) return;
  DB.pedidos = (DB.pedidos || []).filter(function(x) { return x.id !== id; });
  if (SB_KEY) sbDelete('pedidos', 'id=eq.' + encodeURIComponent(id));
  renderPedidosWidget();
}
function _crearGastoDesdePedido(p) {
  var g = {
    id: 'g' + Date.now() + '_' + Math.random().toString(36).slice(2, 8), tienda_id: TIENDA_ID,
    concepto: T('pedidos.concepto_gasto') + ': ' + p.pieza + (p.proveedor ? (' (' + p.proveedor + ')') : ''),
    importe: parseFloat(p.importe) || 0, fecha: hoyLocal(), estado: 'Pagado', categoria: 'Stock/Compras',
    iva_tipo: 21, proveedor_id: null, proveedor_nombre: p.proveedor || null, proveedor_nif: null, numero_factura: null,
    metodo_pago: p.metodo_pago || 'transferencia'
  };
  DB.gastos = DB.gastos || [];
  DB.gastos.push(g);
  if (SB_KEY && TIENDA_ID) sbPost('gastos', g);
  try { guardarDatos(); } catch (e) {}
  try { if (typeof renderGastos === 'function') renderGastos(); } catch (e) {}
  return g.id;
}

// Sube el PDF/factura de un pedido al bucket de adjuntos. Devuelve {path, nombre, mime} o null.
async function _subirPdfPedido(file, grupo) {
  if (!SB_KEY || !TIENDA_ID || !file) return null;
  try {
    var esPdf = file.type === 'application/pdf';
    var blob = esPdf ? file : await comprimirImagen(file, 1600, 0.75);
    var ext = esPdf ? 'pdf' : 'jpg';
    var mime = esPdf ? 'application/pdf' : (blob.type || 'image/jpeg');
    var path = TIENDA_ID + '/pedido-' + grupo + '-' + Date.now() + '.' + ext;
    var blobToUpload = new Blob([blob], { type: mime });
    blobToUpload.name = file.name;
    var resp = await sbStorageUpload('gastos-adjuntos', path, blobToUpload);
    if (!resp.ok) { console.error('Upload PDF pedido falló:', resp.status); toast(T('imp.error_subir_factura'), 'err'); return null; }
    return { path: path, nombre: file.name, mime: mime };
  } catch (e) { console.error('_subirPdfPedido:', e); toast(T('imp.error_procesar_factura'), 'err'); return null; }
}

// Crea UN gasto consolidado para todo un pedido (total real pagado + factura adjunta).
function _crearGastoPedidoGrupo(p) {
  var g = {
    id: 'g' + Date.now() + '_' + Math.random().toString(36).slice(2, 8), tienda_id: TIENDA_ID,
    concepto: (T('pedidos.concepto_gasto_pedido') || 'Pedido') + (p.proveedor ? ' — ' + p.proveedor : ''),
    importe: parseFloat(p.total_real) || 0, fecha: hoyLocal(), estado: 'Pagado', categoria: 'Stock/Compras',
    iva_tipo: 21, proveedor_id: null, proveedor_nombre: p.proveedor || null, proveedor_nif: null, numero_factura: null,
    metodo_pago: p.metodo_pago || 'transferencia',
    adjunto_url: p.pdf_url || null, adjunto_nombre: p.pdf_nombre || null
  };
  DB.gastos = DB.gastos || [];
  DB.gastos.push(g);
  if (SB_KEY && TIENDA_ID) sbPost('gastos', g);
  try { guardarDatos(); } catch (e) {}
  try { if (typeof renderGastos === 'function') renderGastos(); } catch (e) {}
  return g.id;
}

// Marca todas las líneas de un grupo con el mismo gasto_id (para no duplicar gastos al recibir).
function _marcarGrupoGasto(grupo, gid) {
  (DB.pedidos || []).forEach(function (x) {
    if (x.grupo === grupo && x.gasto_id !== gid) {
      x.gasto_id = gid;
      if (SB_KEY && TIENDA_ID) sbPatch('pedidos', 'id=eq.' + encodeURIComponent(x.id), { gasto_id: gid });
    }
  });
}

// Devuelve el gasto_id a asignar al recibir una línea (consolida por grupo si hay total_real).
function _gastoAlRecibir(p) {
  if (p.gasto_id) return p.gasto_id;
  // Pendiente/financiado: aún no se ha pagado → no se crea gasto al recibir.
  // El gasto se crea al "Registrar pago a proveedor" (que es cuando sale el dinero).
  if (p.estado_pago && p.estado_pago !== 'pagado') return null;
  // Pedido con total real pagado → UN solo gasto para todo el grupo (con la factura)
  if (p.grupo && (parseFloat(p.total_real) || 0) > 0) {
    var hermano = (DB.pedidos || []).find(function (x) { return x.grupo === p.grupo && x.gasto_id; });
    var gid = hermano ? hermano.gasto_id : _crearGastoPedidoGrupo(p);
    _marcarGrupoGasto(p.grupo, gid);
    return gid;
  }
  // Clásico: un gasto por línea según su coste
  if ((parseFloat(p.importe) || 0) > 0) return _crearGastoDesdePedido(p);
  return null;
}

// ═══ DEUDA A PROVEEDORES (pedidos pendientes/financiados) ═══
var _SIN_PROV = '(sin proveedor)';
// Solo el admin (o permiso 'todo') ve los IMPORTES de deuda. El empleado puede registrar pagos.
function _esAdmin() { return !!(typeof U !== 'undefined' && U && (U.rol === 'admin' || (U.permisos && U.permisos.todo))); }
// { proveedor: deuda } — suma de (importe - pagado_importe) de pedidos no pagados
function _deudaProveedores() {
  var map = {};
  (DB.pedidos || []).forEach(function (p) {
    if (!p.estado_pago || p.estado_pago === 'pagado') return;
    var debe = (parseFloat(p.importe) || 0) - (parseFloat(p.pagado_importe) || 0);
    if (debe <= 0.005) return;
    var prov = (p.proveedor || '').trim() || _SIN_PROV;
    map[prov] = (map[prov] || 0) + debe;
  });
  return map;
}
// Panel de deuda en la página de pedidos. Empleado: sin importes (solo registrar pago).
function renderDeudaProveedores() {
  var box = document.getElementById('deudaProvBox');
  if (!box) return;
  var map = _deudaProveedores();
  var provs = Object.keys(map).sort(function (a, b) { return map[b] - map[a]; });
  if (!provs.length) { box.innerHTML = ''; return; }
  var admin = _esAdmin();
  var total = provs.reduce(function (a, p) { return a + map[p]; }, 0);
  var cab = '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px"><div style="font-weight:800;font-size:13px">💳 ' + (T('pedidos.deuda_proveedores') || 'Deuda a proveedores') + '</div>' +
    (admin ? '<div style="display:flex;align-items:center;gap:10px"><button class="btn-sm" style="background:var(--light);border:none;border-radius:7px;padding:3px 9px;font-size:11px;cursor:pointer" onclick="abrirPagosProveedor()">📜 ' + (T('pedidos.ver_pagos') || 'Ver pagos') + '</button><span style="font-weight:800;color:var(--red)">' + cur(total) + '</span></div>' : '') + '</div>';
  box.innerHTML = '<div style="background:var(--card,#fff);border:1px solid var(--border);border-radius:12px;padding:12px 14px;margin-bottom:12px">' + cab +
    provs.map(function (p) {
      return '<div style="display:flex;justify-content:space-between;align-items:center;padding:7px 0;border-top:1px solid var(--border);font-size:13px">' +
        '<span style="font-weight:600">' + esc(p) + '</span>' +
        '<span style="display:flex;align-items:center;gap:10px">' +
        (admin ? '<span style="font-weight:700;color:var(--red)">' + cur(map[p]) + '</span>' : '') +
        '<button class="btn-sm" style="background:var(--green);color:#fff;padding:4px 10px;border:none;border-radius:7px;cursor:pointer;font-weight:700" onclick="abrirPagoProveedor(\'' + encodeURIComponent(p) + '\')">' + (T('pedidos.registrar_pago') || 'Registrar pago') + '</button></span></div>';
    }).join('') + '</div>';
}
function abrirPagoProveedor(encProv) {
  var prov = decodeURIComponent(encProv);
  var admin = _esAdmin();
  var deuda = _deudaProveedores()[prov] || 0;
  var msg = admin
    ? (T('pedidos.pago_prompt') || '¿Cuánto pagas a {prov}? (debes {deuda})').replace('{prov}', prov).replace('{deuda}', cur(deuda))
    : (T('pedidos.pago_prompt_emp') || '¿Cuánto pagas a {prov}?').replace('{prov}', prov);
  pedirImporte(msg, (admin && deuda > 0) ? deuda.toFixed(2) : '', function (val) {
    if (val == null || val === '') return;
    var importe = parseFloat(String(val).replace(',', '.')) || 0;
    if (importe <= 0) { toast(T('pedidos.pago_invalido') || 'Importe inválido', 'err'); return; }
    registrarPagoProveedor(prov, importe);
  });
}
// Modal: historial de pagos a proveedores (solo admin), con fecha e importe
function abrirPagosProveedor() {
  if (!_esAdmin()) { toast(T('gen.sin_permiso'), 'err'); return; }
  var pagos = (DB.pagosProv || []).slice().sort(function (a, b) { return String(b.fecha || '').localeCompare(String(a.fecha || '')) || String(b.id).localeCompare(String(a.id)); });
  var cuerpo;
  if (!pagos.length) {
    cuerpo = '<div style="padding:24px;text-align:center;color:var(--muted)">' + (T('pedidos.sin_pagos') || 'Aún no hay pagos registrados') + '</div>';
  } else {
    cuerpo = pagos.map(function (pg) {
      return '<div style="display:flex;justify-content:space-between;align-items:center;padding:9px 2px;border-bottom:1px solid var(--border);font-size:13px">' +
        '<div><div style="font-weight:700">' + esc(pg.proveedor || _SIN_PROV) + '</div><div style="font-size:11px;color:var(--muted)">' + fmtFecha(pg.fecha) + (pg.usuario ? ' · ' + esc(pg.usuario) : '') + '</div></div>' +
        '<div style="font-weight:800;color:var(--green)">' + cur(pg.importe || 0) + '</div></div>';
    }).join('');
  }
  var ov = document.createElement('div');
  ov.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:200;display:flex;align-items:center;justify-content:center;padding:16px';
  ov.onclick = function (e) { if (e.target === ov) document.body.removeChild(ov); };
  ov.innerHTML = '<div style="background:#fff;border-radius:14px;max-width:460px;width:100%;max-height:85vh;display:flex;flex-direction:column;overflow:hidden" onclick="event.stopPropagation()">' +
    '<div style="display:flex;justify-content:space-between;align-items:center;padding:14px 16px;border-bottom:1px solid var(--border)"><div style="font-weight:800">📜 ' + (T('pedidos.historial_pagos') || 'Pagos a proveedores') + '</div><button style="background:none;border:none;font-size:20px;cursor:pointer;color:var(--muted)">×</button></div>' +
    '<div style="overflow-y:auto;padding:6px 16px 16px">' + cuerpo + '</div></div>';
  ov.querySelector('button').onclick = function () { document.body.removeChild(ov); };
  document.body.appendChild(ov);
}
// Aplica el pago FIFO (más antiguos primero) a los pedidos pendientes + crea el gasto del pago real
function registrarPagoProveedor(prov, importe) {
  if (!tienePerm('gastos_crear')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var pend = (DB.pedidos || []).filter(function (p) {
    if (!p.estado_pago || p.estado_pago === 'pagado') return false;
    if ((parseFloat(p.importe) || 0) - (parseFloat(p.pagado_importe) || 0) <= 0.005) return false;
    return ((p.proveedor || '').trim() || _SIN_PROV) === prov;
  }).sort(function (a, b) { return String(a.id).localeCompare(String(b.id)); }); // id lleva timestamp → más antiguo primero
  var restante = importe, saldados = 0;
  pend.forEach(function (p) {
    if (restante <= 0.005) return;
    var debe = (parseFloat(p.importe) || 0) - (parseFloat(p.pagado_importe) || 0);
    var aplica = Math.min(restante, debe);
    p.pagado_importe = Math.round(((parseFloat(p.pagado_importe) || 0) + aplica) * 100) / 100;
    restante = Math.round((restante - aplica) * 100) / 100;
    var patch = { pagado_importe: p.pagado_importe };
    if (p.pagado_importe >= (parseFloat(p.importe) || 0) - 0.005) { p.estado_pago = 'pagado'; patch.estado_pago = 'pagado'; saldados++; }
    if (SB_KEY && TIENDA_ID) sbPatch('pedidos', 'id=eq.' + encodeURIComponent(p.id), patch);
  });
  var aplicado = Math.round((importe - restante) * 100) / 100;
  // Gasto del pago real (lo que sale de caja/banco)
  var g = {
    id: 'g' + Date.now() + '_' + Math.random().toString(36).slice(2, 8), tienda_id: TIENDA_ID,
    concepto: (T('pedidos.concepto_pago_prov') || 'Pago a proveedor') + (prov && prov !== _SIN_PROV ? ' — ' + prov : ''),
    importe: Math.round(importe * 100) / 100, fecha: hoyLocal(), estado: 'Pagado', categoria: 'Stock/Compras',
    iva_tipo: 21, proveedor_id: null, proveedor_nombre: (prov === _SIN_PROV ? null : prov), proveedor_nif: null, numero_factura: null,
    metodo_pago: 'transferencia'
  };
  DB.gastos = DB.gastos || [];
  DB.gastos.push(g);
  if (SB_KEY && TIENDA_ID) sbPost('gastos', g);
  // Registro del pago para el historial (lista de pagos por proveedor con fecha e importe)
  var pago = { id: 'pp' + Date.now() + '_' + Math.random().toString(36).slice(2, 8), tienda_id: TIENDA_ID, proveedor: (prov === _SIN_PROV ? null : prov), importe: Math.round(importe * 100) / 100, fecha: hoyLocal(), usuario: (U ? U.nombre : null) };
  DB.pagosProv = DB.pagosProv || [];
  DB.pagosProv.unshift(pago);
  if (SB_KEY && TIENDA_ID) sbPost('pagos_proveedor', pago);
  try { guardarDatos(); } catch (e) {}
  try { renderGastos(); } catch (e) {}
  try { renderPedidosWidget(); } catch (e) {}
  try { renderDeudaProveedores(); } catch (e) {}
  try { renderLoQueDebes(); } catch (e) {}
  try { if (typeof audit === 'function') audit('crear', 'pago_proveedor', { proveedor: prov, importe: importe, saldados: saldados }); } catch (e) {}
  var sobra = restante > 0.005 ? (' · ' + (T('pedidos.pago_saldo_favor') || 'Sobran') + ' ' + cur(restante)) : '';
  toast((T('pedidos.pago_ok') || 'Pago registrado') + ': ' + cur(aplicado) + ' · ' + saldados + ' ' + (T('pedidos.saldados') || 'saldados') + sobra, 'ok');
}

// ── Puerta de código de Cajas: identifica al empleado al entrar ──
async function pedirCodigoCaja() {
  var users = [];
  try { users = await sbGet('usuarios', 'tienda_id=eq.' + TIENDA_ID + '&select=nombre,codigo,rol,activo'); } catch (e) {}
  var conCodigo = (users || []).filter(function(u) { return u.activo !== false && u.codigo; });
  if (conCodigo.length === 0) {
    // Nadie tiene código configurado → sin puerta (entra como el usuario logueado)
    window._cajaSesion = { codigo: '', nombre: (U ? U.nombre : '') };
    window._cajaGateOk = true;
    navTo('pCajas');
    return;
  }
  window._cajaUsersCache = conCodigo;
  var inp = document.getElementById('codigo-caja-input'); if (inp) inp.value = '';
  var err = document.getElementById('codigo-caja-error'); if (err) err.style.display = 'none';
  var adminBtn = document.getElementById('codigo-caja-admin');
  if (adminBtn) adminBtn.style.display = (U && U.rol === 'admin') ? '' : 'none';
  document.getElementById('modal-codigo-caja').classList.add('activo');
  setTimeout(function() { if (inp) inp.focus(); }, 80);
}
function validarCodigoCaja() {
  var cod = (document.getElementById('codigo-caja-input').value || '').trim();
  var match = (window._cajaUsersCache || []).find(function(u) { return String(u.codigo) === cod; });
  if (!match) {
    var err = document.getElementById('codigo-caja-error');
    if (err) { err.textContent = T('caja.codigo_no_valido'); err.style.display = 'block'; }
    return;
  }
  window._cajaSesion = { codigo: cod, nombre: match.nombre };
  window._cajaGateOk = true;
  document.getElementById('modal-codigo-caja').classList.remove('activo');
  navTo('pCajas');
}
function entrarCajaAdmin() {
  window._cajaSesion = { codigo: '', nombre: (U ? U.nombre : '') };
  window._cajaGateOk = true;
  document.getElementById('modal-codigo-caja').classList.remove('activo');
  navTo('pCajas');
}
function cerrarCodigoCaja() {
  document.getElementById('modal-codigo-caja').classList.remove('activo');
  // No entra en Cajas: se queda donde estaba
}

function navTo(id) {
  // Inicio por plan: el Inicio nuevo (avanzado) es de Premium. Básico/Pro van al panel Clásico.
  // Inicio por plan: Básico/Pro ahora usan el Inicio moderno recortado (ya NO se redirige al Clásico).
  // Cajas: si el admin denegó el permiso a este trabajador, no puede abrirla ni por enlace directo
  if (id === 'pCajas' && U && U.rol !== 'admin' && !(U.permisos && U.permisos.todo)
      && U.permisos && U.permisos.cajas_ver === false) {
    toast(T('gen.sin_permiso'), 'err'); return;
  }
  // Puerta de código: al entrar en Cajas se identifica al empleado por su código
  if (id === 'pCajas' && !window._cajaGateOk) { pedirCodigoCaja(); return; }
  if (id !== 'pCajas') window._cajaGateOk = false;
  // F293: al cambiar de página, cerrar cualquier modal abierto (si no, quedaban apilados
  // de la pantalla anterior — p.ej. abrir Servicio y ver detrás el de Proveedor).
  try { document.querySelectorAll('.modal-bg.open').forEach(function(m) { m.classList.remove('open'); }); } catch (e) {}
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  var el = document.getElementById(id);
  if (el) {
    el.classList.add('active');
    el.scrollTop = 0;
  }
  // F36: sincronizar el resaltado del menú lateral con la página activa,
  // aunque se navegue sin clic directo (botones "+más", llamadas programáticas).
  // Las páginas sin entrada propia en el menú resaltan su sección lógica (alias).
  try {
    var _navAlias = { pDash: 'pInicioNuevo', pCatalogo: 'pServicios', pTienda: 'pAjustes', pImportar: 'pStock' };
    var _sid = _navAlias[id] || id;
    var sbni = document.querySelector('.sidebar-ni[data-p="' + _sid + '"]');
    if (sbni) {
      document.querySelectorAll('.sidebar-ni').forEach(function(n) { n.classList.remove('active'); });
      sbni.classList.add('active');
    }
  } catch (e) {}
  document.getElementById('content').scrollTop = 0;
  // Trigger renders
  if (id === 'pVentas') renderVentas();
  if (id === 'pReps') renderReps();
  if (id === 'pStock') renderStock();
  if (id === 'pClis') renderClis();
  if (id === 'pProvs') renderProvs();
  if (id === 'pCajas') Cajas.renderCajas();
  if (id === 'pInicioNuevo') renderInicioNuevo();
  if (id === 'pDash') renderDash();   // F13: el dashboard Clásico no se re-renderizaba al abrirlo → salía €0/0 ventas
  if (id === 'pPedidos') renderPedidosPage();
  if (id === 'pAyuda') { try { renderGuiaAyuda(); } catch(e){} }
  if (id === 'pGastos') renderGastos();
  if (id === 'pAjustes') { try { renderUbicacionesAjustes(); } catch(e){} cargarAjustes(); try { cargarTienda(); } catch(e){} try { renderStorageUso(); } catch(e){} try { ajRailPlanLocks(); } catch(e){} }
  if (id === 'pReportes') renderReporte();
  if (id === 'pPresupuestos') {
    renderPresupuestos();
    // Sync ligero: recargar reps desde Supabase para tener estados frescos
    if (SB_KEY && TIENDA_ID) {
      sbGet('reparaciones', 'tienda_id=eq.' + TIENDA_ID + '&estado=in.(Presupuesto,Rechazado)&select=id,cliente_id,cliente_nombre,marca,modelo,averia,estado,total,base,iva,iva_importe,iva_modo,servicios,componentes,fecha,presupuesto_aceptado_at,presupuesto_token_exp,piezas_devueltas,es_garantia,rep_original_id,mo,comp,anticipo,restante,pago_final,fecha_entrega,fecha_entrega_real,nota,tipo_bloqueo,bloqueo,imei,prioridad,firma_cliente,firma_fecha,presupuesto_aceptado_ip,fotos_recepcion,fotos_entrega').then(function(rows) {
        if (!Array.isArray(rows)) return;
        // Actualizar solo los presupuestos en DB.reps
        rows.forEach(function(r) {
          var mapped = mapRep(r);
          var idx = DB.reps.findIndex(function(x){ return x.id === r.id; });
          if (idx >= 0) DB.reps[idx] = mapped;
          else DB.reps.push(mapped);
        });
        renderPresupuestos();
        actualizarBadgePresupuestos();
      }).catch(function(e){ console.error('sync pres:', e); });
    }
  }
  if (id === 'pTienda') { navTo('pAjustes'); try { ajSec('negocio'); } catch(e){} return; }
  if (id === 'pServicios') renderServicios();
  if (id === 'pEncargos') renderEncargos();
  if (id === 'pCatalogo') { try { renderCatalogo(); } catch(e){} }
  if (id === 'pUsuarios') cargarUsuarios();
  if (id === 'pFacturas') renderFacturas();
  // COM-NAV-FIX: comisiones también se carga aquí (antes solo se cargaba al
  // hacer click en el sidebar, fallaba si navTo se llamaba directamente).
  if (id === 'pComisiones' && typeof cargarComisiones === 'function') cargarComisiones();
  // F211: reflejar la sección activa en la URL para que un F5 vuelva a la misma vista.
  // replaceState NO dispara 'hashchange', así que no reentra en _navFromHash.
  try {
    var _h = _PAGE_HASH[id];
    if (_h && ('#' + _h) !== location.hash) {
      history.replaceState(history.state, '', location.pathname + location.search + '#' + _h);
    }
  } catch (e) {}
}

// F211: mapa inverso pageId → hash (canónico) para persistir la vista en la URL.
