// ═══ TOAST ═══
function toast(msg, type) {
  var t = document.getElementById('toast');
  t.textContent = msg;
  t.className = 'show' + (type ? ' ' + type : '');
  setTimeout(function() { t.className = ''; }, 2500);
}

// ═══ SPINNER GLOBAL DE MUTACIONES ═══
// Overlay que bloquea la interacción mientras una operación pesada (reembolso, recibir
// pedido…) reescribe stock y re-renderiza. Bloquear la UI evita además el multi-click que
// duplicaba líneas. Usa un contador para soportar llamadas anidadas.
var _tpBusyCount = 0;
function tpBusy(on, msg) {
  if (on) {
    _tpBusyCount++;
    var ov = document.getElementById('tpBusyOverlay');
    if (!ov) {
      if (!document.getElementById('tpBusyStyle')) {
        var st = document.createElement('style');
        st.id = 'tpBusyStyle';
        st.textContent = '@keyframes tpSpin{to{transform:rotate(360deg)}}' +
          '#tpBusyOverlay{position:fixed;inset:0;z-index:99999;display:flex;flex-direction:column;' +
          'align-items:center;justify-content:center;gap:14px;background:rgba(15,23,41,.38);' +
          'backdrop-filter:blur(1px);cursor:wait}' +
          '#tpBusyOverlay .tpb-spin{width:44px;height:44px;border:4px solid rgba(255,255,255,.35);' +
          'border-top-color:#fff;border-radius:50%;animation:tpSpin .8s linear infinite}' +
          '#tpBusyOverlay .tpb-msg{color:#fff;font-weight:600;font-size:14px;text-shadow:0 1px 3px rgba(0,0,0,.3)}';
        document.head.appendChild(st);
      }
      ov = document.createElement('div');
      ov.id = 'tpBusyOverlay';
      ov.innerHTML = '<div class="tpb-spin"></div><div class="tpb-msg"></div>';
      document.body.appendChild(ov);
    }
    ov.querySelector('.tpb-msg').textContent = msg || T('gen.procesando') || 'Procesando…';
    ov.style.display = 'flex';
  } else {
    _tpBusyCount = Math.max(0, _tpBusyCount - 1);
    if (_tpBusyCount === 0) {
      var o = document.getElementById('tpBusyOverlay');
      if (o) o.style.display = 'none';
    }
  }
}
// Ejecuta fn mostrando el spinner. Cede un frame para que el overlay PINTE antes del
// trabajo síncrono pesado (si no, el hilo se bloquea y el spinner no llega a verse).
// Soporta fn síncrona o que devuelva Promise.
function tpWithBusy(msg, fn) {
  tpBusy(true, msg);
  return new Promise(function(resolve) {
    setTimeout(function() {
      var done = function() { tpBusy(false); resolve(); };
      try {
        var r = fn();
        if (r && typeof r.then === 'function') r.then(done, function(e){ console.error(e); done(); });
        else done();
      } catch (e) { console.error(e); done(); }
    }, 30);
  });
}

// ═══ LOCAL DATA ═══
function cargarDatosLocal() {
  var d = localStorage.getItem('tk_db');
  if (d) {
    try {
      var parsed = JSON.parse(d);
      if (parsed.ventas) DB.ventas = parsed.ventas;
      if (parsed.reps) DB.reps = parsed.reps;
      if (parsed.stock) DB.stock = parsed.stock;
      if (parsed.clis) DB.clis = parsed.clis;
      if (parsed.gastos) DB.gastos = parsed.gastos;
      if (parsed.provs) DB.provs = parsed.provs;
      if (parsed.gastos_recurrentes) DB.gastos_recurrentes = parsed.gastos_recurrentes;
      if (parsed.servicios) DB.servicios = parsed.servicios;
      if (parsed.encargos) DB.encargos = parsed.encargos;
    } catch(e) {}
  }
}

function guardarDatos() {
  try {
    localStorage.setItem('tk_db', JSON.stringify(DB));
    var tiendaData = JSON.parse(localStorage.getItem('tk_tienda') || '{}');
    tiendaData.nombre = TIENDA.nombre;
    localStorage.setItem('tk_tienda', JSON.stringify(tiendaData));
  } catch(e) {
    console.error('Error guardarDatos (localStorage):', e);
    // Cuota agotada: intentar liberar espacio cortando el audit log a la mitad
    if (e && (e.name === 'QuotaExceededError' || e.code === 22 || (e.message||'').indexOf('quota') >= 0)) {
      if (DB.audit && DB.audit.length > 100) {
        DB.audit = DB.audit.slice(0, Math.floor(DB.audit.length / 2));
        try {
          localStorage.setItem('tk_db', JSON.stringify(DB));
          if (typeof toast === 'function') toast('⚠ Almacenamiento lleno: se redujo el historial', 'err');
        } catch(e2) {
          if (typeof toast === 'function') toast(T('tst.almacenamiento_lleno'), 'err');
        }
      } else {
        if (typeof toast === 'function') toast(T('tst.almacenamiento_lleno'), 'err');
      }
    }
  }
  if (typeof refreshNotifs === 'function') refreshNotifs();
}

// ═══ AUDITORÍA ═══
function audit(accion, entidad, entidadId, detalle, cambios) {
  if (!DB.audit) DB.audit = [];
  var entry = {
    id: 'a' + Date.now() + '_' + Math.random().toString(36).slice(2, 8),
    ts: new Date().toISOString(),
    usuarioId: (U && U.id) || '?',
    usuarioNom: (U && (U.nombre || U.email)) || '?',
    accion: accion || '',
    entidad: entidad || '',
    entidadId: entidadId || '',
    detalle: detalle || '',
    cambios: cambios || null
  };
  DB.audit.unshift(entry);
  // Limitar a 1000 entradas locales (LIFO, las más viejas se descartan)
  if (DB.audit.length > 1000) DB.audit = DB.audit.slice(0, 1000);
  localStorage.setItem('tk_db', JSON.stringify(DB));
  if (typeof SB_KEY !== 'undefined' && SB_KEY && TIENDA_ID) {
    sbPost('audit', {
      id: entry.id, tienda_id: TIENDA_ID, ts: entry.ts,
      usuario_id: entry.usuarioId, usuario_nom: entry.usuarioNom,
      accion: entry.accion, entidad: entry.entidad, entidad_id: entry.entidadId,
      detalle: entry.detalle, cambios: entry.cambios
    });
  }
}

// ═══ SUPABASE ═══
var _sbErrLast = {};
function _sbErrorToast(method, table, info) {
  console.error('[Supabase ' + method + ' ' + table + ']', info);
  if (typeof navigator !== 'undefined' && navigator.onLine === false) return; // offline, no spam
  var key = method + ':' + table;
  var now = Date.now();
  if (_sbErrLast[key] && now - _sbErrLast[key] < 8000) return;
  _sbErrLast[key] = now;
  var msg = '';
  if (info && info.message) msg = info.message;
  else if (info && info.code) msg = 'cód ' + info.code;
  else if (info && info.status) msg = 'HTTP ' + info.status;
  if (typeof toast === 'function') toast('⚠ Sync ' + table + ': ' + String(msg).substring(0, 60), 'err');
}

// Deduplicación de lecturas: micro-caché (TTL corto) + colapso de GETs idénticos en vuelo.
// Reduce las peticiones repetidas del burst de carga (tiendas/pedidos ×N). Se invalida en
// CADA escritura (sbPost/sbPatch/sbDelete) → las acciones del usuario siempre ven datos frescos.
var _sbReadCache = {};
var _sbReadInflight = {};
var _SB_READ_TTL = 1000; // ms
function _sbReadCacheClear() { _sbReadCache = {}; }
function sbGet(table, query) {
  var key = 'G|' + table + '|' + query;
  var c = _sbReadCache[key];
  if (c && (Date.now() - c.t) < _SB_READ_TTL) return Promise.resolve(c.data);
  if (_sbReadInflight[key]) return _sbReadInflight[key];
  var _err = false;
  var p = fetch(SUPABASE_URL + '/rest/v1/' + table + '?' + query + '&select=*', {
    headers: {'apikey': SB_KEY, 'Authorization': 'Bearer ' + (JWT_TOKEN || SB_KEY)}
  }).then(function(r) {
    if (!r.ok) {
      _err = true;
      return r.json().then(function(err){ _sbErrorToast('GET', table, err); return []; }, function(){ _sbErrorToast('GET', table, {status:r.status}); return []; });
    }
    return r.json();
  }).catch(function(e) {
    _err = true;
    _sbErrorToast('GET', table, e);
    return [];
  }).then(function(data) {
    delete _sbReadInflight[key];
    if (!_err) _sbReadCache[key] = { t: Date.now(), data: data };
    return data;
  });
  _sbReadInflight[key] = p;
  return p;
}

// Como sbGet pero PAGINADO. PostgREST devuelve máx. 1000 filas por petición; en tiendas con mucho
// volumen eso "perdía" datos (clientes/ventas/etc. más allá de 1000 no se cargaban). Trae TODO en lotes.
// La query NO debe traer su propio 'order' (aquí se ordena por id para paginar de forma estable).
function sbGetAll(table, query) {
  var key = 'GA|' + table + '|' + query;
  var c = _sbReadCache[key];
  if (c && (Date.now() - c.t) < _SB_READ_TTL) return Promise.resolve(c.data);
  if (_sbReadInflight[key]) return _sbReadInflight[key];
  var PAGE = 1000, all = [];
  function pag(offset) {
    var url = SUPABASE_URL + '/rest/v1/' + table + '?' + query + '&select=*&order=id.asc&limit=' + PAGE + '&offset=' + offset;
    return fetch(url, { headers: {'apikey': SB_KEY, 'Authorization': 'Bearer ' + (JWT_TOKEN || SB_KEY)} })
      .then(function(r) { return r.ok ? r.json() : []; }, function() { return []; })
      .then(function(rows) {
        if (!Array.isArray(rows) || !rows.length) return all;
        all = all.concat(rows);
        if (rows.length < PAGE) return all; // última página
        return pag(offset + PAGE);
      }, function() { return all; });
  }
  var p = pag(0).catch(function() { return all; }).then(function(rows) {
    delete _sbReadInflight[key];
    _sbReadCache[key] = { t: Date.now(), data: rows };
    return rows;
  });
  _sbReadInflight[key] = p;
  return p;
}


// ═══════════════════════════════════════════════════════════
// SISTEMA ANTI-PÉRDIDA DE DATOS (cola de sync con reintentos)
// ═══════════════════════════════════════════════════════════
var SYNC_QUEUE_KEY = 'tk_sync_queue_v1';
var SYNC_MAX_RETRIES = 5;
var SYNC_RETRY_INTERVAL_MS = 30000;

function _syncQueueGet() {
  try { return JSON.parse(localStorage.getItem(SYNC_QUEUE_KEY) || '[]'); }
  catch(e) { return []; }
}

function _syncQueueSet(q) {
  try { localStorage.setItem(SYNC_QUEUE_KEY, JSON.stringify(q)); }
  catch(e) { console.error('Sync queue full:', e); }
}

function _syncQueueAdd(operation) {
  var q = _syncQueueGet();
  // Evitar duplicados por ID
  var dupIdx = q.findIndex(function(x) {
    return x.method === operation.method && x.table === operation.table && 
           x.dataId === operation.dataId && x.query === operation.query;
  });
  if (dupIdx >= 0) {
    // Reemplazar con el más reciente (más completo)
    q[dupIdx] = operation;
  } else {
    q.push(operation);
  }
  _syncQueueSet(q);
  _syncIndicatorUpdate();
}

function _syncQueueRemove(opId) {
  var q = _syncQueueGet().filter(function(x) { return x._opId !== opId; });
  _syncQueueSet(q);
  _syncIndicatorUpdate();
}

// Reintenta TODOS los pendientes (corre cada 30s y al volver online)
async function _syncQueueRetry() {
  if (!SB_KEY) return;
  if (!navigator.onLine) return; // Sin internet, no reintentar
  
  var q = _syncQueueGet();
  if (!q.length) return;
  
  
  for (var i = 0; i < q.length; i++) {
    var op = q[i];
    op.attempts = (op.attempts || 0) + 1;
    
    if (op.attempts > SYNC_MAX_RETRIES) {
      console.warn('Sync descartado tras', SYNC_MAX_RETRIES, 'intentos:', op);
      _syncQueueRemove(op._opId);
      if (typeof toast === 'function') {
        toast('No se pudo guardar un cambio en "' + op.table + '" y se ha descartado. Si era importante, vuelve a introducirlo.', 'err');
      }
      continue;
    }
    
    try {
      var res = {ok: false, status: 0};
      if (op.method === 'POST') {
        res = await _sbPostRaw(op.table, op.data);
      } else if (op.method === 'PATCH') {
        res = await _sbPatchRaw(op.table, op.query, op.data);
      } else if (op.method === 'DELETE') {
        res = await _sbDeleteRaw(op.table, op.query);
      }

      if (res.ok || (res.status === 409 && !_es409Grave(res))) {
        // 409 duplicado (ya existe) → reenvío idempotente, quitar sin alarmar. (FK/check 409 cae al else.)
        _syncQueueRemove(op._opId);
      } else if (!_esRetriable(res.status)) {
        // Error persistente (4xx no-retriable): descartar la op en lugar de loop infinito
        console.warn('✗ Sync descartado (no retriable):', op.method, op.table, 'HTTP ' + res.status);
        _syncQueueRemove(op._opId);
        if (typeof toast === 'function') {
          toast(T('tst.no_sincronizar').replace('{t}', op.table).replace('{s}', res.status), 'err');
        }
      }
    } catch(e) {
      console.warn('Reintento falló:', op.method, op.table, e);
    }
  }
}

// Indicador visual en topbar
function _syncIndicatorUpdate() {
  var box = document.getElementById('syncIndicator');
  var q = _syncQueueGet();
  
  if (!box) {
    // Crear el indicador si no existe
    box = document.createElement('div');
    box.id = 'syncIndicator';
    box.style.cssText = 'position:fixed;top:14px;right:14px;background:#F97316;color:white;padding:6px 12px;border-radius:8px;font-size:12px;font-weight:700;z-index:9999;cursor:pointer;box-shadow:0 4px 12px rgba(0,0,0,.15);display:none;font-family:Arial';
    box.onclick = function() {
      var qq = _syncQueueGet();
      alert('⚠️ Cambios pendientes de sincronizar: ' + qq.length + '\n\nReintentando automáticamente cada 30 segundos.\n\nNo cierres la app hasta que el indicador desaparezca.');
    };
    document.body.appendChild(box);
  }
  
  if (q.length > 0) {
    var offline = !navigator.onLine;
    box.innerHTML = (offline ? '⚠️ ' + T('sync.sin_conexion') : '🔄 ' + q.length + ' ' + T('gen.sin_sincronizar'));
    box.style.background = offline ? '#DC2626' : '#F97316';
    box.style.display = 'block';
  } else if (_syncPrevCount > 0) {
    // Acababa de drenarse la cola → confirmación verde efímera "Sincronizado ✓"
    box.innerHTML = '✅ ' + T('sync.sincronizado');
    box.style.background = '#16A34A';
    box.style.display = 'block';
    clearTimeout(_syncOkTimer);
    _syncOkTimer = setTimeout(function(){ var bb = document.getElementById('syncIndicator'); if (bb) bb.style.display = 'none'; }, 2500);
  } else {
    box.style.display = 'none';
  }
  _syncPrevCount = q.length;
}
var _syncPrevCount = 0, _syncOkTimer = null;

// Funciones RAW (las originales, sin cola)
// CLI-1: ahora devuelven {ok, status} para que la cola pueda decidir si reintentar.
// Errores 4xx (columna inexistente, datos malformados, PK duplicada, sesión expirada)
// son persistentes — reintentar no los arregla. Solo se debe reintentar:
//   - errores de red (fetch lanza excepción)
//   - 5xx (servidor caído temporalmente)
//   - 408 / 429 (timeout, rate limit)
function _sbPostRaw(table, data) {
  return fetch(SUPABASE_URL + '/rest/v1/' + table, {
    method: 'POST',
    headers: {'apikey': SB_KEY, 'Authorization': 'Bearer ' + (JWT_TOKEN || SB_KEY), 'Content-Type': 'application/json', 'Prefer': 'return=minimal'},
    body: JSON.stringify(data)
  }).then(function(r) {
    if (r.ok) return {ok: true, status: r.status};
    // En 409 leemos el código Postgres: 23505=ya existe (idempotente), 23503=FK rota, etc.
    return r.text().then(function(body) {
      var code = ''; try { code = (JSON.parse(body) || {}).code || ''; } catch (e) {}
      return {ok: false, status: r.status, code: code};
    }).catch(function() { return {ok: false, status: r.status, code: ''}; });
  }).catch(function() { return {ok: false, status: 0}; });  // status 0 = error de red
}
// 409 que NO es duplicado (clave foránea / check / not-null) → error real, no idempotente
function _es409Grave(res) {
  return res && res.status === 409 && ['23503', '23514', '23P01', '23502'].indexOf(res.code) !== -1;
}

function _sbPatchRaw(table, query, data) {
  _sbReadCacheClear();
  return fetch(SUPABASE_URL + '/rest/v1/' + table + '?' + query, {
    method: 'PATCH',
    // return=representation → la respuesta trae las filas actualizadas; así detectamos
    // un UPDATE de 0 filas (bloqueo RLS silencioso) que PostgREST devolvería como 204 OK.
    headers: {'apikey': SB_KEY, 'Authorization': 'Bearer ' + (JWT_TOKEN || SB_KEY), 'Content-Type': 'application/json', 'Prefer': 'return=representation'},
    body: JSON.stringify(data)
  }).then(function(r) {
    if (!r.ok) return {ok: false, status: r.status, rows: 0};
    return r.json().then(function(body) {
      return {ok: true, status: r.status, rows: Array.isArray(body) ? body.length : 1};
    }, function() { return {ok: true, status: r.status, rows: 1}; });
  }).catch(function() { return {ok: false, status: 0, rows: 0}; });
}

function _sbDeleteRaw(table, query) {
  return fetch(SUPABASE_URL + '/rest/v1/' + table + '?' + query, {
    method: 'DELETE',
    headers: {'apikey': SB_KEY, 'Authorization': 'Bearer ' + (JWT_TOKEN || SB_KEY)}
  }).then(function(r) {
    return {ok: r.ok, status: r.status};
  }).catch(function() { return {ok: false, status: 0}; });
}

// CLI-2: distinguir errores retriables (red/5xx) de persistentes (4xx)
// 4xx debería rendirse y mostrar al usuario, no reintentar 100 veces
function _esRetriable(status) {
  return status === 0      // error de red
      || status === 408    // timeout
      || status === 429    // rate limit
      || status >= 500;    // server error
}

// Iniciar el sistema
window.addEventListener('online', function() {
  setTimeout(_syncQueueRetry, 1000);
});
window.addEventListener('beforeunload', function(e) {
  var q = _syncQueueGet();
  if (q.length > 0) {
    e.preventDefault();
    e.returnValue = 'Tienes ' + q.length + ' cambios sin sincronizar. ¿Seguro que quieres salir?';
    return e.returnValue;
  }
});

// Reintentar cada 30 segundos
setInterval(_syncQueueRetry, SYNC_RETRY_INTERVAL_MS);

// Reintentar al cargar la página (por si hay pendientes de sesión anterior)
setTimeout(function(){ _syncQueueRetry(); _syncIndicatorUpdate(); }, 2000);


function sbPost(table, data) {
  _sbReadCacheClear();
  return _sbPostRaw(table, data).then(function(res) {
    if (res.ok) return true;
    // 409 con código 23505 (PK/único) = el registro YA existe. Con ids de cliente + sync "al menos una vez",
    // un POST puede reenviarse cuando el dato ya se guardó → idempotente, NO error. Tratar como OK.
    // PERO un 409 por clave foránea/check (FK rota, etc.) SÍ es un fallo real: avisar, no tragárselo.
    if (res.status === 409 && !_es409Grave(res)) { console.warn('sbPost ' + table + ' 409 (ya existe) — tratado como guardado.'); return true; }
    if (_es409Grave(res)) {
      console.error('sbPost ' + table + ' 409 GRAVE (' + res.code + ') — no se guardó. Payload:', data);
      if (typeof toast === 'function') toast(T('tst.no_guardar_ref').replace('{t}', table), 'err');
      return false;
    }
    // CLI-2: errores 4xx son persistentes — reintentar no ayuda. Avisar al usuario.
    if (!_esRetriable(res.status)) {
      console.error('sbPost ' + table + ' falló con status ' + res.status + ' (no retriable). Payload:', data);
      if (typeof toast === 'function') {
        var msg = '⚠️ Error al sincronizar ' + table + ' (HTTP ' + res.status + ')';
        if (res.status === 401) msg = '⚠️ Sesión expirada — vuelve a iniciar sesión';
        else if (res.status === 400) msg = '⚠️ Datos inválidos al guardar ' + table;
        toast(msg, 'err');
      }
      return false;
    }
    // Solo encolar errores retriables (red caída, 5xx)
    _syncQueueAdd({
      _opId: 'op_' + Date.now() + '_' + Math.random().toString(36).slice(2,8),
      method: 'POST',
      table: table,
      data: data,
      dataId: data.id || null,
      attempts: 0,
      ts: Date.now()
    });
    if (typeof toast === 'function') toast('⚠️ Sin conexión - guardado para sincronizar', 'err');
    return false;
  });
}

function sbPatch(table, query, data) {
  _sbReadCacheClear();
  return _sbPatchRaw(table, query, data).then(function(res) {
    if (res.ok) {
      // RLS-silencioso: 200/204 pero 0 filas actualizadas = la fila no es visible/editable
      // para este usuario (policy RLS de UPDATE bloqueando) o el id no existe. NO es un guardado real.
      if (res.rows === 0) {
        console.error('sbPatch ' + table + ' devolvió 0 filas (RLS bloquea UPDATE o id inexistente). Query: ' + query + ' Payload:', data);
        if (typeof toast === 'function') toast('⚠️ La nube rechazó el cambio — cierra sesión y vuelve a entrar, y reintenta', 'err');
        return false;
      }
      return true;
    }
    // CLI-2: igual que sbPost
    if (!_esRetriable(res.status)) {
      console.error('sbPatch ' + table + ' falló con status ' + res.status + ' (no retriable). Query: ' + query + ' Payload:', data);
      if (typeof toast === 'function') {
        var msg = '⚠️ Error al actualizar ' + table + ' (HTTP ' + res.status + ')';
        if (res.status === 401) msg = '⚠️ Sesión expirada — vuelve a iniciar sesión';
        else if (res.status === 400) msg = '⚠️ Datos inválidos al actualizar ' + table;
        toast(msg, 'err');
      }
      return false;
    }
    _syncQueueAdd({
      _opId: 'op_' + Date.now() + '_' + Math.random().toString(36).slice(2,8),
      method: 'PATCH',
      table: table,
      query: query,
      data: data,
      attempts: 0,
      ts: Date.now()
    });
    if (typeof toast === 'function') toast('⚠️ Sin conexión - cambio guardado para sincronizar', 'err');
    return false;
  });
}

function sbDelete(table, query) {
  _sbReadCacheClear();
  return fetch(SUPABASE_URL + '/rest/v1/' + table + '?' + query, {
    method: 'DELETE',
    headers: {'apikey': SB_KEY, 'Authorization': 'Bearer ' + (JWT_TOKEN || SB_KEY)}
  }).then(function(r) {
    if (!r.ok) {
      return r.json().then(function(err){ _sbErrorToast('DELETE', table, err); return false; }, function(){ _sbErrorToast('DELETE', table, {status:r.status}); return false; });
    }
    return true;
  }).catch(function(e) { _sbErrorToast('DELETE', table, e); return false; });
}

function mapVenta(v) {
  return {
    id:v.id, fecha:v.fecha, clienteId:v.cliente_id, clienteNombre:v.cliente_nombre,
    marca:v.marca||'', modelo:v.modelo||'', imei:v.imei||'',
    pago:v.pago||'Efectivo', precio:parseFloat(v.precio)||0,
    descuento:parseFloat(v.descuento)||0, total:parseFloat(v.total)||0,
    reembolsado:v.reembolsado||false, fechaReembolso:v.fecha_reembolso||'',
    stockId:v.stock_id||'', financiado:v.financiado||false,
    cuotas:v.cuotas?(typeof v.cuotas==='string'?JSON.parse(v.cuotas):v.cuotas):null, entrada:parseFloat(v.entrada)||0, entradaPago:v.entrada_pago||null,
    // IVA: estaba sin mapear → las facturas salían con IVA 0 al recargar / en otros equipos.
    iva:parseFloat(v.iva)||0, ivaModo:v.iva_modo||'sin', base:parseFloat(v.base)||0, ivaImporte:parseFloat(v.iva_importe)||0,
    // Líneas de la venta (carrito multiproducto del TPV). Si la columna no existe aún, queda null.
    items: (function(){ try { return v.items ? (typeof v.items==='string'?JSON.parse(v.items):v.items) : null; } catch(e){ return null; } })()
  };
}

function mapRep(r) {
  return {
    // token: sin él, el link público del QR salía con &t=undefined → "link caducado" (F27).
    id:r.id, token:r.token||'', fecha:r.fecha, clienteId:r.cliente_id, clienteNombre:r.cliente_nombre,
    marca:r.marca||'', modelo:r.modelo||'', imei:r.imei||'',
    averia:r.averia||'', estado:r.estado||'Pendiente', prioridad:r.prioridad||'Normal',
    fechaEntrega:r.fecha_entrega||'', fechaEntregaReal:r.fecha_entrega_real||'',
    nota:r.nota||'', tipoBloqueo:r.tipo_bloqueo||'', bloqueo:r.bloqueo||'', mo:parseFloat(r.mo)||0, comp:parseFloat(r.comp)||0,
    anticipo:parseFloat(r.anticipo)||0, restante:parseFloat(r.restante)||0,
    total:parseFloat(r.total)||0, pagoFinal:r.pago_final||'',
    financiado:r.financiado||false, entrada:parseFloat(r.entrada)||0, entradaPago:r.entrada_pago||'',
    cuotas: r.cuotas ? (typeof r.cuotas === 'string' ? JSON.parse(r.cuotas) : r.cuotas) : null,
    estadoFinanciado:r.estado_financiado||'',
    iva:parseFloat(r.iva)||0, ivaModo:r.iva_modo||'sin', base:parseFloat(r.base)||0, ivaImporte:parseFloat(r.iva_importe)||0,
    componentes: r.componentes ? (typeof r.componentes === 'string' ? JSON.parse(r.componentes) : r.componentes) : [],
    servicios: r.servicios ? (typeof r.servicios === 'string' ? JSON.parse(r.servicios) : r.servicios) : [],
    esGarantia:r.es_garantia||false, repOriginalId:r.rep_original_id||'',
    garantiaTipo:r.garantia_tipo||'reparacion', garantiaPublica:r.garantia_publica!==false,
    garantiaFechaFin:r.garantia_fecha_fin||'',
    piezasDevueltas: r.piezas_devueltas === true,
    presupuesto_aceptado_at: r.presupuesto_aceptado_at || null,
    presupuesto_aceptado_ip: r.presupuesto_aceptado_ip || null,
    firma_cliente: r.firma_cliente || null,
    firma_fecha: r.firma_fecha || null,
    clienteAvisado: r.cliente_avisado === true,
    fotosRecepcion: Array.isArray(r.fotos_recepcion) ? r.fotos_recepcion : [],
    fotosEntrega: Array.isArray(r.fotos_entrega) ? r.fotos_entrega : []
  };
}

function mapStock(s) {
  return {
    id:s.id, categoria:s.categoria||'Telefono', marca:s.marca||'',
    modelo:s.modelo||'', capacidad:s.capacidad||'', color:s.color||'',
    imei:s.imei||'', unidades:parseInt(s.unidades)||0,
    stockMin:parseInt(s.stock_min)||2, stockMax:parseInt(s.stock_max)||10,
    precioC:parseFloat(s.precio_c)||0, precioV:parseFloat(s.precio_v)||0,
    vendido:s.vendido||false, calidad:s.calidad||'',
    tipo: s.tipo || 'nuevo', garantiaMeses: parseInt(s.garantia_meses)||0,
    ubicacion: s.ubicacion || null,
    enOferta: !!s.en_oferta, precioAntes: parseFloat(s.precio_antes)||0
  };
}

function mapCli(c) {
  return {id:c.id, nombre:c.nombre||'', apellidos:c.apellidos||'', tel:c.tel||'', email:c.email||'', dni:c.dni||'', fechaNac:c.fecha_nac||'', nombreFiscal:c.nombre_fiscal||'', dirFiscal:c.dir_fiscal||'', cp:c.cp||'', provincia:c.provincia||'', ciudad:c.ciudad||'', esEmpresa:c.es_empresa||false, personaContacto:c.persona_contacto||'', pais:c.pais||'España', telPrefijo:c.tel_prefijo||'+34', marketingConsent:c.marketing_consent||false};
}

async function cargarDatosSupabase() {
  if (!SB_KEY || !TIENDA_ID) return;
  // Backup pre-sync una sola vez (por si algo va mal, restaurable manualmente)
  if (!localStorage.getItem('tk_db_backup_pre_sync')) {
    localStorage.setItem('tk_db_backup_pre_sync', localStorage.getItem('tk_db') || '{}');
  }
  try {
    var [ventas, reps, stock, clis, gastos, provs, gastosRec, pagosProv, encargos] = await Promise.all([
      sbGetAll('ventas', 'tienda_id=eq.' + TIENDA_ID),
      sbGetAll('reparaciones', 'tienda_id=eq.' + TIENDA_ID),
      sbGetAll('stock', 'tienda_id=eq.' + TIENDA_ID),
      sbGetAll('clientes', 'tienda_id=eq.' + TIENDA_ID),
      sbGetAll('gastos', 'tienda_id=eq.' + TIENDA_ID),
      sbGetAll('proveedores', 'tienda_id=eq.' + TIENDA_ID),
      sbGetAll('gastos_recurrentes', 'tienda_id=eq.' + TIENDA_ID),
      sbGetAll('pagos_proveedor', 'tienda_id=eq.' + TIENDA_ID).catch(function () { return []; }),
      sbGetAll('encargos', 'tienda_id=eq.' + TIENDA_ID).catch(function () { return []; })
    ]);
    if (Array.isArray(ventas)) DB.ventas = ventas.map(mapVenta);
    if (Array.isArray(reps)) DB.reps = reps.map(mapRep);
    if (Array.isArray(stock)) DB.stock = stock.map(mapStock);
    if (Array.isArray(clis)) DB.clis = clis.map(mapCli);
    if (Array.isArray(gastos)) DB.gastos = gastos;
    if (Array.isArray(provs)) DB.provs = provs;
    if (Array.isArray(gastosRec)) DB.gastos_recurrentes = gastosRec;
    if (Array.isArray(pagosProv)) DB.pagosProv = pagosProv;
    if (Array.isArray(encargos)) DB.encargos = encargos;
    guardarDatos();
    // Aplicar plantillas de gastos recurrentes que toquen
    try { aplicarGastosRecurrentes(); } catch(e) { console.warn('Aplicar recurrentes:', e); }
  } catch(e) { console.error('Supabase load error:', e); }
  // Servicios: carga aislada (si falla, no rompe el resto del sync). Antes no se
  // cargaban de la nube y "desaparecían" al recargar / en otro dispositivo.
  try {
    var servicios = await sbGetAll('servicios', 'tienda_id=eq.' + TIENDA_ID);
    if (Array.isArray(servicios)) {
      if (!servicios.length && (DB.servicios || []).length) {
        // Nube vacía pero hay servicios locales (posible guardado previo solo-local):
        // se SUBEN en vez de borrarlos, y se mantienen los locales.
        (DB.servicios || []).forEach(function(s) {
          if (SB_KEY && TIENDA_ID) sbPost('servicios', { id: s.id, tienda_id: TIENDA_ID, nombre: s.nombre, categoria: s.categoria, tipo: s.tipo, precio_fijo: s.precioFijo, precio: s.precio });
        });
      } else {
        // Preserva el precio de coste local (no siempre está en la nube)
        var prevCoste = {};
        (DB.servicios || []).forEach(function(s) { if (s.precioCoste) prevCoste[s.id] = s.precioCoste; });
        DB.servicios = servicios.map(function(s) {
          return {
            id: s.id, nombre: s.nombre || '', categoria: s.categoria || 'Otro', tipo: s.tipo || 'ambos',
            precioFijo: s.precio_fijo !== false, precio: parseFloat(s.precio) || 0,
            precioCoste: (s.precio_coste != null ? parseFloat(s.precio_coste) : (prevCoste[s.id] || 0)) || 0
          };
        });
      }
      guardarDatos();
      try { if (typeof renderServicios === 'function' && document.getElementById('pServicios')) renderServicios(); } catch(e){}
    }
  } catch(e) { /* tabla servicios opcional: si no existe, se mantiene lo local */ }
}

// Refresca todas las vistas activas (no solo el dashboard)
function refrescarVistasActivas() {
  // Globales baratos: siempre (badges, urgentes, notificaciones, logo)
  try { if (!DB.pedidos && typeof cargarPedidos === 'function') cargarPedidos(function(){ updatePedidosBadge(); }); else updatePedidosBadge(); } catch(e){}
  try { actualizarSidebarExtra(); } catch(e){}
  try { if (typeof checkUrgentes === 'function') checkUrgentes(); } catch(e){}
  try { if (typeof refreshNotifs === 'function') refreshNotifs(); } catch(e){}
  try { if (typeof renderSidebarLogo === 'function') renderSidebarLogo(); } catch(e){}
  // Solo re-renderiza la PÁGINA ACTIVA (las demás se renderizan al navegar a ellas).
  // Antes se re-renderizaban las ~16 páginas en cada sync (cada 60s + focus), aunque
  // estuvieran ocultas: trabajo y peticiones de red innecesarios.
  var activa = (document.querySelector('.page.active') || {}).id || '';
  var MAP = {
    pInicioNuevo: 'renderInicioNuevo', pDash: 'renderDash', pVentas: 'renderVentas',
    pReps: 'renderReps', pStock: 'renderStock', pClis: 'renderClis', pProvs: 'renderProvs',
    pGastos: 'renderGastos', pServicios: 'renderServicios', pPedidos: 'renderPedidosPage',
    pAjustes: 'cargarAjustes', pTienda: 'cargarTienda'
  };
  try { var fn = MAP[activa]; if (fn && typeof window[fn] === 'function') window[fn](); } catch(e){}
  try { if (activa === 'pGastos' && typeof renderGastosRec === 'function') renderGastosRec(); } catch(e){}
}

// Sync completa: descarga + refresco de pantalla
var _syncEnCurso = false;
var _syncPausado = false; // se activa durante restauración/import para evitar pisado
async function syncCompleto(silencioso) {
  if (_sesionExpirada) return;
  _sbReadCacheClear(); // la sincronización completa SIEMPRE trae datos frescos (no servir caché)
  if (_syncEnCurso) return;
  if (_syncPausado) return;
  if (!SB_KEY || !TIENDA_ID) return;
  _syncEnCurso = true;
  try {
    await Promise.all([
      cargarDatosSupabase(),
      _pullNotifRead(),
      _pullTiendaCompleta(),
      // F340: refrescar citas + su badge en CADA sync (focus/Realtime/poll), no solo
      // cada 60s — antes el badge de citas quedaba desfasado tras un cambio de otro equipo.
      (typeof syncCitas === 'function' ? syncCitas() : Promise.resolve())
    ]);
    refrescarVistasActivas();
    if (!silencioso && typeof toast === 'function') toast('Sincronizado', 'ok');
  } finally {
    _syncEnCurso = false;
  }
}

// ═══ REALTIME: sincronización instantánea entre dispositivos ═══
// Abre un websocket a Supabase Realtime y, ante cualquier cambio en las tablas de
// ESTA tienda hecho desde otro equipo, dispara syncCompleto() al instante (con debounce
// para colapsar ráfagas). Reutiliza toda la lógica de descarga/render ya existente.
// Requiere SQL: tablas en la publicación supabase_realtime + replica identity full.
var _rtClient = null, _rtTimer = null, _rtReady = false, _rtInit = false;
var _rtChannels = [], _rtGlobalErrs = 0, _rtDead = false;
// Apaga Realtime por completo y cae al poll de 60s. Idempotente.
// Se llama cuando hay tormenta de reconexión (websocket que parpadea) o sesión expirada:
// un token muerto reconectaría los 12 canales en bucle infinito si no cortamos aquí.
function _rtTeardown() {
  if (_rtDead) return;
  _rtDead = true; _rtReady = false;
  try {
    _rtChannels.forEach(function (ch) { try { _rtClient.removeChannel(ch); } catch (e) {} });
    if (_rtClient && _rtClient.realtime && typeof _rtClient.realtime.disconnect === 'function') {
      _rtClient.realtime.disconnect();
    }
  } catch (e) {}
  _rtChannels = [];
  try { console.warn('[Realtime] desactivado; se usa el poll de 60s'); } catch (e) {}
}
function _rtSyncDebounced() {
  if (_rtTimer) clearTimeout(_rtTimer);
  _rtTimer = setTimeout(function () {
    _rtTimer = null;
    if (typeof syncCompleto === 'function' && !document.hidden) syncCompleto(true);
  }, 600);
}
function _initRealtime() {
  if (_rtInit || !SB_KEY || !TIENDA_ID || typeof JWT_TOKEN === 'undefined' || !JWT_TOKEN) return;
  _rtInit = true;
  function start() {
    try {
      if (!window.supabase || !window.supabase.createClient) { _rtInit = false; return; }
      // Idempotencia: si ya hay un cliente con canales vivos, no recrear (anti doble-subscribe #29).
      if (_rtClient && typeof _rtClient.getChannels === 'function' && _rtClient.getChannels().length) return;
      _rtClient = window.supabase.createClient(SUPABASE_URL, SB_KEY, {
        auth: { persistSession: false, autoRefreshToken: false }
      });
      _rtClient.realtime.setAuth(JWT_TOKEN);
      var TABLAS = ['reparaciones', 'ventas', 'stock', 'clientes', 'gastos', 'proveedores',
        'pedidos', 'gastos_recurrentes', 'pagos_proveedor', 'servicios', 'citas', 'tiendas'];
      // UN canal por tabla: así el subscribe sabe QUÉ tabla es (log con nombre) y una tabla
      // que rechace la suscripción no tumba a las demás (antes iban todas en un canal → F20).
      TABLAS.forEach(function (tbl) {
        var topic = 'tk-' + TIENDA_ID + '-' + tbl;
        // No recrear un canal que ya existe para esta tabla (defensa anti doble-subscribe).
        var vivos = (typeof _rtClient.getChannels === 'function') ? _rtClient.getChannels() : [];
        for (var i = 0; i < vivos.length; i++) { if (vivos[i].topic === 'realtime:' + topic) return; }
        var filtro = (tbl === 'tiendas') ? ('id=eq.' + TIENDA_ID) : ('tienda_id=eq.' + TIENDA_ID);
        var ch = _rtClient.channel(topic);
        ch.on('postgres_changes', { event: '*', schema: 'public', table: tbl, filter: filtro }, _rtSyncDebounced);
        _rtChannels.push(ch);
        var errs = 0;
        ch.subscribe(function (status) {
          if (_rtDead) return;
          if (status === 'SUBSCRIBED') { try { console.log('[Realtime]', tbl, status); } catch (e) {} _rtReady = true; errs = 0; return; }
          if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT' || status === 'CLOSED') {
            errs++; _rtGlobalErrs++;
            // Solo logueamos el PRIMER error de cada tabla (evita el spam de 12× por ciclo en consola).
            if (errs === 1) { try { console.warn('[Realtime]', tbl, status, '— cae a poll 60s si persiste'); } catch (e) {} }
            if (errs >= 3) { try { _rtClient.removeChannel(ch); } catch (e) {} } // deja de reintentar esa tabla
            // Tormenta global (websocket que parpadea, token muerto o publicación Realtime no
            // configurada en SQL): en vez de reconectar los 12 canales en bucle, apaga Realtime
            // entero y cae al poll de 60s (#29/#B50). 24 = 2 rondas × 12 tablas → corte rápido.
            if (_rtGlobalErrs >= 24) _rtTeardown();
          }
        });
      });
    } catch (e) { _rtInit = false; try { console.warn('Realtime init:', e); } catch (e2) {} }
  }
  if (window.supabase && window.supabase.createClient) { start(); return; }
  var s = document.createElement('script');
  s.src = 'https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2.45.4/dist/umd/supabase.js';
  s.async = true;
  s.onload = start;
  s.onerror = function () { _rtInit = false; try { console.warn('Realtime: sin supabase-js (seguimos con poll 60s)'); } catch (e) {} };
  document.head.appendChild(s);
}

// ═══ SESION EXPIRADA (JWT 401 handler) ═══
var _sesionExpirada = false;

function mostrarModalSesionExpirada() {
  if (_sesionExpirada) return;
  _sesionExpirada = true;
  // Token muerto → corta Realtime para que no reconecte los 12 canales en bucle (#29).
  try { _rtTeardown(); } catch (e) {}
  try {
    document.querySelectorAll('.modal-bg.open').forEach(function(m){
      m.classList.remove('open');
    });
  } catch(e) {}
  if (typeof openM === 'function') openM('mSesionExpirada');
}

function forzarRelogin() {
  try { localStorage.removeItem('tk_sess'); } catch(e) {}
  window.location.href = '/app.html';
}

// ═══ MULTI-TIENDA · selector de tienda activa ═══
function cargarMisTiendas() {
  var sess = JSON.parse(localStorage.getItem('tk_sess') || '{}');
  if (!sess.token) return;
  fetch('/api/login', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ action: 'mis-tiendas', token: sess.token }) })
    .then(function(r) { return r.json(); })
    .then(function(j) {
      if (!j || !j.ok || !Array.isArray(j.tiendas)) return;
      var sel = document.getElementById('tiendaSelector'); var wrap = document.getElementById('tiendaSelectorWrap');
      var addBtn = document.getElementById('tiendaAddBtn');
      if (!sel || !wrap) return;
      var esAdmin = !!(U && (U.rol === 'admin' || (U.permisos && U.permisos.todo)));
      var multi = j.tiendas.length >= 2;
      var activa = j.activa || (sess.tienda_id || '');
      if (multi) {
        sel.innerHTML = j.tiendas.map(function(t) { return '<option value="' + esc(t.id) + '"' + (t.id === activa ? ' selected' : '') + '>🏪 ' + esc(t.nombre || t.id) + '</option>'; }).join('');
        sel.style.display = '';
      } else { sel.style.display = 'none'; }
      if (addBtn) addBtn.style.display = (esAdmin && (typeof tieneFeature === 'function' && tieneFeature('multi_tienda'))) ? 'block' : 'none';
      // El wrap se ve si hay selector (2+ tiendas) o si el admin puede añadir.
      wrap.style.display = (multi || esAdmin) ? 'block' : 'none';
    }).catch(function() {});
}
// Crear una tienda nueva (add-on de pago). Lleva al checkout de Stripe; el webhook
// crea la tienda y el enlace al completarse el pago.
function anadirTienda() {
  if (!(U && (U.rol === 'admin' || (U.permisos && U.permisos.todo)))) { toast(T('gen.sin_permiso'), 'err'); return; }
  if (typeof tieneFeature === 'function' && !tieneFeature('multi_tienda')) { mostrarModalUpgrade('multi_tienda', 'premium'); return; }
  pedirTexto(T('mt.anadir_prompt') + '\n\n' + T('mt.anadir_precio'), { rows: 1, okLabel: T('mt.anadir_ok') }, function(nombre) {
    if (nombre === null) return;
    nombre = (nombre || '').trim();
    if (!nombre) { toast(T('mt.anadir_falta'), 'err'); return; }
    var sess = JSON.parse(localStorage.getItem('tk_sess') || '{}');
    if (!sess.token) { toast(T('gen.error'), 'err'); return; }
    toast(T('mt.anadir_yendo'), 'ok');
    fetch('/api/checkout', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ action: 'addon', token: sess.token, tienda_nombre: nombre }) })
      .then(function(r) { return r.json(); })
      .then(function(j) {
        if (j && j.ok && j.url) { window.location.href = j.url; return; }
        toast((j && j.error) || T('gen.error'), 'err');
      }).catch(function() { toast(T('gen.error'), 'err'); });
  });
}
function cambiarTienda(tiendaId) {
  var sess = JSON.parse(localStorage.getItem('tk_sess') || '{}');
  if (!sess.token || !tiendaId || tiendaId === sess.tienda_id) return;
  toast(T('mt.cambiando'), 'ok');
  fetch('/api/login', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ action: 'cambiar-tienda', token: sess.token, tienda_id: tiendaId }) })
    .then(function(r) { return r.json(); })
    .then(function(j) {
      if (!j || !j.ok || !j.jwt_token) { toast((j && j.error) || T('gen.error'), 'err'); return; }
      sess.jwt_token = j.jwt_token; sess.tienda_id = j.tienda_id;
      localStorage.setItem('tk_sess', JSON.stringify(sess));
      // Limpiar cachés de datos de la tienda anterior para no mezclar (tk_db es un blob único).
      ['tk_db', 'tk_tienda', 'tk_db_backup_pre_sync', 'tk_avisados', 'tk_ajustes'].forEach(function(k) { try { localStorage.removeItem(k); } catch (e) {} });
      window.location.reload();
    }).catch(function() { toast(T('gen.error'), 'err'); });
}

// ═══ MULTI-TIENDA · asignar a un empleado acceso a varias tiendas ═══
// El dueño marca a qué tiendas (de las suyas) puede entrar cada empleado. La tienda
// principal del empleado va siempre incluida (checkbox fijo). Las extras se guardan en
// usuario_tiendas vía el backend (op set-tiendas), que valida que el admin posee esas tiendas.
var MIS_TIENDAS_ADMIN = [];   // [{id,nombre}] tiendas que el dueño puede otorgar
var _TIENDAS_MAP = {};        // usuario_id -> [tienda_id extra]
var _atUid = null;
function asignarTiendas(uid, nombre) {
  _atUid = uid;
  var nom = document.getElementById('atNombre'); if (nom) nom.textContent = nombre || '';
  var primaria = String(TIENDA_ID || '');
  var acceso = _TIENDAS_MAP[uid] || [];
  var lista = document.getElementById('atLista');
  if (lista) lista.innerHTML = MIS_TIENDAS_ADMIN.map(function(t) {
    var esPrim = String(t.id) === primaria;
    var checked = esPrim || acceso.indexOf(String(t.id)) !== -1;
    return '<label style="display:flex;align-items:center;gap:9px;padding:9px 4px;border-bottom:1px solid var(--border);font-size:13px;cursor:pointer">' +
      '<input type="checkbox" class="atChk" value="' + esc(t.id) + '"' + (checked ? ' checked' : '') + (esPrim ? ' disabled' : '') + '>' +
      '🏪 ' + esc(t.nombre || t.id) + (esPrim ? ' <span style="font-size:10px;color:var(--muted)">(' + T('mt.principal') + ')</span>' : '') +
      '</label>';
  }).join('');
  openM('mAsignarTiendas');
}
async function guardarAsignarTiendas() {
  if (!_atUid) return;
  var ids = Array.prototype.slice.call(document.querySelectorAll('#atLista .atChk:checked')).map(function(c) { return c.value; });
  var ok = await _adminUsuarios('set-tiendas', { target_id: _atUid, tiendas: ids });
  if (ok) { toast(T('mt.acceso_guardado'), 'ok'); closeM('mAsignarTiendas'); cargarUsuarios(); }
}

// ═══ REFERIDOS · "Invita amigos" (Mi Tienda) ═══
function cargarInvitaAmigos() {
  var box = document.getElementById('refBox');
  if (!box) return;
  var sess = JSON.parse(localStorage.getItem('tk_sess') || '{}');
  if (!sess.token) { box.innerHTML = ''; return; }
  fetch('/api/login', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ action: 'mi-referido', token: sess.token }) })
    .then(function(r) { return r.json(); })
    .then(function(j) {
      if (!j || !j.ok || !j.codigo) { box.innerHTML = '<div style="font-size:12px;color:var(--muted)">' + T('ref.error') + '</div>'; return; }
      window._refLink = j.link;
      var STATUS = { pending: T('ref.st_pending'), qualified: T('ref.st_qualified'), rewarded: T('ref.st_rewarded'), refunded: T('ref.st_refunded') };
      var msgWa = encodeURIComponent(T('ref.wa_msg').replace('{link}', j.link));
      var qr = 'https://api.qrserver.com/v1/create-qr-code/?size=140x140&data=' + encodeURIComponent(j.link);
      var hist = (j.referidos || []).map(function(x) {
        var nom = esc(x.referred_nombre || x.referred_email || '—');
        var st = STATUS[x.status] || x.status;
        var col = x.status === 'rewarded' ? 'var(--green)' : (x.status === 'qualified' ? 'var(--orange)' : 'var(--muted)');
        return '<div style="display:flex;justify-content:space-between;gap:8px;padding:6px 0;border-top:1px solid var(--border);font-size:12px"><span style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + nom + '</span><span style="color:' + col + ';font-weight:700;white-space:nowrap">' + esc(st) + '</span></div>';
      }).join('');
      box.innerHTML =
        '<div style="background:var(--light);border-radius:10px;padding:10px 12px;font-weight:700;font-size:13px;word-break:break-all;margin-bottom:10px">' + esc(j.link) + '</div>' +
        '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px">' +
          '<a href="https://wa.me/?text=' + msgWa + '" target="_blank" rel="noopener" style="flex:1;min-width:130px;text-align:center;background:#25D366;color:#fff;text-decoration:none;border-radius:8px;padding:9px;font-size:12.5px;font-weight:700">📲 WhatsApp</a>' +
          '<button onclick="_copiarRefLink()" style="flex:1;min-width:130px;border:1px solid var(--border);background:#fff;border-radius:8px;padding:9px;font:inherit;font-size:12.5px;font-weight:700;cursor:pointer">📋 ' + T('ref.copiar') + '</button>' +
        '</div>' +
        '<div style="display:flex;align-items:center;gap:12px;margin-bottom:8px"><img src="' + qr + '" alt="QR" style="width:72px;height:72px;border-radius:8px;border:1px solid var(--border)"><div style="font-size:13px"><strong style="font-size:18px">' + (j.ganados || 0) + '</strong> ' + T('ref.ganados') + '</div></div>' +
        (hist ? '<div style="font-size:11px;font-weight:700;color:var(--muted);margin:10px 0 2px;text-transform:uppercase;letter-spacing:.4px">' + T('ref.historial') + '</div>' + hist : '<div style="font-size:11.5px;color:var(--muted);margin-top:6px">' + T('ref.sin_invitados') + '</div>');
    }).catch(function() { box.innerHTML = '<div style="font-size:12px;color:var(--muted)">' + T('ref.error') + '</div>'; });
}
function _copiarRefLink() {
  try { navigator.clipboard.writeText(window._refLink || '').then(function() { toast(T('cobro.copiado'), 'ok'); }); } catch (e) {}
}

(function interceptarFetch401() {
  if (typeof window.fetch !== 'function') return;
  if (window.__tkFetchInterceptado) return;
  window.__tkFetchInterceptado = true;
  var origFetch = window.fetch;
  window.fetch = function(url, options) {
    var urlStr = '';
    try {
      urlStr = typeof url === 'string' ? url : (url && url.url) || '';
    } catch(e) { urlStr = ''; }
    // F82: avisar con el modal también ante 401 de la API propia (/api/*), no solo de Supabase.
    // Se excluyen Cobrum/finanzas-app (manejo propio) y /api/login (no aplica en el panel).
    var esAuth = urlStr.indexOf('supabase.co') !== -1 ||
      (urlStr.indexOf('/api/') !== -1 && urlStr.indexOf('cobrum') === -1 &&
       urlStr.indexOf('finanzas-app') === -1 && urlStr.indexOf('/api/login') === -1);
    var promesa = origFetch.apply(this, arguments);
    if (!esAuth) return promesa;
    return promesa.then(function(response) {
      if (response && response.status === 401) {
        mostrarModalSesionExpirada();
      }
      return response;
    });
  };
})();

