function renderGuiaAyuda() {
  var box = document.getElementById('guiaAyuda');
  if (!box) return;
  var L = GUIA_AYUDA[window.TEKPAIR_LANG] || GUIA_AYUDA.es;
  box.innerHTML = L.map(function(s) {
    return '<details style="border:1px solid var(--border);border-radius:10px;margin-bottom:8px;overflow:hidden">' +
      '<summary style="padding:11px 14px;font-weight:700;font-size:13px;cursor:pointer">' + s.e + ' ' + escHtml(s.t) + '</summary>' +
      '<div style="padding:2px 14px 12px"><ul style="margin:0;padding-left:18px;display:flex;flex-direction:column;gap:6px;font-size:12.5px;color:var(--text)">' +
      s.items.map(function(i) { return '<li>' + i + '</li>'; }).join('') + '</ul></div></details>';
  }).join('');
}

async function renderDash() {
  // Analítica avanzada (zona Analítica + periodos Semana/Mes) es de Pro/Premium. Básico: solo Hoy.
  var verAnalitica = (typeof tieneFeature === 'function') ? tieneFeature('analitica') : true;
  (function() {
    var zl = document.getElementById('zoneAnalitica');
    var zc = document.getElementById('zoneAnaliticaCards');
    if (zl) zl.style.display = verAnalitica ? '' : 'none';
    if (zc) zc.style.display = verAnalitica ? '' : 'none';
    var mtabs = document.querySelectorAll('#metricTabs .tab');
    for (var i = 1; i < mtabs.length; i++) mtabs[i].style.display = verAnalitica ? '' : 'none'; // Semana/Mes
    if (!verAnalitica && SEL.metricTab !== 'hoy') {
      SEL.metricTab = 'hoy';
      if (mtabs[0]) { Array.prototype.forEach.call(mtabs, function(t){ t.classList.remove('active'); }); mtabs[0].classList.add('active'); }
    }
  })();
  var tab = SEL.metricTab;
  var hoy = hoyLocal();
  var semana = [];
  var mes = [];
  for (var i = 0; i < 7; i++) {
    var d = new Date(); d.setDate(d.getDate() - i);
    semana.push(d.toISOString().slice(0,10));
  }
  for (var j = 0; j < 30; j++) {
    var d2 = new Date(); d2.setDate(d2.getDate() - j);
    mes.push(d2.toISOString().slice(0,10));
  }

  var filterDates = tab === 'hoy' ? [hoy] : tab === 'semana' ? semana : mes;

  var ventas = DB.ventas.filter(function(v) { return !v.reembolsado && filterDates.includes(v.fecha); });
  var ESTADOS_CERRADOS_STAT = ['Entregado','Rechazado','Devuelto','Sin Solucion','Presupuesto'];
  var repsPendienteReparar = DB.reps.filter(function(r) { return ['Pendiente','En Proceso','En proceso'].indexOf(r.estado) !== -1; });
  var repsPorEntregar = DB.reps.filter(function(r) { return ['Por Entregar','Por entregar'].indexOf(r.estado) !== -1; });
  var repsActivas = DB.reps.filter(function(r) { return ESTADOS_CERRADOS_STAT.indexOf(r.estado) === -1; });

  // CAJA REAL (unificado con el dashboard): financiadas = entrada (día de venta) + cuotas
  // cobradas por su fecha de pago; no financiadas = total el día de la venta; reembolsadas
  // excluidas. Así Reports y el inicio muestran la MISMA cifra (lo que entró en caja).
  var _rd1 = filterDates[0], _rd2 = filterDates[filterDates.length - 1];
  var tVentas = _ventasIngresoTotal(DB.ventas, _rd1, _rd2);

  // v2.4: usar pagos reales (anticipos + finales) en lugar de reps entregadas
  var tReps = 0;
  // Renderizar stats inmediatamente con tReps=0 (datos locales rápidos)
  // Luego actualizar cuando llegan los pagos de Supabase
  var _renderStats = function(tRepsVal, pagosRepData) {
    var mostrarFinanzas = tienePerm('ventas_ver');
    var mostrarOps = tienePerm('reps_ver');
    if (!mostrarFinanzas && !mostrarOps) return;

    var totalIngresos = tVentas + tRepsVal;
    var pctVentas = totalIngresos > 0 ? Math.round(tVentas / totalIngresos * 100) : 0;
    var pctReps = totalIngresos > 0 ? 100 - pctVentas : 0;

    var pagosTotales = {};
    if (mostrarFinanzas) {
      // Caja real por método (igual que tVentas): financiadas cuentan entrada + cuotas cobradas,
      // no el total a plazos. Antes sumaba v.total de todas → no cuadraba con el ingreso.
      var _vpm = _ventasIngresoPorMetodo(DB.ventas, _rd1, _rd2);
      Object.keys(_vpm).forEach(function(m) { pagosTotales[m] = (pagosTotales[m] || 0) + _vpm[m]; });
      if (pagosRepData) {
        pagosRepData.forEach(function(p) {
          var m = p.metodo || 'Efectivo';
          pagosTotales[m] = (pagosTotales[m] || 0) + Number(p.importe || 0);
        });
      }
    }

    var iconosPago = {Efectivo:'💵', Tarjeta:'💳', Bizum:'📲', Transferencia:'🏦', Financiado:'📅'};
    var bgPago = {Efectivo:'rgba(0,200,150,.10)', Tarjeta:'rgba(0,85,255,.10)', Bizum:'rgba(0,85,255,.10)', Transferencia:'rgba(249,115,22,.10)', Financiado:'rgba(100,116,139,.10)'};

    var _html = '';

    if (mostrarFinanzas && (widgetVisible('widget_stats_ventas') || widgetVisible('widget_stats_total'))) {
      var pagosHtml = Object.keys(pagosTotales).filter(function(k){ return pagosTotales[k] > 0; }).map(function(m) {
        return '<div class="fin-pago-item">' +
          '<div class="fin-pago-icon" style="background:' + (bgPago[m]||'var(--light)') + '">' + (iconosPago[m]||'💰') + '</div>' +
          '<div><div class="fin-pago-num">' + cur(pagosTotales[m]) + '</div><div class="fin-pago-lbl">' + m + '</div></div>' +
        '</div>';
      }).join('');
      if (!pagosHtml) pagosHtml = '<div style="font-size:11px;color:var(--muted);padding:6px 0">' + T('gen.sin_movimientos') + '</div>';

      _html += '<div class="fin-widget">' +
        '<div class="fin-widget-header"><span class="fin-widget-title" data-t="dash.resumen_financiero">Resumen financiero</span></div>' +
        '<div class="fin-total-num">' + cur(totalIngresos) + '</div>' +
        '<div class="fin-total-lbl" data-t="dash.total_ingresos">Total ingresos</div>' +
        '<div class="fin-split">' +
          '<div class="fin-split-item">' +
            '<div class="fin-split-num" style="color:var(--green)">' + cur(tVentas) + '</div>' +
            '<div class="fin-split-lbl" data-t="dash.ingresos_ventas">Ingresos ventas</div>' +
            '<div class="fin-split-count">' + ventas.length + ' ' + T('dash.ventas_count') + '</div>' +
          '</div>' +
          '<div class="fin-split-item">' +
            '<div class="fin-split-num" style="color:var(--orange)">' + cur(tRepsVal) + '</div>' +
            '<div class="fin-split-lbl" data-t="dash.ingresos_reps">Ingresos reparaciones</div>' +
            (pagosRepData ? '<div class="fin-split-count">' + pagosRepData.length + ' ' + T('dash.pagos_count') + '</div>' : '') +
          '</div>' +
        '</div>' +
        '<div class="fin-bar-wrap"><div class="fin-bar-v" style="width:' + pctVentas + '%"></div><div class="fin-bar-r" style="width:' + pctReps + '%"></div></div>' +
        '<div class="fin-legend">' +
          '<div class="fin-legend-item"><div class="fin-legend-dot" style="background:var(--green)"></div><span data-t="dash.ventas_lbl">Ventas</span></div>' +
          '<div class="fin-legend-item"><div class="fin-legend-dot" style="background:var(--orange)"></div><span data-t="dash.reps_lbl">Reparaciones</span></div>' +
        '</div>' +
        '<div class="fin-sep"></div>' +
        '<div class="fin-widget-title" style="margin-bottom:8px" data-t="dash.por_forma_pago">Por forma de pago</div>' +
        '<div class="fin-pagos">' + pagosHtml + '</div>' +
      '</div>';
    }

    var grid = document.getElementById('metricsGrid');
    if (grid) {
      grid.innerHTML = _html;
      // Selector de pestañas retirado: ahora cada cosa es su propia tarjeta (sin duplicar)
      if (typeof applyLang === 'function') applyLang();
    }
  };

  // Opciones para el widget selector de la derecha
var WIDGET_SELECTOR_OPTS = [
  {id:'ops', icon:'🔧', labelKey:'dash.ws_ops', label:'Operaciones'},
  {id:'urgentes', icon:'🚨', labelKey:'dash.ws_urgentes', label:'Urgentes hoy'},
  {id:'cobros', icon:'💰', labelKey:'dash.ws_cobros', label:'Cobros pendientes'},
  {id:'pedidos', icon:'📦', labelKey:'dash.ws_pedidos', label:'Pedidos'},
  {id:'cierre', icon:'📊', labelKey:'dash.ws_cierre', label:'Cierre del día'},
  {id:'stock', icon:'📦', labelKey:'dash.ws_stock', label:'Stock crítico'},
  {id:'averias', icon:'📋', labelKey:'dash.ws_averias', label:'Top averías'}
];

// ¿Puede ver info de caja? Mismo criterio que el acceso a Cajas: oculto si el admin
// le quitó el permiso cajas_ver al empleado.
function puedeVerCaja() {
  if (!U) return false;
  if (U.rol === 'admin' || (U.permisos && U.permisos.todo)) return true;
  return !(U.permisos && U.permisos.cajas_ver === false);
}
function _getWidgetSelectorActive() {
  try {
    var a = localStorage.getItem('tk_ws_' + TIENDA_ID + '_' + (U&&U.id||'')) || 'ops';
    if (a === 'cierre' && !puedeVerCaja()) return 'ops';
    return a;
  } catch(e) { return 'ops'; }
}
function _setWidgetSelectorActive(id) {
  try { localStorage.setItem('tk_ws_' + TIENDA_ID + '_' + (U&&U.id||''), id); } catch(e) {}
}

function _renderWidgetSelectorBody(id) {
  var box = document.getElementById('wsSelectorBody');
  if (!box) return;
  if (id === 'ops') {
    var pend = repsPendienteReparar.length;
    var entr = repsPorEntregar.length;
    box.innerHTML =
      '<div style="padding:14px 16px">' +
        '<div class="fin-ops-row">' +
          '<div class="fin-op-mini">' +
            '<div class="fin-op-mini-icon" style="background:rgba(249,115,22,.12)">🔧</div>' +
            '<div><div class="fin-op-mini-num">' + pend + '</div><div class="fin-op-mini-lbl" data-t="dash.pendientes_reparar">Pendientes reparar</div></div>' +
          '</div>' +
          '<div class="fin-op-mini">' +
            '<div class="fin-op-mini-icon" style="background:rgba(0,200,150,.12)">📦</div>' +
            '<div><div class="fin-op-mini-num" style="color:var(--green)">' + entr + '</div><div class="fin-op-mini-lbl" data-t="dash.por_entregar_stat">Por entregar</div></div>' +
          '</div>' +
        '</div>' +
        // Reps en proceso
        (function(){
          var enProceso = DB.reps.filter(function(r){ return r.estado==='En Proceso'; }).length;
          var garantia = DB.reps.filter(function(r){ return r.estado==='Garantía'; }).length;
          return '<div class="fin-ops-row" style="margin-top:6px">' +
            '<div class="fin-op-mini">' +
              '<div class="fin-op-mini-icon" style="background:rgba(0,85,255,.10)">⚙️</div>' +
              '<div><div class="fin-op-mini-num" style="color:var(--blue)">' + enProceso + '</div><div class="fin-op-mini-lbl" data-t="rep.en_proceso">En proceso</div></div>' +
            '</div>' +
            '<div class="fin-op-mini">' +
              '<div class="fin-op-mini-icon" style="background:rgba(168,85,247,.10)">🛡️</div>' +
              '<div><div class="fin-op-mini-num" style="color:#8B5CF6">' + garantia + '</div><div class="fin-op-mini-lbl" data-t="rep.garantia">Garantía</div></div>' +
            '</div>' +
          '</div>';
        })() +
      '</div>';
  } else if (id === 'urgentes') {
    var urg = DB.reps.filter(function(r){ return r.prioridad==='Urgente' && r.estado!=='Entregado' && r.estado!=='Rechazado'; }).slice(0,5);
    var html = '<div style="padding:14px 16px">';
    if (!urg.length) {
      html += '<div style="font-size:12px;color:var(--muted);text-align:center;padding:20px 0">✅ Sin urgentes</div>';
    } else {
      urg.forEach(function(r) {
        html += '<div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--border)">' +
          '<div style="width:6px;height:6px;border-radius:50%;background:var(--orange);flex-shrink:0"></div>' +
          '<div style="flex:1;min-width:0">' +
            '<div style="font-size:12px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + escHtml(_cliLbl(r.clienteNombre)) + '</div>' +
            '<div style="font-size:10px;color:var(--muted)">' + escHtml(r.marca||'') + ' ' + escHtml(r.modelo||'') + '</div>' +
          '</div>' +
          '<div style="font-size:10px;background:rgba(249,115,22,.12);color:var(--orange);padding:2px 7px;border-radius:10px;font-weight:700;flex-shrink:0">' + escHtml(r.estado||'') + '</div>' +
        '</div>';
      });
    }
    html += '</div>';
    box.innerHTML = html;
  } else if (id === 'cobros') {
    var cobros = DB.reps.filter(function(r){ return (r.restante||0) > 0 && r.estado !== 'Entregado'; }).slice(0,5);
    var totalPend = cobros.reduce(function(a,r){ return a+(r.restante||0); }, 0);
    var html = '<div style="padding:14px 16px">';
    html += '<div style="font-size:10px;color:var(--muted);margin-bottom:8px">' + T('dash.ws_cobros_total') + ': <strong style="color:var(--orange)">' + cur(totalPend) + '</strong></div>';
    if (!cobros.length) {
      html += '<div style="font-size:12px;color:var(--muted);text-align:center;padding:16px 0">✅ Sin cobros pendientes</div>';
    } else {
      cobros.forEach(function(r) {
        html += '<div style="display:flex;justify-content:space-between;align-items:center;padding:5px 0;border-bottom:1px solid var(--border)">' +
          '<div style="min-width:0;flex:1">' +
            '<div style="font-size:11px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + escHtml(_cliLbl(r.clienteNombre)) + '</div>' +
            '<div style="font-size:10px;color:var(--muted)">' + escHtml(r.modelo||'') + '</div>' +
          '</div>' +
          '<div style="font-size:12px;font-weight:800;color:var(--orange);flex-shrink:0;margin-left:8px">' + cur(r.restante) + '</div>' +
        '</div>';
      });
    }
    html += '</div>';
    box.innerHTML = html;
  } else if (id === 'pedidos') {
    renderPedidosWidget();
    return;
  } else if (id === 'cierre' && puedeVerCaja()) {
    var hoyReps = DB.reps.filter(function(r){ return r.fechaEntregaReal === hoyLocal(); });
    var hoyVentas = DB.ventas.filter(function(v){ return v.fecha === hoyLocal() && !v.reembolsado; });
    var totalHoy = hoyReps.reduce(function(a,r){ return a+(r.total||0); }, 0) + hoyVentas.reduce(function(a,v){ return a+(v.total||0); }, 0);
    box.innerHTML = '<div style="padding:14px 16px">' +
      '<div class="fin-ops-row">' +
        '<div class="fin-op-mini"><div class="fin-op-mini-icon" style="background:rgba(0,200,150,.12)">🔧</div>' +
        '<div><div class="fin-op-mini-num" style="color:var(--green)">' + hoyReps.length + '</div><div class="fin-op-mini-lbl">Reps entregadas hoy</div></div></div>' +
        '<div class="fin-op-mini"><div class="fin-op-mini-icon" style="background:rgba(0,85,255,.10)">📱</div>' +
        '<div><div class="fin-op-mini-num" style="color:var(--blue)">' + hoyVentas.length + '</div><div class="fin-op-mini-lbl">Ventas hoy</div></div></div>' +
      '</div>' +
      '<div style="margin-top:10px;background:var(--light);border-radius:8px;padding:10px 12px">' +
        '<div style="font-size:10px;color:var(--muted)">Total caja hoy</div>' +
        '<div style="font-size:22px;font-weight:800;color:var(--green)">' + cur(totalHoy) + '</div>' +
      '</div>' +
    '</div>';
  } else if (id === 'stock') {
    var criticos = DB.stock.filter(function(s){ return !s.vendido && (s.unidades||0) <= 2; }).slice(0,6);
    var html = '<div style="padding:14px 16px">';
    if (!criticos.length) {
      html += '<div style="font-size:12px;color:var(--muted);text-align:center;padding:20px 0">✅ Stock en buen estado</div>';
    } else {
      criticos.forEach(function(s) {
        var uds = s.unidades||0;
        html += '<div style="display:flex;justify-content:space-between;align-items:center;padding:5px 0;border-bottom:1px solid var(--border)">' +
          '<div style="font-size:11px;font-weight:700;flex:1;min-width:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + escHtml(s.nombre||'') + '</div>' +
          '<div style="font-size:11px;font-weight:800;padding:2px 8px;border-radius:10px;flex-shrink:0;' + (uds===0?'background:rgba(239,68,68,.12);color:#EF4444':'background:rgba(249,115,22,.12);color:var(--orange)') + '">' + uds + ' ' + T('pedidos.uds') + '</div>' +
        '</div>';
      });
    }
    html += '</div>';
    box.innerHTML = html;
  } else if (id === 'averias') {
    var counts = {};
    DB.reps.forEach(function(r){ if(r.averia) counts[r.averia] = (counts[r.averia]||0)+1; });
    var sorted = Object.keys(counts).sort(function(a,b){ return counts[b]-counts[a]; }).slice(0,5);
    var max = sorted.length ? counts[sorted[0]] : 1;
    var html = '<div style="padding:14px 16px">';
    sorted.forEach(function(av) {
      var pct = Math.round(counts[av]/max*100);
      html += '<div style="margin-bottom:8px">' +
        '<div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:3px">' +
          '<span style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:70%">' + escHtml(av) + '</span>' +
          '<span style="font-weight:700;flex-shrink:0">' + counts[av] + '</span>' +
        '</div>' +
        '<div style="height:4px;border-radius:2px;background:var(--border)"><div style="height:100%;border-radius:2px;background:var(--orange);width:' + pct + '%"></div></div>' +
      '</div>';
    });
    if (!sorted.length) html += '<div style="font-size:12px;color:var(--muted);text-align:center;padding:20px 0">Sin datos</div>';
    html += '</div>';
    box.innerHTML = html;
  }
  if (typeof applyLang === 'function') applyLang();
}

function renderWidgetSelector() {
  var grid = document.getElementById('metricsGrid');
  if (!grid) return;
  var activeId = _getWidgetSelectorActive();
  // Tabs
  var tabsHtml = WIDGET_SELECTOR_OPTS.filter(function(opt) {
    return opt.id !== 'cierre' || puedeVerCaja();   // "Cierre hoy" oculto si no puede ver caja
  }).map(function(opt) {
    return '<button class="widget-sel-tab' + (opt.id===activeId?' active':'') + '" data-wid="' + opt.id + '">' +
      opt.icon + ' ' + (T('dash.ws_' + opt.id)||opt.label) +
    '</button>';
  }).join('');
  // Buscar si ya existe el selector
  var existing = document.getElementById('widgetSelectorCard');
  if (!existing) {
    var div = document.createElement('div');
    div.id = 'widgetSelectorCard';
    div.className = 'widget-selector-card';
    div.innerHTML = '<div class="widget-selector-tabs">' + tabsHtml + '</div><div id="wsSelectorBody"></div>';
    grid.appendChild(div);
    div.querySelector('.widget-selector-tabs').addEventListener('click', function(e) { var btn = e.target.closest('[data-wid]'); if (!btn) return; var wid = btn.dataset.wid; _setWidgetSelectorActive(wid); div.querySelectorAll('.widget-sel-tab').forEach(function(t){t.classList.remove('active')}); btn.classList.add('active'); _renderWidgetSelectorBody(wid); });
  } else {
    existing.querySelector('.widget-selector-tabs').innerHTML = tabsHtml;
  }
  _renderWidgetSelectorBody(activeId);
  renderNotasRecordatorios();
}


  // Caché de pagos_reparacion por RANGO (clave minF_maxF) con TTL corto +
  // invalidación explícita al crear/editar un pago (_invalidarCachePagosRep()).
  // Evita re-consultar Supabase en cada renderDash (se llama tras casi toda acción).
  var fechasISO = filterDates.slice().sort();
  var minF = fechasISO[0], maxF = fechasISO[fechasISO.length - 1];
  var cacheKey = minF + '_' + maxF;
  var cache = window._pagosRepCache;
  var cacheHit = cache && cache.key === cacheKey && (Date.now() - cache.ts < 20000);

  // Render inmediato (con la caché de este rango si la hay)
  _renderStats(0, cacheHit ? cache.data : []);

  if (SB_KEY) {
    if (cacheHit) {
      tReps = cache.data.reduce(function(a, p){ return a + Number(p.importe||0); }, 0);
      _renderStats(tReps, cache.data);
    } else {
      try {
        var pagosRep = await sbGet('pagos_reparacion', 'fecha=gte.' + minF + '&fecha=lte.' + maxF) || [];
        tReps = pagosRep.reduce(function(a, p){ return a + Number(p.importe||0); }, 0);
        window._pagosRepCache = { key: cacheKey, data: pagosRep, ts: Date.now() };
        _renderStats(tReps, pagosRep);
      } catch(e) { console.warn('tReps:', e); }
    }
  }

  // Stats ya renderizados en _renderStats() — solo lanzar widgets
  if (typeof renderDashWidgets === 'function') renderDashWidgets();
}



// modelos_v1: cargar y autocompletar modelos
function cargarModelosPre() {
  fetch('/assets/modelos.json', {cache: 'force-cache'})
    .then(function(r){ return r.ok ? r.json() : null; })
    .then(function(j){
      if (j && Array.isArray(j.modelos)) {
        MODELOS_PRE = j.modelos;
      }
    })
    .catch(function(){ MODELOS_PRE = []; });
}

function cargarModelosCustom() {
  if (!SB_KEY || !TIENDA_ID) { return; }
  sbGet('modelos_custom', 'tienda_id=eq.' + TIENDA_ID + '&order=created_at.desc&limit=500')
    .then(function(rows){
      if (Array.isArray(rows)) {
        DB.modelosCustom = rows.map(function(m){
          return { cat: m.categoria || 'Telefono', marca: m.marca || '', modelo: m.modelo || '', custom: true, _id: m.id };
        });
      }
    })
    .catch(function(){});
}

// F225: modelos más usados por el usuario (de sus reparaciones), para sugerir al hacer
// foco sin escribir. Solo dispositivos reparables y deduplicados.
function _modelosMasUsados(pool, n) {
  var freq = {};
  (DB.reps || []).forEach(function(r){
    if (!r.modelo) return;
    var k = ((r.marca || '') + '|' + r.modelo).toLowerCase();
    freq[k] = (freq[k] || 0) + 1;
  });
  var byKey = {};
  pool.forEach(function(m){ byKey[(m.marca + '|' + m.modelo).toLowerCase()] = m; });
  return Object.keys(freq)
    .sort(function(a, b){ return freq[b] - freq[a]; })
    .map(function(k){
      if (byKey[k]) return byKey[k];
      var p = k.split('|'); // rep cuyo modelo no está en el catálogo: reconstruir mínimamente
      return { marca: (p[0] || ''), modelo: (p[1] || ''), cat: 'Telefono' };
    })
    .filter(_esModeloDispositivo)
    .slice(0, n);
}

function busModelo() {
  var q = (document.getElementById('rModelo').value || '').toLowerCase().trim();
  var box = document.getElementById('rModeloSug');
  if (!box) return;

  // Combinar custom (primero) + pre, evitar duplicados por modelo+marca
  var seen = {};
  var pool = [];
  DB.modelosCustom.forEach(function(m){
    var k = (m.marca + '|' + m.modelo).toLowerCase();
    if (!seen[k]) { seen[k] = 1; pool.push(m); }
  });
  MODELOS_PRE.forEach(function(m){
    var k = (m.marca + '|' + m.modelo).toLowerCase();
    if (!seen[k]) { seen[k] = 1; pool.push(m); }
  });

  var matches, esTopUsados = false;
  if (!q || q.length < 1) {
    // F225: foco sin texto → tus modelos más usados
    esTopUsados = true;
    matches = _modelosMasUsados(pool, 6);
    if (!matches.length) { box.classList.remove('open'); box.innerHTML = ''; return; }
  } else {
    // F217: solo dispositivos reparables (fuera accesorios mal categorizados como "Anker Cargador")
    matches = pool.filter(_esModeloDispositivo).filter(function(m){
      var hay = (m.marca + ' ' + m.modelo).toLowerCase();
      return hay.includes(q);
    }).slice(0, 8);
    if (!matches.length) {
      box.innerHTML = '<div class="cli-item" style="color:var(--muted);font-style:italic;cursor:default">' + T('gen.sin_coincidencias') + '</div>';
      box.classList.add('open');
      return;
    }
  }

  box.innerHTML = (esTopUsados ? '<div class="cli-item" style="color:var(--muted);font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;cursor:default;pointer-events:none">' + (T('rep.tus_mas_usados') || 'Tus más usados') + '</div>' : '') + matches.map(function(m, i){
    var label = _eqNombre(m.marca, m.modelo);
    // F218: separadores claros — antes el texto salía pegado ("…20WtuyoTelefono")
    var tag = m.custom
      ? '<span style="font-size:9px;background:rgba(255,91,31,.12);color:var(--purple);padding:2px 6px;border-radius:4px;margin-left:6px">· tuyo</span>'
      : '';
    return '<div class="cli-item" data-i="' + i + '" data-cat="' + esc(m.cat || '') + '" data-marca="' + esc(m.marca || '') + '" data-modelo="' + esc(m.modelo || '') + '">' +
      '<strong>' + esc(label) + '</strong>' + tag +
      '<span style="float:right;color:var(--muted);font-size:10px">' + esc(_catLabel(m.cat)) + '</span>' +
    '</div>';
  }).join('');
  box.classList.add('open');

  // Listeners
  box.querySelectorAll('.cli-item[data-marca]').forEach(function(el){
    el.addEventListener('mousedown', function(e){
      e.preventDefault();
      seleccionarModelo(el.dataset.cat, el.dataset.marca, el.dataset.modelo);
    });
  });
}

function seleccionarModelo(cat, marca, modelo) {
  var rMarca = document.getElementById('rMarca');
  var rModelo = document.getElementById('rModelo');
  if (rMarca) rMarca.value = marca;
  if (rModelo) rModelo.value = modelo;
  var sug = document.getElementById('rModeloSug');
  if (sug) { sug.classList.remove('open'); sug.innerHTML = ''; }
  try { sugerirPiezasRep(); } catch(e){}
  // Foco al siguiente campo
  var imei = document.getElementById('rImei'); if (imei) imei.focus();
}

function escapeAttr(s){
  return String(s == null ? '' : s).replace(/"/g, '&quot;').replace(/</g, '&lt;');
}

// Despues de crear una rep, ofrecer guardar el modelo en custom si no existe
function ofrecerGuardarModelo(rep) {
  if (!rep || !rep.modelo || !rep.marca) return;
  var key = (rep.marca + '|' + rep.modelo).toLowerCase();
  var existePre = MODELOS_PRE.some(function(m){ return (m.marca + '|' + m.modelo).toLowerCase() === key; });
  var existeCustom = DB.modelosCustom.some(function(m){ return (m.marca + '|' + m.modelo).toLowerCase() === key; });
  if (existePre || existeCustom) return;

  // Pequeno delay para que el modal anterior se cierre y el toast aparezca antes
  setTimeout(function(){
    if (!confirm('Guardar "' + rep.marca + ' ' + rep.modelo + '" en tu catalogo de modelos?')) return;
    var nuevo = {
      id: 'm' + Date.now() + '_' + Math.random().toString(36).slice(2,8),
      tienda_id: TIENDA_ID,
      categoria: 'Telefono',
      marca: rep.marca,
      modelo: rep.modelo,
      creado_por: U ? U.email : ''
    };
    DB.modelosCustom.unshift({ cat: 'Telefono', marca: nuevo.marca, modelo: nuevo.modelo, custom: true, _id: nuevo.id });
    if (SB_KEY && TIENDA_ID) {
      sbPost('modelos_custom', nuevo).catch(function(){});
    }
    toast('Modelo añadido al catálogo', 'ok');
  }, 600);
}


// notas_v1: notas y recordatorios compartidas via Supabase
var NOTAS_REFRESH_INTERVAL = null;

function fmtFechaNota(iso) {
  if (!iso) return '';
  var d = new Date(iso);
  if (isNaN(d.getTime())) return '';
  var hoy = new Date();
  var manana = new Date(); manana.setDate(manana.getDate() + 1);
  var sameDay = function(a,b){ return a.getFullYear()===b.getFullYear() && a.getMonth()===b.getMonth() && a.getDate()===b.getDate(); };
  var hh = ('0'+d.getHours()).slice(-2) + ':' + ('0'+d.getMinutes()).slice(-2);
  if (sameDay(d, hoy)) return 'Hoy ' + hh;
  if (sameDay(d, manana)) return 'Manana ' + hh;
  return d.toLocaleDateString('es') + ' ' + hh;
}

function fechaNotaClass(iso) {
  if (!iso) return 'normal';
  var d = new Date(iso); if (isNaN(d.getTime())) return 'normal';
  var ahora = new Date();
  if (d.getTime() < ahora.getTime()) return 'vencida';
  var fin = new Date(); fin.setHours(23,59,59,999);
  if (d.getTime() <= fin.getTime()) return 'hoy';
  return 'futura';
}

function crearNota() {
  var input = document.getElementById('notaInput');
  var fechaEl = document.getElementById('notaFecha');
  var texto = (input.value || '').trim();
  if (!texto) { input.focus(); return; }

  var nota = {
    id: 'n' + Date.now() + '_' + Math.random().toString(36).slice(2,8),
    tienda_id: TIENDA_ID,
    texto: texto,
    fecha_recordatorio: fechaEl.value ? new Date(fechaEl.value).toISOString() : null,
    hecha: false,
    creada_por: U ? U.email : '',
    creada_por_nombre: U ? U.nombre : ''
  };

  DB.notas.unshift(nota);
  renderNotas();
  input.value = '';
  fechaEl.value = '';

  if (SB_KEY && TIENDA_ID) {
    sbPost('notas', nota).catch(function(e){
      toast('Nota guardada solo localmente', 'err');
    });
  }
}

function toggleNotaHecha(id) {
  var n = DB.notas.find(function(x){ return x.id === id; });
  if (!n) return;
  n.hecha = !n.hecha;
  n.hecha_at = n.hecha ? new Date().toISOString() : null;
  renderNotas();
  if (SB_KEY && TIENDA_ID) {
    sbPatch('notas', 'id=eq.' + id, { hecha: n.hecha, hecha_at: n.hecha_at }).catch(function(){});
  }
}

function eliminarNota(id) {
  if (!confirm('Eliminar esta nota?')) return;
  DB.notas = DB.notas.filter(function(x){ return x.id !== id; });
  renderNotas();
  if (SB_KEY && TIENDA_ID) {
    sbDelete('notas', 'id=eq.' + id).catch(function(){});
  }
}

function renderNotas() {
  var box = document.getElementById('notasBox');
  var cnt = document.getElementById('notasCount');
  if (!box) return;

  // Filtrar hechas mas viejas de 24h
  var ahora = Date.now();
  var visibles = DB.notas.filter(function(n){
    if (!n.hecha) return true;
    if (!n.hecha_at) return true;
    return (ahora - new Date(n.hecha_at).getTime()) < 24*60*60*1000;
  });

  // Ordenar: vencidas primero, luego hoy, luego futuras, luego sin fecha, luego hechas al final
  visibles.sort(function(a, b){
    if (a.hecha !== b.hecha) return a.hecha ? 1 : -1;
    var ca = a.fecha_recordatorio ? new Date(a.fecha_recordatorio).getTime() : Number.MAX_SAFE_INTEGER;
    var cb = b.fecha_recordatorio ? new Date(b.fecha_recordatorio).getTime() : Number.MAX_SAFE_INTEGER;
    return ca - cb;
  });

  var pendientes = visibles.filter(function(n){ return !n.hecha; }).length;
  cnt.textContent = pendientes ? '(' + pendientes + ')' : '';

  if (!visibles.length) {
    box.innerHTML = '<div class="empty" style="padding:14px;font-size:12px">No hay notas</div>';
    return;
  }

  box.innerHTML = visibles.map(function(n){
    var fclass = fechaNotaClass(n.fecha_recordatorio);
    var bg = '#fff', border = 'var(--border)';
    if (!n.hecha) {
      if (fclass === 'vencida') { bg = 'rgba(239,68,68,.06)'; border = 'rgba(239,68,68,.3)'; }
      else if (fclass === 'hoy') { bg = 'rgba(249,115,22,.06)'; border = 'rgba(249,115,22,.3)'; }
    }
    var fechaTxt = fmtFechaNota(n.fecha_recordatorio);
    var fechaColor = fclass === 'vencida' ? 'var(--red)' : fclass === 'hoy' ? 'var(--orange)' : 'var(--muted)';
    var autorTxt = n.creada_por_nombre ? n.creada_por_nombre : '';
    var textoStyle = n.hecha ? 'text-decoration:line-through;color:var(--muted)' : '';

    return '<div style="background:' + bg + ';border:1px solid ' + border + ';border-radius:8px;padding:10px 12px;margin-bottom:6px;display:flex;gap:10px;align-items:flex-start">' +
      '<div style="display:flex;align-items:center;justify-content:center;flex-shrink:0;cursor:pointer;width:22px;height:22px;border:2px solid ' + (n.hecha ? 'var(--green)' : 'var(--border)') + ';border-radius:5px;background:' + (n.hecha ? 'var(--green)' : 'white') + ';color:white;font-size:13px;font-weight:700" onclick="toggleNotaHecha(\'' + n.id + '\')">' + (n.hecha ? '✓' : '') + '</div>' +
      '<div style="flex:1;min-width:0">' +
        '<div style="font-size:13px;line-height:1.3;word-wrap:break-word;' + textoStyle + '">' + escapeHtmlNota(n.texto) + '</div>' +
        '<div style="font-size:10px;color:var(--muted);margin-top:3px;display:flex;gap:8px;flex-wrap:wrap">' +
          (fechaTxt ? '<span style="color:' + fechaColor + ';font-weight:600">⏰ ' + escapeHtmlNota(fechaTxt) + '</span>' : '') +
          (autorTxt ? '<span>· ' + escapeHtmlNota(autorTxt) + '</span>' : '') +
        '</div>' +
      '</div>' +
      '<button onclick="eliminarNota(\'' + n.id + '\')" style="background:none;border:none;color:var(--muted);cursor:pointer;padding:4px;font-size:14px;flex-shrink:0" title="Eliminar">×</button>' +
    '</div>';
  }).join('');
}

function escapeHtmlNota(s) {
  return String(s == null ? '' : s).replace(/[&<>"']/g, function(c){
    return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c];
  });
}

function cargarNotas() {
  if (!SB_KEY || !TIENDA_ID) { renderNotas(); return; }
  sbGet('notas', 'tienda_id=eq.' + TIENDA_ID + '&order=created_at.desc&limit=100')
    .then(function(rows){
      if (Array.isArray(rows)) {
        DB.notas = rows;
        renderNotas();
      }
    })
    .catch(function(){});
}

function iniciarRefrescoNotas() {
  if (NOTAS_REFRESH_INTERVAL) clearInterval(NOTAS_REFRESH_INTERVAL);
  NOTAS_REFRESH_INTERVAL = setInterval(function(){
    // Solo refrescar si la pagina del dashboard esta visible
    if (document.visibilityState === 'visible') {
      var dash = document.getElementById('pDash');
      if (dash && dash.classList.contains('active')) cargarNotas();
    }
  }, 30000);
}


function renderDashWidgets() {
  // VIS-18: empty state si BD vacía
  var esVacio = DB.reps.length === 0 && DB.clis.length === 0 && DB.ventas.length === 0;
  var emptyEl = document.getElementById('dashEmptyState');
  var wrappers = document.querySelectorAll('#pDash .dash-zone-2col, #pDash .dash-zone-3col');
  ['zoneOperaciones','zoneFinanzas','zoneAnalitica'].forEach(function(id){
    var el = document.getElementById(id); if(el) el.style.display = esVacio ? 'none' : '';
  });
  if (emptyEl) emptyEl.style.display = esVacio ? 'block' : 'none';
  wrappers.forEach(function(el){ el.style.display = esVacio ? 'none' : ''; });
  // estado normalizado (minúsculas) para tolerar variantes históricas 'En proceso'/'Por entregar'
  var pend = DB.reps.filter(function(r){ var e=(r.estado||'').toLowerCase(); return e === 'pendiente' || e === 'en proceso'; });
  var ent = DB.reps.filter(function(r){ return (r.estado||'').toLowerCase() === 'por entregar'; });

  // Ordenar por prioridad (Alta primero) y luego por fecha de entrega
  var prioVal = function(p){ return p === 'Alta' ? 0 : p === 'Normal' ? 1 : 2; };
  pend.sort(function(a,b){
    var pa = prioVal(a.prioridad), pb = prioVal(b.prioridad);
    if (pa !== pb) return pa - pb;
    return (a.fechaEntrega || '').localeCompare(b.fechaEntrega || '');
  });
  ent.sort(function(a,b){ return (a.fechaEntrega || '').localeCompare(b.fechaEntrega || ''); });

  var renderList = function(list, emptyMsg, color){
    if (!list.length) return '<div class="empty" style="padding:12px;font-size:12px">' + emptyMsg + '</div>';
    return '<div style="display:flex;flex-direction:column;gap:6px">' + list.slice(0,8).map(function(r){
      var cli = r.clienteNombre || (DB.clis.find(function(c){ return c.id === r.clienteId; }) || {}).nombre || T('gen.sin_cliente');
      var prioBadge = r.prioridad === 'Alta'
        ? '<span style="background:rgba(239,68,68,.12);color:var(--red);font-size:9px;padding:2px 6px;border-radius:4px;font-weight:600">' + T('rep.prio_alta').toUpperCase() + '</span>'
        : '';
      var fecha = r.fechaEntrega ? '<span style="font-size:10px;color:var(--muted)">⏱ ' + r.fechaEntrega + '</span>' : '';
      return '<div class="dash-rep-item" data-rid="' + r.id + '" style="background:var(--light);border-left:3px solid ' + color + ';padding:8px 10px;border-radius:6px;cursor:pointer;display:flex;justify-content:space-between;align-items:center;gap:8px">' +
        '<div style="flex:1;min-width:0;overflow:hidden">' +
          '<div style="font-weight:600;font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + escHtml(r.marca || '') + ' ' + escHtml(r.modelo || '') + '</div>' +
          '<div style="font-size:10px;color:var(--muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + escHtml(cli) + ' · ' + escHtml(r.averia || '') + '</div>' +
        '</div>' +
        '<div style="display:flex;flex-direction:column;align-items:flex-end;gap:3px;flex-shrink:0">' + prioBadge + fecha + '</div>' +
      '</div>';
    }).join('') + (list.length > 8 ? '<div style="text-align:center;font-size:11px;color:var(--muted);padding:4px">+' + (list.length - 8) + ' ' + T('dash.mas') + '</div>' : '') + '</div>';
  };

  document.getElementById('repsPendientesBox').innerHTML = renderList(pend, T('dash.sin_pendientes'), '#F97316');
  document.getElementById('repsEntregarBox').innerHTML = renderList(ent, T('dash.sin_entregas'), '#00C896');
  document.getElementById('repsPendientesCount').textContent = pend.length ? '(' + pend.length + ')' : '';
  document.getElementById('repsEntregarCount').textContent = ent.length ? '(' + ent.length + ')' : '';
  if (typeof renderNotas === 'function') renderNotas();

  // Click sobre un item -> ir a reparaciones
  document.querySelectorAll('.dash-rep-item').forEach(function(it){
    it.addEventListener('click', function(){
      navTo('pReps');
    });
  });

  // Render de los 10 widgets nuevos (cada uno se autocomprueba)
  try { renderWidgetCajaDia(); } catch(e){}
  try { renderWidgetCobros(); } catch(e){}
  try { renderWidgetStockCritico(); } catch(e){}
  try { renderWidgetCumples(); } catch(e){}
  try { renderWidgetTendencia(); } catch(e){}
  try { renderWidgetTopProds(); } catch(e){}
  try { renderWidgetTopAverias(); } catch(e){}
  try { renderWidgetRepsEstado(); } catch(e){}
  try { renderWidgetTiempoMedio(); } catch(e){}
  try { renderWidgetClisInactivos(); } catch(e){}
  // FIX-HOME-1: urgentes se rellena en cada render del home
  try { if (typeof checkUrgentes === 'function') checkUrgentes(); } catch(e){}
  // FIX-HOME-2: cierre se precalcula automáticamente (sin await, sin email, sin PDF)
  try { if (typeof renderWidgetCierre === 'function') renderWidgetCierre(); } catch(e){}
  try { if (typeof renderWidgetComoCobras === 'function') renderWidgetComoCobras(); } catch(e){}
  try { if (typeof renderPedidosWidget === 'function') renderPedidosWidget(); } catch(e){}

  // VIS-5: ocultar cards de Inicio cuyo contenido sea "vacío" + banner resumen
  try { _colapsarCardsVacios(); } catch(e){}
  try { actualizarBadgePresupuestos(); } catch(e){}
}

// VIS-5: Detecta cards del Inicio con contenido "vacío" (clase .empty o texto neutro)
// y los esconde. Muestra un banner verde con "✓ X cosas controladas hoy" al inicio.
function _colapsarCardsVacios() {
  var pDash = document.getElementById('pDash');
  if (!pDash) return;
  var cards = pDash.querySelectorAll('.card');
  var ocultos = [];
  cards.forEach(function(card){
    // Saltar el card de stats / quick actions / notas / planBanner
    if (card.id === 'cardNotas') return; // Notas siempre visible (input)
    // Considerar "vacío" si SOLO tiene un .empty dentro del contenedor de datos
    var box = card.querySelector('[id$="Box"]') || card.querySelector('[id$="Lista"]');
    if (!box) return;
    var emptyEl = box.querySelector('.empty');
    var tieneDatos = box.children.length > 0 && (!emptyEl || box.children.length > 1);
    if (!tieneDatos && emptyEl) {
      // Está vacío → ocultar
      card.style.display = 'none';
      var titulo = (card.querySelector('.card-title') || {}).textContent || '';
      // VIS-5b: regex amplio que limpia TODOS los emojis, símbolos y mojibake.
      // Range completo de emojis Unicode + caracteres de reemplazo (U+FFFD).
      titulo = titulo.replace(/[\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}\u{FFFD}\u200D\uFE0F]/gu, '').replace(/\s+/g, ' ').trim();
      // Quitar contadores "(3)" o similares
      titulo = titulo.replace(/\(\s*\d+\s*\)/g, '').trim();
      if (titulo) ocultos.push(titulo);
    }
  });
  // Si hay ocultos, insertar mini-banner verde resumen
  var prev = document.getElementById('dashTodoOkBanner');
  if (prev) prev.remove();
  if (ocultos.length >= 2) {
    var banner = document.createElement('div');
    banner.id = 'dashTodoOkBanner';
    banner.style.cssText = 'background:#E7F6EC;border:1px solid #BBE5C9;border-left:4px solid var(--green);padding:10px 14px;border-radius:8px;margin:10px 0;font-size:13px;color:var(--dark);display:flex;align-items:center;gap:8px';
    var yMas = ocultos.length > 3 ? T('gen.y_mas').replace('{n}', ocultos.length - 3) : '';
    var lista = ocultos.length > 3 ? ocultos.slice(0,3).join(', ') + ' ' + yMas : ocultos.join(', ');
    banner.innerHTML = '<span style="font-size:16px;color:var(--green);font-weight:700">✓</span><span><strong>' + T('dash.todo_bajo_control') + ':</strong> ' + T('dash.sin_pendientes_en') + ' ' + lista + '.</span>';
    // VIS-5b: insertar arriba del Inicio (después de quick actions), no al final
    var quickGrid = document.getElementById('dashQuickGrid');
    if (quickGrid && quickGrid.parentNode) {
      quickGrid.parentNode.insertBefore(banner, quickGrid.nextSibling);
    }
  }
}

// ═══ WIDGETS NUEVOS DEL DASHBOARD ═══

// Helper: periodo activo según el tab Hoy/Semana/Mes
function _periodoActivo() {
  var tab = (SEL && SEL.metricTab) || 'hoy';
  var hoy = new Date(); hoy.setHours(0,0,0,0);
  var inicio = new Date(hoy);
  var fin = new Date(); fin.setHours(23,59,59,999);
  var label = 'hoy', futuroLabel = 'hoy';
  if (tab === 'semana') {
    inicio.setDate(inicio.getDate() - 6);
    label = 'semana'; futuroLabel = '7 días';
  } else if (tab === 'mes') {
    inicio.setDate(inicio.getDate() - 29);
    label = 'mes'; futuroLabel = '30 días';
  }
  // Versión "futura" del periodo (para cumples y cobros pendientes)
  var futuroFin = new Date(hoy); futuroFin.setHours(23,59,59,999);
  if (tab === 'semana') futuroFin.setDate(futuroFin.getDate() + 6);
  else if (tab === 'mes') futuroFin.setDate(futuroFin.getDate() + 29);
  return {tab: tab, inicio: inicio, fin: fin, futuroFin: futuroFin, label: label, futuroLabel: futuroLabel};
}

function renderWidgetCajaDia() {
  var box = document.getElementById('cajaDiaBox');
  var totEl = document.getElementById('cajaDiaTotal');
  if (!box) return;
  var per = _periodoActivo();
  // Actualizar título
  var card = document.getElementById('cardCajaDia');
  if (card) {
    var t = card.querySelector('.card-title');
    if (t) t.textContent = '💰 ' + T('nav.cajas') + ': ' + (per.tab === 'hoy' ? T('dash.hoy') : per.tab === 'semana' ? T('gen.ultimos_7_dias') : T('gen.ultimo_mes'));
  }
  var pagos = {Efectivo:0, Tarjeta:0, Bizum:0, Transferencia:0};
  DB.ventas.forEach(function(v) {
    if (v.reembolsado) return;
    var fv = _parseDateAny(v.fecha);
    if (!fv || fv < per.inicio || fv > per.fin) return;
    var monto = v.financiado ? (v.entrada || 0) : v.total;
    var p = v.pago || 'Efectivo';
    if (pagos[p] === undefined) pagos[p] = 0;
    pagos[p] += monto;
  });
  // v2.4: usar pagos reales (anticipos + finales) en lugar de fechaEntregaReal
  if (SB_KEY) {
    var minISO = per.inicio.getFullYear() + '-' + String(per.inicio.getMonth()+1).padStart(2,'0') + '-' + String(per.inicio.getDate()).padStart(2,'0');
    var maxISO = per.fin.getFullYear() + '-' + String(per.fin.getMonth()+1).padStart(2,'0') + '-' + String(per.fin.getDate()).padStart(2,'0');
    sbGet('pagos_reparacion', 'fecha=gte.' + minISO + '&fecha=lte.' + maxISO).then(function(pagosReps){
      (pagosReps || []).forEach(function(p){
        var metodo = p.metodo || 'Efectivo';
        if (pagos[metodo] === undefined) pagos[metodo] = 0;
        pagos[metodo] += Number(p.importe||0);
      });
      // Re-renderizar despues de cargar pagos
      var total = 0;
      Object.keys(pagos).forEach(function(k) { total += pagos[k]; });
      if (totEl) totEl.textContent = cur(total);
      var iconos2 = {Efectivo:'💵', Tarjeta:'💳', Bizum:'📲', Transferencia:'🏦'};
      var colores2 = {Efectivo:'#00C896', Tarjeta:'#FF5B1F', Bizum:'#FF5B1F', Transferencia:'#F97316'};
      var html2 = '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:8px">';
      Object.keys(pagos).forEach(function(k) {
        var v = pagos[k];
        var color = colores2[k] || 'var(--muted)';
        html2 += '<div style="background:var(--light);padding:10px 12px;border-radius:8px;border-left:3px solid ' + color + '"><div style="font-size:11px;color:var(--muted);font-weight:600">' + (iconos2[k] || '') + ' ' + k + '</div><div style="font-size:16px;font-weight:800;color:' + color + ';margin-top:2px">' + cur(v) + '</div></div>';
      });
      html2 += '</div>';
      if (total === 0) html2 = '<div class="empty" style="padding:12px;font-size:12px">' + T('gen.sin_movimientos') + '</div>';
      box.innerHTML = html2;
    }).catch(function(e){ console.warn('pagos:', e); });
  }
  var total = 0;
  Object.keys(pagos).forEach(function(k) { total += pagos[k]; });
  if (totEl) totEl.textContent = cur(total);
  var iconos = {Efectivo:'💵', Tarjeta:'💳', Bizum:'📲', Transferencia:'🏦'};
  var colores = {Efectivo:'#00C896', Tarjeta:'#FF5B1F', Bizum:'#FF5B1F', Transferencia:'#F97316'};
  var html = '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:8px">';
  Object.keys(pagos).forEach(function(k) {
    var v = pagos[k];
    var color = colores[k] || 'var(--muted)';
    html += '<div style="background:var(--light);padding:10px 12px;border-radius:8px;border-left:3px solid ' + color + '">';
    html += '<div style="font-size:11px;color:var(--muted);font-weight:600">' + (iconos[k] || '') + ' ' + k + '</div>';
    html += '<div style="font-size:16px;font-weight:800;color:' + color + ';margin-top:2px">' + cur(v) + '</div>';
    html += '</div>';
  });
  html += '</div>';
  if (total === 0) html = '<div class="empty" style="padding:12px;font-size:12px">' + T('gen.sin_movimientos') + '</div>';
  box.innerHTML = html;
}

function renderWidgetCobros() {
  var box = document.getElementById('cobrosBox');
  var countEl = document.getElementById('cobrosCount');
  if (!box) return;
  var per = _periodoActivo();
  var card = document.getElementById('cardCobros');
  if (card) {
    var t = card.querySelector('.card-title');
    if (t) {
      var lbl = per.tab === 'hoy' ? 'hoy + vencidas' : per.tab === 'semana' ? 'próximos 7 días + vencidas' : 'próximos 30 días + vencidas';
      t.innerHTML = '💵 Cobros pendientes <span style="font-size:11px;color:var(--muted);font-weight:500">(' + lbl + ') <span id="cobrosCount"></span></span>';
      countEl = document.getElementById('cobrosCount');
    }
  }
  var hoy = new Date(); hoy.setHours(0,0,0,0);
  var pendientes = [];
  DB.ventas.forEach(function(v) {
    if (!v.financiado || !v.cuotas || v.reembolsado) return;
    v.cuotas.forEach(function(c, idx) {
      if (c.pagado) return;
      var fc = _parseDateAny(c.fecha);
      if (!fc) return;
      // Incluye: vencidas (fc < hoy) o que caen dentro del rango futuro del periodo
      if (fc < hoy || fc <= per.futuroFin) {
        pendientes.push({venta:v, cuota:c, idx:idx, fecha:fc, vencida:fc < hoy});
      }
    });
  });
  pendientes.sort(function(a,b){ return a.fecha - b.fecha; });
  if (countEl) countEl.textContent = pendientes.length ? '(' + pendientes.length + ')' : '';
  if (!pendientes.length) {
    box.innerHTML = '<div class="empty" style="padding:12px;font-size:12px">' + T('gen.sin_cobros') + '</div>';
    return;
  }
  var html = '<div style="display:flex;flex-direction:column;gap:6px">';
  pendientes.slice(0,8).forEach(function(p) {
    var cli = p.venta.clienteNombre || (DB.clis.find(function(c){ return c.id === p.venta.clienteId; }) || {}).nombre || T('gen.sin_cliente');
    var color = p.vencida ? 'var(--red)' : 'var(--orange)';
    var badge = p.vencida ? '<span style="background:rgba(239,68,68,.12);color:var(--red);font-size:9px;padding:2px 6px;border-radius:4px;font-weight:700">VENCIDA</span>' : '';
    html += '<div style="background:var(--light);border-left:3px solid ' + color + ';padding:8px 10px;border-radius:6px;display:flex;justify-content:space-between;align-items:center;gap:8px">';
    html += '<div style="flex:1;min-width:0">';
    html += '<div style="font-weight:600;font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + escHtml(cli) + ' · ' + cur(p.cuota.importe) + '</div>';
    html += '<div style="font-size:10px;color:var(--muted)">Cuota ' + (p.idx+1) + ' · vence ' + p.cuota.fecha + '</div>';
    html += '</div>' + badge + '</div>';
  });
  if (pendientes.length > 8) html += '<div style="text-align:center;font-size:11px;color:var(--muted);padding:4px">+' + (pendientes.length - 8) + ' más</div>';
  html += '</div>';
  box.innerHTML = html;
}

function renderWidgetCumples() {
  var box = document.getElementById('cumplesBox');
  var countEl = document.getElementById('cumplesCount');
  if (!box) return;
  var per = _periodoActivo();
  var card = document.getElementById('cardCumples');
  if (card) {
    var t = card.querySelector('.card-title');
    if (t) {
      var lbl = per.tab === 'hoy' ? 'hoy' : per.tab === 'semana' ? 'próximos 7 días' : 'próximos 30 días';
      t.innerHTML = '🎂 Cumpleaños ' + lbl + ' <span id="cumplesCount" style="font-size:11px;color:var(--muted);font-weight:500"></span>';
      countEl = document.getElementById('cumplesCount');
    }
  }
  var hoy = new Date(); hoy.setHours(0,0,0,0);
  var lista = [];
  DB.clis.forEach(function(c) {
    if (!c.fechaNac) return;
    var d = _parseDateAny(c.fechaNac);
    if (!d) return;
    var cumple = new Date(hoy.getFullYear(), d.getMonth(), d.getDate());
    if (cumple < hoy) cumple.setFullYear(hoy.getFullYear() + 1);
    if (cumple <= per.futuroFin) {
      var diasFalta = Math.round((cumple - hoy) / 86400000);
      lista.push({cli:c, fecha:cumple, dias:diasFalta});
    }
  });
  lista.sort(function(a,b){ return a.dias - b.dias; });
  if (countEl) countEl.textContent = lista.length ? '(' + lista.length + ')' : '';
  if (!lista.length) {
    box.innerHTML = '<div class="empty" style="padding:12px;font-size:12px">' + T('gen.sin_cumples') + '</div>';
    return;
  }
  var html = '<div style="display:flex;flex-direction:column;gap:6px">';
  lista.slice(0,8).forEach(function(it) {
    var lbl = it.dias === 0 ? '🎉 HOY' : it.dias === 1 ? 'Mañana' : 'En ' + it.dias + ' días';
    var color = it.dias === 0 ? 'var(--purple)' : 'var(--blue)';
    html += '<div style="background:var(--light);border-left:3px solid ' + color + ';padding:8px 10px;border-radius:6px;display:flex;justify-content:space-between;align-items:center;gap:8px">';
    html += '<div style="flex:1;min-width:0">';
    html += '<div style="font-weight:600;font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + (it.cli.nombre || '') + ' ' + (it.cli.apellidos || '') + '</div>';
    html += '<div style="font-size:10px;color:' + color + ';font-weight:600">' + lbl + '</div>';
    html += '</div>';
    if (it.cli.tel) html += '<button class="btn-sm" style="background:#25D366;color:white;font-size:11px;padding:4px 10px" onclick="felicitarCumple(\'' + it.cli.id + '\')">💬 Felicitar</button>';
    html += '</div>';
  });
  if (lista.length > 8) html += '<div style="text-align:center;font-size:11px;color:var(--muted);padding:4px">+' + (lista.length - 8) + ' más</div>';
  html += '</div>';
  box.innerHTML = html;
}

function renderWidgetTendencia() {
  var box = document.getElementById('tendenciaBox');
  var totEl = document.getElementById('tendenciaTotal');
  if (!box) return;
  var per = _periodoActivo();
  var card = document.getElementById('cardTendencia');
  if (card) {
    var t = card.querySelector('.card-title');
    if (t) t.textContent = per.tab === 'hoy' ? T('dash.tendencia_hoy') : per.tab === 'semana' ? T('dash.tendencia_semana') : T('dash.tendencia_mes');
  }

  var puntos = [];
  var max = 0; var totalPer = 0;

  if (per.tab === 'hoy') {
    // 24 puntos (uno por hora)
    var hoyStr = hoyLocal();
    var horasCount = new Array(24).fill(0);
    DB.ventas.forEach(function(v) {
      if (v.reembolsado || v.fecha !== hoyStr) return;
      // No tenemos hora de venta exacta, usar hora actual o 0
      var hora = v.hora ? parseInt(v.hora.split(':')[0]) : null;
      if (hora === null && v.createdAt) {
        try { hora = new Date(v.createdAt).getHours(); } catch(e) {}
      }
      if (hora === null) hora = 12; // fallback
      horasCount[hora] += v.financiado ? (v.entrada || 0) : v.total;
    });
    DB.reps.forEach(function(r) {
      if (r.fechaEntregaReal !== hoyStr || !r.total) return;
      horasCount[12] += r.total; // sin hora exacta
    });
    horasCount.forEach(function(val, h) {
      if (val > max) max = val;
      totalPer += val;
      puntos.push({total: val, lbl: (h < 10 ? '0' : '') + h, esHoy: false});
    });
  } else {
    var dias = per.tab === 'semana' ? 7 : 30;
    for (var i = dias - 1; i >= 0; i--) {
      var d = new Date(); d.setDate(d.getDate() - i);
      var fecha = d.toISOString().slice(0,10);
      var totalD = 0;
      DB.ventas.forEach(function(v) {
        if (v.reembolsado || v.fecha !== fecha) return;
        totalD += v.financiado ? (v.entrada || 0) : v.total;
      });
      DB.reps.forEach(function(r) {
        if (r.fechaEntregaReal === fecha) totalD += r.total;
      });
      var lbl;
      if (per.tab === 'semana') {
        lbl = ['D','L','M','X','J','V','S'][d.getDay()];
      } else {
        lbl = d.getDate() + '/' + (d.getMonth()+1);
      }
      puntos.push({total:totalD, lbl:lbl, esHoy:i===0});
      if (totalD > max) max = totalD;
      totalPer += totalD;
    }
  }
  if (totEl) totEl.textContent = cur(totalPer) + ' total';
  if (max === 0 || !puntos.length) {
    box.innerHTML = '<div class="empty" style="padding:12px;font-size:12px">' + T('gen.sin_movimientos') + '</div>';
    return;
  }

  // Sparkline SVG
  var w = 280, h = 80, pad = 10;
  var n = puntos.length;
  var pts = puntos.map(function(d, i) {
    var x = pad + (i * (w - 2*pad) / Math.max(1, n - 1));
    var y = h - pad - (d.total / max) * (h - 2*pad);
    return [x, y, d];
  });
  var poly = pts.map(function(p){ return p[0] + ',' + p[1]; }).join(' ');
  var area = poly + ' ' + pts[n-1][0] + ',' + (h-pad) + ' ' + pts[0][0] + ',' + (h-pad);

  // Etiquetas: si son muchas, solo cada N
  var skip = n <= 7 ? 1 : n <= 12 ? 2 : Math.ceil(n / 8);
  var html = '<svg viewBox="0 0 ' + w + ' ' + h + '" preserveAspectRatio="none" style="width:100%;height:80px;display:block">';
  html += '<polygon points="' + area + '" fill="rgba(255,91,31,.10)"/>';
  html += '<polyline points="' + poly + '" fill="none" stroke="var(--blue)" stroke-width="2"/>';
  pts.forEach(function(p, i) {
    var r = p[2].esHoy ? 4 : (n > 14 ? 1.5 : 3);
    html += '<circle cx="' + p[0] + '" cy="' + p[1] + '" r="' + r + '" fill="' + (p[2].esHoy ? 'var(--blue)' : 'white') + '" stroke="var(--blue)" stroke-width="' + (n > 14 ? 1 : 2) + '"/>';
  });
  html += '</svg>';
  html += '<div style="display:flex;justify-content:space-between;margin-top:4px;font-size:10px;color:var(--muted);gap:2px">';
  puntos.forEach(function(d, i) {
    var visible = (i % skip === 0) || d.esHoy || i === n - 1;
    html += '<div style="text-align:center;flex:1;font-weight:600' + (d.esHoy ? ';color:var(--blue)' : '') + ';overflow:hidden;white-space:nowrap">' + (visible ? d.lbl : '') + '</div>';
  });
  html += '</div>';
  box.innerHTML = html;
}

function renderWidgetTopProds() {
  var box = document.getElementById('topProdsBox');
  if (!box) return;
  var per = _periodoActivo();
  var card = document.getElementById('cardTopProds');
  if (card) {
    var t = card.querySelector('.card-title');
    if (t) t.textContent = per.tab === 'hoy' ? T('dash.top_productos') : per.tab === 'semana' ? T('dash.top_productos_semana') : T('dash.top_productos_mes');
  }
  var conteo = {};
  var ingresos = {};
  DB.ventas.forEach(function(v) {
    if (v.reembolsado) return;
    var fv = _parseDateAny(v.fecha);
    if (!fv || fv < per.inicio || fv > per.fin) return;
    var key = ((v.marca || '') + ' ' + (v.modelo || '')).trim();
    if (!key) return;
    conteo[key] = (conteo[key] || 0) + 1;
    ingresos[key] = (ingresos[key] || 0) + (v.financiado ? (v.entrada || 0) : v.total);
  });
  var top = Object.keys(conteo).map(function(k){ return {nombre:k, count:conteo[k], ingresos:ingresos[k]}; })
    .sort(function(a,b){ return b.count - a.count; }).slice(0,5);
  if (!top.length) {
    box.innerHTML = '<div class="empty" style="padding:12px;font-size:12px">' + T('gen.sin_ventas_hoy') + '</div>';
    return;
  }
  var maxCount = top[0].count;
  var html = '<div style="display:flex;flex-direction:column;gap:6px">';
  top.forEach(function(p, i) {
    var pct = (p.count / maxCount) * 100;
    html += '<div style="display:flex;align-items:center;gap:8px">';
    html += '<div style="width:18px;font-size:11px;color:var(--muted);font-weight:700;text-align:center">' + (i+1) + '</div>';
    html += '<div style="flex:1;min-width:0">';
    html += '<div style="display:flex;justify-content:space-between;font-size:12px;font-weight:600;margin-bottom:3px;gap:8px">';
    html += '<span style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + escHtml(p.nombre) + '</span>';
    html += '<span style="color:var(--blue);flex-shrink:0">' + p.count + ' uds</span></div>';
    html += '<div style="background:var(--light);height:6px;border-radius:3px;overflow:hidden">';
    html += '<div style="width:' + pct + '%;height:100%;background:var(--blue)"></div></div>';
    html += '</div></div>';
  });
  html += '</div>';
  box.innerHTML = html;
}

