function renderWidgetStockCritico() {
  var box = document.getElementById('stockCriticoBox');
  if (!box) return;
  var bajos = DB.stock.filter(function(s) {
    if (s.vendido) return false;
    var min = parseInt(s.stockMin || 0);
    return s.unidades > 0 && min > 0 && s.unidades <= min;
  });
  var sinStock = DB.stock.filter(function(s) {
    return !s.vendido && s.unidades === 0 && parseInt(s.stockMin || 0) > 0;
  });
  var valorTotal = DB.stock.reduce(function(a, s) {
    if (s.vendido) return a;
    var precio = s.precioC || s.precioV || 0;
    return a + (s.unidades * precio);
  }, 0);
  var html = '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px">';
  html += '<div style="background:var(--light);padding:10px;border-radius:8px;border-left:3px solid var(--red)">';
  html += '<div style="font-size:11px;color:var(--muted);font-weight:600"><span data-t="dash.sin_stock">Sin stock</span></div>';
  html += '<div style="font-size:18px;font-weight:800;color:var(--red)">' + sinStock.length + '</div></div>';
  html += '<div style="background:var(--light);padding:10px;border-radius:8px;border-left:3px solid var(--orange)">';
  html += '<div style="font-size:11px;color:var(--muted);font-weight:600"><span data-t="dash.bajo_minimo">Bajo mínimo</span></div>';
  html += '<div style="font-size:18px;font-weight:800;color:var(--orange)">' + bajos.length + '</div></div>';
  html += '<div style="background:var(--light);padding:10px;border-radius:8px;border-left:3px solid var(--blue);grid-column:1/-1">';
  html += '<div style="font-size:11px;color:var(--muted);font-weight:600"><span data-t="stock.valor_inventario">Valor total inventario (precio coste)</span></div>';
  html += '<div style="font-size:18px;font-weight:800;color:var(--blue)">' + cur(valorTotal) + '</div></div>';
  html += '</div>';
  var todos = sinStock.concat(bajos).slice(0,5);
  if (todos.length) {
    html += '<div style="display:flex;flex-direction:column;gap:4px">';
    todos.forEach(function(s) {
      var color = s.unidades === 0 ? 'var(--red)' : 'var(--orange)';
      html += '<div style="font-size:11px;padding:6px 10px;background:var(--light);border-radius:6px;border-left:3px solid ' + color + ';display:flex;justify-content:space-between;gap:8px">';
      var nombreProd = [s.marca, s.modelo].filter(Boolean).join(' ') || s.categoria || 'Producto';
      var extraProd = [s.capacidad, s.color].filter(Boolean).join(' ');
      html += '<span style="font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1">' + escHtml(nombreProd) + (extraProd ? ' ' + escHtml(extraProd) : '') + '</span>';
      html += '<span style="color:' + color + ';font-weight:700;flex-shrink:0">' + s.unidades + '/' + (s.stockMin||0) + '</span></div>';
    });
    html += '</div>';
  } else {
    html += '<div class="empty" style="padding:12px;font-size:12px">✅ Stock OK</div>';
  }
  box.innerHTML = html;
}

function renderWidgetRepsEstado() {
  var box = document.getElementById('repsEstadoBox');
  if (!box) return;
  var estados = {Pendiente:0, 'En Proceso':0, 'Por Entregar':0, Garantia:0, 'Sin Solucion':0};
  DB.reps.forEach(function(r) {
    if (r.estado === 'Entregado' || r.estado === 'Rechazado') return;
    if (estados[r.estado] === undefined) estados[r.estado] = 0;
    estados[r.estado]++;
  });
  var total = 0;
  Object.keys(estados).forEach(function(k){ total += estados[k]; });
  if (total === 0) {
    box.innerHTML = '<div class="empty" style="padding:12px;font-size:12px">' + T('gen.sin_reps_activas') + '</div>';
    return;
  }
  var colores = {Pendiente:'#F97316', 'En Proceso':'#FF5B1F', 'Por Entregar':'#00C896', Garantia:'#FF5B1F', 'Sin Solucion':'#EF4444'};
  // Barra horizontal segmentada
  var html = '<div style="display:flex;height:32px;border-radius:8px;overflow:hidden;background:var(--light);margin-bottom:10px">';
  Object.keys(estados).forEach(function(k) {
    var v = estados[k];
    if (!v) return;
    var pct = (v / total) * 100;
    html += '<div style="background:' + colores[k] + ';width:' + pct + '%;display:flex;align-items:center;justify-content:center;color:white;font-size:11px;font-weight:700" title="' + k + ': ' + v + '">' + (pct > 12 ? v : '') + '</div>';
  });
  html += '</div>';
  // Leyenda
  html += '<div style="display:flex;flex-wrap:wrap;gap:8px;font-size:11px">';
  Object.keys(estados).forEach(function(k) {
    if (!estados[k]) return;
    html += '<div style="display:flex;align-items:center;gap:5px"><span style="width:10px;height:10px;border-radius:3px;background:' + colores[k] + '"></span><span style="font-weight:600">' + k + '</span><span style="color:var(--muted)">' + estados[k] + '</span></div>';
  });
  html += '</div>';
  box.innerHTML = html;
}

function renderWidgetTiempoMedio() {
  var box = document.getElementById('tiempoMedioBox');
  if (!box) return;
  var per = _periodoActivo();
  var card = document.getElementById('cardTiempoMedio');
  if (card) {
    var t = card.querySelector('.card-title');
    if (t) t.textContent = per.tab === 'hoy' ? T('dash.tiempo_medio') : per.tab === 'semana' ? T('dash.tiempo_medio_semana') : T('dash.tiempo_medio_mes');
  }
  var entregadas = DB.reps.filter(function(r) {
    if (r.estado !== 'Entregado' || !r.fecha || !r.fechaEntregaReal) return false;
    var fr = _parseDateAny(r.fechaEntregaReal);
    return fr && fr >= per.inicio && fr <= per.fin;
  });
  if (!entregadas.length) {
    box.innerHTML = '<div class="empty" style="padding:12px;font-size:12px">' + T('gen.sin_reps_entregadas') + '</div>';
    return;
  }
  var totalMs = 0; var min = Infinity; var max = 0;
  entregadas.forEach(function(r) {
    var f1 = _parseDateAny(r.fecha);
    var f2 = _parseDateAny(r.fechaEntregaReal);
    if (f1 && f2) {
      var diff = f2 - f1;
      if (diff < 0) diff = 0;
      totalMs += diff;
      if (diff < min) min = diff;
      if (diff > max) max = diff;
    }
  });
  var medioDias = (totalMs / entregadas.length) / 86400000;
  var minDias = min / 86400000;
  var maxDias = max / 86400000;
  var fmt = function(d) { return d < 1 ? '<1d' : d.toFixed(1) + 'd'; };
  var html = '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px">';
  html += '<div style="background:var(--light);padding:10px;border-radius:8px;text-align:center;border-left:3px solid var(--green)">';
  html += '<div style="font-size:10px;color:var(--muted);font-weight:600">MÍNIMO</div>';
  html += '<div style="font-size:16px;font-weight:800;color:var(--green)">' + fmt(minDias) + '</div></div>';
  html += '<div style="background:var(--light);padding:10px;border-radius:8px;text-align:center;border-left:3px solid var(--blue)">';
  html += '<div style="font-size:10px;color:var(--muted);font-weight:600">MEDIA</div>';
  html += '<div style="font-size:16px;font-weight:800;color:var(--blue)">' + fmt(medioDias) + '</div></div>';
  html += '<div style="background:var(--light);padding:10px;border-radius:8px;text-align:center;border-left:3px solid var(--orange)">';
  html += '<div style="font-size:10px;color:var(--muted);font-weight:600">MÁXIMO</div>';
  html += '<div style="font-size:16px;font-weight:800;color:var(--orange)">' + fmt(maxDias) + '</div></div>';
  html += '</div>';
  html += '<div style="text-align:center;font-size:11px;color:var(--muted);margin-top:8px">Basado en ' + entregadas.length + ' reparación(es) entregadas</div>';
  box.innerHTML = html;
}

function renderWidgetClisInactivos() {
  var box = document.getElementById('clisInactivosBox');
  if (!box) return;
  var hace3m = new Date(); hace3m.setMonth(hace3m.getMonth() - 3); hace3m.setHours(0,0,0,0);
  var lista = DB.clis.map(function(c) {
    var ultV = 0;
    DB.ventas.forEach(function(v) {
      if (v.clienteId !== c.id) return;
      var fv = _parseDateAny(v.fecha);
      if (fv && fv > ultV) ultV = fv;
    });
    var ultR = 0;
    DB.reps.forEach(function(r) {
      if (r.clienteId !== c.id) return;
      var fr = _parseDateAny(r.fecha);
      if (fr && fr > ultR) ultR = fr;
    });
    var ultima = Math.max(ultV, ultR);
    return {cli:c, ultima:ultima ? new Date(ultima) : null};
  }).filter(function(x) {
    return x.ultima && x.ultima < hace3m;
  }).sort(function(a,b){ return a.ultima - b.ultima; });

  if (!lista.length) {
    box.innerHTML = '<div class="empty" style="padding:12px;font-size:12px">' + T('gen.no_clientes_inactivos') + '</div>';
    return;
  }
  var html = '<div style="font-size:11px;color:var(--muted);margin-bottom:8px">' + lista.length + ' cliente(s) sin actividad en 3+ meses</div>';
  html += '<div style="display:flex;flex-direction:column;gap:6px">';
  lista.slice(0,5).forEach(function(it) {
    var meses = Math.round((Date.now() - it.ultima) / (86400000 * 30));
    html += '<div style="background:var(--light);border-left:3px solid var(--muted);padding:8px 10px;border-radius:6px;display:flex;justify-content:space-between;align-items:center;gap:8px">';
    html += '<div style="flex:1;min-width:0">';
    html += '<div style="font-weight:600;font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + (it.cli.nombre || '') + ' ' + (it.cli.apellidos || '') + '</div>';
    html += '<div style="font-size:10px;color:var(--muted)">Hace ' + meses + ' meses · ' + it.ultima.toLocaleDateString('es') + '</div>';
    html += '</div>';
    if (it.cli.tel) {
      var msg = encodeURIComponent(waMsg('saludar')(it.cli.nombre || '', TIENDA.nombre || 'la tienda'));
      html += '<a href="https://wa.me/' + waTel(it.cli.tel) + '?text=' + msg + '" target="_blank" rel="noopener noreferrer" class="btn-sm" style="background:#25D366;color:white;font-size:11px;padding:4px 10px;text-decoration:none">💬 Saludar</a>';
    }
    html += '</div>';
  });
  if (lista.length > 5) html += '<div style="text-align:center;font-size:11px;color:var(--muted);padding:4px">+' + (lista.length - 5) + ' más</div>';
  html += '</div>';
  box.innerHTML = html;
}

function setMetricTab(el) {
  document.querySelectorAll('#metricTabs .tab').forEach(function(t) { t.classList.remove('active'); });
  el.classList.add('active');
  // data-t es la CLAVE i18n ('dash.hoy'/'dash.semana'/'dash.mes'); renderDash espera el periodo
  // pelado ('hoy'/'semana'/'mes'). Sin el replace, el ternario caía siempre en 'mes'.
  SEL.metricTab = (el.dataset.t || '').replace('dash.', '');
  renderDash();
}

// S\u00edmbolo por moneda (LatAm + Europa). Las que no est\u00e9n en el mapa caen a su propio c\u00f3digo.
var CUR_SYM = {
  EUR:'\u20ac', USD:'$', GBP:'\u00a3',
  MXN:'$', ARS:'$', COP:'$', CLP:'$', UYU:'$', DOP:'$',
  PEN:'S/', BRL:'R$', BOB:'Bs', PYG:'\u20b2', GTQ:'Q', CRC:'\u20a1'
};
function curSym(m) { m = m || (AJUSTES && AJUSTES.moneda) || 'EUR'; return CUR_SYM[m] || (m + ' '); }
function cur(n) {
  return curSym(AJUSTES.moneda) + parseFloat(n).toFixed(2);
}

// Normalización para búsqueda: minúsculas + sin acentos (Martín → martin)
function _norm(s) {
  return String(s == null ? '' : s).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

// ═══ URGENTES ═══
function checkUrgentes() {
  var hoy = new Date(); hoy.setHours(0,0,0,0);
  var en2 = new Date(); en2.setDate(en2.getDate() + 2); en2.setHours(23,59,59,999);
  // Estados "cerrados" en minúsculas para comparar sin importar mayúsculas/acentos
  // de datos antiguos (el codebase tiene variantes como 'En proceso'/'Por entregar').
  var ESTADOS_CERRADOS = ['entregado','devuelto','rechazado','sin solucion','sin solución','presupuesto'];
  var urgentes = DB.reps.filter(function(r) {
    if (!r.fechaEntrega) return false;
    // Si tiene fecha de entrega REAL, ya se entregó (aunque el estado venga sucio) → fuera de urgentes
    if (r.fechaEntregaReal) return false;
    var est = (r.estado || '').toString().trim().toLowerCase();
    if (ESTADOS_CERRADOS.indexOf(est) >= 0) return false;
    var fe = new Date(r.fechaEntrega); fe.setHours(23,59,59,999);
    return fe >= hoy && fe <= en2;
  }).sort(function(a,b){ return new Date(a.fechaEntrega) - new Date(b.fechaEntrega); });
  var el = document.getElementById('urgentesBox');
  if (!urgentes.length) { el.innerHTML = '<div class="empty" style="padding:12px">'+T('dash.sin_urgencias')+'</div>'; return; }
  el.innerHTML = urgentes.map(function(r) {
    var fe = new Date(r.fechaEntrega); fe.setHours(0,0,0,0);
    var dias = Math.round((fe - hoy) / 86400000);
    var label = dias === 0 ? 'Hoy' : dias === 1 ? 'Ma\u00f1ana' : 'En ' + dias + ' d\u00edas';
    var color = dias === 0 ? 'var(--red)' : 'var(--orange)';
    return '<div class="urgent-card">' +
      '<strong>' + escHtml(r.clienteNombre) + '</strong> \u2014 ' + escHtml(r.marca) + ' ' + escHtml(r.modelo) +
      '<br><span style="color:' + color + ';font-size:11px;font-weight:700">\u23f0 ' + label + '</span>' +
      ' \u00b7 ' + escHtml(r.averia) + '</div>';
  }).join('');
}

// ═══ VENTAS ═══
// "Nueva venta" abre el TPV, que permite añadir y vender VARIOS productos en una
// misma venta (cliente, IVA, descuento, financiado) y guarda las líneas para la
// factura. Antes el modal mVenta solo dejaba 1 producto. El modal sigue disponible
// vía abrirVentaSimple() por si se quisiera el formulario rápido de 1 línea.
function abrirVenta() {
  if (typeof tienePerm === 'function' && !tienePerm('ventas_crear')) { toast(T('gen.sin_permiso'), 'err'); return; }
  window.location.href = 'tpv.html';
}

function abrirVentaSimple() {
  SEL.vStock = null; SEL.vCli = null;
  document.getElementById('vBusCli').value = '';
  document.getElementById('vBusStock').value = '';
  document.getElementById('vPrecio').value = '';
  document.getElementById('vDescuento').value = '0';
  document.getElementById('vTotal').textContent = cur(0);
  document.getElementById('vSelCliBox').classList.remove('show');
  document.getElementById('vSelStock').classList.remove('show');
  document.getElementById('vStockRes').classList.remove('open');
  document.getElementById('vSelCli').classList.remove('open');
  document.getElementById('finOpts').style.display = 'none';
  // Financiado es Pro/Premium: ocultar la opción del selector si el plan no la tiene
  var _vPago = document.getElementById('vPago');
  var _vFinOpt = document.getElementById('vPagoFinOpt');
  if (_vFinOpt) _vFinOpt.hidden = (typeof tieneFeature === 'function' && !tieneFeature('financiado'));
  if (_vPago && _vFinOpt && _vFinOpt.hidden && _vPago.value === 'Financiado') _vPago.value = 'Efectivo';
  // Reset IVA selector to default
  var ivaSelV = document.getElementById('vIva');
  if (ivaSelV) ivaSelV.value = String((AJUSTES.iva && AJUSTES.iva.tipoDefault != null) ? AJUSTES.iva.tipoDefault : 21);
  calcV();
  openM('mVenta');
  _DRAFT_VENTA.banner();
  _DRAFT_VENTA.start();
}

function calcV() {
  var p = parseFloat(document.getElementById('vPrecio').value) || 0;
  var d = parseFloat(document.getElementById('vDescuento').value) || 0;
  var subtotal = Math.max(0, p - d);
  var ivaSel = document.getElementById('vIva');
  var tipoIva = ivaSel ? parseFloat(ivaSel.value) : ((AJUSTES.iva && AJUSTES.iva.tipoDefault) || 0);
  var c = calcIVA(subtotal, tipoIva);
  // Mostrar/ocultar IVA según ajustes
  var on = !!(AJUSTES.iva && AJUSTES.iva.activo);
  var ivaRow = document.getElementById('vIvaRow');
  var baseRow = document.getElementById('vBaseRow');
  var ivaImpRow = document.getElementById('vIvaImpRow');
  if (ivaRow) ivaRow.style.display = on ? 'block' : 'none';
  if (baseRow) baseRow.style.display = on ? 'flex' : 'none';
  if (ivaImpRow) ivaImpRow.style.display = on ? 'flex' : 'none';
  if (on) {
    document.getElementById('vBase').textContent = cur(c.base);
    document.getElementById('vIvaImp').textContent = cur(c.iva);
    document.getElementById('vIvaImpLbl').textContent = 'IVA (' + c.tipo + '%)';
    var totalLbl = document.getElementById('vTotalLbl');
    if (totalLbl) totalLbl.textContent = c.modo === 'incluido' ? 'Total (IVA inc.)' : 'Total con IVA';
  } else {
    var lbl = document.getElementById('vTotalLbl');
    if (lbl) lbl.textContent = 'Total';
  }
  document.getElementById('vTotal').textContent = cur(c.total);
}

function guardarVenta() {
  if (!tienePerm('ventas_crear')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var precio = parseFloat(document.getElementById('vPrecio').value) || 0;
  if (precio <= 0) { toast('Introduce un precio', 'err'); return; }
  var pago = document.getElementById('vPago').value;
  var desc = parseFloat(document.getElementById('vDescuento').value) || 0;
  var subtotal = Math.max(0, precio - desc);
  var ivaSelV = document.getElementById('vIva');
  var tipoIvaV = ivaSelV ? parseFloat(ivaSelV.value) : ((AJUSTES.iva && AJUSTES.iva.tipoDefault) || 0);
  var calcV2 = calcIVA(subtotal, tipoIvaV);
  var total = calcV2.total;
  var esFinanciado = pago === 'Financiado';
  // Revalidar plan: financiar es de Pro/Premium (defensa por si se manipula el DOM)
  if (esFinanciado && typeof tieneFeature === 'function' && !tieneFeature('financiado')) {
    if (typeof checkFeature === 'function') checkFeature('financiado');
    return;
  }

  var cuotas = null;
  var entrada = 0;
  if (esFinanciado) {
    entrada = parseFloat(document.getElementById('vEntrada').value) || 0;
    if (entrada > 0 && !((document.getElementById('vEntradaPago') || {}).value || '')) {
      toast(T('tst.elige_pago_entrada'), 'err'); return;
    }
    var numCuotas = parseInt(document.getElementById('vNumCuotas').value) || 3;
    var diaPago = parseInt(document.getElementById('vDiaPago').value) || 8;
    // Cuotas redondeadas a 2 decimales; el residuo se mete en la última cuota
    // para que la suma de cuotas + entrada == total exactamente.
    var pendiente = Math.round((total - entrada) * 100) / 100;
    var montoCuota = Math.round((pendiente / numCuotas) * 100) / 100;
    cuotas = [];
    for (var i = 0; i < numCuotas; i++) {
      var fechaCuota = new Date();
      fechaCuota.setMonth(fechaCuota.getMonth() + i + 1);
      fechaCuota.setDate(diaPago);
      var importeCuota = montoCuota;
      if (i === numCuotas - 1) {
        // Última cuota: ajustar para que la suma cuadre exactamente
        importeCuota = Math.round((pendiente - montoCuota * (numCuotas - 1)) * 100) / 100;
      }
      cuotas.push({
        num: i + 1,
        importe: importeCuota,
        fecha: fechaCuota.toISOString().slice(0,10),
        pagado: false,
        formaPago: '',
        fechaPago: ''
      });
    }
  }

  var venta = {
    id: 'v' + Date.now() + '_' + Math.random().toString(36).slice(2,8),
    fecha: hoyLocal(),
    clienteId: SEL.vCli ? SEL.vCli.id : '',
    clienteNombre: SEL.vCli ? (SEL.vCli.nombre + ' ' + SEL.vCli.apellidos).trim() : T('gen.sin_cliente'),
    marca: SEL.vStock ? (SEL.vStock.marca || '') : '',
    modelo: SEL.vStock ? (SEL.vStock.modelo || '') : '',
    imei: SEL.vStock ? (SEL.vStock.imei || '') : '',
    pago: esFinanciado ? 'Financiado' : pago,
    precio: precio,
    descuento: desc,
    iva: (AJUSTES.iva && AJUSTES.iva.activo) ? tipoIvaV : 0,
    ivaModo: (AJUSTES.iva && AJUSTES.iva.activo) ? (AJUSTES.iva.modo || 'incluido') : 'sin',
    base: calcV2.base,
    ivaImporte: calcV2.iva,
    total: total,
    reembolsado: false,
    stockId: SEL.vStock && !SEL.vStock.esServicio ? SEL.vStock.id : '',
    financiado: esFinanciado,
    cuotas: cuotas,
    entrada: entrada,
    entradaPago: (esFinanciado && entrada > 0) ? ((document.getElementById('vEntradaPago') || {}).value || 'Efectivo') : null,
    items: [{ nombre: (((SEL.vStock ? ((SEL.vStock.marca || '') + ' ' + (SEL.vStock.modelo || '')) : '').trim()) || 'Venta'), qty: 1, precio: precio }]
  };

  // Reduce stock
  if (SEL.vStock && !SEL.vStock.esServicio) {
    var s = DB.stock.find(function(x) { return x.id === SEL.vStock.id; });
    if (s) {
      s.unidades = Math.max(0, s.unidades - 1);
      if (s.unidades === 0) s.vendido = true;
      _logMov('salida', _stockNombre(s), 1, (venta.clienteNombre || T('inicio.ventas')));
      // Sincronizar con Supabase para que no quede inconsistente
      if (SB_KEY && TIENDA_ID) {
        sbPatch('stock', 'id=eq.' + encodeURIComponent(s.id), {
          unidades: s.unidades,
          vendido: s.vendido
        });
      }
    }
  }

  DB.ventas.push(venta);
  guardarDatos();

  if (SB_KEY && TIENDA_ID) {
    sbPost('ventas', {
      id: venta.id, tienda_id: TIENDA_ID, fecha: venta.fecha,
      cliente_id: venta.clienteId, cliente_nombre: venta.clienteNombre,
      marca: venta.marca, modelo: venta.modelo, imei: venta.imei,
      pago: venta.pago, precio: venta.precio, descuento: venta.descuento,
      total: venta.total, stock_id: venta.stockId || null,
      reembolsado: false, financiado: venta.financiado,
      cuotas: cuotas ? JSON.stringify(cuotas) : null, entrada: entrada, entrada_pago: venta.entradaPago || null,
      iva: venta.iva, iva_modo: venta.ivaModo, base: venta.base, iva_importe: venta.ivaImporte,
      items: (venta.items && venta.items.length) ? JSON.stringify(venta.items) : null
    });
  }

  _DRAFT_VENTA.clear(); _DRAFT_VENTA.stop();
  closeM('mVenta');
  toast(T('gen.guardado'), 'ok');
  audit('crear', 'venta', venta.id, (venta.clienteNombre || 'Cliente puntual') + ' · ' + cur(venta.total), null);
  renderDash();
}

function setVentaFiltro(el) {
  document.querySelectorAll('#ventaTabs .tab').forEach(function(t) { t.classList.remove('active'); });
  el.classList.add('active');
  SEL.ventaFiltro = el.dataset.f;
  renderVentas();
}

// Helpers de visualización i18n para VALORES guardados en español (no se cambia el dato, solo su etiqueta).
// Nombre del método de pago por móvil configurado (Fase 2). El VALOR sigue siendo 'Bizum'
// (clave canónica, sin migrar datos); solo cambia la ETIQUETA que se muestra.
function _nombreMovil() {
  try { var c = (typeof TIENDA !== 'undefined' && TIENDA && TIENDA.cobroDatos) || {}; return (c.movil_nombre || '').trim() || 'Bizum'; } catch(e) { return 'Bizum'; }
}
function _aplicarNombreMovilUI() {
  var nm = _nombreMovil();
  try { Array.prototype.forEach.call(document.querySelectorAll('option'), function(o){ if ((o.value||'').toLowerCase() === 'bizum') o.textContent = nm; }); } catch(e){}
}
function _pagoLbl(p){ if (!p) return ''; if (String(p).toLowerCase() === 'bizum') return _nombreMovil(); var k = 'pago.' + String(p).toLowerCase(); var t = T(k); return (t && t !== k) ? t : p; }
function _cliLbl(n){ return (n === 'Sin cliente' || !n) ? T('gen.sin_cliente') : n; }
var _CAT_KEY = { 'Telefono':'cat_telefono','Tablet':'cat_tablet','Smartwatch':'cat_smartwatch','Pantalla':'cat_pantalla','Tapa':'cat_tapa','Bateria':'cat_bateria','Flex de Carga':'cat_flex','Altavoz':'cat_altavoz','Repuesto':'cat_repuesto','Accesorio':'cat_accesorio','Otro':'cat_otro' };
function _catLbl(c){ if (!c) return ''; var kk = _CAT_KEY[c]; if (!kk) return c; var t = T('stock.' + kk); return (t && t !== 'stock.' + kk) ? t : c; }

// ¿Es una venta financiada aún PENDIENTE (no completada ni reembolsada)?
function _esFinPendiente(v) {
  if (!v || !v.financiado || v.reembolsado) return false;
  if (v.estadoFinanciado === 'completado') return false;
  var c = v.cuotas || [];
  if (c.length > 0 && c.every(function(x){ return x.pagado; })) return false;
  return true;
}
function renderVentas() {
  var q = _norm(document.getElementById('busVentas').value);
  var filtro = SEL.ventaFiltro || 'todas';
  var list = DB.ventas.slice().reverse().filter(function(v) {
    var matchQ = !q || _norm(v.clienteNombre + ' ' + v.modelo + ' ' + (v.imei || '')).indexOf(q) !== -1;
    if (filtro === 'reembolsos') return matchQ && v.reembolsado;
    if (filtro === 'financiados') return matchQ && v.financiado;
    return matchQ && !v.reembolsado;
  });
  // Financiadas pendientes primero (lo accionable arriba); el sort estable conserva la recencia dentro de cada grupo.
  list.sort(function(a, b) { return (_esFinPendiente(a) ? 0 : 1) - (_esFinPendiente(b) ? 0 : 1); });
  var el = document.getElementById('listaVentas');
  if (!list.length) { el.innerHTML = '<div class="empty"><div class="empty-icon">📱</div>' + T('gen.sin_registros') + '</div>'; return; }
  var html = '<div class="tbl-wrap"><table class="tbl"><thead><tr><th>' + T('gen.fecha') + '</th><th>' + T('gen.cliente') + '</th><th>' + T('gen.modelo') + '</th><th>' + T('gen.pago') + '</th><th>' + T('gen.total') + '</th><th></th></tr></thead><tbody>';
  list.forEach(function(v) {
    var badges = '';
    if (v.reembolsado) badges += '<span class="badge-reem">' + T('ventas.reembolsado') + '</span>';
    if (v.financiado && !v.reembolsado) {
      var _cuoF = v.cuotas || [];
      var _nPagF = _cuoF.filter(function(c){ return c.pagado; }).length;
      var _compF = (v.estadoFinanciado === 'completado') || (_cuoF.length > 0 && _nPagF >= _cuoF.length);
      badges += '<span class="badge-fin" style="background:' + (_compF ? 'rgba(0,200,150,.15)' : 'rgba(234,88,12,.12)') + ';color:' + (_compF ? '#0F7355' : '#C2491A') + '">' + (_compF ? '✅ ' + T('fin.completado') : '⏳ ' + T('finv.pendiente') + (_cuoF.length ? ' ' + _nPagF + '/' + _cuoF.length : '')) + '</span>';
    }
    var btnR = !v.reembolsado ? '<button data-vid="' + v.id + '" data-action="del" class="row-btn btn-reem" title="Reembolsar">\u21a9</button>' : '';
    var btnF = v.financiado && !v.reembolsado ? '<button data-vid="' + v.id + '" data-action="edit" class="row-btn btn-fin" title="Financiación">\ud83d\udcb0</button>' : '';
    var btnImpr = '<button data-vid="' + v.id + '" class="row-btn btn-impr-v" title="Reimprimir ticket">\ud83d\udda8</button>';
    var btnFact = !v.reembolsado ? '<button data-vid="' + v.id + '" data-action="fact" class="row-btn btn-fact-v" title="Generar factura">📄</button>' : '';
    var btnEdit = (!v.reembolsado && (typeof _esAdmin === 'function' && _esAdmin())) ? '<button data-vid="' + v.id + '" class="row-btn btn-edit-v" title="Editar venta">✏️</button>' : '';
    html += '<tr style="' + (v.reembolsado ? 'opacity:.55' : '') + '">' +
      '<td>' + fmtFecha(v.fecha) + '</td>' +
      '<td>' + esc(_cliLbl(v.clienteNombre)) + badges + '</td>' +
      '<td>' + esc(v.modelo) + '</td>' +
      '<td><span class="badge bb">' + esc(_pagoLbl(v.pago)) + '</span></td>' +
      '<td style="color:' + (v.reembolsado ? 'var(--red)' : 'var(--green)') + ';font-weight:700">' + (v.reembolsado ? '-' : '') + cur(v.total) + '</td>' +
      '<td style="display:flex;gap:3px">' + btnR + btnF + btnFact + btnImpr + btnEdit + '</td></tr>';
  });
  html += '</tbody></table></div>';
  el.innerHTML = html;
  el.querySelectorAll('.btn-reem').forEach(function(btn) {
    btn.addEventListener('click', function() { reembolsarVenta(this.dataset.vid); });
  });
  el.querySelectorAll('.btn-fin').forEach(function(btn) {
    btn.addEventListener('click', function() { verFinanciado(this.dataset.vid); });
  });
  el.querySelectorAll('.btn-impr-v').forEach(function(btn) {
    btn.addEventListener('click', function() { imprimirTicketVenta(this.dataset.vid); });
  });
  el.querySelectorAll('.btn-fact-v').forEach(function(btn) {
    btn.addEventListener('click', function() { factVenta(this.dataset.vid); });
  });
  el.querySelectorAll('.btn-edit-v').forEach(function(btn) {
    btn.addEventListener('click', function() { abrirEditarVenta(this.dataset.vid); });
  });
}

// ═══ EDITAR VENTA (admin): cliente, concepto, pago, importe ═══
function _evFillCliDatalist() {
  var dl = document.getElementById('evCliList'); if (!dl) return;
  dl.innerHTML = (DB.clis || []).filter(function(c){ return c && c.nombre; }).slice(0,500).map(function(c){
    return '<option value="' + escHtml(((c.nombre||'') + (c.apellidos ? ' ' + c.apellidos : '')).trim()) + '">'; }).join('');
}
function abrirEditarVenta(id) {
  if (typeof _esAdmin === 'function' && !_esAdmin()) { toast(T('perm.solo_admin'), 'err'); return; }
  var v = (DB.ventas || []).find(function(x){ return x.id === id; });
  if (!v) { toast(T('tst.venta_no_encontrada'), 'err'); return; }
  if (v.reembolsado) { toast(T('ev.reembolsada_no'), 'err'); return; }
  SEL.editVentaId = id;
  _evFillCliDatalist();
  document.getElementById('evCliente').value = v.clienteNombre || '';
  document.getElementById('evModelo').value = v.modelo || '';
  var sel = document.getElementById('evPago');
  var metodos = ['efectivo','tarjeta','bizum','transferencia'];
  if (v.pago && metodos.indexOf(v.pago) === -1) metodos.push(v.pago);
  sel.innerHTML = metodos.map(function(m){ return '<option value="' + escHtml(m) + '">' + escHtml(_pagoLbl(m)) + '</option>'; }).join('');
  sel.value = v.pago || 'efectivo';
  document.getElementById('evDescuento').value = v.descuento || 0;
  document.getElementById('evTotal').value = v.total || 0;
  var fin = !!v.financiado;
  document.getElementById('evTotal').disabled = fin;
  document.getElementById('evDescuento').disabled = fin;
  var nota = document.getElementById('evNotaFin'); if (nota) nota.style.display = fin ? 'block' : 'none';
  openM('mEditarVenta');
}
function guardarEdicionVenta() {
  var v = (DB.ventas || []).find(function(x){ return x.id === SEL.editVentaId; });
  if (!v) return;
  var nom = (document.getElementById('evCliente').value || '').trim();
  v.clienteNombre = nom || T('gen.sin_cliente');
  var c = (DB.clis || []).find(function(x){ return (((x.nombre||'') + (x.apellidos ? ' ' + x.apellidos : '')).trim()) === nom; });
  v.clienteId = c ? c.id : (nom ? v.clienteId : null);
  v.modelo = (document.getElementById('evModelo').value || '').trim();
  v.pago = document.getElementById('evPago').value;
  if (!v.financiado) {
    var desc = parseFloat(document.getElementById('evDescuento').value) || 0;
    var total = parseFloat(document.getElementById('evTotal').value) || 0;
    var rate = parseFloat(v.iva) || 0;
    v.descuento = desc;
    v.total = total;
    v.base = rate > 0 ? Math.round((total / (1 + rate / 100)) * 100) / 100 : total;
    v.ivaImporte = Math.round((total - v.base) * 100) / 100;
    v.precio = Math.round((total + desc) * 100) / 100;
    if (v.items && v.items[0]) { v.items[0].nombre = v.modelo || v.items[0].nombre; v.items[0].precio = total; }
  } else if (v.items && v.items[0]) {
    v.items[0].nombre = v.modelo || v.items[0].nombre;
  }
  if (SB_KEY && TIENDA_ID) {
    sbPatch('ventas', 'id=eq.' + encodeURIComponent(v.id), {
      cliente_id: v.clienteId, cliente_nombre: v.clienteNombre, modelo: v.modelo,
      pago: v.pago, precio: v.precio, descuento: v.descuento, total: v.total,
      base: v.base, iva_importe: v.ivaImporte,
      items: (v.items && v.items.length) ? JSON.stringify(v.items) : null
    });
  }
  try { if (typeof audit === 'function') audit('editar', 'venta', v.id, (v.clienteNombre || '') + ' · ' + cur(v.total), null); } catch(e){}
  guardarDatos(); closeM('mEditarVenta'); renderVentas();
  try { renderInicioNuevo(); } catch(e){}
  toast(T('gen.guardado'), 'ok');
}

function imprimirTicketVenta(id) {
  var v = DB.ventas.find(function(x){ return x.id === id; });
  if (!v) { toast(T('gen.error'), 'err'); return; }
  var logoBlock = TIENDA.logo_url
    ? '<div style="text-align:center;margin-bottom:6px"><img src="' + esc(TIENDA.logo_url) + '" style="max-height:50px;max-width:200px;object-fit:contain"></div>'
    : '<div style="text-align:center;font-size:14px;font-weight:800;margin-bottom:4px">\u26a1 ' + esc(TIENDA.nombre || 'Tekpair') + '</div>';
  var nombreLinea = TIENDA.logo_url && TIENDA.nombre ? '<div style="text-align:center;font-size:13px;font-weight:700;margin-bottom:4px">' + esc(TIENDA.nombre) + '</div>' : '';
  var dirLinea = TIENDA.dir ? '<div style="text-align:center;font-size:10px;color:#666">' + esc(TIENDA.dir) + '</div>' : '';
  var telLinea = TIENDA.tel ? '<div style="text-align:center;font-size:10px;color:#666">Tel: ' + esc(TIENDA.tel) + '</div>' : '';
  var ivaOn = !!(v.iva && v.ivaModo && v.ivaModo !== 'sin');
  var items = (v.items && v.items.length) ? v.items : [{nombre: v.modelo || 'Venta', precio: v.precio || v.total, qty: 1}];
  var itemsHtml = items.map(function(it) {
    var sub = (parseFloat(it.precio) || 0) * (parseFloat(it.qty) || 1);
    return '<div style="display:flex;justify-content:space-between;font-size:11px;margin:2px 0"><span>' + esc(it.nombre) + ' x' + (it.qty || 1) + '</span><span>' + cur(sub) + '</span></div>';
  }).join('');

  var html = '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Ticket ' + v.id + '</title>' +
    '<style>@page{size:80mm auto;margin:0}body{font-family:-apple-system,Helvetica,Arial,sans-serif;width:80mm;margin:0;padding:5mm 4mm;color:#000;font-size:10.5px;line-height:1.35}hr{border:none;border-top:1px dashed #999;margin:6px 0}</style>' +
    '</head><body>' +
    logoBlock + nombreLinea + dirLinea + telLinea +
    '<hr>' +
    '<div style="display:flex;justify-content:space-between"><span>Fecha:</span><strong>' + fmtFecha(v.fecha) + '</strong></div>' +
    '<div style="display:flex;justify-content:space-between"><span>Cliente:</span><strong>' + esc(v.clienteNombre || T('gen.sin_cliente')) + '</strong></div>' +
    '<div style="display:flex;justify-content:space-between"><span>Pago:</span><strong>' + esc(v.pago) + '</strong></div>' +
    (v.reembolsado ? '<div style="text-align:center;color:#c00;font-weight:800;margin-top:4px;border:1.5px solid #c00;padding:3px">REEMBOLSADA</div>' : '') +
    '<hr>' +
    itemsHtml +
    '<hr>' +
    (v.descuento > 0 ? '<div style="display:flex;justify-content:space-between"><span><span data-t="tpv.subtotal">Subtotal</span></span><span>' + cur(v.precio || 0) + '</span></div>' +
      '<div style="display:flex;justify-content:space-between"><span><span data-t="tpv.descuento">Descuento</span></span><span>-' + cur(v.descuento) + '</span></div>' : '') +
    (ivaOn ?
      '<div style="display:flex;justify-content:space-between"><span>Base imponible</span><span>' + cur(v.base || 0) + '</span></div>' +
      '<div style="display:flex;justify-content:space-between"><span>IVA (' + v.iva + '%)</span><span>' + cur(v.ivaImporte || 0) + '</span></div>'
      : '') +
    '<div style="display:flex;justify-content:space-between;font-size:13px;font-weight:800;margin-top:4px;border-top:1px solid #000;padding-top:4px"><span>TOTAL' + (v.ivaModo === 'incluido' ? ' (IVA inc.)' : '') + '</span><span>' + cur(v.total || 0) + '</span></div>' +
    '<hr>' +
    '<div style="text-align:center;font-size:10px;color:#666;margin-top:6px">Gracias por su compra</div>' +
    (TIENDA.garVenActiva !== false && TIENDA.garantiaVentas ? '<div style="text-align:center;font-size:9px;color:#666;margin-top:6px;line-height:1.4">' + esc(TIENDA.garantiaVentas) + '</div>' : '') +
    (TIENDA.politicaVentas ? '<div style="text-align:center;font-size:9px;color:#888;margin-top:4px;line-height:1.4">' + esc(TIENDA.politicaVentas) + '</div>' : '') +
    '<div style="text-align:center;font-size:9px;color:#888;margin-top:8px;border-top:1px dashed #ccc;padding-top:4px">Generado por TekPair &middot; tekpair.tech</div>' +
    '<script>window.onload=function(){setTimeout(function(){window.print();},200);}<\/script>' +
    '</body></html>';

  if (typeof tkIsDesktop === 'function' && tkIsDesktop() && typeof tkPrintTicket === 'function') {
    tkPrintTicket(html, 80, function () { _docPopupImprimir(html, 380, 600); });
    return;
  }
  _docPopupImprimir(html, 380, 600);
}

// ── Modales in-app que reemplazan confirm()/prompt() nativos (feos y que bloquean el navegador automatizado) ──
function _modalOverlay(inner) {
  var bg = document.createElement('div');
  bg.style.cssText = 'position:fixed;inset:0;background:rgba(2,11,46,.65);backdrop-filter:blur(6px);-webkit-backdrop-filter:blur(6px);z-index:2147483600;display:flex;align-items:center;justify-content:center;padding:16px;font-family:inherit';
  var box = document.createElement('div');
  box.style.cssText = 'background:var(--white,#fff);color:var(--text,#0F1729);border-radius:16px;padding:20px;max-width:380px;width:100%;box-shadow:0 16px 50px rgba(0,0,0,.4)';
  box.innerHTML = inner;
  bg.appendChild(box);
  document.body.appendChild(bg);
  return { bg: bg, box: box, close: function () { try { document.body.removeChild(bg); } catch (e) {} } };
}
// Confirmación sí/no. Llama onYes() si confirma y devuelve Promise<bool>.
function confirmar(msg, onYes, opts) {
  opts = opts || {};
  return new Promise(function (resolve) {
    var m = _modalOverlay(
      '<div style="font-size:14.5px;line-height:1.5;white-space:pre-line;margin-bottom:18px">' + escHtml(String(msg)) + '</div>' +
      '<div style="display:flex;gap:10px;justify-content:flex-end">' +
        '<button id="_cfNo" style="padding:9px 16px;border:1px solid var(--border,#E5E7EB);background:transparent;color:var(--text,#334155);border-radius:9px;cursor:pointer;font:inherit;font-weight:600">' + (opts.cancelLabel || 'Cancelar') + '</button>' +
        '<button id="_cfYes" style="padding:9px 16px;border:none;background:' + (opts.danger ? '#EF4444' : 'var(--green,#10B981)') + ';color:#fff;border-radius:9px;cursor:pointer;font:inherit;font-weight:700">' + (opts.okLabel || 'Confirmar') + '</button>' +
      '</div>'
    );
    function fin(val) { m.close(); if (val && typeof onYes === 'function') onYes(); resolve(val); }
    m.box.querySelector('#_cfYes').onclick = function () { fin(true); };
    m.box.querySelector('#_cfNo').onclick = function () { fin(false); };
    m.bg.addEventListener('click', function (e) { if (e.target === m.bg) fin(false); });
  });
}
window.confirmar = confirmar;
// Selector de forma de pago (reemplaza el prompt "1.Efectivo 2.Tarjeta..."). onPick recibe el método o null.
function pedirMetodoPago(onPick, titulo) {
  var METODOS = [['Efectivo', '💵'], ['Tarjeta', '💳'], ['Bizum', '📲'], ['Transferencia', '🏦']];
  var btns = METODOS.map(function (mt) {
    return '<button data-m="' + mt[0] + '" style="display:flex;align-items:center;gap:10px;width:100%;padding:13px 14px;margin-bottom:8px;border:1px solid var(--border,#E5E7EB);background:var(--light,#F8FAFC);color:inherit;border-radius:10px;cursor:pointer;font:inherit;font-size:14px;font-weight:600;text-align:left">' + mt[1] + ' ' + mt[0] + '</button>';
  }).join('');
  var m = _modalOverlay(
    '<div style="font-size:15px;font-weight:800;margin-bottom:14px">' + escHtml(titulo || '¿Cómo se ha pagado?') + '</div>' + btns +
    '<button id="_mpCancel" style="width:100%;padding:9px;border:none;background:transparent;color:var(--muted,#94A3B8);cursor:pointer;font:inherit">Cancelar</button>'
  );
  function fin(val) { m.close(); if (typeof onPick === 'function') onPick(val); }
  m.box.querySelectorAll('[data-m]').forEach(function (b) { b.onclick = function () { fin(b.getAttribute('data-m')); }; });
  m.box.querySelector('#_mpCancel').onclick = function () { fin(null); };
  m.bg.addEventListener('click', function (e) { if (e.target === m.bg) fin(null); });
}
window.pedirMetodoPago = pedirMetodoPago;
// Input numérico (reemplaza prompt() de importes). onOk recibe el texto o null si cancela.
function pedirImporte(msg, defaultVal, onOk) {
  var m = _modalOverlay(
    '<div style="font-size:14.5px;line-height:1.5;white-space:pre-line;margin-bottom:12px">' + escHtml(String(msg)) + '</div>' +
    '<input id="_piInput" type="number" step="0.01" inputmode="decimal" value="' + escHtml(String(defaultVal == null ? '' : defaultVal)) + '" style="width:100%;padding:11px;border:1px solid var(--border,#E5E7EB);border-radius:9px;font:inherit;font-size:16px;margin-bottom:16px;color:inherit;background:var(--light,#fff)">' +
    '<div style="display:flex;gap:10px;justify-content:flex-end">' +
      '<button id="_piNo" style="padding:9px 16px;border:1px solid var(--border,#E5E7EB);background:transparent;color:var(--text,#334155);border-radius:9px;cursor:pointer;font:inherit;font-weight:600">Cancelar</button>' +
      '<button id="_piYes" style="padding:9px 16px;border:none;background:var(--green,#10B981);color:#fff;border-radius:9px;cursor:pointer;font:inherit;font-weight:700">Aceptar</button>' +
    '</div>'
  );
  var inp = m.box.querySelector('#_piInput');
  try { inp.focus(); inp.select(); } catch (e) {}
  function fin(val) { m.close(); if (typeof onOk === 'function') onOk(val); }
  m.box.querySelector('#_piYes').onclick = function () { fin(inp.value); };
  m.box.querySelector('#_piNo').onclick = function () { fin(null); };
  inp.addEventListener('keydown', function (e) { if (e.key === 'Enter') fin(inp.value); });
  m.bg.addEventListener('click', function (e) { if (e.target === m.bg) fin(null); });
}
window.pedirImporte = pedirImporte;

// Modal de texto multilínea (p.ej. pegar varios IMEIs). onOk recibe el texto, o null si cancela.
function pedirTexto(msg, opts, onOk) {
  opts = opts || {};
  var m = _modalOverlay(
    '<div style="font-size:14.5px;line-height:1.5;white-space:pre-line;margin-bottom:12px">' + escHtml(String(msg)) + '</div>' +
    '<textarea id="_ptArea" rows="' + (opts.rows || 4) + '" placeholder="' + escHtml(opts.placeholder || '') + '" style="width:100%;padding:10px;border:1px solid var(--border,#E5E7EB);border-radius:9px;font:inherit;font-size:13px;resize:vertical;color:inherit;background:var(--light,#fff)"></textarea>' +
    '<div style="display:flex;gap:10px;justify-content:flex-end;margin-top:14px">' +
      '<button id="_ptNo" style="padding:9px 16px;border:1px solid var(--border,#E5E7EB);background:transparent;color:var(--text,#334155);border-radius:9px;cursor:pointer;font:inherit;font-weight:600">' + (opts.cancelLabel || 'Cancelar') + '</button>' +
      '<button id="_ptYes" style="padding:9px 16px;border:none;background:var(--green,#10B981);color:#fff;border-radius:9px;cursor:pointer;font:inherit;font-weight:700">' + (opts.okLabel || 'Aceptar') + '</button>' +
    '</div>'
  );
  var ta = m.box.querySelector('#_ptArea');
  setTimeout(function () { try { ta.focus(); } catch (e) {} }, 50);
  function fin(val) { m.close(); if (typeof onOk === 'function') onOk(val); }
  m.box.querySelector('#_ptYes').onclick = function () { fin(ta.value); };
  m.box.querySelector('#_ptNo').onclick = function () { fin(null); };
  m.bg.addEventListener('click', function (e) { if (e.target === m.bg) fin(null); });
}
window.pedirTexto = pedirTexto;
function _pedBtnLbl(k){var L=(typeof TEKPAIR_LANG!=="undefined"?TEKPAIR_LANG:"es");var M={imei:{es:"Registrar IMEIs",en:"Register IMEIs",fr:"Enregistrer les IMEI",it:"Registra IMEI",de:"IMEIs erfassen",pt:"Registar IMEIs"},stock:{es:"Sumar al stock",en:"Add to stock",fr:"Ajouter au stock",it:"Aggiungi al magazzino",de:"Zum Lager hinzufügen",pt:"Adicionar ao stock"},recibir:{es:"Recibir",en:"Receive",fr:"Recevoir",it:"Ricevi",de:"Empfangen",pt:"Receber"}};return (M[k]&&M[k][L])||(M[k]&&M[k].es)||"";}

// Marca un pedido como recibido (estado + fecha + gasto + sync). No toca el stock.
function _finalizarRecibido(p) {
  p.estado = 'recibido';
  p.fecha_recibido = hoyLocal();
  var patch = { estado: 'recibido' };
  if (SB_KEY && typeof _sbPatchRaw === 'function') { try { _sbPatchRaw('pedidos', 'id=eq.' + encodeURIComponent(p.id), { fecha_recibido: p.fecha_recibido }); } catch (e) {} }
  var gid = _gastoAlRecibir(p); if (gid) { p.gasto_id = gid; patch.gasto_id = gid; }
  if (SB_KEY) sbPatch('pedidos', 'id=eq.' + encodeURIComponent(p.id), patch);
}

// F207 (bulk): procesa una lista de pedidos a recibir de uno en uno, encadenando MODALES
// (en vez de prompt()/confirm() nativos que bloqueaban la automatización). Recursivo asíncrono.
function _procesarRecibirLista(lista, idx, ctr, onDone) {
  if (idx >= lista.length) {
    try { guardarDatos(); } catch (e) {}
    renderPedidosWidget(); try { renderStock(); } catch (e) {}
    if (onDone) onDone(ctr);
    return;
  }
  var p = lista[idx];
  var next = function () { _procesarRecibirLista(lista, idx + 1, ctr, onDone); };
  var uds = parseInt(p.cantidad, 10) || 1;
  var existe = _stockMatch(p.pieza);
  if (existe && p.calidad && (existe.calidad || '') !== p.calidad) existe = null;
  var cat = p.categoria || (existe ? existe.categoria : '');
  if (_esImeiCat(cat)) {
    pedirTexto((T('pedidos.imeis_prompt') || 'IMEIs de "{pieza}" ({n} uds), uno por línea:').replace('{pieza}', p.pieza || '').replace('{n}', uds),
      { rows: 4, placeholder: '356789012345678\n356789012345679', okLabel: _pedBtnLbl('imei') },
      function (raw) {
        if (raw == null) { ctr.saltados++; return next(); }
        var imeis = String(raw).split(/[\s,;]+/).map(function (s) { return s.trim(); }).filter(Boolean).filter(function (x, i, a) { return a.indexOf(x) === i; }).slice(0, 50);
        if (!imeis.length) { ctr.saltados++; return next(); }
        if (imeis.length !== uds) {
          confirmar((T('pedidos.imeis_descuadre') || 'Has puesto {a} IMEI(s) pero el pedido es de {b} ud. Se registrarán solo {a} en stock. ¿Continuar?').replace(/{a}/g, imeis.length).replace('{b}', uds), null, { okLabel: 'Continuar' })
            .then(function (ok) { if (ok) { _recibirImeisDePedido(p, imeis, cat); _finalizarRecibido(p); ctr.recibidos++; } else { ctr.saltados++; } next(); });
        } else {
          _recibirImeisDePedido(p, imeis, cat); _finalizarRecibido(p); ctr.recibidos++; next();
        }
      });
  } else {
    _recibirAStock(p, uds, existe, true, cat);
    _finalizarRecibido(p);
    ctr.recibidos++;
    next();
  }
}

function reembolsarVenta(id) {
  if (!tienePerm('ventas_reembolso')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var v = DB.ventas.find(function(x) { return x.id === id; });
  if (!v) return;
  confirmar('Reembolsar venta de ' + v.clienteNombre + ' por ' + cur(v.total) + '?', function () {
  tpWithBusy(T('venta.reembolsando') || 'Reembolsando…', function () {
  if (typeof audit === 'function') audit('reembolso', 'venta', v.id, (v.clienteNombre || '') + ' · ' + cur(v.total) + ' · ' + ((v.marca || '') + ' ' + (v.modelo || '')).trim(), null);
  v.reembolsado = true;
  v.fechaReembolso = hoyLocal();
  // Devolver el artículo al stock. Por stockId; si no (ventas antiguas sin stock_id guardado),
  // buscar por IMEI (los móviles tienen IMEI único).
  // F48: devolver artículo(s) al stock. Las ventas del TPV son multi-producto (v.items con el id
  // de stock por línea, igual que se descontó en cobrar()); las viejas del panel eran de un solo
  // artículo (v.stockId / v.imei). Antes solo se restauraba el modo single → el TPV perdía stock.
  function _restaurarStock(sid, qty, imei) {
    var st = sid ? DB.stock.find(function(x) { return x.id === sid; }) : null;
    if (!st && imei) st = DB.stock.find(function(x) { return (x.imei || '') && (x.imei || '') === imei; });
    if (!st) return false;
    st.unidades = (st.unidades || 0) + (parseInt(qty, 10) || 1);
    if (st.unidades > 0 && st.vendido) st.vendido = false;
    if (SB_KEY && TIENDA_ID) {
      sbPatch('stock', 'id=eq.' + encodeURIComponent(st.id), { unidades: st.unidades, vendido: st.vendido });
    }
    return true;
  }
  var _items = Array.isArray(v.items) ? v.items : [];
  var _rest = 0;
  _items.forEach(function(it) {
    if (it.esServicio || it.esRapida || it.esFijo) return; // servicios/rápidas no tocan stock
    if (_restaurarStock(it.id, it.qty, it.imei)) _rest++;
  });
  // Fallback: venta de un solo artículo sin items, o si ningún item casó con el stock
  if (!_rest && !_restaurarStock(v.stockId, 1, v.imei)) {
    toast('Venta reembolsada. Revisa el stock manualmente (no se encontró el artículo original)', 'err', 5000);
  }
  guardarDatos();
  if (SB_KEY && TIENDA_ID) sbPatch('ventas', 'id=eq.' + id, {reembolsado: true, fecha_reembolso: v.fechaReembolso});
  toast(T('venta.reembolsada'), 'ok');
  renderVentas();
  renderDash();
  // F49: el reembolso también debe refrescar el Inicio nuevo (ingresos/caja del día) y avisos,
  // que antes quedaban con cifras viejas porque solo se re-renderizaba renderDash (clásico).
  try { if (typeof renderInicioNuevo === 'function') renderInicioNuevo(); } catch (e) {}
  try { if (typeof checkUrgentes === 'function') checkUrgentes(); } catch (e) {}
  }).then(function () {
    // F50/F51: si la venta tenía factura emitida, ofrecer emitir la rectificativa (abono).
    // Fuera del spinner: abre su propio modal de confirmación.
    _ofrecerAbonoPorVenta(id);
  });
  }, { okLabel: 'Reembolsar', danger: true });
}

// F50/F51: tras reembolsar una venta con factura emitida (y no abonada aún), ofrecer emitir
// su rectificativa (abono). La factura original se conserva por ley; el abono la anula.
function _ofrecerAbonoPorVenta(ventaId) {
  if (typeof window.emitirAbonoFactura !== 'function' || !SB_KEY || !TIENDA_ID) return;
  var url = SUPABASE_URL + '/rest/v1/facturas?tienda_id=eq.' + encodeURIComponent(TIENDA_ID) +
    '&origen_tipo=eq.venta&origen_id=eq.' + encodeURIComponent(ventaId) + '&select=*';
  fetch(url, { headers: { apikey: SB_KEY, Authorization: 'Bearer ' + (JWT_TOKEN || SB_KEY) } })
    .then(function(r) { return r.ok ? r.json() : []; })
    .then(function(arr) {
      arr = Array.isArray(arr) ? arr : [];
      var orig = arr.find(function(x) { return !x.rectifica_a && x.estado === 'emitida'; });
      if (!orig) return;
      if (arr.some(function(x) { return x.rectifica_a === orig.id; })) return; // ya abonada
      confirmar(T('fact.abono_confirm').replace('{num}', orig.numero || '').replace('{total}', cur(orig.total)), function() {
        window.emitirAbonoFactura(orig);
      }, { okLabel: 'Emitir abono', danger: true });
    }).catch(function() {});
}

// ═══ FINANCIADOS ═══
function verFinanciado(id) {
  var v = DB.ventas.find(function(x) { return x.id === id; });
  if (!v || !v.cuotas) return;
  var pagado = v.cuotas.reduce(function(a, c) { return a + _cuotaPagado(c); }, 0);
  var pendiente = v.total - pagado - (v.entrada || 0);
  var totalCobrado = pagado + (v.entrada || 0);
  var html = '<div class="modal-title">💰 ' + T('finv.titulo') + '</div>' +
    '<div style="font-size:13px;margin-bottom:10px"><strong>' + escHtml(v.clienteNombre || '') + '</strong>' + (v.modelo ? ' · ' + escHtml(v.modelo) : '') +
      '<div style="font-size:11px;color:var(--muted)">' + T('det.total') + ': ' + cur(v.total) + (v.entrada ? ' · ' + T('finv.entrada') + ': ' + cur(v.entrada) : '') + '</div></div>' +
    '<div style="display:flex;gap:8px;margin-bottom:14px">' +
      '<div style="flex:1;background:rgba(0,200,150,.10);border:1px solid rgba(0,200,150,.3);border-radius:10px;padding:10px 12px">' +
        '<div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.4px;color:#0F7355">✅ ' + T('finv.cobrado') + '</div>' +
        '<div style="font-size:19px;font-weight:800;color:#0F7355">' + cur(totalCobrado) + '</div></div>' +
      '<div style="flex:1;background:rgba(234,88,12,.08);border:1px solid rgba(234,88,12,.25);border-radius:10px;padding:10px 12px">' +
        '<div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.4px;color:#C2491A">⏳ ' + T('finv.pendiente') + '</div>' +
        '<div style="font-size:19px;font-weight:800;color:#C2491A">' + cur(pendiente) + '</div></div>' +
    '</div>';
  function _finCuotaRow(cu, i) {
    var vencido = !cu.pagado && cu.fecha && String(cu.fecha).slice(0, 10) < hoyLocal();
    var pag = _cuotaPagado(cu);
    var parcial = pag > 0.005 && !cu.pagado;
    var subPag = cu.pagado ? (' · ' + T('finv.pagado_con') + ' ' + escHtml(cu.formaPago || ''))
      : (parcial ? ' · ' + T('fin.parcial').replace('{p}', cur(pag)).replace('{q}', cur(Math.round(((parseFloat(cu.importe) || 0) - pag) * 100) / 100)) : (vencido ? ' · ' + T('finv.vencida') : ''));
    return '<div style="display:flex;align-items:center;justify-content:space-between;padding:10px;border-radius:8px;margin-bottom:6px;background:' +
      (cu.pagado ? 'rgba(0,200,150,.08)' : parcial ? 'rgba(230,148,18,.10)' : vencido ? 'rgba(239,68,68,.08)' : 'var(--light)') + '">' +
      '<div><div style="font-size:13px;font-weight:600">' + T('finv.cuota') + ' ' + (i + 1) + ' · ' + cur(cu.importe) + '</div>' +
      '<div style="font-size:10px;color:' + (vencido ? 'var(--red)' : 'var(--muted)') + '">' + T('finv.vence') + ': ' + escHtml(cu.fecha || '') + subPag + '</div></div>' +
      '<div>' + (cu.pagado
        ? '<span style="color:var(--green);font-size:11px;font-weight:700">✓ ' + T('finv.pagado') + '</span>'
        : '<button data-vid="' + id + '" data-cidx="' + i + '" class="btn-pc btn-primary" style="padding:5px 10px;font-size:11px;width:auto">' + (parcial ? T('fin.completar') : T('finv.registrar')) + '</button>'
      ) + '</div></div>';
  }
  var _pendR = '', _cobrR = '', _nP = 0, _nC = 0;
  v.cuotas.forEach(function(cu, i) { if (cu.pagado) { _cobrR += _finCuotaRow(cu, i); _nC++; } else { _pendR += _finCuotaRow(cu, i); _nP++; } });
  if (_nP) html += '<div style="font-size:11px;font-weight:800;color:#C2491A;text-transform:uppercase;letter-spacing:.4px;margin:4px 0 8px">⏳ ' + T('finv.pendientes') + ' (' + _nP + ')</div>' + _pendR;
  if (v.entrada || _nC) {
    html += '<div style="font-size:11px;font-weight:800;color:#0F7355;text-transform:uppercase;letter-spacing:.4px;margin:14px 0 8px">✅ ' + T('finv.cobrado') + (_nC ? ' (' + _nC + ')' : '') + '</div>';
    if (v.entrada) html += '<div style="display:flex;align-items:center;justify-content:space-between;padding:10px;border-radius:8px;margin-bottom:6px;background:rgba(0,200,150,.08)"><div style="font-size:13px;font-weight:600">' + T('finv.entrada') + ' · ' + cur(v.entrada) + '</div><span style="color:var(--green);font-size:11px;font-weight:700">✓</span></div>';
    html += _cobrR;
  }
  if (v.estadoFinanciado !== 'completado' && tienePerm('ventas_editar')) {
    html += '<button class="btn-secondary" style="margin-top:12px;border-color:var(--orange);color:var(--orange-d,#C2491A)" onclick="editarTotalFinanciado(\'' + id + '\')">✏️ ' + T('fin.editar_total') + '</button>';
  }
  html += '<button class="btn-secondary" style="margin-top:8px" onclick="closeM(&quot;finModal&quot;)">Cerrar</button>';
  document.getElementById('finModalContent').innerHTML = html;
  openM('finModal');
  document.getElementById('finModalContent').querySelectorAll('.btn-pc').forEach(function(btn) {
    btn.addEventListener('click', function() { registrarPagoCuota(this.dataset.vid, parseInt(this.dataset.cidx)); });
  });
}

// #43: editar el importe de una venta financiada (antes solo Reembolsar+rehacer).
// Guardrail: el nuevo total nunca puede ser menor que lo ya cobrado (entrada + cuotas pagadas).
function editarTotalFinanciado(vid) {
  var v = DB.ventas.find(function(x){ return x.id === vid; });
  if (!v || !v.cuotas) return;
  if (!tienePerm('ventas_editar')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var cobrado = (parseFloat(v.entrada) || 0) + v.cuotas.reduce(function(a, c){ return a + _cuotaPagado(c); }, 0);
  cobrado = Math.round(cobrado * 100) / 100;
  var pendientes = v.cuotas.filter(function(c){ return !c.pagado; });
  pedirTexto(T('fin.nuevo_total').replace('{c}', cur(cobrado)), { rows: 1, placeholder: String(v.total || 0), okLabel: T('gen.guardar') }, function(val) {
    if (val === null) return;
    var nuevo = parseFloat(String(val).replace(',', '.'));
    if (!isFinite(nuevo) || nuevo <= 0) { toast(T('fin.total_invalido'), 'err'); return; }
    nuevo = Math.round(nuevo * 100) / 100;
    if (nuevo < cobrado) { toast(T('fin.min_cobrado').replace('{c}', cur(cobrado)), 'err'); return; }
    if (!pendientes.length && nuevo !== cobrado) { toast(T('fin.todas_pagadas'), 'err'); return; }
    // Redistribuir el pendiente entre las cuotas NO pagadas (las pagadas no se tocan).
    var nuevoPendiente = Math.round((nuevo - cobrado) * 100) / 100;
    if (pendientes.length) {
      var per = Math.floor((nuevoPendiente / pendientes.length) * 100) / 100;
      var acum = 0, k = 0;
      v.cuotas.forEach(function(c){
        if (c.pagado) return;
        k++;
        if (k === pendientes.length) { c.importe = Math.round((nuevoPendiente - acum) * 100) / 100; }
        else { c.importe = per; acum = Math.round((acum + per) * 100) / 100; }
      });
    }
    v.total = nuevo;
    // Recalcular base/IVA desde el nuevo total para que la factura cuadre.
    if (v.ivaModo && v.ivaModo !== 'sin' && (parseFloat(v.iva) || 0) > 0) {
      var rate = (parseFloat(v.iva) || 0) / 100;
      v.base = Math.round((nuevo / (1 + rate)) * 100) / 100;
      v.ivaImporte = Math.round((nuevo - v.base) * 100) / 100;
    } else { v.base = nuevo; v.ivaImporte = 0; }
    if (v.cuotas.every(function(c){ return c.pagado; })) v.estadoFinanciado = 'completado';
    guardarDatos();
    if (SB_KEY && TIENDA_ID) sbPatch('ventas', 'id=eq.' + vid, { total: v.total, base: v.base, iva_importe: v.ivaImporte, cuotas: JSON.stringify(v.cuotas), estado_financiado: v.estadoFinanciado || 'activo' });
    audit('editar', 'venta', vid, '', null);
    toast(T('fin.editado'), 'ok');
    closeM('finModal');
    verFinanciado(vid);
    try { renderVentas(); renderDash(); } catch (e) {}
  });
}

function registrarPagoCuota(vid, cidx) {
  var v = DB.ventas.find(function(x) { return x.id === vid; });
  if (!v || !v.cuotas || !v.cuotas[cidx]) return;
  var c = v.cuotas[cidx];
  var imp = parseFloat(c.importe) || 0;
  var yaPag = _cuotaPagado(c);
  var queda = Math.round((imp - yaPag) * 100) / 100;
  if (queda <= 0.005) return;
  pedirImporte(T('fin.cuanto_paga').replace('{q}', cur(queda)), queda, function(val) {
    if (val === null) return;
    var pago = Math.round((parseFloat(String(val).replace(',', '.')) || 0) * 100) / 100;
    if (!(pago > 0)) { toast(T('fin.total_invalido'), 'err'); return; }
    if (pago > queda + 0.005) pago = queda;
    pedirMetodoPago(function (fp) {
      if (!fp) return;
      c.pagadoImporte = Math.round((yaPag + pago) * 100) / 100;
      c.formaPago = fp;
      c.fechaPago = hoyLocal();
      c.pagado = c.pagadoImporte >= imp - 0.005;
      if (v.cuotas.every(function(cc) { return cc.pagado; })) { v.estadoFinanciado = 'completado'; toast(T('tst.financiado_completado'), 'ok'); }
      guardarDatos();
      if (SB_KEY && TIENDA_ID) sbPatch('ventas', 'id=eq.' + vid, { cuotas: JSON.stringify(v.cuotas) });
      closeM('finModal');
      verFinanciado(vid);
      renderVentas();
    }, 'Cuota ' + (cidx + 1) + ' — ¿cómo se ha pagado?');
  });
}

// ═══ FINANCIADO EN REPARACIONES (mismo modelo que ventas) ═══
function verFinanciadoRep(id) {
  var r = DB.reps.find(function(x) { return x.id === id; });
  if (!r || !r.cuotas) { toast(T('gen.error'), 'err'); return; }
  var pagado = r.cuotas.reduce(function(a, c) { return a + _cuotaPagado(c); }, 0);
  var pendiente = Math.max(0, Math.round(((r.total || 0) - (r.entrada || 0) - pagado) * 100) / 100);
  var html = '<div class="modal-title">💰 Financiado</div>' +
    '<div style="background:var(--light);border-radius:10px;padding:12px;margin-bottom:14px;font-size:13px">' +
    '<strong>' + esc(r.clienteNombre) + '</strong> — ' + esc(r.marca) + ' ' + esc(r.modelo) + '<br>' +
    '<span style="font-size:11px;color:var(--muted)">Total: ' + cur(r.total) + ' | Entrada: ' + cur(r.entrada || 0) + ' | Pagado: ' + cur(pagado) + ' | ' + T('rep.queda_deber') + ': ' + cur(pendiente) + '</span></div>' +
    '<div style="font-size:11px;font-weight:700;color:var(--muted);margin-bottom:8px">CUOTAS:</div>';
  r.cuotas.forEach(function(cu, i) {
    var vencido = !cu.pagado && cu.fecha && cu.fecha < hoyLocal();
    var pag = _cuotaPagado(cu);
    var parcial = pag > 0.005 && !cu.pagado;
    var subPag = cu.pagado ? (' | Pagado: ' + cu.formaPago)
      : (parcial ? ' · ' + T('fin.parcial').replace('{p}', cur(pag)).replace('{q}', cur(Math.round(((parseFloat(cu.importe) || 0) - pag) * 100) / 100)) : '');
    html += '<div style="display:flex;align-items:center;justify-content:space-between;padding:10px;border-radius:8px;margin-bottom:6px;background:' +
      (cu.pagado ? 'rgba(0,200,150,.08)' : parcial ? 'rgba(230,148,18,.10)' : vencido ? 'rgba(239,68,68,.08)' : 'var(--light)') + '">' +
      '<div><div style="font-size:13px;font-weight:600">Cuota ' + (i + 1) + ' — ' + cur(cu.importe) + '</div>' +
      '<div style="font-size:10px;color:var(--muted)">Vence: ' + (cu.fecha || '-') + subPag + '</div></div>' +
      '<div style="display:flex;gap:6px;align-items:center">' + (cu.pagado
        ? '<span style="color:var(--green);font-size:11px;font-weight:700">✓ Pagado</span>'
        : '<button data-rid="' + id + '" data-cidx="' + i + '" class="btn-lcr" title="' + T('cobro.enviar_link') + '" style="padding:5px 9px;font-size:12px;width:auto;border:1px solid var(--border);background:#fff;border-radius:7px;cursor:pointer">📤</button>' +
          '<button data-rid="' + id + '" data-cidx="' + i + '" class="btn-pcr btn-primary" style="padding:5px 10px;font-size:11px;width:auto">' + (parcial ? T('fin.completar') : 'Registrar') + '</button>'
      ) + '</div></div>';
  });
  html += '<button class="btn-secondary" style="margin-top:12px" onclick="closeM(&quot;finModal&quot;)">Cerrar</button>';
  document.getElementById('finModalContent').innerHTML = html;
  openM('finModal');
  document.getElementById('finModalContent').querySelectorAll('.btn-pcr').forEach(function(btn) {
    btn.addEventListener('click', function() { registrarPagoCuotaRep(this.dataset.rid, parseInt(this.dataset.cidx)); });
  });
  document.getElementById('finModalContent').querySelectorAll('.btn-lcr').forEach(function(btn) {
    btn.addEventListener('click', function() { enviarLinkCobro(this.dataset.rid, parseInt(this.dataset.cidx)); });
  });
}

function registrarPagoCuotaRep(rid, cidx) {
  var r = DB.reps.find(function(x) { return x.id === rid; });
  if (!r || !r.cuotas || !r.cuotas[cidx]) return;
  var c = r.cuotas[cidx];
  var imp = parseFloat(c.importe) || 0;
  var yaPag = _cuotaPagado(c);
  var queda = Math.round((imp - yaPag) * 100) / 100;
  if (queda <= 0.005) return;
  // Pago PARCIAL: preguntar cuánto paga ahora (por defecto lo que queda).
  pedirImporte(T('fin.cuanto_paga').replace('{q}', cur(queda)), queda, function(val) {
    if (val === null) return;
    var pago = Math.round((parseFloat(String(val).replace(',', '.')) || 0) * 100) / 100;
    if (!(pago > 0)) { toast(T('fin.total_invalido'), 'err'); return; }
    if (pago > queda + 0.005) pago = queda; // nunca más de lo que queda
    pedirMetodoPago(function (fp) {
      if (!fp) return;
      c.pagadoImporte = Math.round((yaPag + pago) * 100) / 100;
      c.formaPago = fp;
      c.fechaPago = hoyLocal();
      c.pagado = c.pagadoImporte >= imp - 0.005;
      var pagadoCuotas = r.cuotas.reduce(function(a, cc) { return a + _cuotaPagado(cc); }, 0);
      r.restante = Math.max(0, Math.round(((r.total || 0) - (r.entrada || 0) - pagadoCuotas) * 100) / 100);
      if (r.cuotas.every(function(cc) { return cc.pagado; })) { r.estadoFinanciado = 'completado'; r.restante = 0; toast(T('tst.financiado_completado'), 'ok'); }
      guardarDatos();
      if (SB_KEY && TIENDA_ID) {
        sbPatch('reparaciones', 'id=eq.' + rid, { cuotas: JSON.stringify(r.cuotas), restante: r.restante, estado_financiado: r.estadoFinanciado || 'activo' });
        // Cada pago (parcial o total) = un pago_reparacion propio (id único) → no machaca anteriores.
        sbPost('pagos_reparacion', { id: 'pg_cuo_' + rid + '_' + cidx + '_' + Date.now(), tienda_id: TIENDA_ID, reparacion_id: rid, fecha: hoyLocal(), importe: pago, metodo: fp, tipo: 'cuota' });
        window._pagosRepCache = null;
      }
      closeM('finModal');
      verFinanciadoRep(rid);
      renderReps();
      renderDash();
    }, 'Cuota ' + (cidx + 1) + ' — ¿cómo se ha pagado?');
  });
}

// ═══ FINANCIACIÓN · LINK DE COBRO (Modelo C) ═══
// Envía al cliente un link público para pagar la cuota por Bizum/IBAN/PayPal.
// El dinero va directo a la tienda; TekPair solo enlaza cliente y tienda.
function enviarLinkCobro(rid, cidx) {
  var r = DB.reps.find(function(x){ return x.id === rid; });
  if (!r || !r.cuotas || !r.cuotas[cidx]) return;
  var cd = (TIENDA && TIENDA.cobroDatos) || {};
  if (!cd.bizum_on && !cd.transfer_on && !cd.paypal_on) {
    toast(T('cobro.sin_datos'), 'err');
    if (typeof navTo === 'function') setTimeout(function(){ navTo('pTienda'); }, 800);
    return;
  }
  asegurarToken(r).then(function(token){
    var base = (location.origin && location.origin.indexOf('http') === 0) ? location.origin : 'https://www.tekpair.tech';
    var link = base + '/cobrar.html?id=' + encodeURIComponent(r.id) + '&t=' + encodeURIComponent(token) + '&n=' + cidx;
    var cu = r.cuotas[cidx];
    var cliente = (DB.clis || []).find(function(c){ return c.id === r.clienteId; });
    var nombre = (r.clienteNombre || '').trim().split(' ')[0] || '';
    var equipo = ((r.marca||'') + ' ' + (r.modelo||'')).trim();
    var tienda = (TIENDA && TIENDA.nombre) || 'TekPair';
    // Plantilla en español (Sprint 1). Multi-idioma editable = refinamiento posterior.
    var msg = '¡Hola ' + nombre + '! 👋\n\n' +
      'Tu cuota ' + (cidx + 1) + '/' + r.cuotas.length + ' de tu ' + equipo + ' vence el ' + (cu.fecha || '') + '.\n' +
      '💰 Importe: ' + cur(cu.importe) + '\n\n' +
      'Puedes pagarla cómodamente desde aquí:\n🔗 ' + link + '\n\n' +
      'Tienes Bizum, transferencia y otras opciones.\n\n— ' + tienda;
    var telRaw = cliente ? ((cliente.telPrefijo||'+34') + (cliente.tel||'')) : '';
    var telE164 = telRaw.replace(/[^0-9]/g, '');
    window._cobroLinkActual = link;
    var waUrl = 'https://wa.me/' + telE164 + '?text=' + encodeURIComponent(msg);
    var qrUrl = 'https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=' + encodeURIComponent(link);
    var html = '<div class="modal-title">📤 ' + T('cobro.enviar_titulo') + '</div>' +
      '<div style="font-size:12px;color:var(--muted);margin-bottom:12px">' + T('cobro.enviar_sub') + '</div>' +
      (telE164 ? '<a href="' + waUrl + '" target="_blank" rel="noopener" style="display:block;text-align:center;background:#25D366;color:#fff;margin-bottom:8px;text-decoration:none;padding:12px;border-radius:9px;font-weight:700">📲 WhatsApp</a>' : '<div style="font-size:11.5px;color:var(--muted);margin-bottom:8px">' + T('cobro.sin_tel') + '</div>') +
      '<button class="btn-secondary" style="width:100%;margin-bottom:10px" onclick="_copiarCobroLink()">📋 ' + T('cobro.copiar') + '</button>' +
      '<div style="text-align:center;margin:8px 0"><img src="' + qrUrl + '" alt="QR" style="width:170px;height:170px;border-radius:10px;border:1px solid var(--border)"><div style="font-size:11px;color:var(--muted);margin-top:4px">' + T('cobro.qr') + '</div></div>' +
      '<div style="word-break:break-all;font-size:11px;background:var(--light);border-radius:8px;padding:8px;color:var(--muted)">' + esc(link) + '</div>' +
      '<button class="btn-secondary" style="margin-top:12px;width:100%" onclick="closeM(\'mCobroLink\')">' + T('gen.cerrar') + '</button>';
    var cont = document.getElementById('cobroLinkContent');
    if (cont) { cont.innerHTML = html; openM('mCobroLink'); }
  });
}
function _copiarCobroLink() {
  var link = window._cobroLinkActual || '';
  try { navigator.clipboard.writeText(link).then(function(){ toast(T('cobro.copiado'), 'ok'); }); }
  catch (e) { toast(link, 'ok'); }
}

// ═══ FINANCIACIÓN · PARTE C — CONFIRMACIONES DE PAGO DEL DUEÑO ═══
// El cliente declaró un pago en /cobrar (payment_attempts). El dueño verifica su
// Bizum/banco y confirma (marca la cuota pagada) o rechaza.
var _COBRO_METODO_LBL = { bizum: 'Bizum', transferencia: 'Transferencia', paypal: 'PayPal', otro: 'Otro' };
function cargarConfirmacionesPend(cb) {
  if (!SB_KEY || !TIENDA_ID) { if (cb) cb(); return; }
  sbGet('payment_attempts', 'tienda_id=eq.' + encodeURIComponent(TIENDA_ID) + '&estado=eq.pendiente_confirmacion&order=created_at.desc').then(function(rows) {
    window._cobrosPend = Array.isArray(rows) ? rows : [];
    renderConfirmacionesPend();
    if (cb) cb();
  });
}
function renderConfirmacionesPend() {
  var box = document.getElementById('inv-cobros-pend');
  if (!box) return;
  if (!(U && (U.rol === 'admin' || (U.permisos && (U.permisos.todo || U.permisos.ventas_ver))))) { _inicioBuckets.cobros = 0; box.style.display = 'none'; try { renderInicioChips(); } catch (e) {} return; }
  var arr = window._cobrosPend || [];
  if (!arr.length) { _inicioBuckets.cobros = 0; box.style.display = 'none'; box.innerHTML = ''; try { renderInicioChips(); } catch (e) {} return; }
  var rows = arr.map(function(a) {
    var r = (DB.reps || []).find(function(x){ return x.id === a.reparacion_id; });
    var nom = r ? (r.clienteNombre || '') : '';
    var equipo = r ? ((r.marca || '') + ' ' + (r.modelo || '')).trim() : '';
    var met = _COBRO_METODO_LBL[a.metodo_declarado] || a.metodo_declarado || '';
    var sub = (T('cobro.cuota') + ' ' + ((a.cuota_idx | 0) + 1)) + (equipo ? ' · ' + esc(equipo) : '') + (a.comentario ? ' · “' + esc(a.comentario) + '”' : '');
    return '<div style="display:flex;align-items:center;gap:10px;padding:9px 10px;border-radius:8px;background:#fff;margin-bottom:6px">' +
      '<div style="min-width:0;flex:1"><div style="font-weight:700;font-size:13px">' + esc(nom || a.reparacion_id) + ' · ' + cur(a.importe || 0) + ' <span style="font-weight:600;color:var(--muted)">(' + esc(met) + ')</span></div>' +
      '<div style="font-size:11px;color:var(--muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + sub + '</div></div>' +
      '<button onclick="confirmarCobro(\'' + a.id + '\')" style="flex-shrink:0;border:none;background:var(--green,#16A34A);color:#fff;border-radius:7px;padding:6px 10px;font:inherit;font-size:12px;font-weight:700;cursor:pointer">✅ ' + T('cobro.confirmar') + '</button>' +
      '<button onclick="rechazarCobro(\'' + a.id + '\')" style="flex-shrink:0;border:1px solid var(--border);background:#fff;color:var(--ink2,#475569);border-radius:7px;padding:6px 10px;font:inherit;font-size:12px;font-weight:700;cursor:pointer">✕</button>' +
      '</div>';
  }).join('');
  box.innerHTML = '<div style="background:rgba(255,193,7,.08);border:1px solid rgba(255,193,7,.35);border-left:4px solid #E6A700;border-radius:12px;padding:14px 16px;margin-bottom:18px">' +
    '<div style="display:flex;align-items:center;gap:8px;margin-bottom:10px"><span style="font-size:16px">🔔</span><strong style="color:#9A6700;font-size:14px">' + arr.length + ' ' + T('cobro.pend_titulo') + '</strong></div>' +
    '<div>' + rows + '</div></div>';
  _inicioBuckets.cobros = arr.length;
  box.style.display = _inicioChipsOpen.cobros ? 'block' : 'none';
  try { renderInicioChips(); } catch (e) {}
  try { renderProximaAccion(); } catch (e) {}
}
function confirmarCobro(attemptId) {
  var a = (window._cobrosPend || []).find(function(x){ return x.id === attemptId; });
  if (!a) return;
  var r = (DB.reps || []).find(function(x){ return x.id === a.reparacion_id; });
  if (!r || !r.cuotas || !r.cuotas[a.cuota_idx]) { toast(T('gen.error'), 'err'); return; }
  var cidx = a.cuota_idx | 0;
  if (r.cuotas[cidx].pagado) { _resolverIntento(attemptId, 'confirmado'); toast(T('cobro.ya_pagada'), 'ok'); return; }
  var fp = _COBRO_METODO_LBL[a.metodo_declarado] || 'Otro';
  r.cuotas[cidx].pagado = true;
  r.cuotas[cidx].formaPago = fp;
  r.cuotas[cidx].fechaPago = hoyLocal();
  var pagadoCuotas = r.cuotas.reduce(function(acc, c){ return acc + _cuotaPagado(c); }, 0);
  r.restante = Math.max(0, Math.round(((r.total || 0) - (r.entrada || 0) - pagadoCuotas) * 100) / 100);
  if (r.cuotas.every(function(c){ return c.pagado; })) { r.estadoFinanciado = 'completado'; r.restante = 0; }
  guardarDatos();
  if (SB_KEY && TIENDA_ID) {
    sbPatch('reparaciones', 'id=eq.' + r.id, { cuotas: JSON.stringify(r.cuotas), restante: r.restante, estado_financiado: r.estadoFinanciado || 'activo' });
    sbPost('pagos_reparacion', { id: 'pg_cuo_' + r.id + '_' + cidx, tienda_id: TIENDA_ID, reparacion_id: r.id, fecha: hoyLocal(), importe: parseFloat(r.cuotas[cidx].importe) || 0, metodo: fp, tipo: 'cuota' });
    window._pagosRepCache = null;
  }
  _resolverIntento(attemptId, 'confirmado');
  toast(T('cobro.confirmado'), 'ok');
  try { renderReps(); } catch (e) {}
  try { renderInicioNuevo(); renderDash(); } catch (e) {}
}
function rechazarCobro(attemptId) {
  pedirTexto(T('cobro.motivo_rechazo'), { okLabel: T('cobro.rechazar_ok') }, function(motivo) {
    if (motivo === null) return; // cancelado (el cliente sigue pudiendo reintentar)
    _resolverIntento(attemptId, 'rechazado', (motivo || '').trim() || null);
    toast(T('cobro.rechazado'), 'ok');
  });
}
function _resolverIntento(attemptId, estado, motivo) {
  window._cobrosPend = (window._cobrosPend || []).filter(function(x){ return x.id !== attemptId; });
  renderConfirmacionesPend();
  if (SB_KEY && TIENDA_ID) {
    var patch = { estado: estado, resuelto_por: (U ? U.nombre : null), resuelto_at: new Date().toISOString() };
    if (motivo) patch.motivo_rechazo = motivo;
    sbPatch('payment_attempts', 'id=eq.' + encodeURIComponent(attemptId), patch);
  }
}

// ═══ COBRAR SALDO DE REPARACIÓN A DEBER (sin financiar) ═══
function cobrarSaldoRep(id) {
  var r = DB.reps.find(function(x) { return x.id === id; });
  if (!r) { toast(T('gen.error'), 'err'); return; }
  SEL.cobrarRepId = id;
  var resta = parseFloat(r.restante) || 0;
  document.getElementById('cobrarRepInfo').innerHTML =
    '<strong>' + esc(r.clienteNombre) + '</strong> — ' + esc(r.marca) + ' ' + esc(r.modelo) +
    '<br><br>' + T('rep.queda_deber') + ': <strong style="color:#F97316">' + cur(resta) + '</strong>';
  document.getElementById('cobrarRepImporte').value = resta.toFixed(2);
  document.getElementById('cobrarRepMetodo').value = 'Efectivo';
  openM('mCobrarRep');
}

function confirmarCobroRep() {
  var r = DB.reps.find(function(x) { return x.id === SEL.cobrarRepId; });
  if (!r) return;
  var imp = parseFloat(document.getElementById('cobrarRepImporte').value) || 0;
  if (imp <= 0) { toast('Importe inválido', 'err'); return; }
  // No permitir cobrar más de lo que se debe (evita inflar ingresos por encima del total)
  var _resta = parseFloat(r.restante) || 0;
  if (imp > _resta) imp = _resta;
  if (imp <= 0) { toast(T('tst.rep_saldada'), 'ok'); closeM('mCobrarRep'); return; }
  var met = document.getElementById('cobrarRepMetodo').value;
  r.restante = Math.max(0, Math.round(((parseFloat(r.restante) || 0) - imp) * 100) / 100);
  guardarDatos();
  if (SB_KEY && TIENDA_ID) {
    sbPatch('reparaciones', 'id=eq.' + r.id, { restante: r.restante });
    // El pago se registra en pagos_reparacion -> el ingreso del día entra solo (y va a Cobrum por el volcado).
    sbPost('pagos_reparacion', { id: 'pg' + Date.now() + '_' + Math.random().toString(36).slice(2, 8), tienda_id: TIENDA_ID, reparacion_id: r.id, fecha: hoyLocal(), importe: imp, metodo: met, tipo: 'parcial' });
    window._pagosRepCache = null;
  }
  closeM('mCobrarRep');
  toast(r.restante > 0 ? (T('rep.queda_deber') + ': ' + cur(r.restante)) : 'Saldado ✓', 'ok');
  renderReps();
  renderDash();
}

// ═══ BUSQUEDA CLIENTES ═══
function busCliCtx(ctx) {
  var inputId = ctx === 'v' ? 'vBusCli' : ctx === 'r' ? 'rBusCli' : 'fiado-busca-cli';
  var resId = ctx === 'v' ? 'vSelCli' : ctx === 'r' ? 'rSelCli' : 'fSelCli';
  var q = _norm(document.getElementById(inputId).value).trim();
  var res = document.getElementById(resId);
  if (!q) { res.classList.remove('open'); return; }

  // Calcular score: menor es mejor
  function scoreCli(c) {
    var nombre = _norm(c.nombre).trim();
    var apellidos = _norm(c.apellidos).trim();
    var nomCompleto = (nombre + ' ' + apellidos).trim();
    var tel = _norm(c.tel);
    var dni = _norm(c.dni);

    if (nombre === q) return 0;                              // 1. nombre exacto
    if (nomCompleto === q) return 1;                         // 2. nombre+apellidos exacto
    if (nombre.split(/\s+/).indexOf(q) !== -1) return 2;     // 3. q es palabra completa del nombre
    if (apellidos.split(/\s+/).indexOf(q) !== -1) return 3;  // 4. palabra completa del apellido
    if (nombre.startsWith(q)) return 4;                      // 5. nombre empieza por q
    if (apellidos.startsWith(q)) return 5;                   // 6. apellidos empieza por q
    if (tel === q || dni === q) return 6;                    // 7. tel/dni exacto
    if (tel.indexOf(q) !== -1 || dni.indexOf(q) !== -1) return 7; // 8. tel/dni contiene
    if (nomCompleto.indexOf(q) !== -1) return 8;             // 9. substring en nombre
    return 99;
  }

  var ranked = DB.clis
    .map(function(c){ return { c: c, s: scoreCli(c) }; })
    .filter(function(x){ return x.s < 99; })
    .sort(function(a, b){
      if (a.s !== b.s) return a.s - b.s;
      // Mismo score: alfabetico por nombre
      return (a.c.nombre || '').localeCompare(b.c.nombre || '');
    });

  res.innerHTML = '<div class="cli-item" style="font-size:11px;color:var(--blue);font-weight:700" onclick="openNuevoCliRapido(\'' + ctx + '\')">+ Crear nuevo cliente</div>' +
    ranked.slice(0, 10).map(function(x) {
      var c = x.c;
      return '<div class="cli-item" data-id="' + c.id + '" data-ctx="' + ctx + '">' +
        (c.nombre || '') + ' ' + (c.apellidos || '') + (c.tel ? ' \u00b7 ' + c.tel : '') + '</div>';
    }).join('');
  res.classList.add('open');
  res.querySelectorAll('[data-id]').forEach(function(el) {
    el.addEventListener('click', function() { selCli(this.dataset.id, this.dataset.ctx); });
  });
}

function selCli(id, ctx) {
  var c = DB.clis.find(function(x) { return x.id === id; });
  if (!c) return;
  if (ctx === 'f') {
    document.getElementById('fiado-busca-cli').value = '';
    document.getElementById('fSelCli').classList.remove('open');
    document.getElementById('fSelCliNom').textContent = (c.nombre + ' ' + (c.apellidos||'')).trim() + (c.tel ? ' · ' + c.tel : '');
    document.getElementById('fSelCliBox').style.display = 'flex';
    document.getElementById('fiado-cliente').value = (c.nombre + ' ' + (c.apellidos||'')).trim();
    document.getElementById('fiado-telefono').value = c.tel || '';
    return;
  }
  if (ctx === 'v') {
    SEL.vCli = c;
    document.getElementById('vBusCli').value = '';
    document.getElementById('vSelCli').classList.remove('open');
    document.getElementById('vSelCliNom').textContent = (c.nombre + ' ' + c.apellidos).trim() + (c.tel ? ' \u00b7 ' + c.tel : '');
    document.getElementById('vSelCliBox').classList.add('show');
  } else {
    SEL.rCli = c;
    document.getElementById('rBusCli').value = '';
    document.getElementById('rSelCli').classList.remove('open');
    document.getElementById('rSelCliNom').textContent = (c.nombre + ' ' + c.apellidos).trim() + (c.tel ? ' \u00b7 ' + c.tel : '');
    document.getElementById('rSelCliBox').classList.add('show');
    actualizarAvisoGarantia();
  }
}

function clearCli(ctx) {
  if (ctx === 'v') { SEL.vCli = null; document.getElementById('vSelCliBox').classList.remove('show'); }
  else {
    SEL.rCli = null;
    document.getElementById('rSelCliBox').classList.remove('show');
    var ga = document.getElementById('rGarantiaAlert');
    if (ga) ga.style.display = 'none';
  }
}

function actualizarAvisoGarantia() {
  var alert = document.getElementById('rGarantiaAlert');
  if (!alert) return;
  if (!SEL.rCli) { alert.style.display = 'none'; return; }
  var marca = document.getElementById('rMarca').value.trim();
  var modelo = document.getElementById('rModelo').value.trim();
  if (!marca && !modelo) { alert.style.display = 'none'; return; }
  var info = checkGarantia(SEL.rCli.id, marca, modelo, null, ((SEL.rCli.nombre || '') + ' ' + (SEL.rCli.apellidos || '')).trim());
  if (!info) { alert.style.display = 'none'; return; }
  var fechaPrev = info.rep.fechaEntregaReal;
  alert.innerHTML = '<strong style="color:var(--blue)">🛡️ ' + T('rep.en_garantia') + '</strong><br>' +
    '<span style="font-size:11px;color:var(--muted)">Reparación previa entregada el ' + fechaPrev + ' (' + info.dias + ' días). ' +
    'Le quedan ' + info.restantes + ' días de garantía. Avería previa: "' + esc(info.rep.averia || '') + '"</span>';
  alert.style.display = 'block';
}

function openNuevoCliRapido(ctx) {
  window._cliCtx = ctx;
  window._cliRapidoForzar = false; // F232: reset del bypass de "posible duplicado"
  // F227: pre-rellenar con lo que escribió el usuario en el buscador (nombre, o teléfono si parece)
  var inputId = ctx === 'v' ? 'vBusCli' : ctx === 'r' ? 'rBusCli' : 'fiado-busca-cli';
  var typed = ((document.getElementById(inputId) || {}).value || '').trim();
  var soloDig = typed.replace(/[\s+().-]/g, '');
  var pareceTel = !!typed && /^[+\d]/.test(typed) && soloDig.length >= 6 && /^\d+$/.test(soloDig);
  document.getElementById('ncNom').value = pareceTel ? '' : typed;
  document.getElementById('ncApe').value = '';
  document.getElementById('ncTel').value = pareceTel ? typed : '';
  var ncDni = document.getElementById('ncDni'); if(ncDni) ncDni.value = '';
  openM('mNuevoCli');
}

// F413: valida DNI/NIE español por la letra de control (mod-23). Devuelve true si es válido
// O si NO parece un DNI/NIE español (pasaporte/ID extranjero/CIF → no lo bloqueamos).
function _dniEspanolValido(dni) {
  var s = (dni || '').toUpperCase().replace(/[\s-]/g, '');
  var letras = 'TRWAGMYFPDXBNJZSQVHLCKE';
  // DNI: 8 dígitos + letra
  var mDni = /^(\d{8})([A-Z])$/.exec(s);
  if (mDni) return letras[parseInt(mDni[1], 10) % 23] === mDni[2];
  // NIE: X/Y/Z + 7 dígitos + letra
  var mNie = /^([XYZ])(\d{7})([A-Z])$/.exec(s);
  if (mNie) {
    var pref = { X: '0', Y: '1', Z: '2' }[mNie[1]];
    return letras[parseInt(pref + mNie[2], 10) % 23] === mNie[3];
  }
  return true; // no es un patrón DNI/NIE español → no validamos (CIF, pasaporte, etc.)
}

// F232: ¿ya existe un cliente con este teléfono o DNI?
function _clienteDuplicado(tel, dni) {
  var t = _norm(tel || ''), d = _norm(dni || '');
  if (!t && !d) return null;
  return (DB.clis || []).find(function(c){
    if (t && t.length >= 6 && _norm(c.tel || '') === t) return true;
    if (d && d.length >= 5 && _norm(c.dni || '') === d) return true;
    return false;
  }) || null;
}

function crearClienteRapido() {
  if (!_puedeAnadirCliente()) return;
  var nom = document.getElementById('ncNom').value.trim();
  if (!nom) { toast(T('tst.escribe_nombre'), 'err'); return; }
  var telV = document.getElementById('ncTel').value.trim();
  var dniV = document.getElementById('ncDni').value.trim();
  // F232: avisar de posible duplicado (salvo que el usuario ya haya decidido crear igualmente)
  if (!window._cliRapidoForzar) {
    var dup = _clienteDuplicado(telV, dniV);
    if (dup) {
      var coincide = (telV && _norm(dup.tel || '') === _norm(telV)) ? 'teléfono' : 'DNI/NIF';
      confirmar('Posible duplicado: ya existe «' + ((dup.nombre || '') + ' ' + (dup.apellidos || '')).trim() + '» con ese ' + coincide + '.\n\n¿Usar el cliente existente en vez de crear uno nuevo?',
        null, { okLabel: 'Usar el existente' }).then(function(ok){
          if (ok) { closeM('mNuevoCli'); selCli(dup.id, window._cliCtx || 'v'); }
          else { window._cliRapidoForzar = true; } // el siguiente «Crear» lo crea igualmente
        });
      return;
    }
  }
  var c = {
    id: 'c' + Date.now() + '_' + Math.random().toString(36).slice(2, 8),
    nombre: nom,
    apellidos: document.getElementById('ncApe').value.trim(),
    tel: telV,
    email: (document.getElementById('ncEmail')||{}).value ? document.getElementById('ncEmail').value.trim() : '',
    dni: dniV,
    direccion: (document.getElementById('ncDir')||{}).value ? document.getElementById('ncDir').value.trim() : '',
    fecha_nacimiento: (document.getElementById('ncNac')||{}).value || null
  };
  window._cliRapidoForzar = false;
  DB.clis.push(c);
  guardarDatos();
  if (SB_KEY && TIENDA_ID) sbPost('clientes', {id:c.id,tienda_id:TIENDA_ID,nombre:c.nombre,apellidos:c.apellidos,tel:c.tel,email:c.email,dni:c.dni,dir_fiscal:c.direccion,fecha_nac:c.fecha_nacimiento});
  closeM('mNuevoCli');
  selCli(c.id, window._cliCtx || 'v');
  toast(T('cli.creado'), 'ok');
}

// ═══ BUSQUEDA STOCK VENTA ═══
function busStockVenta() {
  var q = document.getElementById('vBusStock').value.toLowerCase();
  var res = document.getElementById('vStockRes');
  if (!q) { res.classList.remove('open'); return; }
  var matches = DB.stock.filter(function(s) {
    var esTel = s.categoria === 'Telefono' || s.categoria === 'Tablet' || s.categoria === 'Smartwatch' || !s.categoria;
    return esTel && s.unidades > 0 && (s.marca + ' ' + s.modelo + ' ' + (s.capacidad || '') + ' ' + (s.imei || '')).toLowerCase().includes(q);
  });
  var srvMatches = (DB.servicios || []).filter(function(s) {
    return (s.tipo === 'venta' || s.tipo === 'ambos') && s.nombre.toLowerCase().includes(q);
  });
  var html = matches.map(function(s) {
    return '<div class="cli-item" data-sid="' + s.id + '" data-type="stock">' +
      '<strong>' + s.marca + ' ' + s.modelo + '</strong>' + (s.capacidad ? ' ' + s.capacidad : '') + (s.color ? ' \u00b7 ' + s.color : '') +
      (s.imei ? '<br><span style="font-family:monospace;font-size:10px;color:var(--muted)">IMEI: ' + s.imei + '</span>' : '') +
      '<span style="float:right;color:var(--green);font-weight:700">' + cur(s.precioV) + '</span></div>';
  }).join('');
  html += srvMatches.map(function(s) {
    return '<div class="cli-item" data-sid="' + s.id + '" data-type="servicio" style="border-left:3px solid #E0531C">' +
      '<span style="font-size:9px;color:#E0531C;font-weight:700">SERVICIO</span><br>' +
      '<strong>' + s.nombre + '</strong>' +
      '<span style="float:right;color:#E0531C;font-weight:700">' + (s.precioFijo ? cur(s.precio || 0) : 'Variable') + '</span></div>';
  }).join('');
  res.innerHTML = html;
  if (matches.length || srvMatches.length) res.classList.add('open');
  else res.classList.remove('open');
  res.querySelectorAll('[data-sid]').forEach(function(el) {
    el.addEventListener('click', function() {
      if (this.dataset.type === 'servicio') selServicioVenta(this.dataset.sid);
      else selStockVenta(this.dataset.sid);
    });
  });
}

function selStockVenta(id) {
  var s = DB.stock.find(function(x) { return x.id === id; });
  if (!s) return;
  SEL.vStock = s;
  document.getElementById('vBusStock').value = '';
  document.getElementById('vStockRes').classList.remove('open');
  document.getElementById('vSelStockNom').textContent = s.marca + ' ' + s.modelo + (s.capacidad ? ' ' + s.capacidad : '');
  document.getElementById('vSelStockDet').textContent = (s.color || '') + (s.imei ? ' \u00b7 IMEI: ' + s.imei : '');
  document.getElementById('vSelStock').classList.add('show');
  document.getElementById('vPrecio').value = s.precioV;
  calcV();
}

function selServicioVenta(id) {
  var s = (DB.servicios || []).find(function(x) { return x.id === id; });
  if (!s) return;
  SEL.vStock = {id: s.id, marca: 'Servicio', modelo: s.nombre, precioV: s.precioFijo ? s.precio : 0, esServicio: true};
  document.getElementById('vBusStock').value = '';
  document.getElementById('vStockRes').classList.remove('open');
  document.getElementById('vSelStockNom').textContent = s.nombre;
  document.getElementById('vSelStockDet').textContent = 'Servicio \u00b7 ' + s.categoria;
  document.getElementById('vSelStock').classList.add('show');
  document.getElementById('vPrecio').value = s.precioFijo ? s.precio : '';
  calcV();
}

function limpiarSelStock() {
  SEL.vStock = null;
  document.getElementById('vSelStock').classList.remove('show');
  document.getElementById('vPrecio').value = '';
  calcV();
}

// ═══ REPARACIONES ═══


// patron_v1: modal del patron de bloqueo (canvas-like SVG)
var PATRON = { size: 3, path: [], drawing: false };

function patronCambiarSize(s) {
  PATRON.size = s;
  PATRON.path = [];
  document.querySelectorAll('.patron-size-btn').forEach(function(b){
    b.classList.toggle('on', parseInt(b.dataset.sz) === s);
  });
  patronRender();
  patronUpdSeq();
}

function patronCoords(idx) {
  // idx 1-based, devuelve {x,y} en el SVG 280x280
  var s = PATRON.size;
  var n = idx - 1;
  var col = n % s;
  var row = Math.floor(n / s);
  var pad = s === 3 ? 50 : 38;
  var step = s === 3 ? 90 : 68;
  return { x: pad + col * step, y: pad + row * step };
}

function patronPuntoEnPos(x, y) {
  // Devuelve indice 1-based si el (x,y) esta cerca de un punto
  var s = PATRON.size;
  var thresh = s === 3 ? 32 : 24;
  for (var i = 1; i <= s * s; i++) {
    var p = patronCoords(i);
    var dx = x - p.x, dy = y - p.y;
    if (Math.sqrt(dx*dx + dy*dy) < thresh) return i;
  }
  return 0;
}

function patronRender() {
  var svg = document.getElementById('patronSvg');
  if (!svg) return;
  var s = PATRON.size;
  var html = '';
  // Lineas entre puntos del path
  for (var i = 0; i < PATRON.path.length - 1; i++) {
    var a = patronCoords(PATRON.path[i]);
    var b = patronCoords(PATRON.path[i+1]);
    html += '<line x1="' + a.x + '" y1="' + a.y + '" x2="' + b.x + '" y2="' + b.y + '" stroke="#FF5B1F" stroke-width="3" stroke-linecap="round"/>';
  }
  // Linea actual de drag
  if (PATRON.drawing && PATRON.path.length > 0 && PATRON.dragX != null) {
    var last = patronCoords(PATRON.path[PATRON.path.length-1]);
    html += '<line x1="' + last.x + '" y1="' + last.y + '" x2="' + PATRON.dragX + '" y2="' + PATRON.dragY + '" stroke="#FF5B1F" stroke-width="2" stroke-linecap="round" opacity="0.5"/>';
  }
  // Puntos
  for (var j = 1; j <= s * s; j++) {
    var p = patronCoords(j);
    var idxInPath = PATRON.path.indexOf(j);
    var fill = idxInPath !== -1 ? '#FF5B1F' : '#475569';
    var rOuter = s === 3 ? 18 : 14;
    var rInner = s === 3 ? 7 : 5;
    html += '<circle cx="' + p.x + '" cy="' + p.y + '" r="' + rOuter + '" fill="none" stroke="' + fill + '" stroke-width="2" opacity="0.5"/>';
    html += '<circle cx="' + p.x + '" cy="' + p.y + '" r="' + rInner + '" fill="' + fill + '"/>';
    if (idxInPath !== -1) {
      html += '<text x="' + p.x + '" y="' + (p.y - rOuter - 4) + '" text-anchor="middle" fill="#94A3B8" font-size="10" font-family="monospace">' + (idxInPath + 1) + '</text>';
    }
  }
  svg.innerHTML = html;
}

function patronUpdSeq() {
  var el = document.getElementById('patronSeq');
  if (el) el.textContent = PATRON.path.length ? PATRON.path.join(' → ') : '(vacio)';
}

function patronEvento(e) {
  var svg = document.getElementById('patronSvg');
  if (!svg) return null;
  var rect = svg.getBoundingClientRect();
  var clientX = e.touches ? e.touches[0].clientX : e.clientX;
  var clientY = e.touches ? e.touches[0].clientY : e.clientY;
  var x = (clientX - rect.left) * (280 / rect.width);
  var y = (clientY - rect.top) * (280 / rect.height);
  return { x: x, y: y };
}

function patronStart(e) {
  e.preventDefault();
  var pos = patronEvento(e);
  if (!pos) return;
  PATRON.path = [];
  PATRON.drawing = true;
  var idx = patronPuntoEnPos(pos.x, pos.y);
  if (idx) PATRON.path.push(idx);
  PATRON.dragX = pos.x; PATRON.dragY = pos.y;
  patronRender();
  patronUpdSeq();
}

function patronMove(e) {
  if (!PATRON.drawing) return;
  e.preventDefault();
  var pos = patronEvento(e);
  if (!pos) return;
  var idx = patronPuntoEnPos(pos.x, pos.y);
  if (idx && PATRON.path.indexOf(idx) === -1) {
    PATRON.path.push(idx);
  }
  PATRON.dragX = pos.x; PATRON.dragY = pos.y;
  patronRender();
  patronUpdSeq();
}

function patronEnd(e) {
  if (!PATRON.drawing) return;
  PATRON.drawing = false;
  PATRON.dragX = null; PATRON.dragY = null;
  patronRender();
}

function patronLimpiar() {
  PATRON.path = [];
  patronRender();
  patronUpdSeq();
}

function patronGuardar() {
  if (PATRON.path.length < 2) {
    toast(T('tst.dibuja_puntos'), 'err');
    return;
  }
  var json = JSON.stringify({ size: PATRON.size, path: PATRON.path.slice() });
  var bv = document.getElementById('rBloqVal');
  if (bv) bv.value = json;
  closeM('mPatron');
  toast('Patron guardado', 'ok');
}

function patronAbrir() {
  // Si ya hay un patron guardado en rBloqVal, parsearlo
  var bv = document.getElementById('rBloqVal');
  PATRON.path = [];
  PATRON.size = 3;
  if (bv && bv.value) {
    try {
      var p = JSON.parse(bv.value);
      if (p && Array.isArray(p.path)) {
        PATRON.size = p.size || 3;
        PATRON.path = p.path.slice();
      }
    } catch(e) {}
  }
  document.querySelectorAll('.patron-size-btn').forEach(function(b){
    b.classList.toggle('on', parseInt(b.dataset.sz) === PATRON.size);
  });
  openM('mPatron');
  setTimeout(function(){
    patronRender();
    patronUpdSeq();
    var svg = document.getElementById('patronSvg');
    if (svg && !svg._patronBound) {
      svg._patronBound = true;
      svg.addEventListener('mousedown', patronStart);
      svg.addEventListener('mousemove', patronMove);
      svg.addEventListener('mouseup', patronEnd);
      svg.addEventListener('mouseleave', patronEnd);
      svg.addEventListener('touchstart', patronStart, {passive:false});
      svg.addEventListener('touchmove', patronMove, {passive:false});
      svg.addEventListener('touchend', patronEnd);
    }
  }, 100);
}

// Mini SVG del patron para mostrar en la tabla (~28x28px)
function patronMiniSvg(json) {
  if (!json) return '';
  var p;
  try { p = JSON.parse(json); } catch(e) { return ''; }
  if (!p || !Array.isArray(p.path) || p.path.length < 2) return '';
  var s = p.size || 3;
  var size = 32;
  var pad = 4;
  var step = (size - 2*pad) / (s - 1);
  function pos(idx) {
    var n = idx - 1;
    var col = n % s, row = Math.floor(n / s);
    return { x: pad + col*step, y: pad + row*step };
  }
  var svg = '<svg class="patron-mini" width="' + size + '" height="' + size + '" viewBox="0 0 ' + size + ' ' + size + '">';
  // Lineas
  for (var i = 0; i < p.path.length - 1; i++) {
    var a = pos(p.path[i]), b = pos(p.path[i+1]);
    svg += '<line x1="' + a.x + '" y1="' + a.y + '" x2="' + b.x + '" y2="' + b.y + '" stroke="#FF5B1F" stroke-width="1.5"/>';
  }
  // Puntos
  for (var j = 1; j <= s*s; j++) {
    var c = pos(j);
    var on = p.path.indexOf(j) !== -1;
    svg += '<circle cx="' + c.x + '" cy="' + c.y + '" r="1.6" fill="' + (on ? '#FF5B1F' : '#64748B') + '"/>';
  }
  svg += '</svg>';
  return svg;
}


// passcode_v1: gestion del campo de bloqueo segun tipo
function cambiarTipoBloq() {
  var tipo = document.getElementById('rTipoBloq').value;
  var input = document.getElementById('rBloqVal');
  var lbl = document.getElementById('rBloqLbl');
  if (!input || !lbl) return;
  if (!tipo) {
    input.disabled = true;
    input.value = '';
    input.required = false;
    input.placeholder = T('rep.ph_no_aplica');
    lbl.textContent = T('rep.codigo');
    input.readOnly = false; input.style.cursor = ''; input.onclick = null;
    return;
  }
  input.disabled = false;
  // F222: con bloqueo de PIN/Contraseña el código es obligatorio (si no, el técnico no
  // puede entrar al equipo). El Patrón se dibuja y Huella/FaceID se pide al recibir.
  input.required = (tipo === 'PIN' || tipo === 'Contrasena');
  if (tipo === 'PIN') {
    lbl.textContent = T('rep.bloq_pin');
    input.placeholder = T('rep.ph_pin');
    input.type = 'text';
    input.inputMode = 'numeric';
    input.readOnly = false; input.style.cursor = ''; input.onclick = null;
  } else if (tipo === 'Patron') {
    lbl.textContent = T('rep.bloq_patron_lbl');
    input.placeholder = T('rep.ph_patron');
    input.type = 'text';
    input.readOnly = true;
    input.style.cursor = 'pointer';
    input.onclick = patronAbrir;
    return;
  } else if (tipo === 'Contrasena') {
    lbl.textContent = T('rep.bloq_contrasena');
    input.placeholder = T('rep.ph_contrasena');
    input.type = 'text';
    input.inputMode = 'text';
    input.readOnly = false; input.style.cursor = ''; input.onclick = null;
  } else if (tipo === 'Huella') {
    lbl.textContent = T('rep.bloq_huella_lbl');
    input.placeholder = T('rep.ph_huella');
    input.type = 'text';
    input.inputMode = 'text';
    input.readOnly = false; input.style.cursor = ''; input.onclick = null;
  }
}

// ═══ DRAFT AUTOSAVE — modal Nueva Reparación (red de seguridad ante cierre/recarga) ═══
var _REP_DRAFT_KEY = 'tk_draft_rep';
var _repDraftTimer = null;

function _repDraftCampos() {
  var g = function(id){ var e = document.getElementById(id); return e ? e.value : ''; };
  var conds = [];
  document.querySelectorAll('#mRep .chk-btn.on').forEach(function(b){ if (b.dataset.cond) conds.push(b.dataset.cond); });
  var cli = SEL.rCli ? { id: SEL.rCli.id, nombre: ((SEL.rCli.nombre || '') + ' ' + (SEL.rCli.apellidos || '')).trim() } : null;
  return { marca: g('rMarca'), modelo: g('rModelo'), imei: g('rImei'), averia: g('rAveria'), nota: g('rNota'),
    tipoBloq: g('rTipoBloq'), bloqVal: g('rBloqVal'), prioridad: g('rPrioridad'), fechaEnt: g('rFechaEnt'),
    iva: g('rIva'), conds: conds, cli: cli, _ts: Date.now() };
}
function _repDraftVacio(d) {
  return !d || (!d.marca && !d.modelo && !d.imei && !d.averia && !d.nota && (!d.conds || !d.conds.length) && !d.cli);
}
function _repDraftGuardar() {
  var m = document.getElementById('mRep');
  if (!m || !m.classList.contains('open') || SEL.editRepId) return; // solo nuevas reps abiertas
  var d = _repDraftCampos();
  if (_repDraftVacio(d)) return; // no persistir borradores vacíos
  try { localStorage.setItem(_REP_DRAFT_KEY, JSON.stringify(d)); } catch (e) {}
}
function _repDraftHay() {
  try {
    var d = JSON.parse(localStorage.getItem(_REP_DRAFT_KEY) || 'null');
    if (_repDraftVacio(d)) return null;
    if (Date.now() - (d._ts || 0) > 86400000) { _repDraftBorrar(); return null; } // caduca a las 24h
    return d;
  } catch (e) { return null; }
}
function _repDraftBorrar() {
  try { localStorage.removeItem(_REP_DRAFT_KEY); } catch (e) {}
  var b = document.getElementById('repDraftBanner'); if (b) b.style.display = 'none';
}
function _repDraftBannerShow() {
  var b = document.getElementById('repDraftBanner'); if (!b) return;
  var d = _repDraftHay();
  if (!d) { b.style.display = 'none'; return; }
  var resumen = [d.marca, d.modelo].filter(Boolean).join(' ') || d.averia || '';
  var r = b.querySelector('.draft-resumen'); if (r) r.textContent = resumen ? ' · ' + resumen.slice(0, 40) : '';
  b.style.display = 'flex';
}
function _repDraftRestaurar() {
  var d = _repDraftHay(); if (!d) return;
  var s = function(id, v){ var e = document.getElementById(id); if (e) e.value = v || ''; };
  s('rMarca', d.marca); s('rModelo', d.modelo); s('rImei', d.imei); s('rAveria', d.averia); s('rNota', d.nota);
  s('rTipoBloq', d.tipoBloq); if (typeof cambiarTipoBloq === 'function') cambiarTipoBloq(); s('rBloqVal', d.bloqVal);
  s('rPrioridad', d.prioridad); s('rFechaEnt', d.fechaEnt); s('rIva', d.iva);
  (d.conds || []).forEach(function(c){
    var sel = '#mRep .chk-btn[data-cond="' + c.replace(/"/g, '\\"') + '"]';
    var btn = document.querySelector(sel); if (btn) btn.classList.add('on');
  });
  if (d.cli && d.cli.id && DB.clis.some(function(x){ return x.id === d.cli.id; })) {
    try { selCli(d.cli.id, 'r'); } catch (e) {}
  }
  try { calcR(); } catch (e) {}
  try { actualizarAvisoGarantia(); } catch (e) {}
  _repDraftBorrar();
  toast(T('draft.recuperado'), 'ok');
}
// Arranca/para el autosave (cada 2s) según el modal esté abierto
function _repDraftStartAutosave() {
  if (_repDraftTimer) clearInterval(_repDraftTimer);
  _repDraftTimer = setInterval(_repDraftGuardar, 2000);
}
function _repDraftStopAutosave() {
  if (_repDraftTimer) { clearInterval(_repDraftTimer); _repDraftTimer = null; }
}

// ═══ Factory genérico de draft-autosave (reutilizado por Venta y Cliente) ═══
function _makeDraft(opts) {
  var KEY = opts.key, timer = null;
  function _open(){ var m = document.getElementById(opts.modalId); return m && m.classList.contains('open'); }
  function save(){
    if (!_open() || (opts.skip && opts.skip())) return;
    var d = opts.get(); d._ts = Date.now();
    if (opts.empty(d)) return;
    try { localStorage.setItem(KEY, JSON.stringify(d)); } catch (e) {}
  }
  function read(){
    try { var d = JSON.parse(localStorage.getItem(KEY) || 'null'); if (!d || opts.empty(d)) return null; if (Date.now() - (d._ts || 0) > 86400000) { clear(); return null; } return d; } catch (e) { return null; }
  }
  function clear(){ try { localStorage.removeItem(KEY); } catch (e) {} var b = document.getElementById(opts.bannerId); if (b) b.style.display = 'none'; }
  function banner(){ var b = document.getElementById(opts.bannerId); if (!b) return; var d = read(); if (!d) { b.style.display = 'none'; return; } var r = b.querySelector('.draft-resumen'); if (r) r.textContent = opts.resumen ? opts.resumen(d) : ''; b.style.display = 'flex'; }
  function restore(){ var d = read(); if (!d) return; opts.set(d); clear(); toast(T('draft.recuperado'), 'ok'); }
  function start(){ if (timer) clearInterval(timer); timer = setInterval(save, 2000); }
  function stop(){ if (timer) { clearInterval(timer); timer = null; } }
  return { save: save, read: read, clear: clear, banner: banner, restore: restore, start: start, stop: stop };
}

var _DRAFT_VENTA = _makeDraft({
  key: 'tk_draft_venta', modalId: 'mVenta', bannerId: 'ventaDraftBanner',
  empty: function(d){ return !(parseFloat(d.precio) > 0) && !d.cli && !d.busStock; },
  get: function(){
    var g = function(id){ var e = document.getElementById(id); return e ? e.value : ''; };
    return { precio: g('vPrecio'), descuento: g('vDescuento'), pago: g('vPago'), iva: g('vIva'),
      busStock: g('vBusStock'), stockId: SEL.vStock ? SEL.vStock.id : null, cli: SEL.vCli ? { id: SEL.vCli.id } : null };
  },
  set: function(d){
    var s = function(id, v){ var e = document.getElementById(id); if (e) e.value = v || ''; };
    if (d.cli && d.cli.id && DB.clis.some(function(x){ return x.id === d.cli.id; })) { try { selCli(d.cli.id, 'v'); } catch (e) {} }
    if (d.stockId && DB.stock.some(function(x){ return x.id === d.stockId; }) && typeof selStock === 'function') { try { selStock(d.stockId); } catch (e) {} }
    s('vPrecio', d.precio); s('vDescuento', d.descuento); s('vPago', d.pago); s('vIva', d.iva);
    if (!d.stockId) s('vBusStock', d.busStock);
    try { calcV(); } catch (e) {}
  },
  resumen: function(d){ return d.busStock ? ' · ' + d.busStock.slice(0, 30) : (parseFloat(d.precio) > 0 ? ' · ' + cur(parseFloat(d.precio)) : ''); }
});

var _DRAFT_CLI = _makeDraft({
  key: 'tk_draft_cli', modalId: 'mCli', bannerId: 'cliDraftBanner',
  skip: function(){ return !!ECID; }, // no autoguardar al EDITAR un cliente existente
  empty: function(d){ return !d.nom && !d.ape && !d.razon && !d.tel && !d.email && !d.dni; },
  get: function(){
    var g = function(id){ var e = document.getElementById(id); return e ? e.value : ''; };
    var ck = function(id){ var e = document.getElementById(id); return e ? !!e.checked : false; };
    return { esEmp: ck('cEsEmpresa'), nom: g('cNom'), ape: g('cApe'), razon: g('cRazon'), persona: g('cPersonaCont'),
      telPref: g('cTelPref'), tel: g('cTel'), email: g('cEmail'), dni: g('cDni'), dir: g('cDir'),
      cp: g('cCp'), ciudad: g('cCiudad'), prov: g('cProv'), pais: g('cPais'), fnac: g('cFnac') };
  },
  set: function(d){
    var s = function(id, v){ var e = document.getElementById(id); if (e) e.value = v || ''; };
    var cb = document.getElementById('cEsEmpresa'); if (cb) { cb.checked = !!d.esEmp; if (typeof toggleCliEmpresa === 'function') toggleCliEmpresa(); }
    s('cNom', d.nom); s('cApe', d.ape); s('cRazon', d.razon); s('cPersonaCont', d.persona);
    s('cTelPref', d.telPref); s('cTel', d.tel); s('cEmail', d.email); s('cDni', d.dni); s('cDir', d.dir);
    s('cCp', d.cp); s('cCiudad', d.ciudad); s('cProv', d.prov); s('cPais', d.pais); s('cFnac', d.fnac);
  },
  resumen: function(d){ var n = (d.esEmp ? d.razon : ((d.nom || '') + ' ' + (d.ape || '')).trim()) || d.tel || ''; return n ? ' · ' + n.slice(0, 30) : ''; }
});
function _ventaDraftRestaurar(){ _DRAFT_VENTA.restore(); }
function _ventaDraftBorrar(){ _DRAFT_VENTA.clear(); }
function _cliDraftRestaurar(){ _DRAFT_CLI.restore(); }
function _cliDraftBorrar(){ _DRAFT_CLI.clear(); }

function abrirRep() {
  SEL.editRepId = null; SEL.rCli = null; SEL.selParts = []; SEL.rServicios = []; SEL.fotosRecepcion = [];
  var _ft = document.getElementById('repFotosRecepThumbs'); if (_ft) _ft.innerHTML = '';
  var t = document.querySelector('#mRep .modal-title'); if (t) t.textContent = T('rep.titulo_nuevo');
  var _bg = document.getElementById('btnGuardarRepTxt'); if (_bg) _bg.textContent = T('rep.crear_orden');
  ['rBusCli','rMarca','rModelo','rImei','rAveria','rNota','rSrvBus','rBloqVal'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.value = '';
  });
  try { sugerirPiezasRep(); } catch(e){}
  if (typeof resetPagosRep === 'function') resetPagosRep();
  document.getElementById('rSelCliBox').classList.remove('show');
  document.getElementById('rSelCli').classList.remove('open');
  var ga = document.getElementById('rGarantiaAlert'); if (ga) ga.style.display = 'none';
  document.getElementById('partsList').innerHTML = '';
  document.getElementById('rTotal').textContent = cur(0);
  document.getElementById('rRestante').textContent = cur(0);
  var _antiRow = document.getElementById('rAnticipoRow'); if (_antiRow) _antiRow.style.display = 'none';
  // Reset financiación a plazos (solo Pro/Premium)
  var _finWrap = document.getElementById('rFinanciarWrap'); if (_finWrap) _finWrap.style.display = (typeof tieneFeature === 'function' && !tieneFeature('financiado')) ? 'none' : '';
  var _fin = document.getElementById('rFinanciar'); if (_fin) _fin.checked = false;
  var _finE = document.getElementById('rFinEntrada'); if (_finE) _finE.value = '';
  var _finN = document.getElementById('rFinNumCuotas'); if (_finN) _finN.value = '3';
  var _finD = document.getElementById('rFinDiaPago'); if (_finD) _finD.value = '8';
  if (typeof toggleFinanciarRep === 'function') toggleFinanciarRep();
  document.querySelectorAll('.chk-btn').forEach(function(b) { b.classList.remove('on'); });
  var tb = document.getElementById('rTipoBloq'); if (tb) { tb.value = ''; cambiarTipoBloq(); }
  // Limpiar errores de validación
  document.querySelectorAll('#mRep .fi.error').forEach(function(el){ el.classList.remove('error'); });
  document.querySelectorAll('#mRep .fg.error').forEach(function(el){ el.classList.remove('error'); });
  // Reset IVA al default
  var ivaSel = document.getElementById('rIva');
  if (ivaSel) ivaSel.value = String((AJUSTES.iva && AJUSTES.iva.tipoDefault != null) ? AJUSTES.iva.tipoDefault : 21);
  renderServiciosRep();
  calcR();
  renderPlantillasRep();
  openM('mRep');
  // Draft autosave: ofrecer recuperar un borrador previo y empezar a autoguardar
  _repDraftBannerShow();
  _repDraftStartAutosave();
  // Foco en cliente
  setTimeout(function(){
    var inp = document.getElementById('rBusCli');
    if (inp) inp.focus();
  }, 200);
}

