// ── PRES-C: Enviar presupuesto remoto al cliente ─────────────────────────────
var _presEnviarId = null;

function abrirModalEnviarPres(id) {
  _presEnviarId = id;
  var r = DB.reps.find(function(x){ return x.id === id; });
  if (!r) { toast(T('tst.presupuesto_no_encontrado'), 'err'); return; }

  // Buscar cliente para ver si tiene tel y email
  var cli = r.clienteId ? DB.clis.find(function(c){ return c.id === r.clienteId; }) : null;
  if (!cli && r.clienteNombre) {
    var nom = _norm(r.clienteNombre);
    cli = DB.clis.find(function(c){ return _norm(((c.nombre||'')+' '+(c.apellidos||'')).trim()) === nom; });
  }
  var tel   = cli ? (cli.tel   || '') : '';
  var email = cli ? (cli.email || '') : '';

  // Info del presupuesto
  var infoEl = document.getElementById('mPresEnviarInfo');
  infoEl.innerHTML = '<strong>' + escHtml(r.clienteNombre||'Sin nombre') + '</strong> &mdash; '
    + escHtml(r.marca+' '+r.modelo) + '<br>'
    + (tel   ? '📲 ' + escHtml(tel)   + '&nbsp;&nbsp;' : '<span style="color:var(--red)">⚠️ Sin teléfono</span>&nbsp;&nbsp;')
    + (email ? '📧 ' + escHtml(email) : '<span style="color:var(--muted)">Sin email</span>');

  // Preseleccionar según datos disponibles
  document.getElementById('chkPresWA').checked    = !!tel;
  document.getElementById('chkPresEmail').checked = !!email;
  document.getElementById('chkPresWA').disabled    = !tel;
  document.getElementById('chkPresEmail').disabled = !email;

  presEnviarToggle();
  openM('mPresEnviar');
}

function presEnviarToggle() {
  var wa    = document.getElementById('chkPresWA').checked;
  var email = document.getElementById('chkPresEmail').checked;
  var warn  = document.getElementById('presEnviarWarn');
  var btn   = document.getElementById('btnPresEnviarConf');
  if (!wa && !email) {
    warn.style.display = 'block';
    warn.textContent   = 'Selecciona al menos un método de envío.';
    btn.disabled = true;
  } else {
    warn.style.display = 'none';
    btn.disabled = false;
  }
}

async function confirmarEnviarPres() {
  if (!_presEnviarId) return;
  var wa    = document.getElementById('chkPresWA').checked;
  var email = document.getElementById('chkPresEmail').checked;
  if (!wa && !email) { toast(T('tst.selecciona_metodo'), 'err'); return; }

  var btn = document.getElementById('btnPresEnviarConf');
  btn.disabled = true;
  btn.textContent = 'Generando...';

  var sess = JSON.parse(localStorage.getItem('tk_sess')||'{}');
  var jwt  = sess.jwt_token || sess.jwt || '';

  try {
    var enviar = [];
    if (wa)    enviar.push('wa');
    if (email) enviar.push('email');

    var res = await fetch('/api/citas-publicas', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + jwt },
      body: JSON.stringify({ action: 'pres-generar-token', rep_id: _presEnviarId, enviar: enviar })
    });
    var data = await res.json();

    if (!data.ok) {
      toast(data.error || 'Error al generar enlace', 'err');
      btn.disabled = false; btn.textContent = '📤 Generar y enviar';
      return;
    }

    closeM('mPresEnviar');

    // Si WhatsApp: abrir wa.me directamente
    if (wa && data.tel && data.waMensaje) {
      var telLimpio = waTel(data.tel);
      var waUrl = 'https://wa.me/' + telLimpio + '?text=' + data.waMensaje;
      window.open(waUrl, '_blank');
      registrarAviso({ tipo:'presupuesto_enviado', canal:'whatsapp', destinatario:data.tel, ref_id:_presEnviarId, asunto:'Presupuesto enviado por WhatsApp' });
    }

    // Si email: ya fue enviado por el servidor, solo notificar
    var metodos = [];
    if (wa && data.tel)     metodos.push('WhatsApp');
    if (email && data.email) metodos.push('email');
    toast('Enlace enviado por ' + (metodos.join(' y ') || 'enlace generado') + ' ✓', 'ok');

    // Guardar URL en clipboard como bonus
    if (navigator.clipboard && data.url) {
      navigator.clipboard.writeText(data.url).catch(function(){});
    }

  } catch(e) {
    console.error('confirmarEnviarPres:', e);
    toast(T('gen.error_conexion'), 'err');
    btn.disabled = false; btn.textContent = '📤 Generar y enviar';
  }
}

// Aceptar presupuesto → convertir a reparación normal (estado Pendiente)
function aceptarPresupuesto(id) {
  if (!tienePerm('reps_editar')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var r = DB.reps.find(function(x){ return x.id === id; });
  if (!r) { toast(T('tst.presupuesto_no_encontrado'), 'err'); return; }
  if (r.estado !== 'Presupuesto') { toast(T('tst.no_es_presupuesto'), 'err'); return; }
  // F46: modal en vez de confirm() nativo (el nativo congelaba la automatización, patrón F30)
  confirmar(T('pres.convertir_confirm').replace('{cli}', r.clienteNombre).replace('{disp}', (r.marca + ' ' + r.modelo).trim()).replace('{total}', cur(r.total)), function () {
    r.estado = 'Pendiente';
    r.fechaAceptacion = new Date().toISOString();
    guardarDatos();
    // Sincronizar a Supabase
    if (SB_KEY && TIENDA_ID) {
      sbPatch('reparaciones', 'id=eq.' + r.id, { estado: 'Pendiente' });
    }
    toast('Presupuesto aceptado · ahora es una reparación pendiente', 'ok');
    if (document.getElementById('pPresupuestos') && document.getElementById('pPresupuestos').classList.contains('active')) {
      renderPresupuestos();
    }
    renderReps();
    // Cambiar al filtro Pendiente para que el usuario vea dónde fue
    var tab = document.querySelector('#repTabs .tab[data-f="Pendiente"]');
    if (tab) setRepFiltro(tab);
  }, { okLabel: T('gen.convertir') });
}

// Rechazar presupuesto → estado Rechazado (lo tienes ya)
function rechazarPresupuesto(id) {
  if (!tienePerm('reps_editar')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var r = DB.reps.find(function(x){ return x.id === id; });
  if (!r) { toast(T('tst.presupuesto_no_encontrado'), 'err'); return; }
  confirmar('¿Marcar este presupuesto como rechazado?\n\nQuedará en histórico para consulta posterior.', function () {
    r.estado = 'Rechazado';
    guardarDatos();
    if (SB_KEY && TIENDA_ID) {
      sbPatch('reparaciones', 'id=eq.' + r.id, { estado: 'Rechazado' });
    }
    toast(T('pres.rechazado_ok'), 'ok');
    if (document.getElementById('pPresupuestos') && document.getElementById('pPresupuestos').classList.contains('active')) {
      renderPresupuestos();
    }
    renderReps();
  }, { okLabel: 'Rechazar', danger: true });
}

// ═══ FIRMA DIGITAL DEL CLIENTE (FIRM-1 a FIRM-5) ═══
// Permite al cliente firmar el presupuesto con dedo (tablet/móvil) o ratón (PC).
// La firma se guarda como dataURL base64 en r.firma_cliente y r.firma_fecha (ISO).

var _firmaCanvasState = {
  ctx: null,
  drawing: false,
  hasDrawn: false,
  lastX: 0,
  lastY: 0,
  repId: null
};

function abrirFirmaPresupuesto(id) {
  if (!tienePerm('reps_editar')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var r = DB.reps.find(function(x){ return x.id === id; });
  if (!r) { toast(T('tst.presupuesto_no_encontrado'), 'err'); return; }
  if (r.estado !== 'Presupuesto') { toast('Solo se puede firmar un presupuesto', 'err'); return; }

  _firmaCanvasState.repId = id;
  _firmaCanvasState.hasDrawn = false;

  // Rellenar resumen
  var resumen = document.getElementById('firmaResumen');
  if (resumen) {
    var servicios = (r.servicios || []).map(function(s){ return s.nombre || ''; }).filter(Boolean).join(', ');
    resumen.innerHTML =
      '<div><strong>' + T('firma.r_cliente') + ':</strong> ' + esc(r.clienteNombre || '—') + '</div>' +
      '<div><strong>' + T('firma.r_dispositivo') + ':</strong> ' + esc(r.marca || '') + ' ' + esc(r.modelo || '') + (r.imei ? ' · IMEI: ' + esc(r.imei) : '') + '</div>' +
      '<div><strong>' + T('firma.r_averia') + ':</strong> ' + esc(r.averia || '—') + '</div>' +
      (servicios ? '<div><strong>' + T('firma.r_servicios') + ':</strong> ' + esc(servicios) + '</div>' : '') +
      '<div style="margin-top:8px;font-size:16px;font-weight:700;color:var(--green)"><strong>' + T('firma.r_total') + ' ' + cur(r.total || 0) + '</strong></div>';
  }

  // Reset checkbox + canvas
  var chk = document.getElementById('firmaAceptaTerminos');
  if (chk) chk.checked = false;
  firmaCanvasClear();

  openM('mFirma');

  // Inicializar canvas DESPUÉS de mostrar (sino width=0)
  setTimeout(function(){ _initFirmaCanvas(); }, 100);
}

function _initFirmaCanvas() {
  var canvas = document.getElementById('firmaCanvas');
  if (!canvas) return;

  // Ajustar tamaño real del canvas (pixel ratio para nitidez)
  var rect = canvas.getBoundingClientRect();
  var dpr = window.devicePixelRatio || 1;
  canvas.width = Math.floor(rect.width * dpr);
  canvas.height = Math.floor(rect.height * dpr);
  var ctx = canvas.getContext('2d');
  ctx.scale(dpr, dpr);
  ctx.strokeStyle = '#0E0E10';
  ctx.lineWidth = 2.2;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  _firmaCanvasState.ctx = ctx;
  _firmaCanvasState.hasDrawn = false;

  // Quitar handlers viejos si los había (evita doble suscripción)
  canvas.onmousedown = null; canvas.onmousemove = null; canvas.onmouseup = null; canvas.onmouseleave = null;
  canvas.ontouchstart = null; canvas.ontouchmove = null; canvas.ontouchend = null;

  function getXY(e) {
    var r = canvas.getBoundingClientRect();
    var x, y;
    if (e.touches && e.touches.length) {
      x = e.touches[0].clientX - r.left;
      y = e.touches[0].clientY - r.top;
    } else {
      x = e.clientX - r.left;
      y = e.clientY - r.top;
    }
    return { x: x, y: y };
  }

  function start(e) {
    e.preventDefault();
    _firmaCanvasState.drawing = true;
    var p = getXY(e);
    _firmaCanvasState.lastX = p.x;
    _firmaCanvasState.lastY = p.y;
  }
  function move(e) {
    if (!_firmaCanvasState.drawing) return;
    e.preventDefault();
    var p = getXY(e);
    ctx.beginPath();
    ctx.moveTo(_firmaCanvasState.lastX, _firmaCanvasState.lastY);
    ctx.lineTo(p.x, p.y);
    ctx.stroke();
    _firmaCanvasState.lastX = p.x;
    _firmaCanvasState.lastY = p.y;
    _firmaCanvasState.hasDrawn = true;
  }
  function end(e) {
    if (e) e.preventDefault();
    _firmaCanvasState.drawing = false;
  }

  canvas.addEventListener('mousedown', start);
  canvas.addEventListener('mousemove', move);
  canvas.addEventListener('mouseup', end);
  canvas.addEventListener('mouseleave', end);
  canvas.addEventListener('touchstart', start, { passive: false });
  canvas.addEventListener('touchmove', move, { passive: false });
  canvas.addEventListener('touchend', end, { passive: false });
}

function firmaCanvasClear() {
  var canvas = document.getElementById('firmaCanvas');
  if (!canvas) return;
  var ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  // Fondo blanco (necesario para que el PDF no salga transparente)
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  _firmaCanvasState.hasDrawn = false;
}

function confirmarFirma() {
  var id = _firmaCanvasState.repId;
  if (!id) return;
  var r = DB.reps.find(function(x){ return x.id === id; });
  if (!r) { toast(T('tst.presupuesto_no_encontrado'), 'err'); return; }

  var chk = document.getElementById('firmaAceptaTerminos');
  if (!chk || !chk.checked) {
    toast('Marca la casilla de aceptación', 'err');
    return;
  }
  if (!_firmaCanvasState.hasDrawn) {
    toast(T('tst.cliente_debe_firmar'), 'err');
    return;
  }

  // Capturar firma como dataURL (PNG)
  var canvas = document.getElementById('firmaCanvas');
  var dataUrl = canvas.toDataURL('image/png');

  // Guardar en la reparación
  r.firma_cliente = dataUrl;
  r.firma_fecha = new Date().toISOString();
  r.estado = 'Pendiente';
  r.fechaAceptacion = r.firma_fecha;

  guardarDatos();

  if (SB_KEY && TIENDA_ID) {
    sbPatch('reparaciones', 'id=eq.' + r.id, {
      estado: 'Pendiente',
      firma_cliente: dataUrl,
      firma_fecha: r.firma_fecha
    });
  }

  audit('firmar', 'presupuesto', r.id, r.clienteNombre + ' · firmado', null);
  closeM('mFirma');
  toast(T('tst.firmado_convertido').replace('{n}', (r.clienteNombre || 'cliente')), 'ok');
  renderReps();
  // Saltar a filtro Pendiente para que el usuario vea dónde fue
  var tab = document.querySelector('#repTabs .tab[data-f="Pendiente"]');
  if (tab) setRepFiltro(tab);
}

// === PLANTILLAS RÁPIDAS DE REPARACIÓN ===
var PLANTILLAS_REP_DEFAULT = [
  {key:'pantalla',  icon:'📱', label:'Pantalla rota',     averia:'Pantalla rota',                    servicio:'Instalación de Pantalla', precio:0, chk:['Pantalla rota']},
  {key:'bateria',   icon:'🔋', label:'Cambio batería',    averia:'Batería agotada / no aguanta',     servicio:'Instalación de Batería',  precio:0, chk:[]},
  {key:'nocarga',   icon:'🔌', label:'No carga',          averia:'No carga / problema de carga',     servicio:'Reparación pin de carga', precio:0, chk:['Sin cargador']},
  {key:'liquidos',  icon:'💧', label:'Líquidos',          averia:'Daños por líquidos / humedad',     servicio:'Limpieza por humedad',    precio:0, chk:['Humedad']},
  {key:'altavoz',   icon:'🔊', label:'Altavoz',           averia:'No suena / altavoz',               servicio:'Reparación altavoz',      precio:0, chk:[]},
  {key:'camara',    icon:'📷', label:'Cámara',            averia:'Cámara no funciona',               servicio:'Reparación cámara',       precio:0, chk:[]},
  {key:'boton',     icon:'🔘', label:'Botón',             averia:'Botón Power / Volumen / Home',     servicio:'Reparación botones',      precio:0, chk:[]},
  {key:'software',  icon:'⚙️', label:'Software',          averia:'Problema de software / sistema',   servicio:'Reparación software',     precio:0, chk:[]}
];

function getPlantillasRep() {
  if (TIENDA && Array.isArray(TIENDA.plantillasRep) && TIENDA.plantillasRep.length) {
    return TIENDA.plantillasRep;
  }
  return PLANTILLAS_REP_DEFAULT;
}

function renderPlantillasRep() {
  var box = document.getElementById('repPlantillasChips');
  if (!box) return;
  var plantillas = getPlantillasRep();
  var html = plantillas.map(function(p, i) {
    return '<button type="button" class="rep-quick-chip" onclick="aplicarPlantillaRep(\'' + (p.key || i) + '\')">' + (p.icon || '🔧') + ' ' + esc(p.label || '') + '</button>';
  }).join('');
  // Botón configurar al final
  html += '<button type="button" class="rep-quick-cfg" onclick="abrirGestorPlantillas()" title="Configurar plantillas">⚙️</button>';
  box.innerHTML = html;
}

function aplicarPlantillaRep(key) {
  var plantillas = getPlantillasRep();
  var p = plantillas.find(function(x){ return (x.key || '') === key; });
  if (!p) {
    var idx = parseInt(key);
    if (!isNaN(idx) && plantillas[idx]) p = plantillas[idx];
  }
  if (!p) return;
  // Avería = lo que reporta el cliente
  if (p.averia) document.getElementById('rAveria').value = p.averia;
  // Servicio (separado de avería) = lo que cobramos
  if (p.servicio) {
    agregarServicioRep({
      nombre: p.servicio,
      desc: '',
      coste: 0,
      precio: parseFloat(p.precio) || 0
    });
  }
  // Activar chips de estado
  if (p.chk && p.chk.length) {
    document.querySelectorAll('#mRep .chk-btn').forEach(function(b) {
      var txt = (b.dataset.cond || b.textContent).trim();
      // Bidireccional: compatible con guardados antiguos que incluían el emoji
      // ("🔌 Sin cargador") y con los nuevos limpios ("Sin cargador").
      if (p.chk.some(function(c){ c = String(c); return txt.indexOf(c) !== -1 || c.indexOf(txt) !== -1; })) {
        b.classList.add('on');
      }
    });
  }
  calcR();
  toast(T('tst.plantilla_aplicada').replace('{n}', (p.label || '')), 'ok');
}

// ═══ GESTOR DE PLANTILLAS RÁPIDAS ═══
var SEL_PLANTILLAS_EDIT = [];

function abrirGestorPlantillas() {
  if (!checkFeature('plantillas_rep')) return;
  SEL_PLANTILLAS_EDIT = JSON.parse(JSON.stringify(getPlantillasRep()));
  renderPlantillasEdit();
  openM('mPlantillasRep');
}

function renderPlantillasEdit() {
  var box = document.getElementById('plantillasRepList');
  if (!box) return;
  if (!SEL_PLANTILLAS_EDIT.length) {
    box.innerHTML = '<div class="empty" style="padding:18px;font-size:12px">No hay plantillas. Pulsa "+ Añadir plantilla".</div>';
    return;
  }
  box.innerHTML = SEL_PLANTILLAS_EDIT.map(function(p, i) {
    return '<div class="plantilla-card">' +
      '<button type="button" class="srv-card-x" onclick="quitarPlantilla(' + i + ')" title="Quitar">×</button>' +
      '<div style="display:grid;grid-template-columns:60px 1fr 90px;gap:8px;padding-right:24px;margin-bottom:6px">' +
        '<div class="fg" style="margin:0"><label class="fl">Icono</label><input class="fi" maxlength="2" value="' + esc(p.icon || '') + '" placeholder="📱" oninput="updPlantilla(' + i + ',\'icon\',this.value)" style="text-align:center;font-size:16px"></div>' +
        '<div class="fg" style="margin:0"><label class="fl">Etiqueta del chip</label><input class="fi" value="' + esc(p.label || '') + '" placeholder="Pantalla rota" oninput="updPlantilla(' + i + ',\'label\',this.value)"></div>' +
        '<div class="fg" style="margin:0"><label class="fl">Precio (€)</label><input class="fi" type="number" step="0.01" value="' + (p.precio || '') + '" placeholder="0" oninput="updPlantilla(' + i + ',\'precio\',parseFloat(this.value)||0)"></div>' +
      '</div>' +
      '<div class="fg" style="margin-bottom:6px"><label class="fl">Avería <span style="font-size:9px;color:var(--muted);font-weight:500;text-transform:none;letter-spacing:0">— lo que dice el cliente</span></label><input class="fi" value="' + esc(p.averia || '') + '" placeholder="Ej: Pantalla rota" oninput="updPlantilla(' + i + ',\'averia\',this.value)"></div>' +
      '<div class="fg" style="margin-bottom:0"><label class="fl">Servicio <span style="font-size:9px;color:var(--muted);font-weight:500;text-transform:none;letter-spacing:0">— lo que se cobra</span></label><input class="fi" value="' + esc(p.servicio || '') + '" placeholder="Ej: Instalación de Pantalla" oninput="updPlantilla(' + i + ',\'servicio\',this.value)"></div>' +
    '</div>';
  }).join('');
}

function updPlantilla(i, field, value) {
  if (SEL_PLANTILLAS_EDIT[i]) SEL_PLANTILLAS_EDIT[i][field] = value;
}

function quitarPlantilla(i) {
  SEL_PLANTILLAS_EDIT.splice(i, 1);
  renderPlantillasEdit();
}

function anadirPlantilla() {
  SEL_PLANTILLAS_EDIT.push({
    key: 'p' + Date.now() + '_' + Math.random().toString(36).slice(2,8),
    icon: '🔧',
    label: 'Nueva plantilla',
    averia: '',
    servicio: '',
    precio: 0,
    chk: []
  });
  renderPlantillasEdit();
}

function restablecerPlantillas() {
  if (!confirm('¿Restaurar las plantillas por defecto?\nPerderás los cambios sin guardar.')) return;
  SEL_PLANTILLAS_EDIT = JSON.parse(JSON.stringify(PLANTILLAS_REP_DEFAULT));
  renderPlantillasEdit();
}

function guardarPlantillas() {
  // Filtrar plantillas vacías
  var validas = SEL_PLANTILLAS_EDIT.filter(function(p){
    return (p.label || '').trim() && ((p.averia || '').trim() || (p.servicio || '').trim());
  });
  TIENDA.plantillasRep = validas;
  guardarDatos();
  if (typeof SB_KEY !== 'undefined' && SB_KEY && TIENDA_ID) {
    sbPatch('tiendas', 'id=eq.' + TIENDA_ID, {
      plantillas_rep: TIENDA.plantillasRep
    });
  }
  toast('Plantillas guardadas', 'ok');
  closeM('mPlantillasRep');
  // Refrescar chips si modal de rep abierto
  renderPlantillasRep();
}

function toggleChk(el) { el.classList.toggle('on'); }

// ═══ GESTIÓN DE SERVICIOS DE REPARACIÓN ═══
function agregarServicioRep(servicio) {
  if (!SEL.rServicios) SEL.rServicios = [];
  SEL.rServicios.push(servicio || {nombre:'', desc:'', coste:0, precio:0});
  renderServiciosRep();
  calcR();
  // Foco en el último añadido
  setTimeout(function(){
    var cards = document.querySelectorAll('.srv-card');
    if (cards.length) {
      var last = cards[cards.length-1];
      var inp = last.querySelector('input.fi');
      if (inp) inp.focus();
    }
  }, 50);
}

function quitarServicioRep(idx) {
  if (!SEL.rServicios) return;
  SEL.rServicios.splice(idx, 1);
  renderServiciosRep();
  calcR();
}

function updateServicioRep(idx, field, value) {
  if (!SEL.rServicios || !SEL.rServicios[idx]) return;
  SEL.rServicios[idx][field] = value;
}

function renderServiciosRep() {
  var box = document.getElementById('repServiciosList');
  if (!box) return;
  if (!SEL.rServicios || !SEL.rServicios.length) {
    box.innerHTML = '<div class="empty" style="padding:12px;font-size:11px;color:var(--muted)">Añade servicios desde el buscador, "Explorar" o "+ Agregar nuevo"</div>';
    return;
  }
  box.innerHTML = SEL.rServicios.map(function(s, i) {
    return '<div class="srv-card" data-idx="' + i + '">' +
      '<button type="button" class="srv-card-x" onclick="quitarServicioRep(' + i + ')" title="Quitar servicio">×</button>' +
      '<div class="srv-card-grid">' +
        '<div class="fg" style="margin:0"><label class="fl">Nombre del servicio</label>' +
          '<input class="fi" value="' + esc(s.nombre || '') + '" placeholder="Ej: Instalación de Pantalla" oninput="updateServicioRep(' + i + ',\'nombre\',this.value)">' +
        '</div>' +
        '<div class="fg" style="margin:0"><label class="fl" title="Solo interno">🔒 Costo</label>' +
          '<input class="fi" type="number" step="0.01" value="' + (s.coste || 0) + '" oninput="updateServicioRep(' + i + ',\'coste\',parseFloat(this.value)||0)">' +
        '</div>' +
        '<div class="fg" style="margin:0"><label class="fl">Precio</label>' +
          '<input class="fi" type="number" step="0.01" value="' + (s.precio || 0) + '" oninput="updateServicioRep(' + i + ',\'precio\',parseFloat(this.value)||0);calcR()">' +
        '</div>' +
      '</div>' +
      '<textarea class="fi" rows="2" placeholder="Descripción del servicio (opcional)..." oninput="updateServicioRep(' + i + ',\'desc\',this.value)" style="margin-top:8px">' + esc(s.desc || '') + '</textarea>' +
    '</div>';
  }).join('');
}

function explorarServicios() {
  var inp = document.getElementById('exploreSrvSearch');
  if (inp) inp.value = '';
  SEL.exploreCheckedIds = [];
  renderExploreSrv();
  openM('mExplorarSrv');
}

function renderExploreSrv() {
  var q = ((document.getElementById('exploreSrvSearch') || {}).value || '').toLowerCase().trim();
  var box = document.getElementById('exploreSrvList');
  var btn = document.getElementById('btnAgregarSrvSel');
  if (!box) return;
  var srvs = (DB.servicios || []).filter(function(s) {
    if (s.tipo === 'venta') return false;
    if (!q) return true;
    return s.nombre.toLowerCase().includes(q);
  });
  // Ordenar alfabético
  srvs.sort(function(a, b){ return (a.nombre || '').localeCompare(b.nombre || ''); });

  if (!srvs.length) {
    box.innerHTML = '<div class="empty" style="padding:24px 18px;font-size:12px">' +
      (q ? 'Sin coincidencias para "<strong>' + esc(q) + '</strong>"' : 'No hay servicios todavía.') +
      '<br><button type="button" class="btn-primary" style="background:var(--green);margin-top:12px;padding:8px 16px;font-size:12px" onclick="abrirCrearSrvSimple(\'' + (q ? q.replace(/'/g, "\\'") : '') + '\')">+ Crear nuevo servicio</button>' +
      '</div>';
    if (btn) { btn.disabled = true; btn.textContent = 'Agregar seleccionados'; }
    return;
  }

  if (!SEL.exploreCheckedIds) SEL.exploreCheckedIds = [];

  var html = srvs.map(function(s) {
    var coste = parseFloat(s.precioCoste) || 0;
    var venta = parseFloat(s.precio) || 0;
    var checked = SEL.exploreCheckedIds.indexOf(s.id) !== -1;
    return '<div class="explore-srv-item" data-sid="' + s.id + '">' +
      '<input type="checkbox" ' + (checked ? 'checked' : '') + ' onchange="toggleExplorerSel(\'' + s.id + '\')" style="width:18px;height:18px;cursor:pointer;flex-shrink:0;accent-color:var(--purple)">' +
      '<div style="flex:1;min-width:0;cursor:pointer" onclick="toggleExplorerSel(\'' + s.id + '\')">' +
        '<div style="font-size:13px;font-weight:600">' + esc(s.nombre) + '</div>' +
        '<div style="font-size:11px;color:var(--muted)">' +
          (coste > 0 ? '🔒 ' + cur(coste) + ' · ' : '') +
          (s.precioFijo ? '<strong style="color:var(--green)">' + cur(venta) + '</strong>' : '<em>Variable</em>') +
        '</div>' +
      '</div>' +
      '<button type="button" onclick="event.stopPropagation();borrarServicioCatalogo(\'' + s.id + '\')" title="Eliminar del catálogo" style="background:none;border:none;cursor:pointer;padding:6px;border-radius:6px;font-size:14px;color:var(--muted);transition:all .15s">🗑️</button>' +
    '</div>';
  }).join('');
  box.innerHTML = html;

  // Actualizar contador y estado del botón
  var cnt = SEL.exploreCheckedIds.length;
  if (btn) {
    btn.disabled = cnt === 0;
    btn.textContent = cnt > 0 ? 'Agregar ' + cnt + ' servicio' + (cnt > 1 ? 's' : '') : 'Agregar seleccionados';
    btn.style.opacity = cnt === 0 ? '0.5' : '1';
  }
}

function toggleExplorerSel(sid) {
  if (!SEL.exploreCheckedIds) SEL.exploreCheckedIds = [];
  var i = SEL.exploreCheckedIds.indexOf(sid);
  if (i >= 0) SEL.exploreCheckedIds.splice(i, 1);
  else SEL.exploreCheckedIds.push(sid);
  renderExploreSrv();
}

function agregarSeleccionados() {
  if (!SEL.exploreCheckedIds || !SEL.exploreCheckedIds.length) return;
  SEL.exploreCheckedIds.forEach(function(sid) {
    var s = (DB.servicios || []).find(function(x){ return x.id === sid; });
    if (!s) return;
    agregarServicioRep({
      id: s.id,
      nombre: s.nombre || '',
      desc: '',
      coste: parseFloat(s.precioCoste) || 0,
      precio: parseFloat(s.precio) || 0
    });
  });
  var cnt = SEL.exploreCheckedIds.length;
  SEL.exploreCheckedIds = [];
  closeM('mExplorarSrv');
  toast(cnt + ' servicio' + (cnt > 1 ? 's' : '') + ' añadido' + (cnt > 1 ? 's' : ''), 'ok');
}

function borrarServicioCatalogo(sid) {
  var s = (DB.servicios || []).find(function(x){ return x.id === sid; });
  if (!s) return;
  if (!confirm('¿Eliminar "' + s.nombre + '" del catálogo?\nLas reparaciones que ya lo usan no se ven afectadas.')) return;
  DB.servicios = (DB.servicios || []).filter(function(x){ return x.id !== sid; });
  // Limpiar de seleccionados si estaba
  if (SEL.exploreCheckedIds) {
    SEL.exploreCheckedIds = SEL.exploreCheckedIds.filter(function(id){ return id !== sid; });
  }
  guardarDatos();
  if (typeof SB_KEY !== 'undefined' && SB_KEY && TIENDA_ID) {
    sbDelete('servicios', 'id=eq.' + sid);
  }
  toast(T('tst.servicio_eliminado'), 'ok');
  renderExploreSrv();
  if (typeof renderServicios === 'function') renderServicios();
}

function abrirCrearSrvSimple(prefName) {
  document.getElementById('csrvNom').value = prefName || '';
  document.getElementById('csrvCat').value = 'Otro';
  openM('mCrearSrvSimple');
  setTimeout(function(){
    var inp = document.getElementById('csrvNom');
    if (inp) { inp.focus(); if (prefName) inp.select(); }
  }, 50);
}

// F240: valida el nombre de un servicio. Devuelve mensaje de error o null si es válido.
function _validarNombreServicio(nom) {
  nom = (nom || '').trim();
  if (nom.length < 3) return 'El nombre del servicio es muy corto (mínimo 3 caracteres)';
  if (nom.length > 60) return 'El nombre del servicio es muy largo (máximo 60 caracteres)';
  // Texto repetido ("HISTORIA/WESTERN HISTORIA/WESTERN") → casi siempre un error de pegado
  var mitad = nom.slice(0, Math.floor(nom.length / 2)).trim();
  if (mitad.length >= 4 && _norm(nom) === _norm(mitad + ' ' + mitad)) return 'El nombre parece estar duplicado. Revísalo.';
  if (!/[a-zA-ZÀ-ÿ0-9]/.test(nom)) return 'El nombre debe contener letras o números';
  return null;
}

function guardarSrvSimple() {
  var nom = (document.getElementById('csrvNom').value || '').trim();
  // F240: validación de nombre (evita servicios basura tipo "CV" o nombres rotos)
  var errSrv = _validarNombreServicio(nom);
  if (errSrv) { toast(errSrv, 'err'); return; }
  var cat = document.getElementById('csrvCat').value || 'Otro';
  // Comprobar duplicado por nombre normalizado
  var nomNorm = _norm(nom);
  var existente = (DB.servicios || []).find(function(s){ return _norm(s.nombre) === nomNorm; });
  if (existente) {
    toast(T('tst.servicio_duplicado'), 'err');
    return;
  }
  var srv = {
    id: 'srv' + Date.now() + '_' + Math.random().toString(36).slice(2,8),
    nombre: nom,
    categoria: cat,
    tipo: 'reparacion',
    precioFijo: true,
    precio: 0,
    precioCoste: 0
  };
  if (!DB.servicios) DB.servicios = [];
  DB.servicios.push(srv);
  guardarDatos();
  if (typeof SB_KEY !== 'undefined' && SB_KEY && TIENDA_ID) {
    sbPost('servicios', {
      id:srv.id, tienda_id:TIENDA_ID,
      nombre:srv.nombre, categoria:srv.categoria, tipo:srv.tipo,
      precio_fijo:srv.precioFijo, precio:srv.precio
    });
  }
  toast(T('tst.servicio_creado'), 'ok');
  closeM('mCrearSrvSimple');
  // Si el modal Explorar está abierto, refrescar y marcar el nuevo
  var explorer = document.getElementById('mExplorarSrv');
  if (explorer && explorer.classList.contains('open')) {
    if (!SEL.exploreCheckedIds) SEL.exploreCheckedIds = [];
    SEL.exploreCheckedIds.push(srv.id);
    renderExploreSrv();
  }
  if (typeof renderServicios === 'function') renderServicios();
}

function agregarServicioFromExplore(sid) {
  // Compatibilidad legacy
  var s = (DB.servicios || []).find(function(x){ return x.id === sid; });
  if (!s) return;
  agregarServicioRep({
    id: s.id,
    nombre: s.nombre || '',
    desc: '',
    coste: parseFloat(s.precioCoste) || 0,
    precio: parseFloat(s.precio) || 0
  });
  closeM('mExplorarSrv');
}

function calcR() {
  var srvTotal = (SEL.rServicios || []).reduce(function(a, s){ return a + (parseFloat(s.precio) || 0); }, 0);
  var comp = (SEL.selParts || []).reduce(function(a, p) { return a + p.precio; }, 0);
  var anti = (SEL.repPagos || []).reduce(function(a, p) { return a + (parseFloat(p.importe) || 0); }, 0);
  var subtotal = srvTotal + comp; // lo que el usuario ha tecleado
  // Actualizar UI de resumen de pagos
  if (typeof renderResumenPagos === 'function') renderResumenPagos(srvTotal + comp);
  var ivaSel = document.getElementById('rIva');
  var tipoIva = ivaSel ? parseFloat(ivaSel.value) : (AJUSTES.iva && AJUSTES.iva.tipoDefault) || 0;
  var c = calcIVA(subtotal, tipoIva);
  // Mostrar/ocultar filas IVA segun config
  var on = !!(AJUSTES.iva && AJUSTES.iva.activo);
  var ivaRow = document.getElementById('rIvaRow');
  var baseRow = document.getElementById('rBaseRow');
  var ivaImpRow = document.getElementById('rIvaImpRow');
  if (ivaRow) ivaRow.style.display = on ? 'block' : 'none';
  if (baseRow) baseRow.style.display = on ? 'flex' : 'none';
  if (ivaImpRow) ivaImpRow.style.display = on ? 'flex' : 'none';
  if (on) {
    document.getElementById('rBase').textContent = cur(c.base);
    document.getElementById('rIvaImp').textContent = cur(c.iva);
    document.getElementById('rIvaImpLbl').textContent = 'IVA (' + c.tipo + '%)';
    var totalLbl = document.getElementById('rTotalLbl');
    if (totalLbl) totalLbl.textContent = c.modo === 'incluido' ? 'Total (IVA inc.)' : 'Total con IVA';
  } else {
    var lbl = document.getElementById('rTotalLbl');
    if (lbl) lbl.textContent = 'Total';
  }
  document.getElementById('rTotal').textContent = cur(c.total);
  // Anticipo pagado (suma de pagos) + lo que queda a deber (restante sobre el total final con IVA)
  var resta = Math.max(0, c.total - anti);
  var antiRow = document.getElementById('rAnticipoRow');
  var antiEl = document.getElementById('rAnticipo');
  if (antiEl) antiEl.textContent = cur(anti);
  if (antiRow) antiRow.style.display = anti > 0 ? 'block' : 'none';
  var restEl = document.getElementById('rRestante');
  restEl.textContent = cur(resta);
  restEl.style.color = resta > 0 ? '#F97316' : 'var(--green)';
  window._rTotalActual = c.total;
  if (typeof calcFinRep === 'function') calcFinRep();
}

// ═══ FINANCIAR REPARACIÓN A PLAZOS ═══
function toggleFinanciarRep() {
  var on = document.getElementById('rFinanciar').checked;
  var box = document.getElementById('rFinBox');
  if (box) box.style.display = on ? 'block' : 'none';
  // Al financiar, ocultar el sistema de pagos normal (la entrada + cuotas lo sustituye)
  var pagosBox = document.getElementById('rPagosBox');
  var pagoForm = document.getElementById('rPagoForm');
  if (pagosBox) pagosBox.style.display = on ? 'none' : 'block';
  if (on && pagoForm) pagoForm.style.display = 'none';
  if (on) calcFinRep();
}

function calcFinRep() {
  var prev = document.getElementById('rFinPreview');
  var chk = document.getElementById('rFinanciar');
  if (!prev || !chk) return;
  if (!chk.checked) { prev.textContent = ''; return; }
  var total = window._rTotalActual || 0;
  var entrada = parseFloat(document.getElementById('rFinEntrada').value) || 0;
  var n = parseInt(document.getElementById('rFinNumCuotas').value) || 1;
  if (n < 1) n = 1;
  var pendiente = Math.max(0, Math.round((total - entrada) * 100) / 100);
  var porCuota = Math.round((pendiente / n) * 100) / 100;
  prev.textContent = n + ' × ' + cur(porCuota) + ' = ' + cur(pendiente);
}

// Genera el array de cuotas a partir de los campos del formulario (mismo modelo que ventas)
function generarCuotasRep(total) {
  var entrada = parseFloat(document.getElementById('rFinEntrada').value) || 0;
  var n = parseInt(document.getElementById('rFinNumCuotas').value) || 1;
  if (n < 1) n = 1;
  var diaPago = parseInt(document.getElementById('rFinDiaPago').value) || 8;
  var pendiente = Math.max(0, Math.round((total - entrada) * 100) / 100);
  var montoCuota = Math.round((pendiente / n) * 100) / 100;
  var cuotas = [];
  for (var i = 0; i < n; i++) {
    var fc = new Date();
    fc.setMonth(fc.getMonth() + i + 1);
    fc.setDate(diaPago);
    var imp = (i === n - 1) ? Math.round((pendiente - montoCuota * (n - 1)) * 100) / 100 : montoCuota;
    cuotas.push({ num: i + 1, importe: imp, fecha: fc.toISOString().slice(0, 10), pagado: false, formaPago: '', fechaPago: '' });
  }
  return cuotas;
}

function busComp() {
  var q = document.getElementById('compBus').value.toLowerCase();
  var res = document.getElementById('compRes');
  if (!q) { res.classList.remove('open'); return; }
  var matches = DB.stock.filter(function(s) {
    var esComp = s.categoria !== 'Telefono' && s.categoria !== 'Tablet' && s.categoria !== 'Smartwatch';
    return esComp && s.unidades > 0 && (s.marca + ' ' + s.modelo + ' ' + (s.categoria || '')).toLowerCase().includes(q);
  });
  res.innerHTML = matches.slice(0, 5).map(function(s) {
    var ya = SEL.selParts.find(function(p) { return p.id === s.id; });
    return '<div class="cli-item" data-sid="' + escHtml(s.id) + '" style="' + (ya ? 'background:rgba(0,200,150,.06)' : '') + '">' +
      '<span style="background:var(--light);padding:2px 6px;border-radius:4px;font-size:10px;font-weight:700;color:var(--muted);margin-right:6px">' + escHtml(s.categoria || 'Otro') + '</span>' +
      escHtml(s.modelo) + ' (' + escHtml(s.marca) + ')' + (s.color ? ' · ' + escHtml(s.color) : '') + (s.calidad ? ' <span style="font-size:10px;font-weight:700;color:#7C5CFC;background:rgba(124,92,252,.1);padding:1px 5px;border-radius:4px">' + escHtml(s.calidad) + '</span>' : '') + ' · Stock: ' + s.unidades + (ya ? ' ✓' : '') +
      '<span style="float:right;color:var(--green);font-weight:700">' + cur(s.precioV) + '</span></div>';
  }).join('');
  if (matches.length) res.classList.add('open');
  res.querySelectorAll('[data-sid]').forEach(function(el) {
    el.addEventListener('click', function() { addPart(this.dataset.sid); });
  });
}

function addPart(id) {
  var s = DB.stock.find(function(x) { return x.id === id; });
  if (!s) return;
  var ya = SEL.selParts.find(function(p) { return p.id === id; });
  if (!ya) SEL.selParts.push({id: s.id, nombre: s.marca + ' ' + s.modelo + (s.color ? ' (' + s.color + ')' : ''), precio: s.precioV});
  document.getElementById('compBus').value = '';
  document.getElementById('compRes').classList.remove('open');
  renderParts();
  calcR();
  try { sugerirPiezasRep(); } catch(e){}
}
// ¿El modelo de la pieza encaja EXACTAMENTE con el del dispositivo? Evita que
// "iPhone 11" traiga "11 Pro" / "11 Pro Max": exige el mismo conjunto de
// palabras-variante (pro/max/plus/mini/ultra/se/lite...).
var _MODEL_VARIANTS = ['pro', 'max', 'plus', 'mini', 'ultra', 'se', 'lite', 'fe', 'neo', 'note', 'air'];
function _normModelo(x) { return (x || '').toLowerCase().replace(/[^a-z0-9 ]/g, ' ').replace(/\s+/g, ' ').trim(); }
function _modeloEncaja(deviceMod, partMod) {
  var d = _normModelo(deviceMod), p = _normModelo(partMod);
  if (!d || !p) return false;
  if (p.indexOf(d) === -1 && d.indexOf(p) === -1) return false;  // uno contiene al otro
  var dv = d.split(' ').filter(function(t) { return _MODEL_VARIANTS.indexOf(t) !== -1; });
  var pv = p.split(' ').filter(function(t) { return _MODEL_VARIANTS.indexOf(t) !== -1; });
  for (var i = 0; i < pv.length; i++) { if (dv.indexOf(pv[i]) === -1) return false; }  // pieza tiene variante que el equipo no
  for (var j = 0; j < dv.length; j++) { if (pv.indexOf(dv[j]) === -1) return false; }  // equipo tiene variante que la pieza no
  return true;
}
// Sugiere piezas del stock que encajan con el modelo de la reparación (1 clic para añadir).
// Si la avería menciona pantalla/tapa/batería, esas se resaltan y van primero.
function sugerirPiezasRep() {
  var box = document.getElementById('repPiezasSug'); if (!box) return;
  var modEl = document.getElementById('rModelo'); var mod = (modEl ? modEl.value : '').trim().toLowerCase();
  if (!mod || mod.length < 2) { box.style.display = 'none'; box.innerHTML = ''; return; }
  var aver = (document.getElementById('rAveria') ? document.getElementById('rAveria').value : '').toLowerCase();
  var sel = {}; (SEL.selParts || []).forEach(function(p) { sel[p.id] = 1; });
  var rel = function(s) {
    var c = (s.categoria || '').toLowerCase();
    if (aver.indexOf('pantalla') !== -1 && c === 'pantalla') return 0;
    if ((aver.indexOf('tapa') !== -1 || aver.indexOf('cristal') !== -1 || aver.indexOf('trasera') !== -1) && c === 'tapa') return 0;
    if (aver.indexOf('bater') !== -1 && c === 'bateria') return 0;
    if ((aver.indexOf('carga') !== -1 || aver.indexOf('flex') !== -1) && c === 'flex de carga') return 0;
    return 1;
  };
  var parts = (DB.stock || []).filter(function(s) {
    if (s.vendido || (parseInt(s.unidades, 10) || 0) <= 0) return false;
    if (['Telefono', 'Tablet', 'Smartwatch'].indexOf(s.categoria) !== -1) return false;
    if (sel[s.id]) return false;
    return _modeloEncaja(mod, s.modelo);
  }).sort(function(a, b) { return rel(a) - rel(b); }).slice(0, 8);
  if (!parts.length) { box.style.display = 'none'; box.innerHTML = ''; return; }
  box.style.display = 'flex';
  box.innerHTML = '<div style="width:100%;font-size:10px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:.3px">' + T('rep.piezas_sug') + '</div>' + parts.map(function(s) {
    var hot = rel(s) === 0;
    return '<button type="button" onclick="addPart(\'' + s.id + '\')" style="display:inline-flex;align-items:center;gap:6px;padding:5px 10px;border-radius:16px;border:1.5px solid ' + (hot ? 'var(--orange)' : 'var(--border)') + ';background:' + (hot ? 'rgba(249,115,22,.08)' : '#fff') + ';color:var(--text);font:inherit;font-size:12px;font-weight:600;cursor:pointer">' +
      '➕ ' + escHtml(((s.categoria || '') + ' ' + (s.modelo || '') + (s.color ? ' · ' + s.color : '')).trim()) + ' <span style="color:var(--green);font-weight:700">' + cur(s.precioV) + '</span> <span style="color:var(--muted)">·' + s.unidades + '</span></button>';
  }).join('');
}

function renderParts() {
  document.getElementById('partsList').innerHTML = SEL.selParts.map(function(p, i) {
    return '<div class="part-item">' +
      '<span>' + escHtml(p.nombre) + '</span>' +
      '<div style="display:flex;align-items:center;gap:8px">' +
      '<input type="number" step="0.01" min="0" data-idx="' + i + '" class="part-precio" value="' + (p.precio || 0) + '" style="width:74px;padding:4px 6px;border:1px solid var(--border);border-radius:5px;font-size:12px;text-align:right;color:var(--green);font-weight:700">' +
      '<button data-idx="' + i + '" class="part-del" style="background:none;border:none;color:var(--muted);cursor:pointer;font-size:14px">\u00d7</button>' +
      '</div></div>';
  }).join('');
  document.querySelectorAll('.part-del').forEach(function(btn) {
    btn.addEventListener('click', function() {
      SEL.selParts.splice(parseInt(this.dataset.idx), 1);
      renderParts(); calcR();
    });
  });
  document.querySelectorAll('.part-precio').forEach(function(inp) {
    inp.addEventListener('input', function() {
      var idx = parseInt(this.dataset.idx);
      if (SEL.selParts[idx]) { SEL.selParts[idx].precio = parseFloat(this.value) || 0; calcR(); }
    });
  });
}

function busServicioRep() {
  var q = document.getElementById('rSrvBus').value.toLowerCase();
  var res = document.getElementById('rSrvRes');
  if (!q) { res.classList.remove('open'); return; }
  var matches = (DB.servicios || []).filter(function(s) {
    return (s.tipo === 'reparacion' || s.tipo === 'ambos') && s.nombre.toLowerCase().includes(q);
  });
  if (!matches.length) { res.classList.remove('open'); return; }
  res.innerHTML = matches.map(function(s) {
    var coste = parseFloat(s.precioCoste) || 0;
    var venta = parseFloat(s.precio) || 0;
    var margen = venta - coste;
    var precioInfo = '';
    if (s.precioFijo) {
      precioInfo = '<div style="font-size:11px;color:var(--muted);margin-top:3px;display:flex;gap:10px;flex-wrap:wrap">';
      if (coste > 0) precioInfo += '<span title="Solo interno">🔒 Coste: <strong style="color:var(--orange)">' + cur(coste) + '</strong></span>';
      precioInfo += '<span>Venta: <strong style="color:var(--green)">' + cur(venta) + '</strong></span>';
      if (coste > 0 && margen !== 0) {
        var col = margen < 0 ? 'var(--red)' : 'var(--blue)';
        precioInfo += '<span>Margen: <strong style="color:' + col + '">' + cur(margen) + '</strong></span>';
      }
      precioInfo += '</div>';
    } else {
      precioInfo = '<div style="font-size:11px;color:var(--muted);margin-top:3px">Precio variable</div>';
    }
    return '<div class="cli-item" data-sid="' + s.id + '" style="border-left:3px solid var(--purple);padding:10px 12px">' +
      '<div style="display:flex;justify-content:space-between;align-items:start;gap:8px">' +
      '<div style="flex:1;min-width:0">' +
      '<span style="font-size:9px;color:var(--purple);font-weight:700">SERVICIO · ' + (s.categoria || '') + '</span><br>' +
      '<strong style="font-size:13px">' + esc(s.nombre) + '</strong>' +
      precioInfo +
      '</div></div></div>';
  }).join('');
  res.classList.add('open');
  res.querySelectorAll('[data-sid]').forEach(function(el) {
    el.addEventListener('click', function() {
      var s = (DB.servicios || []).find(function(x) { return x.id === el.dataset.sid; });
      if (!s) return;
      agregarServicioRep({
        id: s.id,
        nombre: s.nombre || '',
        desc: '',
        coste: parseFloat(s.precioCoste) || 0,
        precio: parseFloat(s.precio) || 0
      });
      document.getElementById('rSrvBus').value = '';
      res.classList.remove('open');
    });
  });
}



// qr_seguimiento_v1: helpers para token de seguimiento
function genToken() {
  // 16 chars alfanumericos seguros
  var chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
  var s = '';
  if (window.crypto && crypto.getRandomValues) {
    var arr = new Uint32Array(16);
    crypto.getRandomValues(arr);
    for (var i = 0; i < 16; i++) s += chars[arr[i] % chars.length];
  } else {
    for (var j = 0; j < 16; j++) s += chars[Math.floor(Math.random() * chars.length)];
  }
  return s;
}

function asegurarToken(r) {
  if (r.token) return Promise.resolve(r.token);
  r.token = genToken();
  guardarDatos();
  // El token es opcional en Supabase - si la columna no existe, no mostramos error
  if (typeof SB_KEY !== 'undefined' && SB_KEY && TIENDA_ID) {
    var url = SUPABASE_URL + '/rest/v1/reparaciones?id=eq.' + r.id;
    return fetch(url, {
      method: 'PATCH',
      headers: {'apikey': SB_KEY, 'Authorization':'Bearer ' + (JWT_TOKEN || SB_KEY), 'Content-Type':'application/json', 'Prefer':'return=representation'},
      body: JSON.stringify({token: r.token})
    }).then(function(resp){
      // F27: si el token no se persiste (RLS o columna ausente), el link público NO abrirá.
      // Antes el fallo se tragaba en silencio → "parte caducado". Ahora lo avisamos.
      return resp.json().then(function(rows){
        if (!resp.ok || !Array.isArray(rows) || !rows.length) {
          try { toast('⚠️ No se pudo guardar el token del parte (permisos). El link podría no abrir.', 'err'); } catch(e){}
        }
        return r.token;
      }).catch(function(){ return r.token; });
    }).catch(function(){ return r.token; });
  }
  return Promise.resolve(r.token);
}

function linkParte(r) {
  if (!r.token) r.token = genToken();
  return location.origin + '/parte.html?id=' + encodeURIComponent(r.id) + '&t=' + encodeURIComponent(r.token);
}

function copiarLinkRep(id) {
  abrirTracking(id);
}

// qr_modal_v1: estado del modal
var TRACKING = { rep: null, url: '' };

function abrirTracking(id) {
  var r = DB.reps.find(function(x){ return x.id === id; });
  if (!r) return;
  asegurarToken(r).then(function(){
    var url = linkParte(r);
    TRACKING.rep = r;
    TRACKING.url = url;
    document.getElementById('trackingHeader').textContent = (r.marca || '') + ' ' + (r.modelo || '') + ' · ' + (r.clienteNombre || '');
    document.getElementById('trackingLink').textContent = url;
    var qrBox = document.getElementById('trackingQR');
    qrBox.innerHTML = '';
    try {
      var qr = qrcode(0, 'M');
      qr.addData(url);
      qr.make();
      qrBox.innerHTML = qr.createImgTag(5, 8);
    } catch(e) {
      qrBox.innerHTML = '<div style="color:var(--red);font-size:12px">No se pudo generar el QR</div>';
    }
    openM('mTracking');
  });
}

function trackingCopy() {
  if (!TRACKING.url) return;
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(TRACKING.url).then(function(){
      toast('Link copiado', 'ok');
    }).catch(function(){
      prompt('Copia el link:', TRACKING.url);
    });
  } else {
    prompt('Copia el link:', TRACKING.url);
  }
}

function trackingWA() {
  var r = TRACKING.rep, url = TRACKING.url;
  if (!r) return;
  var cli = DB.clis.find(function(c){ return c.id === r.clienteId; });
  var tel = (cli && cli.tel) ? waTel(cli.tel) : '';
  var msg = waMsg('recibida')(r.clienteNombre, r.marca, r.modelo, url);
  if (tel) {
    window.open('https://wa.me/' + tel + '?text=' + encodeURIComponent(msg));
  } else {
    window.open('https://wa.me/?text=' + encodeURIComponent(msg));
  }
}

