  AJUSTES.iva.modo = document.getElementById('ajIvaModo').value;
  AJUSTES.iva.tipoDefault = parseFloat(document.getElementById('ajIvaTipoDefault').value) || 21;
  var ajNomEl = document.getElementById('ajIvaNombre');
  if (ajNomEl) AJUSTES.iva.nombre = ajNomEl.value.trim() || 'IVA';
  var ajExtraEl = document.getElementById('ajIvaTiposExtra');
  if (ajExtraEl) {
    var extras = ajExtraEl.value.split(',').map(function(x){ return parseFloat(x.trim()); }).filter(function(x){ return !isNaN(x); });
    AJUSTES.iva.tiposPermitidos = extras.length ? extras : [0,4,10,21];
    AJUSTES.iva.tiposExtra = ajExtraEl.value.trim();
  }
  var ajNomEl = document.getElementById('ajIvaNombre');
  if (ajNomEl) AJUSTES.iva.nombre = ajNomEl.value.trim() || 'IVA';
  var ajExtraEl = document.getElementById('ajIvaTiposExtra');
  if (ajExtraEl) {
    var extras = ajExtraEl.value.split(',').map(function(x){ return parseFloat(x.trim()); }).filter(function(x){ return !isNaN(x); });
    AJUSTES.iva.tiposPermitidos = extras.length ? extras : [0,4,10,21];
    AJUSTES.iva.tiposExtra = ajExtraEl.value.trim();
  }
  if (!AJUSTES.iva.tiposPermitidos) AJUSTES.iva.tiposPermitidos = [0,4,10,21];
  // Notificaciones
  AJUSTES.notif = AJUSTES.notif || {};
