// ═══ SERVICIOS ═══
function renderServicios() {
  var el = document.getElementById('listaServicios');
  if (!DB.servicios || !DB.servicios.length) { el.innerHTML = '<div class="empty"><div class="empty-icon">\ud83d\udee0\ufe0f</div>Sin servicios</div>'; return; }
  var cats = {};
  DB.servicios.forEach(function(s) {
    if (!cats[s.categoria]) cats[s.categoria] = [];
    cats[s.categoria].push(s);
  });
  var html = '';
  Object.keys(cats).forEach(function(cat) {
    html += '<div style="font-size:10px;font-weight:700;color:var(--muted);text-transform:uppercase;padding:6px 0;border-bottom:2px solid var(--border);margin-bottom:8px">' + cat + '</div>';
    cats[cat].forEach(function(s) {
      var coste = parseFloat(s.precioCoste) || 0;
      var venta = parseFloat(s.precio) || 0;
      var margen = venta - coste;
      var precioHtml = '';
      if (s.precioFijo) {
        precioHtml = '<div style="display:flex;flex-direction:column;align-items:flex-end;gap:1px">';
        if (coste > 0) precioHtml += '<span style="font-size:10px;color:var(--muted)" title="Solo interno">🔒 Coste: <strong style="color:var(--orange)">' + cur(coste) + '</strong></span>';
        precioHtml += '<span style="font-size:14px;font-weight:700;color:var(--blue)">' + cur(venta) + '</span>';
        if (coste > 0 && margen !== 0) {
          var col = margen < 0 ? 'var(--red)' : 'var(--green)';
          var pct = venta > 0 ? Math.round((margen / venta) * 100) : 0;
          precioHtml += '<span style="font-size:10px;color:' + col + ';font-weight:700">+' + cur(margen) + ' (' + pct + '%)</span>';
        }
        precioHtml += '</div>';
      } else {
        precioHtml = '<span style="font-size:14px;font-weight:700;color:var(--blue)">Variable</span>';
      }
      var sid = String(s.id).replace(/'/g, "\\'");
      var tipoTxt = (s.tipo === 'reparacion' ? 'Solo reparaciones' : s.tipo === 'venta' ? 'Solo ventas' : 'Ventas y reparaciones');
      // onclick inline: con el patr\u00f3n anterior (addEventListener + cont.outerHTML)
      // la serializaci\u00f3n a string perd\u00eda los listeners y los botones no hac\u00edan nada.
      html += '<div class="card" style="padding:12px;margin-bottom:8px">' +
        '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px">' +
        '<div style="flex:1;min-width:0"><div style="font-size:13px;font-weight:700">' + escHtml(s.nombre || '') + '</div>' +
        '<div style="font-size:11px;color:var(--muted)">' + tipoTxt + '</div></div>' +
        precioHtml +
        '</div>' +
        '<button onclick="editarServicio(\'' + sid + '\')" style="background:var(--light);border:none;padding:4px 8px;border-radius:6px;font-size:11px;cursor:pointer;margin-top:8px;margin-right:6px">\u270f\ufe0f</button>' +
        '<button onclick="eliminarServicio(\'' + sid + '\')" style="background:rgba(239,68,68,.1);border:none;color:var(--red);padding:4px 8px;border-radius:6px;font-size:11px;cursor:pointer;margin-top:8px">\ud83d\uddd1\ufe0f</button>' +
        '</div>';
    });
  });
  el.innerHTML = html;
}

function limpiarFormSrv() {
  document.getElementById('srvNom').value = '';
  document.getElementById('srvPrecio').value = '';
  var pc = document.getElementById('srvPrecioCoste'); if (pc) pc.value = '';
  document.getElementById('srvCat').value = ''; // F288: arranca sin categoría (elección consciente)
  document.getElementById('srvTipo').value = 'ambos';
  document.getElementById('srvFijo').checked = true;
  var mb = document.getElementById('srvMargenBox'); if (mb) mb.style.display = 'none';
  document.getElementById('mServicioTit').textContent = T('srv.nuevo_titulo');
}

function calcMargenSrv() {
  var coste = parseFloat(document.getElementById('srvPrecioCoste').value) || 0;
  var venta = parseFloat(document.getElementById('srvPrecio').value) || 0;
  var box = document.getElementById('srvMargenBox');
  if (!box) return;
  if (coste <= 0 || venta <= 0) { box.style.display = 'none'; return; }
  var margen = venta - coste;
  var pct = (margen / venta) * 100;
  document.getElementById('srvMargenAbs').textContent = cur(margen);
  document.getElementById('srvMargenPct').textContent = pct.toFixed(0) + '%';
  // Color rojo si margen negativo
  var color = margen < 0 ? 'var(--red)' : 'var(--green)';
  document.getElementById('srvMargenAbs').style.color = color;
  document.getElementById('srvMargenPct').style.color = color;
  box.style.display = 'block';
}

function guardarServicio() {
  if (!tienePerm('servicios_crear')) { toast(T('gen.sin_permiso'), 'err'); return; }
  var nom = document.getElementById('srvNom').value.trim();
  // F240: validación de nombre (longitud + texto duplicado)
  var errSrv2 = _validarNombreServicio(nom);
  if (errSrv2) { toast(errSrv2, 'err'); return; }
  // F288: forzar elección de categoría (el select arranca en "— Selecciona —")
  if (!document.getElementById('srvCat').value) { toast(T('tst.elige_categoria'), 'err'); document.getElementById('srvCat').focus(); return; }
  // F374: evitar servicios duplicados por nombre (excluyendo el que se edita)
  var _nomNormSrv = _norm(nom);
  if ((DB.servicios || []).some(function(s) { return s.id !== ESID && _norm(s.nombre) === _nomNormSrv; })) {
    toast(T('tst.servicio_duplicado'), 'err'); return;
  }
  var pcEl = document.getElementById('srvPrecioCoste');
  var data = {
    nombre: nom,
    categoria: document.getElementById('srvCat').value,
    tipo: document.getElementById('srvTipo').value,
    precioFijo: document.getElementById('srvFijo').checked,
    precio: parseFloat(document.getElementById('srvPrecio').value) || 0,
    precioCoste: pcEl ? (parseFloat(pcEl.value) || 0) : 0
  };
  if (!DB.servicios) DB.servicios = [];
  if (ESID) {
    // MODO EDICIÓN
    var srv = DB.servicios.find(function(s) { return s.id === ESID; });
    if (srv) {
      Object.assign(srv, data);
      if (SB_KEY && TIENDA_ID) {
        sbPatch('servicios', 'id=eq.' + encodeURIComponent(srv.id), {
          nombre: srv.nombre,
          categoria: srv.categoria,
          tipo: srv.tipo,
          precio_fijo: srv.precioFijo,
          precio: srv.precio
        });
      }
    }
    ESID = null;
  } else {
    // MODO CREAR
    data.id = 'srv' + Date.now() + '_' + Math.random().toString(36).slice(2,8);
    DB.servicios.push(data);
    if (SB_KEY && TIENDA_ID) {
      sbPost('servicios', {
        id: data.id, tienda_id: TIENDA_ID,
        nombre: data.nombre, categoria: data.categoria, tipo: data.tipo,
        precio_fijo: data.precioFijo, precio: data.precio
      });
    }
  }
  guardarDatos();
  closeM('mServicio');
  toast(T('tst.servicio_guardado'), 'ok');
  renderServicios();
}

function editarServicio(id) {
  var s = (DB.servicios || []).find(function(x) { return x.id === id; });
  if (!s) return;
  ESID = id;
  document.getElementById('mServicioTit').textContent = T('srv.editar_titulo');
  document.getElementById('srvNom').value = s.nombre || '';
  document.getElementById('srvCat').value = s.categoria || 'Otro';
  document.getElementById('srvTipo').value = s.tipo || 'ambos';
  document.getElementById('srvFijo').checked = s.precioFijo !== false;
  document.getElementById('srvVariable').checked = s.precioFijo === false;
  document.getElementById('srvPrecio').value = s.precio || '';
  var pc = document.getElementById('srvPrecioCoste');
  if (pc) pc.value = s.precioCoste || '';
  calcMargenSrv();
  openM('mServicio');
}

function eliminarServicio(id) {
  if (!tienePerm('servicios_eliminar')) { toast(T('gen.sin_permiso'), 'err'); return; }
  if (!confirm('Eliminar este servicio?')) return;
  DB.servicios = (DB.servicios || []).filter(function(s) { return s.id !== id; });
  if (SB_KEY && TIENDA_ID) sbDelete('servicios', 'id=eq.' + encodeURIComponent(id));  // faltaba: borrar también en la nube
  guardarDatos();
  toast(T('tst.eliminado'), 'ok');
  renderServicios();
}

// ═══ CATÁLOGO (stock por modelo) — integrado, sincronizado con Supabase ═══
var _catFiltro = '';
var _catFiltroMarca = '';
// Swatch de color para el desglose por color (nombres comunes ES/EN)
var CAT_COLOR_HEX = { negro:'#222', black:'#222', blanco:'#eee', white:'#eee', azul:'#2563eb', blue:'#2563eb', rojo:'#dc2626', red:'#dc2626', verde:'#16a34a', green:'#16a34a', dorado:'#d4af37', gold:'#d4af37', plata:'#c0c0c0', silver:'#c0c0c0', gris:'#6b7280', gray:'#6b7280', grey:'#6b7280', rosa:'#ec4899', pink:'#ec4899', morado:'#7c3aed', purple:'#7c3aed', violeta:'#7c3aed', amarillo:'#eab308', yellow:'#eab308', naranja:'#f97316', orange:'#f97316', titanio:'#8a8d8f', grafito:'#383838' };
function _catColorHex(c) { var k = (c || '').toLowerCase().replace(/[^a-z]/g, ''); for (var key in CAT_COLOR_HEX) { if (k.indexOf(key) !== -1) return CAT_COLOR_HEX[key]; } return '#cbd5e1'; }
var CAT_CALIDADES = [
  { v: 'Nuevo', k: 'catalogo.cal_nuevo', bg: 'rgba(22,163,74,.12)', col: '#16A34A' },
  { v: 'Reacondicionado', k: 'catalogo.cal_reacond', bg: 'rgba(0,85,255,.10)', col: 'var(--blue)' },
  { v: 'Bueno', k: 'catalogo.cal_bueno', bg: 'rgba(202,138,4,.12)', col: '#CA8A04' },
  { v: 'Regular', k: 'catalogo.cal_regular', bg: 'rgba(220,38,38,.10)', col: '#DC2626' },
  { v: 'Para piezas', k: 'catalogo.cal_piezas', bg: 'rgba(100,116,139,.12)', col: '#64748B' }
];
// Calidades de PANTALLA (términos técnicos universales, sin traducción). Permite distinguir
// varias pantallas del mismo modelo por su tipo. Otras categorías usan CAT_CALIDADES (condición).
var CALIDADES_PANTALLA = [
  { v: 'Original', bg: 'rgba(22,163,74,.12)', col: '#16A34A' },
  { v: 'OLED', bg: 'rgba(124,92,252,.12)', col: '#7C5CFC' },
  { v: 'Soft OLED', bg: 'rgba(124,92,252,.10)', col: '#7C5CFC' },
  { v: 'Hard OLED', bg: 'rgba(0,85,255,.10)', col: 'var(--blue)' },
  { v: 'Incell', bg: 'rgba(202,138,4,.12)', col: '#CA8A04' },
  { v: 'TFT', bg: 'rgba(100,116,139,.12)', col: '#64748B' }
];
// Lista de calidades aplicable según la categoría del producto
function calidadesDe(cat) { return cat === 'Pantalla' ? CALIDADES_PANTALLA : CAT_CALIDADES; }
// Etiqueta de una calidad (i18n si tiene clave, si no el valor literal)
function calLabel(c) { return (c && c.k) ? T(c.k) : (c ? c.v : ''); }
function _catNombre(cat) {
  var map = { 'Telefono': 'stock.cat_telefono', 'Tablet': 'stock.cat_tablet', 'Smartwatch': 'stock.cat_smartwatch', 'Pantalla': 'stock.cat_pantalla', 'Tapa': 'stock.cat_tapa', 'Bateria': 'stock.cat_bateria', 'Flex de Carga': 'stock.cat_flex', 'Altavoz': 'stock.cat_altavoz', 'Repuesto': 'stock.cat_repuesto', 'Accesorio': 'stock.cat_accesorio', 'Otro': 'stock.cat_otro' };
  return map[cat] ? T(map[cat]) : cat;
}
function setCatFiltro(f, btn) {
  _catFiltro = f;
  _catFiltroMarca = '';  // al cambiar de categoría, limpiar filtro de marca
  try { Array.prototype.forEach.call(document.querySelectorAll('#catTabs .cat-tab-btn'), function(b) { b.classList.toggle('active', b === btn); }); } catch(e){}
  renderCatalogo();
}
function setCatFiltroMarca(m) {
  _catFiltroMarca = (_catFiltroMarca === m) ? '' : m;  // toggle
  renderCatalogo();
}
// Chips de marca del catálogo (marcas presentes en la categoría activa)
function renderCatFiltroMarcas(catBase) {
  var box = document.getElementById('catMarcasFiltro'); if (!box) return;
  var counts = {};
  (catBase || []).forEach(function(s) {
    var m = (s.marca || '').trim(); if (!m) return;
    var k = m.toLowerCase();
    if (!counts[k]) counts[k] = { nombre: m, n: 0 };
    counts[k].n += (parseInt(s.unidades, 10) || 1);
  });
  var arr = Object.keys(counts).map(function(k) { return counts[k]; }).sort(function(a, b) { return b.n - a.n; });
  if (arr.length < 2) { box.style.display = 'none'; box.innerHTML = ''; return; }
  box.style.display = 'flex';
  var sel = (_catFiltroMarca || '').toLowerCase();
  var chip = function(val, on, inner) {
    return '<button type="button" onclick="setCatFiltroMarca(\'' + (val || '').replace(/'/g, "\\'") + '\')" style="display:inline-flex;align-items:center;gap:6px;padding:5px 11px;border-radius:18px;border:1.5px solid ' + (on ? 'var(--orange)' : 'var(--border)') + ';background:' + (on ? 'rgba(249,115,22,.10)' : '#fff') + ';color:var(--text);font:inherit;font-size:12px;font-weight:600;cursor:pointer;white-space:nowrap">' + inner + '</button>';
  };
  var html = chip('', !sel, '🏷️ ' + T('tpv.todas_marcas'));
  html += arr.slice(0, 16).map(function(o) {
    return chip(o.nombre, o.nombre.toLowerCase() === sel, _stkBrandChip(o.nombre) + '<span>' + escHtml(_tcMarca(o.nombre)) + '</span><span style="color:var(--muted);font-weight:700">' + o.n + '</span>');
  }).join('');
  box.innerHTML = html;
}
// F14-15: marcas consistentes en el catálogo. La agrupación ya es case-insensitive,
// pero el display tomaba la caja del PRIMER item ("samsung" vs "Samsung"). Capitaliza
// la 1ª letra de cada palabra sin tocar el resto (no rompe acrónimos tipo "BQ").
function _tcMarca(s) {
  return String(s || '').replace(/(^|[\s\-/])(\S)/g, function(m, p, c) { return p + c.toUpperCase(); });
}
// F15: Title Case para modelos preservando mayúsculas conocidas (no rompe "iPhone").
// Diccionario para tokens que NO son simple capitalización; el resto se capitaliza
// solo si venían todo en minúscula (palabras con mayúsculas internas se respetan).
var _MODELO_DICT = {
  iphone: 'iPhone', ipad: 'iPad', ipod: 'iPod', imac: 'iMac', macbook: 'MacBook',
  airpods: 'AirPods', galaxy: 'Galaxy', redmi: 'Redmi', poco: 'POCO', oneplus: 'OnePlus',
  realme: 'realme', xiaomi: 'Xiaomi', huawei: 'Huawei', honor: 'Honor', oppo: 'OPPO',
  vivo: 'vivo', moto: 'Moto', nokia: 'Nokia', pixel: 'Pixel', mate: 'Mate', nova: 'Nova',
  se: 'SE', plus: 'Plus', pro: 'Pro', max: 'Max', mini: 'Mini', ultra: 'Ultra',
  lite: 'Lite', note: 'Note', edge: 'Edge', fold: 'Fold', flip: 'Flip', neo: 'Neo'
};
function _tcModelo(s) {
  s = String(s || '').trim();
  if (!s) return s;
  return s.split(/\s+/).map(function(w) {
    var lw = w.toLowerCase();
    if (_MODELO_DICT[lw]) return _MODELO_DICT[lw];
    if (/^[a-z]/.test(w) && /\d/.test(w)) return w.charAt(0).toUpperCase() + w.slice(1); // a52 → A52
    if (w === lw) return w.charAt(0).toUpperCase() + w.slice(1);                          // galaxy → Galaxy
    return w; // ya tiene mayúsculas internas (iPhone, BQ, 5G) → respetar
  }).join(' ');
}
function renderCatalogo() {
  var el = document.getElementById('catalogoContainer'); if (!el) return;
  var qEl = document.getElementById('catSearch');
  var q = (qEl ? qEl.value : '').toLowerCase();
  var filtro = _catFiltro || '';
  var marcaF = (_catFiltroMarca || '').toLowerCase();
  // Base filtrada solo por categoría (para construir los chips de marca).
  // Solo items con stock real (>0), igual que la página de Stock — así no
  // aparecen modelos agotados que confundían (ej: "Repuestos" a 0 unidades).
  var catBase = (DB.stock || []).filter(function(s) { return !s.vendido && (parseInt(s.unidades, 10) || 0) > 0 && (!filtro || (s.categoria || 'Otro') === filtro); });
  renderCatFiltroMarcas(catBase);
  // Mapa stockId → color (incluye vendidos) para contar ventas por color
  var stockColor = {};
  (DB.stock || []).forEach(function(s) { stockColor[s.id] = (s.color || '').trim(); });
  var grupos = {};
  catBase.forEach(function(s) {
    var marca = s.marca || '—', modelo = s.modelo || '—';
    if (marcaF && marca.toLowerCase() !== marcaF) return;
    if (q && (marca + ' ' + modelo + ' ' + (s.imei || '') + ' ' + (s.color || '')).toLowerCase().indexOf(q) === -1) return;
    var cat = s.categoria || 'Otro';
    var key = cat + '::' + marca.toLowerCase() + '::' + modelo.toLowerCase();
    if (!grupos[key]) grupos[key] = { cat: cat, marca: _tcMarca(marca), modelo: _tcModelo(modelo), unidades: 0, conImei: 0, pvp: 0, calidad: '', ids: [], colores: {} };
    var g = grupos[key];
    g.unidades += parseInt(s.unidades, 10) || 0;
    if (s.imei) g.conImei++;
    if ((parseFloat(s.precioV) || 0) > 0 && !g.pvp) g.pvp = parseFloat(s.precioV) || 0;
    if (s.calidad && !g.calidad) g.calidad = s.calidad;
    g.ids.push(s.id);
    var col = (s.color || '').trim();
    if (col) { if (!g.colores[col]) g.colores[col] = { stock: 0, vend: 0 }; g.colores[col].stock += parseInt(s.unidades, 10) || 0; }
    if (s.imei) { g.units = g.units || []; g.units.push({ imei: s.imei, color: col, precio: parseFloat(s.precioV) || 0 }); }
  });
  // Conteos de reparaciones y ventas por marca|modelo (+ ventas por color vía stockId)
  var repC = {}, venC = {};
  (DB.reps || []).forEach(function(r) { var k = ((r.marca || '') + '|' + (r.modelo || '')).toLowerCase(); repC[k] = (repC[k] || 0) + 1; });
  (DB.ventas || []).forEach(function(v) {
    if (v.reembolsado) return;
    var k = ((v.marca || '') + '|' + (v.modelo || '')).toLowerCase(); venC[k] = (venC[k] || 0) + 1;
    // ventas por color: resolver color del item vendido (match case-insensitive)
    var col = stockColor[v.stockId] || '';
    if (col) {
      var vm = (v.marca || '').toLowerCase(), vmod = (v.modelo || '').toLowerCase();
      Object.keys(grupos).forEach(function(gk) { var g = grupos[gk]; if ((g.marca || '').toLowerCase() === vm && (g.modelo || '').toLowerCase() === vmod && g.colores[col]) g.colores[col].vend++; });
    }
  });
  var keys = Object.keys(grupos);
  var tot = document.getElementById('catTotal'); if (tot) tot.textContent = keys.length ? (keys.length + ' ' + T('catalogo.modelos')) : '';
  if (!keys.length) { el.innerHTML = '<div class="empty"><div class="empty-icon">📚</div>' + T('catalogo.sin') + '</div>'; return; }
  var catGroups = {};
  keys.forEach(function(k) { var it = grupos[k]; (catGroups[it.cat] = catGroups[it.cat] || []).push(it); });
  var html = '';
  Object.keys(catGroups).sort().forEach(function(cat) {
    var items = catGroups[cat].sort(function(a, b) { return (a.marca + a.modelo).localeCompare(b.marca + b.modelo); });
    html += '<div style="font-size:10px;font-weight:700;color:var(--muted);text-transform:uppercase;padding:6px 0;border-bottom:2px solid var(--border);margin:14px 0 8px">' + escHtml(_catNombre(cat)) + ' (' + items.length + ')</div>';
    items.forEach(function(it) {
      var rk = (it.marca + '|' + it.modelo).toLowerCase();
      var reps = repC[rk] || 0, vens = venC[rk] || 0;
      var imeiTag = it.conImei > 0 ? '<span style="font-size:10px;color:var(--muted)"> · 📱 ' + it.conImei + ' ' + T('catalogo.con_imei') + '</span>' : '';
      var pvpTag = (it.conImei === 0 && it.pvp > 0) ? '<span style="font-size:11px;color:var(--green);font-weight:700;margin-left:6px">' + cur(it.pvp) + '</span>' : '';
      var calBadge = _catCalBadge(it);
      var stockCol = it.unidades <= 0 ? 'var(--red)' : 'var(--blue)';
      html += '<div class="card" style="padding:12px;margin-bottom:8px">' +
        '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px">' +
        '<div style="flex:1;min-width:0">' +
        '<div style="font-size:13px;font-weight:700">' + escHtml(it.marca) + ' ' + escHtml(it.modelo) + pvpTag + imeiTag + '</div>' +
        calBadge +
        '</div>' +
        '<div style="display:flex;gap:12px;text-align:center;flex-shrink:0">' +
        '<div><div style="font-size:18px;font-weight:800;color:' + stockCol + '">' + it.unidades + '</div><div style="font-size:9px;color:var(--muted)">' + T('catalogo.stock') + '</div></div>' +
        '<div><div style="font-size:18px;font-weight:800;color:#7C3AED">' + reps + '</div><div style="font-size:9px;color:var(--muted)">' + T('catalogo.reparaciones') + '</div></div>' +
        '<div><div style="font-size:18px;font-weight:800;color:var(--green)">' + vens + '</div><div style="font-size:9px;color:var(--muted)">' + T('catalogo.ventas') + '</div></div>' +
        '</div></div>' +
        _catColoresHtml(it) +
        _catUnidadesHtml(it) +
        '</div>';
    });
  });
  el.innerHTML = html;
}
// Desglose por color de un modelo: stock y vendidas por color, el más vendido marcado
function _catColoresHtml(it) {
  var cols = Object.keys(it.colores || {});
  if (cols.length < 2) return '';  // solo tiene sentido si hay varios colores
  var maxVend = 0; cols.forEach(function(c) { if (it.colores[c].vend > maxVend) maxVend = it.colores[c].vend; });
  cols.sort(function(a, b) { return (it.colores[b].vend - it.colores[a].vend) || (it.colores[b].stock - it.colores[a].stock); });
  var pills = cols.map(function(c) {
    var o = it.colores[c];
    var top = (maxVend > 0 && o.vend === maxVend) ? ' 🔥' : '';
    var vendTxt = o.vend > 0 ? ' · <span style="color:var(--green);font-weight:700">' + o.vend + ' ' + T('catalogo.vend') + '</span>' : '';
    return '<span style="display:inline-flex;align-items:center;gap:5px;background:var(--light);border-radius:12px;padding:3px 9px;font-size:11px">' +
      '<span style="width:10px;height:10px;border-radius:50%;border:1px solid rgba(0,0,0,.15);background:' + _catColorHex(c) + ';flex-shrink:0"></span>' +
      '<span style="font-weight:600">' + escHtml(c) + '</span>' +
      '<span style="color:var(--muted)">' + o.stock + '</span>' + vendTxt + top + '</span>';
  }).join('');
  return '<div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:9px;padding-top:9px;border-top:1px dashed var(--border)">' + pills + '</div>';
}
// Lista de unidades con IMEI: muestra IMEI · color · precio de cada teléfono
function _catUnidadesHtml(it) {
  if (!it.units || !it.units.length) return '';
  var rows = it.units.slice(0, 30).map(function(u) {
    var colDot = u.color ? '<span style="display:inline-flex;align-items:center;gap:4px"><span style="width:9px;height:9px;border-radius:50%;border:1px solid rgba(0,0,0,.15);background:' + _catColorHex(u.color) + '"></span>' + escHtml(u.color) + '</span>' : '';
    var precio = u.precio > 0 ? '<span style="color:var(--green);font-weight:700">' + cur(u.precio) + '</span>' : '';
    var parts = ['<span style="font-family:monospace;font-size:11px">' + escHtml(u.imei) + '</span>', colDot, precio].filter(Boolean).join(' <span style="color:var(--border)">·</span> ');
    return '<div style="display:flex;align-items:center;gap:6px;font-size:11.5px;padding:3px 0;color:var(--ink2,#475569)">📱 ' + parts + '</div>';
  }).join('');
  var mas = it.units.length > 30 ? '<div style="font-size:10px;color:var(--muted);padding-top:3px">+ ' + (it.units.length - 30) + '…</div>' : '';
  return '<div style="margin-top:9px;padding-top:9px;border-top:1px dashed var(--border)">' + rows + mas + '</div>';
}
function _catCalBadge(it) {
  var encIds = encodeURIComponent(JSON.stringify(it.ids));
  var _listaCal = (typeof calidadesDe === 'function') ? calidadesDe(it.cat) : CAT_CALIDADES;
  var curCal = _listaCal.filter(function(c) { return c.v === it.calidad; })[0];
  var opts = '<option value="">' + T('catalogo.calidad') + '</option>' + _listaCal.map(function(c) {
    return '<option value="' + c.v + '"' + (c.v === it.calidad ? ' selected' : '') + '>' + calLabel(c) + '</option>';
  }).join('');
  var style = curCal
    ? 'background:' + curCal.bg + ';color:' + curCal.col
    : 'background:var(--light);color:var(--muted)';
  return '<select onchange="setCalidadModelo(this.getAttribute(\'data-ids\'),this.value)" data-ids="' + escHtml(encIds) + '" style="margin-top:5px;border:none;border-radius:10px;font-size:10px;font-weight:700;padding:3px 8px;cursor:pointer;font-family:inherit;' + style + '">' + opts + '</select>';
}
function setCalidadModelo(encIds, cal) {
  var ids;
  try { ids = JSON.parse(decodeURIComponent(encIds)); } catch(e) { return; }
  if (!Array.isArray(ids)) return;
  (DB.stock || []).forEach(function(s) {
    if (ids.indexOf(s.id) === -1) return;
    s.calidad = cal;
    if (SB_KEY && TIENDA_ID) sbPatch('stock', 'id=eq.' + encodeURIComponent(s.id), { calidad: cal });
  });
  guardarDatos();
  renderCatalogo();
}

// ═══ USUARIOS ═══
async function cargarUsuarios() {
  var el = document.getElementById('listaUsuarios');
  if (!SB_KEY || !TIENDA_ID) { el.innerHTML = '<div class="empty">Necesitas Supabase configurado</div>'; return; }
  // Multi-tienda: si el dueño tiene >1 tienda, cargar qué tiendas puede otorgar y el acceso actual.
  if (_esAdmin()) {
    try {
      var mr = await fetch('/api/login', { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (JWT_TOKEN || '') }, body: JSON.stringify({ action: 'usuarios-admin', op: 'map-tiendas' }) });
      var mj = await mr.json().catch(function() { return {}; });
      if (mj && mj.ok) { MIS_TIENDAS_ADMIN = mj.mis_tiendas || []; _TIENDAS_MAP = mj.map || {}; }
    } catch (e) { /* sin multi-tienda */ }
  }
  var lista = await sbGet('usuarios', 'tienda_id=eq.' + TIENDA_ID);
  if (!lista || !lista.length) { el.innerHTML = '<div class="empty">Sin usuarios</div>'; return; }
  var container = document.createElement('div');
  container.className = 'tbl-wrap';
  var table = document.createElement('table');
  table.className = 'tbl';
  table.innerHTML = '<thead><tr><th>Nombre</th><th><span data-t="gen.rol">Rol</span></th><th>Estado</th><th></th></tr></thead>';
  var tbody = document.createElement('tbody');
  lista.forEach(function(u) {
    var esYo = U && u.email === U.email;
    var tr = document.createElement('tr');
    tr.innerHTML = '<td><strong>' + escHtml(u.nombre) + '</strong>' + (esYo ? ' <span class="badge bb">Tu</span>' : '') + '<br><span style="font-size:10px;color:var(--muted)">' + escHtml(u.email) + '</span></td>' +
      '<td><span class="badge ' + (u.rol === 'admin' ? 'br' : 'bb') + '">' + u.rol + '</span></td>' +
      '<td><span class="badge ' + (u.activo ? 'bg' : 'bo') + '">' + (u.activo ? 'Activo' : 'Inactivo') + '</span></td>';
    var tdAcc = document.createElement('td');
    tdAcc.style = 'display:flex;gap:3px;flex-wrap:wrap';
    // Botón de permisos: TODOS pueden editarse a sí mismos (para configurar widgets propios)
    var btnP = document.createElement('button');
    btnP.textContent = '\ud83d\udd10';
    btnP.style = 'background:rgba(255,91,31,.1);border:none;color:var(--purple);padding:4px 7px;border-radius:6px;font-size:10px;cursor:pointer';
    btnP.title = esYo ? 'Mis permisos y widgets' : 'Editar permisos';
    btnP.dataset.uid = u.id; btnP.dataset.unom = u.nombre;
    btnP.addEventListener('click', function() { editarPermisos(this.dataset.uid, this.dataset.unom); });
    tdAcc.appendChild(btnP);
    // Código para fichar la caja (admin se lo da a cada empleado)
    var btnC = document.createElement('button');
    btnC.textContent = u.codigo ? ('🔢 ' + u.codigo) : '🔢';
    btnC.style = 'background:rgba(0,85,255,.1);border:none;color:var(--blue);padding:4px 7px;border-radius:6px;font-size:10px;cursor:pointer';
    btnC.title = 'Código para fichar la caja';
    btnC.dataset.uid = u.id; btnC.dataset.unom = u.nombre; btnC.dataset.ucod = u.codigo || '';
    btnC.addEventListener('click', function() { setCodigoUsuario(this.dataset.uid, this.dataset.unom, this.dataset.ucod); });
    tdAcc.appendChild(btnC);
    // Multi-tienda: a qué tiendas puede entrar este empleado (solo si el dueño tiene >1 tienda, y no a uno mismo)
    if (!esYo && MIS_TIENDAS_ADMIN.length > 1) {
      var nExtra = (_TIENDAS_MAP[u.id] || []).filter(function(id) { return String(id) !== String(TIENDA_ID); }).length;
      var btnTi = document.createElement('button');
      btnTi.textContent = '🏪' + (nExtra > 0 ? ' ' + (nExtra + 1) : '');
      btnTi.style = 'background:rgba(255,91,31,.1);border:none;color:var(--orange);padding:4px 7px;border-radius:6px;font-size:10px;cursor:pointer';
      btnTi.title = T('mt.acceso_titulo');
      btnTi.dataset.uid = u.id; btnTi.dataset.unom = u.nombre;
      btnTi.addEventListener('click', function() { asignarTiendas(this.dataset.uid, this.dataset.unom); });
      tdAcc.appendChild(btnTi);
    }
    // Desactivar y eliminar solo a OTROS usuarios (no a uno mismo)
    if (!esYo) {
      var btnT = document.createElement('button');
      btnT.textContent = u.activo ? 'Desact.' : 'Activar';
      btnT.style = 'background:var(--light);border:none;color:var(--blue);padding:4px 7px;border-radius:6px;font-size:10px;cursor:pointer';
      btnT.dataset.uid = u.id; btnT.dataset.activo = u.activo ? '1' : '0';
      btnT.addEventListener('click', function() { toggleUsuario(this.dataset.uid, this.dataset.activo === '1'); });
      var btnD = document.createElement('button');
      btnD.textContent = '\ud83d\uddd1\ufe0f';
      btnD.style = 'background:rgba(239,68,68,.1);border:none;color:var(--red);padding:4px 7px;border-radius:6px;font-size:10px;cursor:pointer';
      btnD.dataset.uid = u.id;
      btnD.addEventListener('click', function() { eliminarUsuario(this.dataset.uid); });
      tdAcc.appendChild(btnT); tdAcc.appendChild(btnD);
    }
    tr.appendChild(tdAcc);
    tbody.appendChild(tr);
  });
  table.appendChild(tbody);
  container.appendChild(table);
  el.innerHTML = '';
  el.appendChild(container);
}

var PLAN_LIMITES = {basico: 1, pro: 3, top: 999};

// F341: antes usaba 4 prompt() nativos en cadena → bloqueaban el renderer (y colgaban la
// automatización >30s). Ahora abre un modal en condiciones. El límite de plan se valida en
// crearUsuario(), así que aquí solo abrimos el formulario.
function openNuevoUsuario() {
  ['nuNombre', 'nuEmail', 'nuPass'].forEach(function(id) { var el = document.getElementById(id); if (el) el.value = ''; });
  var rol = document.getElementById('nuRol'); if (rol) rol.value = 'empleado';
  openM('mNuevoUsuario');
  setTimeout(function() { var n = document.getElementById('nuNombre'); if (n) n.focus(); }, 100);
}

function submitNuevoUsuario() {
  var nom = (document.getElementById('nuNombre').value || '').trim();
  var email = (document.getElementById('nuEmail').value || '').trim();
  var pass = (document.getElementById('nuPass').value || '');
  var rol = (document.getElementById('nuRol') || {}).value || 'empleado';
  if (!nom) { toast(T('tst.escribe_nombre'), 'err'); return; }
  if (!email || email.indexOf('@') < 1) { toast(T('tst.email_invalido'), 'err'); return; }
  if (pass.length < 8) { toast('La contraseña debe tener al menos 8 caracteres', 'err'); return; }
  closeM('mNuevoUsuario');
  crearUsuario(nom, email, pass, rol);
}

// Gestión de usuarios vía backend (login.js ?action=usuarios-admin) en lugar de escribir
// 'usuarios' directo: el servidor verifica que eres admin de la tienda, hashea con bcrypt y
// filtra los campos (evita escalada de privilegios y exposición de hashes en el navegador).
async function _adminUsuarios(op, payload) {
  try {
    var r = await fetch('/api/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (JWT_TOKEN || '') },
      body: JSON.stringify(Object.assign({ action: 'usuarios-admin', op: op }, payload))
    });
    var data = await r.json().catch(function(){ return {}; });
    if (!r.ok || !data.ok) { toast(data.error || ('Error (HTTP ' + r.status + ')'), 'err'); return false; }
    return true;
  } catch (e) { toast('Sin conexión', 'err'); return false; }
}

async function setCodigoUsuario(uid, nom, actual) {
  var cod = prompt('Código (PIN) de ' + nom + ' para fichar la caja.\n3-12 dígitos. Vacío = quitar el código.', actual || '');
  if (cod === null) return;  // cancelado
  cod = cod.trim();
  if (cod && !/^[0-9]{3,12}$/.test(cod)) { toast(T('tst.codigo_3_12'), 'err'); return; }
  var ok = await _adminUsuarios('codigo', { target_id: uid, codigo: cod });
  if (ok) { toast(cod ? 'Código guardado' : 'Código quitado', 'ok'); cargarUsuarios(); }
}

async function crearUsuario(nom, email, pass, rol) {
  // Comprobar límite de usuarios del plan actual
  var limite = (PLAN_LIMITS[PLAN_INFO.plan] || PLAN_LIMITS.basico).usuarios;
  var actuales = (DB.usuarios || []).filter(function(u){ return u.activo !== false; }).length;
  if (actuales >= limite) {
    var planMin = limite < 3 ? 'pro' : 'premium';
    mostrarModalUpgrade('permisos_usuarios', planMin);
    toast(T('tst.limite_usuarios').replace('{n}', limite), 'err');
    return;
  }
  // El backend hashea con bcrypt y asigna tienda_id/rol de forma segura.
  var ok = await _adminUsuarios('crear', { nombre: nom, email: email, password: pass, rol: rol });
  if (ok) { toast(T('tst.usuario_creado'), 'ok'); cargarUsuarios(); }
}

async function toggleUsuario(id, activo) {
  var ok = await _adminUsuarios('toggle', { target_id: id, activo: !activo });
  if (ok) { toast(activo ? 'Desactivado' : 'Activado', 'ok'); cargarUsuarios(); }
}

async function eliminarUsuario(id) {
  if (!confirm('Eliminar usuario?')) return;
  var ok = await _adminUsuarios('borrar', { target_id: id });
  if (ok) { toast(T('tst.eliminado'), 'ok'); cargarUsuarios(); }
}

// ═══ PERMISOS ═══

// ═══ APLICAR PERMISOS ═══
// Re-lee rol/permisos del usuario logueado desde Supabase y actualiza la sesión.
// Soluciona que un cambio de permisos por el admin no llegaba hasta cerrar sesión.
function refrescarPermisosSesion() {
  if (!SB_KEY || !JWT_TOKEN || !U || !U.id) return;
  sbGet('usuarios', 'id=eq.' + encodeURIComponent(U.id) + '&select=rol,permisos,activo').then(function(rows) {
    var u = rows && rows[0];
    if (!u) return;
    var changed = false;
    if (u.permisos && typeof u.permisos === 'object' && JSON.stringify(u.permisos) !== JSON.stringify(U.permisos || {})) { U.permisos = u.permisos; changed = true; }
    if (u.rol && u.rol !== U.rol) { U.rol = u.rol; changed = true; }
    if (!changed) return;
    try { localStorage.setItem('tk_user', JSON.stringify(U)); } catch(e){}
    try { var s = JSON.parse(localStorage.getItem('tk_sess') || '{}'); if (s.usuario) { s.usuario.permisos = U.permisos; s.usuario.rol = U.rol; localStorage.setItem('tk_sess', JSON.stringify(s)); } } catch(e){}
    try { aplicarPermisos(); } catch(e){}
    try { if (typeof refrescarVistasActivas === 'function') refrescarVistasActivas(); } catch(e){}
  }).catch(function(){});
}
function tienePerm(perm) {
  if (!U) return false;
  if (U.rol === 'admin') return true;
  if (!U.permisos) return false;
  if (U.permisos.todo) return true;
  return U.permisos[perm] === true;
}

// Para widgets: visible por defecto, solo se oculta si el usuario pone explícitamente false
function widgetVisible(perm) {
  if (!U) return false;
  if (U.permisos && U.permisos[perm] === false) return false;
  return true;
}

// ═══ BÚSQUEDA GLOBAL ═══
var _busquedaGlobalResultados = [];
var _busquedaGlobalSel = 0;

function abrirBusquedaGlobal() {
  document.getElementById('mBuscarGlobal').classList.add('show');
  setTimeout(function() {
    var inp = document.getElementById('busquedaGlobalInput');
    if (inp) { inp.value = ''; inp.focus(); }
    renderBusquedaGlobal();
  }, 30);
}

function cerrarBusquedaGlobal() {
  document.getElementById('mBuscarGlobal').classList.remove('show');
}

function renderBusquedaGlobal() {
  var q = _norm(document.getElementById('busquedaGlobalInput').value);
  var box = document.getElementById('busquedaGlobalResultados');
  var countEl = document.getElementById('busquedaGlobalCount');
  if (!q || q.length < 2) {
    box.innerHTML = '<div class="search-global-empty">' + T('busq.min_letras') + '</div>';
    if (countEl) countEl.textContent = '';
    _busquedaGlobalResultados = [];
    return;
  }
  var results = [];

  // Clientes
  if (tienePerm('clis_ver')) {
    DB.clis.forEach(function(c) {
      var hay = _norm((c.nombre||'') + ' ' + (c.apellidos||'') + ' ' + (c.tel||'') + ' ' + (c.dni||'') + ' ' + (c.email||''));
      if (hay.indexOf(q) !== -1) {
        results.push({tipo:'cliente', icon:'👤', titulo:((c.nombre||'') + ' ' + (c.apellidos||'')).trim() || 'Sin nombre', sub:[c.tel, c.dni, c.email].filter(Boolean).join(' · ') || '—', id:c.id});
      }
    });
  }

  // Reparaciones
  if (tienePerm('reps_ver')) {
    DB.reps.forEach(function(r) {
      var cli = (DB.clis.find(function(c){ return c.id === r.clienteId; }) || {});
      var hay = _norm((r.marca||'') + ' ' + (r.modelo||'') + ' ' + (r.averia||'') + ' ' + (cli.nombre||'') + ' ' + (cli.apellidos||'') + ' ' + (r.imei||''));
      if (hay.indexOf(q) !== -1) {
        results.push({tipo:'rep', icon:'🔧', titulo:((r.marca||'') + ' ' + (r.modelo||'')).trim() + ' · ' + (r.averia||'').slice(0,40), sub:(cli.nombre||T('gen.sin_cliente')) + ' · ' + _estadoLabel(r.estado||'') + ' · ' + cur(r.total||0), id:r.id});
      }
    });
  }

  // Ventas
  if (tienePerm('ventas_ver')) {
    DB.ventas.forEach(function(v) {
      var cli = (DB.clis.find(function(c){ return c.id === v.clienteId; }) || {});
      var hay = _norm((v.marca||'') + ' ' + (v.modelo||'') + ' ' + (cli.nombre||'') + ' ' + (cli.apellidos||'') + ' ' + (v.imei||''));
      if (hay.indexOf(q) !== -1) {
        results.push({tipo:'venta', icon:'📱', titulo:((v.marca||'') + ' ' + (v.modelo||'')).trim() || 'Venta', sub:(cli.nombre||T('gen.sin_cliente')) + ' · ' + (v.fecha||'') + ' · ' + cur(v.total||0) + (v.reembolsado?' · ↩ REEMBOLSADA':''), id:v.id});
      }
    });
  }

  // Stock
  if (tienePerm('stock_ver')) {
    DB.stock.forEach(function(s) {
      if (s.vendido) return;
      var hay = _norm((s.tipo||'') + ' ' + (s.marca||'') + ' ' + (s.modelo||'') + ' ' + (s.imei||''));
      if (hay.indexOf(q) !== -1) {
        results.push({tipo:'stock', icon:'📦', titulo:((s.tipo||'') + ' ' + (s.marca||'') + ' ' + (s.modelo||'')).trim(), sub:s.unidades + ' uds · ' + cur(s.precioV||0) + (s.imei?(' · IMEI ' + s.imei):''), id:s.id});
      }
    });
  }

  // Servicios
  if (tienePerm('servicios_ver')) {
    (DB.servicios || []).forEach(function(s) {
      var hay = _norm((s.nombre||'') + ' ' + (s.descripcion||''));
      if (hay.indexOf(q) !== -1) {
        results.push({tipo:'servicio', icon:'🛠️', titulo:s.nombre, sub:cur(s.precio||0) + ' · ' + (s.descripcion||'').slice(0,60), id:s.id});
      }
    });
  }

  results = results.slice(0, 30);
  _busquedaGlobalResultados = results;
  _busquedaGlobalSel = 0;

  if (countEl) countEl.textContent = results.length + ' resultado' + (results.length === 1 ? '' : 's');

  if (!results.length) {
    box.innerHTML = '<div class="search-global-empty">' + T('busq.sin_resultados').replace('{q}', esc(q)) + '</div>';
    return;
  }

  var grupos = [['cliente',T('nav.clientes')],['rep',T('nav.reparaciones')],['venta',T('nav.ventas')],['stock',T('nav.stock')],['servicio',T('nav.servicios')]];
  var html = '';
  var idx = 0;
  grupos.forEach(function(g) {
    var items = results.filter(function(r){ return r.tipo === g[0]; });
    if (!items.length) return;
    html += '<div class="search-global-group">' + g[1] + '</div>';
    items.forEach(function(it) {
      var isSel = idx === _busquedaGlobalSel;
      html += '<div class="search-global-item' + (isSel ? ' selected' : '') + '" data-idx="' + idx + '" onclick="ejecutarBusquedaGlobal(' + idx + ')">';
      html += '<span class="search-global-icon">' + it.icon + '</span>';
      html += '<div style="flex:1;min-width:0">';
      html += '<div class="search-global-title" style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + esc(it.titulo) + '</div>';
      html += '<div class="search-global-sub" style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + esc(it.sub) + '</div>';
      html += '</div></div>';
      idx++;
    });
  });
  box.innerHTML = html;
}

function navBusquedaGlobal(e) {
  if (e.key === 'Escape') { cerrarBusquedaGlobal(); return; }
  if (!_busquedaGlobalResultados.length) return;
  if (e.key === 'ArrowDown') {
    e.preventDefault();
    _busquedaGlobalSel = (_busquedaGlobalSel + 1) % _busquedaGlobalResultados.length;
    actualizarSeleccionBusqueda();
  } else if (e.key === 'ArrowUp') {
    e.preventDefault();
    _busquedaGlobalSel = (_busquedaGlobalSel - 1 + _busquedaGlobalResultados.length) % _busquedaGlobalResultados.length;
    actualizarSeleccionBusqueda();
  } else if (e.key === 'Enter') {
    e.preventDefault();
    ejecutarBusquedaGlobal(_busquedaGlobalSel);
  }
}

function actualizarSeleccionBusqueda() {
  document.querySelectorAll('.search-global-item').forEach(function(el) {
    var i = parseInt(el.dataset.idx);
    if (i === _busquedaGlobalSel) {
      el.classList.add('selected');
      el.scrollIntoView({block:'nearest'});
    } else {
      el.classList.remove('selected');
    }
  });
}

function ejecutarBusquedaGlobal(idx) {
  var r = _busquedaGlobalResultados[idx];
  if (!r) return;
  cerrarBusquedaGlobal();
  if (r.tipo === 'cliente') { setTimeout(function(){ abrirFichaCli(r.id); }, 100); }
  else if (r.tipo === 'rep') { setTimeout(function(){ abrirDetalleRep(r.id); }, 100); }
  else if (r.tipo === 'venta') { navTo('pVentas'); }
  else if (r.tipo === 'stock') { navTo('pStock'); }
  else if (r.tipo === 'servicio') { navTo('pServicios'); }
}

// ═══ FICHA DEL CLIENTE (vista lectura con todas sus reps y ventas) ═══
var _fichaCliId = null;

function abrirFichaCli(cliId) {
  var c = DB.clis.find(function(x){ return x.id === cliId; });
  if (!c) { toast(T('tst.cliente_no_encontrado'), 'err'); return; }
  _fichaCliId = cliId;
  document.getElementById('fichaCliNombre').textContent = '👤 ' + ((c.nombre || '') + ' ' + (c.apellidos || '')).trim();

  // Info card
  var info = '';
  info += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:8px">';
  if (c.tel) info += '<div><span style="color:var(--muted);font-size:11px">📞 Teléfono</span><br><strong>' + esc(c.tel) + '</strong></div>';
  if (c.dni) info += '<div><span style="color:var(--muted);font-size:11px">🆔 DNI</span><br><strong>' + esc(c.dni) + '</strong></div>';
  if (c.email) info += '<div><span style="color:var(--muted);font-size:11px">✉️ Email</span><br><strong style="font-size:11px">' + esc(c.email) + '</strong></div>';
  if (c.fechaNac) info += '<div><span style="color:var(--muted);font-size:11px">🎂 Cumple</span><br><strong>' + esc(c.fechaNac) + '</strong></div>';
  if (c.dir) info += '<div style="grid-column:1/-1"><span style="color:var(--muted);font-size:11px">📍 Dirección</span><br><strong>' + esc(c.dir) + '</strong></div>';
  if (c.notas) info += '<div style="grid-column:1/-1"><span style="color:var(--muted);font-size:11px">📝 Notas</span><br>' + esc(c.notas) + '</div>';
  info += '</div>';
  document.getElementById('fichaCliInfo').innerHTML = info;

  // Botones de acción
  var acc = '';
  if (c.tel) {
    var telLimpio = c.tel.replace(/\D/g, '');
    acc += '<a href="tel:' + esc(c.tel) + '" class="btn-sm" style="background:var(--blue);color:white;text-decoration:none;flex:1;text-align:center;padding:8px 12px">📞 Llamar</a>';
    acc += '<button class="btn-sm" style="background:#25D366;color:white;flex:1;text-align:center;padding:8px 12px" onclick="abrirWhatsAppCli(\'' + cliId + '\')">📲 WhatsApp</button>';
  }
  if (c.email) acc += '<a href="mailto:' + esc(c.email) + '" class="btn-sm" style="background:var(--purple);color:white;text-decoration:none;flex:1;text-align:center;padding:8px 12px">✉️ Email</a>';
  if (tienePerm('clis_editar')) acc += '<button class="btn-sm" style="background:var(--light);color:var(--text);flex:1;padding:8px 12px" onclick="editarClienteDesdeFicha(\'' + cliId + '\')">✏️ Editar</button>';
  acc += '<button class="btn-sm" style="background:#1F2937;color:white;flex:1;padding:8px 12px" onclick="closeM(\'mFichaCli\')">✕ Cerrar</button>';
  document.getElementById('fichaCliAcciones').innerHTML = acc;

  // Lista de reps (busco por cliId Y también por nombre coincidente, para incluir reps huérfanas)
  var nombreNorm = _norm(((c.nombre || '') + ' ' + (c.apellidos || '')).trim());
  var reps = DB.reps.filter(function(r){
    if (r.clienteId === cliId) return true;
    // Match por nombre cuando cliId está vacío o no coincide pero el nombre sí
    var nomRep = _norm(r.clienteNombre || '');
    if (nomRep && nombreNorm && nomRep === nombreNorm) return true;
    return false;
  }).sort(function(a,b){
    return _parseDateAny(b.fecha || '') - _parseDateAny(a.fecha || '');
  });
  var ventas = DB.ventas.filter(function(v){
    if (v.clienteId === cliId) return true;
    var nomV = _norm(v.clienteNombre || '');
    if (nomV && nombreNorm && nomV === nombreNorm) return true;
    return false;
  }).sort(function(a,b){
    return _parseDateAny(b.fecha || '') - _parseDateAny(a.fecha || '');
  });
  document.getElementById('fichaTabRepsCount').textContent = '(' + reps.length + ')';
  document.getElementById('fichaTabVentasCount').textContent = '(' + ventas.length + ')';

  // Render reps
  var repsBox = document.getElementById('fichaCliReps');
  if (!reps.length) {
    repsBox.innerHTML = '<div class="empty" style="padding:14px;font-size:12px">Sin reparaciones</div>';
  } else {
    var coloresEstado = {
      'Pendiente':'#F97316', 'En Proceso':'#FF5B1F', 'Por Entregar':'#00C896',
      'Entregado':'#94A3B8', 'Garantia':'#FF5B1F', 'Sin Solucion':'#EF4444',
      'Devuelto':'#94A3B8', 'Rechazado':'#94A3B8'
    };
    var html = '<div style="display:flex;flex-direction:column;gap:6px">';
    reps.forEach(function(r) {
      var color = coloresEstado[r.estado] || 'var(--muted)';
      html += '<div style="background:var(--light);border-left:3px solid ' + color + ';padding:10px 12px;border-radius:8px;cursor:pointer" onclick="abrirDetalleRep(\'' + r.id + '\')">';
      html += '<div style="display:flex;justify-content:space-between;align-items:start;gap:10px">';
      html += '<div style="flex:1;min-width:0">';
      html += '<div style="font-weight:700;font-size:13px">' + esc((r.marca || '') + ' ' + (r.modelo || '')) + '</div>';
      html += '<div style="font-size:11px;color:var(--red);margin-top:2px">' + esc(r.averia || '—') + '</div>';
      html += '<div style="font-size:10px;color:var(--muted);margin-top:3px">📅 ' + esc(r.fecha || '') + (r.fechaEntregaReal ? ' · entregado ' + esc(r.fechaEntregaReal) : '') + '</div>';
      html += '</div>';
      html += '<div style="text-align:right;flex-shrink:0">';
      html += '<div style="font-size:10px;font-weight:700;color:' + color + ';text-transform:uppercase">' + esc(r.estado) + '</div>';
      html += '<div style="font-size:14px;font-weight:800;color:var(--green);margin-top:3px">' + cur(r.total || 0) + '</div>';
      html += '</div>';
      html += '</div></div>';
    });
    html += '</div>';
    repsBox.innerHTML = html;
  }

  // Render ventas
  var ventasBox = document.getElementById('fichaCliVentas');
  if (!ventas.length) {
    ventasBox.innerHTML = '<div class="empty" style="padding:14px;font-size:12px">Sin ventas</div>';
  } else {
    var html = '<div style="display:flex;flex-direction:column;gap:6px">';
    ventas.forEach(function(v) {
      var estado = v.reembolsado ? '↩ REEMBOLSADA' : (v.financiado ? '💳 Financiada' : '✓ Pagada');
      var colorE = v.reembolsado ? 'var(--red)' : (v.financiado ? 'var(--purple)' : 'var(--green)');
      html += '<div style="background:var(--light);border-left:3px solid ' + colorE + ';padding:10px 12px;border-radius:8px">';
      html += '<div style="display:flex;justify-content:space-between;align-items:start;gap:10px">';
      html += '<div style="flex:1;min-width:0">';
      html += '<div style="font-weight:700;font-size:13px">' + esc((v.marca || '') + ' ' + (v.modelo || '') || 'Venta') + '</div>';
      html += '<div style="font-size:10px;color:var(--muted);margin-top:3px">📅 ' + fmtFecha(v.fecha) + ' · ' + esc(v.pago || '') + '</div>';
      html += '</div>';
      html += '<div style="text-align:right;flex-shrink:0">';
      html += '<div style="font-size:10px;font-weight:700;color:' + colorE + '">' + estado + '</div>';
      html += '<div style="font-size:14px;font-weight:800;color:var(--green);margin-top:3px">' + cur(v.total || 0) + '</div>';
      html += '</div>';
      html += '</div></div>';
    });
    html += '</div>';
    ventasBox.innerHTML = html;
  }

  openM('mFichaCli');
}

