function waMsg(tipo) { return (WA_MSGS[TEKPAIR_LANG] || WA_MSGS.es)[tipo]; }

// ═══ WHATSAPP PLANTILLAS ═══
var PLANTILLAS_WA_DEFAULT = {
  rep_lista: {nombre:'Reparación lista', texto:'¡Hola {nombre}! 📱\n\nTu {modelo} ya está reparado y listo para recoger.\n\nTotal: {total}\n\nTe esperamos en {tienda}. ¡Saludos!'},
  rep_presupuesto: {nombre:'Presupuesto reparación', texto:'Hola {nombre}, te paso el presupuesto de la reparación de tu {modelo}:\n\n📋 {averia}\n💰 Total: {total}\n\n¿Lo confirmamos? Saludos desde {tienda}.'},
  rep_recogida: {nombre:'Recordatorio recogida', texto:'Hola {nombre}, te recuerdo que tu {modelo} sigue en {tienda} listo para recoger desde hace días. Cuando puedas pásate, ¡gracias!'},
  rep_recibida: {nombre:'Reparación recibida', texto:'Hola {nombre}, hemos recibido tu {modelo} en {tienda}. Te avisaremos cuando tengamos novedades sobre la reparación. ¡Gracias por confiar en nosotros!'},
  cuota_proxima: {nombre:'Cuota próxima', texto:'Hola {nombre}, te recuerdo que tu cuota de {total} vence el {fecha}. Saludos desde {tienda}.'},
  cuota_vencida: {nombre:'Cuota vencida', texto:'Hola {nombre}, tu cuota de {total} venció el {fecha}. Pásate por {tienda} cuando puedas para regularizarla. Gracias.'},
  fiado_recordatorio: {nombre:'Recordatorio pago pendiente', texto:'Hola {nombre} 👋\n\nTe escribo desde {tienda} para recordarte que tienes un pago pendiente:\n\n💰 Importe: {total}\n📅 Del día: {fecha}\n\nCuando puedas pásate por la tienda para regularizar. ¡Gracias!'},
  generico: {nombre:'Mensaje libre', texto:'Hola {nombre}, te escribo desde {tienda}.'}
};

function getPlantillasWA() {
  return AJUSTES.plantillasWA || PLANTILLAS_WA_DEFAULT;
}

// Nombre de plantilla traducido: solo para las plantillas por defecto (las personalizadas
// por la tienda se respetan tal cual). Devuelve el nombre i18n o el original.
function _waPlNombre(key, p) {
  if (AJUSTES.plantillasWA) return (p && p.nombre) || key; // personalizada → no tocar
  var t = (typeof T === 'function') ? T('wa.pl_' + key) : '';
  return (t && t !== 'wa.pl_' + key) ? t : ((p && p.nombre) || key);
}

function aplicarVariablesWA(texto, datos) {
  return (texto || '')
    .replace(/\{nombre\}/g, datos.nombre || '')
    .replace(/\{tienda\}/g, datos.tienda || (TIENDA && TIENDA.nombre) || 'la tienda')
    .replace(/\{modelo\}/g, datos.modelo || '')
    .replace(/\{marca\}/g, datos.marca || '')
    .replace(/\{averia\}/g, datos.averia || '')
    .replace(/\{total\}/g, datos.total != null ? cur(datos.total) : '')
    .replace(/\{fecha\}/g, datos.fecha || '')
    .replace(/\{estado\}/g, datos.estado || '');
}

var _waContexto = null;

function abrirWhatsAppFiado(fiadoId) {
  // Buscar fiado en cobros cacheados
  if (!window.Cajas || !window.Cajas) return;
  // Acceder al Estado interno de Cajas via su API publica
  var fiado = null;
  try {
    // Estado.cobros tiene los fiados; buscamos por id
    var allCobros = window._cajasFiadosCache || [];
    fiado = allCobros.find(function(f){ return f.id === fiadoId; });
  } catch(e) {}
  if (!fiado) {
    // Fallback: pedir al backend
    toast('No se encontró el fiado', 'err');
    return;
  }
  if (!fiado.cliente_telefono) { toast(T('tst.cliente_sin_telefono'), 'err'); return; }

  // Formato fecha DD/MM/YYYY
  var partes = (fiado.fecha || '').split('-');
  var fechaVisible = partes.length === 3 ? (partes[2] + '/' + partes[1] + '/' + partes[0]) : fiado.fecha;

  _waContexto = {
    tipo: 'fiado',
    cli: { tel: fiado.cliente_telefono, nombre: fiado.cliente_nombre },
    datos: {
      nombre: fiado.cliente_nombre || '',
      tienda: TIENDA.nombre || '',
      total: Number(fiado.importe || 0),
      fecha: fechaVisible
    }
  };
  document.getElementById('waInfoCli').innerHTML = '<strong>📱 ' + esc(fiado.cliente_nombre || 'Sin nombre') + '</strong> · ' + esc(fiado.cliente_telefono) + '<br><span style="color:var(--muted);font-size:11px">Pendiente de ' + cur(fiado.importe||0) + ' · ' + esc(fechaVisible) + '</span>';
  var sel = document.getElementById('waPlantilla');
  var plantillas = getPlantillasWA();
  var keysFiado = ['fiado_recordatorio','generico'];
  sel.innerHTML = keysFiado.filter(function(k){ return plantillas[k]; }).map(function(k) {
    return '<option value="' + k + '"' + (k === 'fiado_recordatorio' ? ' selected' : '') + '>' + plantillas[k].nombre + '</option>';
  }).join('');
  renderPreviewWA();
  openM('mWhatsApp');
}

function abrirWhatsAppRep(repId) {
  var r = DB.reps.find(function(x){ return x.id === repId; });
  if (!r) return;
  var cli = r.clienteId ? DB.clis.find(function(c){ return c.id === r.clienteId; }) : null;
  if (!cli && r.clienteNombre) {
    var nomNorm = _norm(r.clienteNombre);
    cli = DB.clis.find(function(c){
      return _norm(((c.nombre||'') + ' ' + (c.apellidos||'')).trim()) === nomNorm;
    });
  }
  if (!cli) { toast(T('tst.cliente_no_encontrado'), 'err'); return; }
  if (!cli.tel) { toast(T('tst.cliente_sin_telefono'), 'err'); return; }
  _marcarAvisado(repId); // marca como avisado para el tablero
  _waContexto = {
    tipo: 'rep',
    refId: r.id, refTipo: 'reparacion',
    cli: cli,
    datos: {
      nombre: cli.nombre || '',
      tienda: TIENDA.nombre || '',
      marca: r.marca || '',
      modelo: r.modelo || '',
      averia: r.averia || '',
      total: r.total || 0,
      estado: r.estado || ''
    }
  };
  document.getElementById('waInfoCli').innerHTML = '<strong>📱 ' + esc(cli.nombre + ' ' + (cli.apellidos||'')) + '</strong> · ' + esc(cli.tel) + '<br><span style="color:var(--muted);font-size:11px">' + esc(r.marca + ' ' + r.modelo) + ' · ' + esc(r.averia||'') + '</span>';
  // Llenar selector con plantillas relevantes para reparación
  var sel = document.getElementById('waPlantilla');
  var plantillas = getPlantillasWA();
  var keysRep = ['rep_lista','rep_presupuesto','rep_recogida','rep_recibida','generico'];
  var defaultKey = r.estado === 'Por Entregar' ? 'rep_lista' : (r.estado === 'Pendiente' ? 'rep_recibida' : 'rep_lista');
  sel.innerHTML = keysRep.filter(function(k){ return plantillas[k]; }).map(function(k) {
    return '<option value="' + k + '"' + (k === defaultKey ? ' selected' : '') + '>' + _waPlNombre(k, plantillas[k]) + '</option>';
  }).join('');
  renderPreviewWA();
  openM('mWhatsApp');
}

function abrirWhatsAppCuota(ventaId, idxCuota) {
  var v = DB.ventas.find(function(x){ return x.id === ventaId; });
  if (!v) return;
  var cli = DB.clis.find(function(c){ return c.id === v.clienteId; });
  if (!cli || !cli.tel) { toast(T('tst.cliente_sin_telefono'), 'err'); return; }
  var c = v.cuotas[idxCuota];
  if (!c) return;
  var hoy = new Date(); hoy.setHours(0,0,0,0);
  var fc = _parseDateAny(c.fecha);
  var vencida = fc && fc < hoy;
  _waContexto = {
    tipo: 'cuota',
    cli: cli,
    datos: {
      nombre: cli.nombre || '',
      tienda: TIENDA.nombre || '',
      modelo: v.modelo || '',
      total: c.importe || 0,
      fecha: c.fecha || ''
    }
  };
  document.getElementById('waInfoCli').innerHTML = '<strong>💵 ' + esc(cli.nombre + ' ' + (cli.apellidos||'')) + '</strong> · ' + esc(cli.tel) + '<br><span style="color:var(--muted);font-size:11px">Cuota ' + (idxCuota+1) + ' · ' + cur(c.importe) + ' · ' + (vencida ? 'VENCIDA' : 'vence ' + c.fecha) + '</span>';
  var sel = document.getElementById('waPlantilla');
  var plantillas = getPlantillasWA();
  var keysCuota = vencida ? ['cuota_vencida','cuota_proxima','generico'] : ['cuota_proxima','cuota_vencida','generico'];
  sel.innerHTML = keysCuota.filter(function(k){ return plantillas[k]; }).map(function(k) {
    return '<option value="' + k + '">' + _waPlNombre(k, plantillas[k]) + '</option>';
  }).join('');
  renderPreviewWA();
  openM('mWhatsApp');
}

function renderPreviewWA() {
  if (!_waContexto) return;
  var key = document.getElementById('waPlantilla').value;
  var plantillas = getPlantillasWA();
  var p = plantillas[key];
  if (!p) return;
  document.getElementById('waMensaje').value = aplicarVariablesWA(p.texto, _waContexto.datos);
}

// Registra un aviso (envío) en la tabla `avisos` — historial de comunicaciones.
// Frontend → REST con anon+JWT (la policy avisos_insert_tienda lo permite). No bloqueante.
function registrarAviso(d) {
  if (!SB_KEY || !TIENDA_ID || typeof _sbPostRaw !== 'function') return;
  try {
    _sbPostRaw('avisos', {
      id: 'av_' + Date.now() + '_' + Math.random().toString(36).slice(2, 7),
      tienda_id: TIENDA_ID, tipo: d.tipo || 'aviso', canal: d.canal || 'whatsapp',
      destinatario: d.destinatario || null, ref_tipo: d.ref_tipo || 'reparacion',
      ref_id: d.ref_id || null, asunto: d.asunto || null, estado: d.estado || 'enviado',
      fecha: new Date().toISOString()
    });
  } catch (e) {}
}
try { window.registrarAviso = registrarAviso; } catch(e){}

// Carga y muestra el historial de avisos de una reparación en #avisosHistorial.
function _cargarHistorialAvisos(repId) {
  var box = document.getElementById('avisosHistorial');
  if (!box || !SB_KEY || typeof sbGet !== 'function') return;
  sbGet('avisos', 'ref_id=eq.' + encodeURIComponent(repId) + '&order=fecha.desc&limit=40').then(function(rows){
    if (!Array.isArray(rows) || !rows.length) { box.innerHTML = '<div style="font-size:11px;color:var(--muted)">' + T('det.sin_avisos') + '</div>'; return; }
    var TIPO = {presupuesto_enviado:'Presupuesto enviado', presupuesto_aceptado:'Aceptado por el cliente', presupuesto_rechazado:'Rechazado por el cliente', factura_enviada:'Factura enviada', aviso_rep:'Aviso al cliente', aviso_cliente:'Aviso al cliente', cita_aviso:'Aviso de cita'};
    var CANAL = {whatsapp:'📱 WhatsApp', email:'📧 Email', sistema:'🔔 Sistema'};
    box.innerHTML = rows.map(function(a){
      var f = ''; try { var d = new Date(a.fecha); f = d.toLocaleDateString('es',{day:'2-digit',month:'2-digit',year:'2-digit'}) + ' ' + d.toLocaleTimeString('es',{hour:'2-digit',minute:'2-digit'}); } catch(e){}
      var fallo = a.estado === 'fallo' ? ' <span style="color:var(--red)">(fallo)</span>' : '';
      return '<div style="display:flex;justify-content:space-between;gap:8px;padding:5px 0;border-bottom:1px solid var(--light);font-size:11px">'
        + '<span>' + (CANAL[a.canal]||escHtml(a.canal||'')) + ' · ' + escHtml(TIPO[a.tipo]||a.tipo||'') + fallo + '</span>'
        + '<span style="color:var(--muted);white-space:nowrap">' + f + '</span></div>';
    }).join('');
  }).catch(function(){ box.innerHTML = '<div style="font-size:11px;color:var(--muted)">No se pudo cargar el historial</div>'; });
}

function enviarWhatsApp() {
  if (!_waContexto || !_waContexto.cli) return;
  var msg = document.getElementById('waMensaje').value;
  var tel = waTel(_waContexto.cli.tel);
  if (!tel) { toast('Sin teléfono', 'err'); return; }
  var url = 'https://wa.me/' + tel + '?text=' + encodeURIComponent(msg);
  window.open(url, '_blank');
  registrarAviso({ tipo: 'aviso_' + (_waContexto.tipo || 'cliente'), canal: 'whatsapp', destinatario: _waContexto.cli.tel, ref_id: _waContexto.refId || (_waContexto.cli && _waContexto.cli.id), ref_tipo: _waContexto.refTipo || 'cliente' });
  closeM('mWhatsApp');
}

// ═══ GARANTÍA POR DÍAS ═══
function getDiasGarantia() {
  if (TIENDA && TIENDA.garantiaDias) return parseInt(TIENDA.garantiaDias);
  return 90; // default
}

// Comprueba si una nueva avería del mismo cliente y modelo está dentro de garantía
// Devuelve la rep anterior + días transcurridos, o null
function checkGarantia(cliId, marca, modelo, fechaActual, clienteNombre) {
  // Si la tienda desactivó garantía → no detectar
  if (TIENDA.garRepActiva === false) return null;
  if (!cliId && !clienteNombre) return null;
  var diasGlobal = getDiasGarantia();
  if (!diasGlobal || diasGlobal <= 0) return null;
  var fechaRef = fechaActual ? _parseDateAny(fechaActual) : new Date();
  if (!fechaRef) fechaRef = new Date();
  var marcaN = _norm(marca||'');
  var modeloN = _norm(modelo||'');
  if (!modeloN) return null; // sin modelo no podemos comparar
  var nombreNorm = _norm(clienteNombre || '');
  var candidatas = DB.reps.filter(function(r) {
    // Match cliente: por cliId exacto, o por nombre normalizado como fallback
    var matchCli = (cliId && r.clienteId === cliId);
    if (!matchCli && nombreNorm && r.clienteNombre) {
      matchCli = _norm(r.clienteNombre) === nombreNorm;
    }
    if (!matchCli) return false;
    if (r.estado !== 'Entregado' || !r.fechaEntregaReal) return false;
    var fe = _parseDateAny(r.fechaEntregaReal);
    if (!fe) return false;
    // Usar días específicos de esa rep si los tiene, si no el global
    var diasRep = (typeof r.garantiaDias === 'number') ? r.garantiaDias : diasGlobal;
    if (diasRep <= 0) return false; // rep marcada "sin garantía"
    var diff = (fechaRef - fe) / 86400000;
    if (diff < 0 || diff > diasRep) return false;
    var mr = _norm(r.marca||'');
    var mm = _norm(r.modelo||'');
    var marcaCoincide = !marcaN || !mr || mr === marcaN;
    var modeloCoincide = mm === modeloN;
    return marcaCoincide && modeloCoincide;
  }).sort(function(a,b){
    return _parseDateAny(b.fechaEntregaReal) - _parseDateAny(a.fechaEntregaReal);
  });
  if (!candidatas.length) return null;
  var rep = candidatas[0];
  var diasUsados = (typeof rep.garantiaDias === 'number') ? rep.garantiaDias : diasGlobal;
  var diasDesde = Math.floor((fechaRef - _parseDateAny(rep.fechaEntregaReal)) / 86400000);
  return {rep: rep, dias: diasDesde, diasTotal: diasUsados, restantes: diasUsados - diasDesde};
}

// ═══ ORDEN PERSONALIZADO DE WIDGETS ═══
var WIDGETS_DEFAULT_ORDER = [
  'cardUrgentes','cardCajaDia','cardCobros','cardPendientes',
  'cardRepsEstado','cardPorEntregar','cardStockCritico','cardCumples',
  'cardTendencia','cardTopProds','cardTopAverias','cardTiempoMedio',
  'cardClisInactivos','cardNotas','cardCierre'
];

function getWidgetOrderKey() {
  return 'tk_widget_order_' + (U && U.id ? U.id : 'default');
}

function getWidgetOrder() {
  var saved = localStorage.getItem(getWidgetOrderKey());
  if (!saved) return WIDGETS_DEFAULT_ORDER.slice();
  try {
    var arr = JSON.parse(saved);
    if (!Array.isArray(arr)) return WIDGETS_DEFAULT_ORDER.slice();
    // Combinar con default por si hay nuevos widgets que el usuario aún no tiene en su orden
    var merged = arr.slice();
    WIDGETS_DEFAULT_ORDER.forEach(function(id) {
      if (merged.indexOf(id) === -1) merged.push(id);
    });
    return merged;
  } catch(e) { return WIDGETS_DEFAULT_ORDER.slice(); }
}

function aplicarOrdenWidgets() {
  var orden = getWidgetOrder();
  var pDash = document.getElementById('pDash');
  if (!pDash) return;
  // VIS-16 fix: cards ahora viven dentro de wrappers .dash-zone-*
  // Solo reordena cards que siguen sueltos en pDash (compatibilidad layout legacy)
  orden.forEach(function(id) {
    var card = document.getElementById(id);
    if (card && card.parentNode === pDash) pDash.appendChild(card);
  });
}

var modoEdicionWidgets = false;

function toggleModoEdicion() {
  modoEdicionWidgets = !modoEdicionWidgets;
  var btn = document.getElementById('btnPersonalizar');
  if (modoEdicionWidgets) {
    if (btn) {
      btn.innerHTML = '✓ ' + T('gen.listo');
      btn.style.background = 'var(--green)';
      btn.style.color = 'white';
      btn.style.borderColor = 'var(--green)';
    }
    activarControlesEdicion();
    toast(T('gen.modo_edicion'), 'ok');
  } else {
    if (btn) {
      btn.innerHTML = '✏️ ' + T('gen.personalizar');
      btn.style.background = 'white';
      btn.style.color = 'var(--blue)';
      btn.style.borderColor = 'var(--border)';
    }
    desactivarControlesEdicion();
    guardarOrdenWidgets();
    toast(T('dash.orden_guardado'), 'ok');
  }
}

function activarControlesEdicion() {
  document.querySelectorAll('#pDash .card[id^="card"]').forEach(function(card) {
    card.classList.add('widget-editing');
    if (!card.querySelector('.widget-edit-controls')) {
      var ctrl = document.createElement('div');
      ctrl.className = 'widget-edit-controls';
      ctrl.innerHTML = '<button onclick="moverWidget(\'' + card.id + '\',-1)" title="Subir">▲</button>' +
                       '<button onclick="moverWidget(\'' + card.id + '\',1)" title="Bajar">▼</button>';
      card.appendChild(ctrl);
    }
  });
}

function desactivarControlesEdicion() {
  document.querySelectorAll('#pDash .card[id^="card"]').forEach(function(card) {
    card.classList.remove('widget-editing');
    var c = card.querySelector('.widget-edit-controls');
    if (c) c.remove();
  });
}

function moverWidget(id, dir) {
  var card = document.getElementById(id);
  if (!card) return;
  var pDash = card.parentNode;
  if (dir < 0) {
    var prev = card.previousElementSibling;
    while (prev && (!prev.classList.contains('card') || !prev.id || !/^card/.test(prev.id))) {
      prev = prev.previousElementSibling;
    }
    if (prev) pDash.insertBefore(card, prev);
  } else {
    var next = card.nextElementSibling;
    while (next && (!next.classList.contains('card') || !next.id || !/^card/.test(next.id))) {
      next = next.nextElementSibling;
    }
    if (next) pDash.insertBefore(next, card);
  }
  // Scroll al elemento movido para feedback
  card.scrollIntoView({behavior:'smooth', block:'center'});
}

function guardarOrdenWidgets() {
  var orden = [];
  document.querySelectorAll('#pDash .card[id^="card"]').forEach(function(c) {
    orden.push(c.id);
  });
  localStorage.setItem(getWidgetOrderKey(), JSON.stringify(orden));
}

function aplicarPermisos() {
  if (!U) return;
  var esAdmin = U.rol === 'admin' || (U.permisos && U.permisos.todo);

  // Para no-admin: ocultar menús/botones según permisos de acción
  if (!esAdmin) {
    var hideNav = function(p, perm) {
      if (tienePerm(perm)) return;
      var ni = document.querySelector('.ni[data-p="' + p + '"]');
      if (ni) ni.style.display = 'none';
      var sb = document.querySelector('.sidebar-ni[data-p="' + p + '"]');
      if (sb) sb.style.display = 'none';
    };
  hideNav('pVentas', 'ventas_ver');
  hideNav('pReps', 'reps_ver');
  hideNav('pStock', 'stock_ver');
  hideNav('pClis', 'clis_ver');
  hideNav('pProvs', 'provs_ver');
  hideNav('pGastos', 'gastos_ver');
  hideNav('pReportes', 'reportes_ver');
  hideNav('pServicios', 'servicios_ver');
  hideNav('pTienda', 'tienda_ver');
  hideNav('pAjustes', 'ajustes_ver');
  hideNav('pImportar', 'herramientas_importar');
  // Cajas: visible por defecto; el admin la deniega poniendo cajas_ver = false → el trabajador no la ve
  if (U.permisos && U.permisos.cajas_ver === false) {
    document.querySelectorAll('.sidebar-ni[data-p="pCajas"], .ni[data-p="pCajas"], .pmas-btn[onclick*="pCajas"], .qbtn[onclick*="pCajas"]')
      .forEach(function(el){ el.style.display = 'none'; });
  }

  // Quick action buttons en dashboard
  document.querySelectorAll('#pDash .qbtn-dash, #pDash .qbtn').forEach(function(btn) {
    var onclick = btn.getAttribute('onclick') || '';
    if (onclick.includes('abrirVenta') && !tienePerm('ventas_crear')) btn.style.display = 'none';
    if (onclick.includes('abrirRep') && !tienePerm('reps_crear')) btn.style.display = 'none';
    if (onclick.includes('mStock') && !tienePerm('stock_crear')) btn.style.display = 'none';
    if (onclick.includes('mCli') && !tienePerm('clis_crear')) btn.style.display = 'none';
    if (onclick.includes('tpv.html') && !tienePerm('ventas_crear')) btn.style.display = 'none';
  });

  // Sidebar items extra (catalogo, backup, ayuda)
  document.querySelectorAll('.sidebar-ni').forEach(function(btn) {
    var onclick = btn.getAttribute('onclick') || '';
    if ((onclick.includes('catalogo') || onclick.includes('pCatalogo')) && !tienePerm('catalogo')) btn.style.display = 'none';
    if (onclick.includes('backupManual') && !tienePerm('herramientas_backup')) btn.style.display = 'none';
    if (onclick.includes('pUsuarios')) btn.style.display = 'none'; // solo admin
    if (onclick.includes('tpv.html') && !tienePerm('ventas_crear')) btn.style.display = 'none';
  });

  // Mas menu (móvil) — incluye los botones grandes .pmas-btn (Ajustes, Usuarios…)
  document.querySelectorAll('#pMas .qbtn, #pMas .pmas-btn').forEach(function(btn) {
    var onclick = btn.getAttribute('onclick') || '';
    if (onclick.includes('pReportes') && !tienePerm('reportes_ver')) btn.style.display = 'none';
    if (onclick.includes('pGastos') && !tienePerm('gastos_ver')) btn.style.display = 'none';
    if (onclick.includes('pServicios') && !tienePerm('servicios_ver')) btn.style.display = 'none';
    if (onclick.includes('pProvs') && !tienePerm('provs_ver')) btn.style.display = 'none';
    if (onclick.includes('pClis') && !tienePerm('clis_ver')) btn.style.display = 'none';
    if ((onclick.includes('catalogo') || onclick.includes('pCatalogo')) && !tienePerm('catalogo')) btn.style.display = 'none';
    if (onclick.includes('pImportar') && !tienePerm('herramientas_importar')) btn.style.display = 'none';
    if (onclick.includes('backupManual') && !tienePerm('herramientas_backup')) btn.style.display = 'none';
    if (onclick.includes('pTienda') && !tienePerm('tienda_ver')) btn.style.display = 'none';
    if (onclick.includes('pAjustes') && !tienePerm('ajustes_ver')) btn.style.display = 'none';
    if (onclick.includes('pUsuarios')) btn.style.display = 'none';
  });

  // Ocultar grupos vacíos del sidebar
  document.querySelectorAll('.sidebar-group').forEach(function(g) {
    var next = g.nextElementSibling;
    var algunoVisible = false;
    while (next && !next.classList.contains('sidebar-group')) {
      if (next.style.display !== 'none') { algunoVisible = true; break; }
      next = next.nextElementSibling;
    }
    if (!algunoVisible) g.style.display = 'none';
  });

  // Ocultar botones de creación en cabeceras de páginas
  if (!tienePerm('ventas_crear')) document.querySelectorAll('[onclick*="abrirVenta"]').forEach(function(b) { b.style.display = 'none'; });
  if (!tienePerm('reps_crear')) document.querySelectorAll('[onclick*="abrirRep"]').forEach(function(b) { b.style.display = 'none'; });
  if (!tienePerm('stock_crear')) document.querySelectorAll('[onclick*="mStock"]').forEach(function(b) { b.style.display = 'none'; });
  if (!tienePerm('clis_crear')) document.querySelectorAll('[onclick*="mCli"]').forEach(function(b) { b.style.display = 'none'; });
  if (!tienePerm('provs_crear')) document.querySelectorAll('[onclick*="mProv"]').forEach(function(b) { b.style.display = 'none'; });
  if (!tienePerm('gastos_crear')) document.querySelectorAll('[onclick*="mGasto"]').forEach(function(b) { b.style.display = 'none'; });
  if (!tienePerm('servicios_crear')) document.querySelectorAll('[onclick*="mServicio"]').forEach(function(b) { b.style.display = 'none'; });
  } // fin if (!esAdmin)

  // ═══ WIDGETS DEL DASHBOARD (aplica a TODOS, incluido admin) ═══
  // Resetear visibilidad primero (para que reactivar funcione)
  var WIDGET_IDS = ['dashQuickGrid','cardUrgentes','cardPendientes','cardPorEntregar','cardNotas','cardCierre',
                    'cardCajaDia','cardCobros','cardStockCritico','cardCumples','cardTendencia',
                    'cardTopProds','cardTopAverias','cardRepsEstado','cardTiempoMedio','cardClisInactivos'];
  WIDGET_IDS.forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.style.display = '';
  });
  // Y los stat cards del metricsGrid se controlan en renderDash directamente

  function hideEl(id) {
    var el = document.getElementById(id);
    if (el) el.style.display = 'none';
  }
  if (!widgetVisible('widget_quickactions')) hideEl('dashQuickGrid');
  if (!widgetVisible('widget_urgentes')) hideEl('cardUrgentes');
  if (!widgetVisible('widget_pendientes')) hideEl('cardPendientes');
  if (!widgetVisible('widget_porentregar')) hideEl('cardPorEntregar');
  if (!widgetVisible('widget_notas')) hideEl('cardNotas');
  if (!widgetVisible('widget_cierre')) hideEl('cardCierre');
  if (!widgetVisible('widget_caja')) hideEl('cardCajaDia');
  if (!widgetVisible('widget_cobros')) hideEl('cardCobros');
  if (!widgetVisible('widget_comocobras') || typeof puedeVerCaja !== 'function' || !puedeVerCaja()) hideEl('cardComoCobras');
  if (!widgetVisible('widget_pedidos')) hideEl('cardPedidos');
  if (!widgetVisible('widget_stockcritico')) hideEl('cardStockCritico');
  if (!widgetVisible('widget_cumples')) hideEl('cardCumples');
  if (!widgetVisible('widget_tendencia')) hideEl('cardTendencia');
  if (!widgetVisible('widget_topprods')) hideEl('cardTopProds');
  if (!widgetVisible('widget_topaverias')) hideEl('cardTopAverias');
  if (!widgetVisible('widget_repsestado')) hideEl('cardRepsEstado');
  if (!widgetVisible('widget_tiempomedio')) hideEl('cardTiempoMedio');
  if (!widgetVisible('widget_clisinactivos')) hideEl('cardClisInactivos');
}

