function abrirAuditoria() {
  if (!checkFeature('auditoria')) return;
  if (!U || U.rol !== 'admin') { toast('Solo admin', 'err'); return; }
  // Poblar dropdown usuarios
  var sel = document.getElementById('audFiltroUsuario');
  if (sel) {
    var usuarios = {};
    (DB.audit || []).forEach(function(a){
      if (a.usuarioId) usuarios[a.usuarioId] = a.usuarioNom || a.usuarioId;
    });
    sel.innerHTML = '<option value="">Todos</option>' + Object.keys(usuarios).map(function(uid){
      return '<option value="' + esc(uid) + '">' + esc(usuarios[uid]) + '</option>';
    }).join('');
  }
  document.getElementById('audFiltroAccion').value = '';
  document.getElementById('audFiltroEntidad').value = '';
  document.getElementById('audFiltroTexto').value = '';
  renderAuditoria();
  openM('mAuditoria');
}

function renderAuditoria() {
  var tbody = document.getElementById('audTbody');
  if (!tbody) return;
  var entries = (DB.audit || []).slice();
  var fU = document.getElementById('audFiltroUsuario').value;
  var fA = document.getElementById('audFiltroAccion').value;
  var fE = document.getElementById('audFiltroEntidad').value;
  var fT = (document.getElementById('audFiltroTexto').value || '').toLowerCase().trim();

  if (fU) entries = entries.filter(function(a){ return a.usuarioId === fU; });
  if (fA) entries = entries.filter(function(a){ return a.accion === fA; });
  if (fE) entries = entries.filter(function(a){ return a.entidad === fE; });
  if (fT) entries = entries.filter(function(a){
    return ((a.detalle||'') + ' ' + (a.usuarioNom||'') + ' ' + (a.entidadId||'')).toLowerCase().indexOf(fT) !== -1;
  });

  // Limitar a 500 para rendimiento
  var totalFiltradas = entries.length;
  entries = entries.slice(0, 500);

  document.getElementById('audResumen').textContent = totalFiltradas + ' ' + (totalFiltradas===1?T('aud.actividad'):T('aud.actividades')) + (totalFiltradas > 500 ? ' ' + T('aud.ultimas_500') : '');

  if (!entries.length) {
    tbody.innerHTML = '<tr><td colspan="4" style="padding:24px;text-align:center;color:var(--muted)">' + T('aud.sin_actividad') + '</td></tr>';
    return;
  }

  var iconAccion = {
    crear: '🟢', editar: '🟡', eliminar: '🔴', cambio_estado: '🔄'
  };
  var iconEntidad = {
    reparacion: '🔧', venta: '💰', cliente: '👤', stock: '📦', servicio: '🛠️'
  };

  tbody.innerHTML = entries.map(function(a) {
    var _lc = (typeof TEKPAIR_LANG === 'string' ? TEKPAIR_LANG : 'es');
    var d = new Date(a.ts);
    var fechaStr = d.toLocaleDateString(_lc) + ' ' + d.toLocaleTimeString(_lc, {hour:'2-digit', minute:'2-digit'});
    var ico = iconAccion[a.accion] || '•';
    var icoE = iconEntidad[a.entidad] || '';
    var accionLabel = ({crear:T('aud.creo'), editar:T('aud.edito'), eliminar:T('aud.elimino'), cambio_estado:T('aud.cambio_est')})[a.accion] || a.accion;
    return '<tr>' +
      '<td style="padding:8px 10px;border-bottom:1px solid var(--border);white-space:nowrap;font-size:11px;color:var(--muted)">' + fechaStr + '</td>' +
      '<td style="padding:8px 10px;border-bottom:1px solid var(--border);white-space:nowrap;font-weight:600">' + esc(a.usuarioNom || '?') + '</td>' +
      '<td style="padding:8px 10px;border-bottom:1px solid var(--border);white-space:nowrap">' + ico + ' ' + accionLabel + ' ' + icoE + ' <span style="color:var(--muted);font-size:11px">' + esc(a.entidad) + '</span></td>' +
      '<td style="padding:8px 10px;border-bottom:1px solid var(--border);font-size:11px">' + esc(a.detalle || '') + '</td>' +
    '</tr>';
  }).join('');
}

function exportarAuditoria() {
  var entries = DB.audit || [];
  if (!entries.length) { toast(T('tst.sin_datos'), 'err'); return; }
  var hdr = 'Fecha,Usuario,Accion,Entidad,EntidadID,Detalle\n';
  function esc2(s) { if (s == null) return ''; return '"' + String(s).replace(/"/g, '""') + '"'; }
  var csv = hdr + entries.map(function(a){
    return [a.ts, a.usuarioNom, a.accion, a.entidad, a.entidadId, a.detalle].map(esc2).join(',');
  }).join('\n');
  var blob = new Blob(['\uFEFF' + csv], {type:'text/csv;charset=utf-8'});
  var d = new Date();
  var fecha = d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
  downloadBlob(blob, 'tekpair-auditoria-' + fecha + '.csv');
  toast(T('tst.auditoria_exportada'), 'ok');
}

