// ═══════════════════════════════════════════════════════════
// CALENDARIO DE CITAS (vista mes con mini cal + lista del día)
// ═══════════════════════════════════════════════════════════
var CAL_VIEW = 'lista'; // 'lista' o 'calendario'
var CAL_MES = new Date().getMonth();
var CAL_ANO = new Date().getFullYear();
var CAL_DIA_SEL = null; // 'YYYY-MM-DD'

function setVistaCitas(vista) {
  CAL_VIEW = vista;
  document.querySelectorAll('#citasVistaToggle button').forEach(function(b){
    b.classList.toggle('active', b.dataset.v === vista);
  });
  var vL = document.getElementById('vistaListaCitas');
  var vC = document.getElementById('vistaCalendarioCitas');
  if (vista === 'calendario') {
    if (vL) vL.style.display = 'none';
    if (vC) vC.style.display = 'block';
    // Inicializar día seleccionado al de hoy si no hay
    if (!CAL_DIA_SEL) {
      var h = new Date();
      CAL_DIA_SEL = h.getFullYear() + '-' + String(h.getMonth()+1).padStart(2,'0') + '-' + String(h.getDate()).padStart(2,'0');
    }
    renderCalendario();
  } else {
    if (vL) vL.style.display = 'block';
    if (vC) vC.style.display = 'none';
  }
}

function cambiarMes(delta) {
  CAL_MES += delta;
  if (CAL_MES < 0) { CAL_MES = 11; CAL_ANO--; }
  else if (CAL_MES > 11) { CAL_MES = 0; CAL_ANO++; }
  renderCalendario();
}

function irHoy() {
  var h = new Date();
  CAL_MES = h.getMonth();
  CAL_ANO = h.getFullYear();
  CAL_DIA_SEL = h.getFullYear() + '-' + String(h.getMonth()+1).padStart(2,'0') + '-' + String(h.getDate()).padStart(2,'0');
  renderCalendario();
}

function _fechaToStr(d) {
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}

function _citasDelDia(fechaStr) {
  return (DB.citas || []).filter(function(c){ return c.fecha === fechaStr && c.estado !== 'cancelada'; })
    .sort(function(a,b){ return (a.hora || '').localeCompare(b.hora || ''); });
}

function renderCalendario() {
  var grid = document.getElementById('calGrid');
  var titulo = document.getElementById('calMesAno');
  if (!grid || !titulo) return;

  var _lc = (typeof TEKPAIR_LANG === 'string' ? TEKPAIR_LANG : 'es');
  titulo.textContent = new Date(CAL_ANO, CAL_MES, 1).toLocaleDateString(_lc, {month:'long', year:'numeric'});

  // Limpiar grid pero mantener los weekdays
  var weekdays = grid.querySelectorAll('.cal-weekday');
  grid.innerHTML = '';
  weekdays.forEach(function(w){ grid.appendChild(w); });

  // Calcular el primer día del mes y cuántos días tiene
  var primero = new Date(CAL_ANO, CAL_MES, 1);
  var ultimo = new Date(CAL_ANO, CAL_MES + 1, 0);
  var diasMes = ultimo.getDate();
  
  // Día de la semana del primero (0=Dom, 1=Lun, ..., 6=Sab) → ajustar a Lun=0
  var diaSemPrimero = primero.getDay();
  var offset = diaSemPrimero === 0 ? 6 : diaSemPrimero - 1;

  // Días del mes anterior (para rellenar)
  var diasAntes = new Date(CAL_ANO, CAL_MES, 0).getDate();
  
  var hoy = new Date();
  var hoyStr = _fechaToStr(hoy);

  // Pintar días del mes anterior (grises)
  for (var i = offset - 1; i >= 0; i--) {
    var num = diasAntes - i;
    var prevMes = CAL_MES === 0 ? 11 : CAL_MES - 1;
    var prevAno = CAL_MES === 0 ? CAL_ANO - 1 : CAL_ANO;
    var fechaStr = prevAno + '-' + String(prevMes+1).padStart(2,'0') + '-' + String(num).padStart(2,'0');
    grid.appendChild(_crearDiaCalendario(num, fechaStr, true, hoyStr));
  }

  // Pintar días del mes actual
  for (var d = 1; d <= diasMes; d++) {
    var fechaStr = CAL_ANO + '-' + String(CAL_MES+1).padStart(2,'0') + '-' + String(d).padStart(2,'0');
    grid.appendChild(_crearDiaCalendario(d, fechaStr, false, hoyStr));
  }

  // Pintar días del mes siguiente para completar la última semana
  var totalCeldas = offset + diasMes;
  var faltan = (7 - (totalCeldas % 7)) % 7;
  for (var s = 1; s <= faltan; s++) {
    var nextMes = CAL_MES === 11 ? 0 : CAL_MES + 1;
    var nextAno = CAL_MES === 11 ? CAL_ANO + 1 : CAL_ANO;
    var fechaStr = nextAno + '-' + String(nextMes+1).padStart(2,'0') + '-' + String(s).padStart(2,'0');
    grid.appendChild(_crearDiaCalendario(s, fechaStr, true, hoyStr));
  }

  // Renderizar lista del día seleccionado
  _renderListaDelDia();
}

function _crearDiaCalendario(num, fechaStr, esOtroMes, hoyStr) {
  var div = document.createElement('div');
  div.className = 'cal-day';
  if (esOtroMes) div.classList.add('other-month');
  if (fechaStr === hoyStr) div.classList.add('today');
  if (fechaStr === CAL_DIA_SEL) div.classList.add('selected');
  div.dataset.fecha = fechaStr;
  
  var citas = _citasDelDia(fechaStr);
  
  var html = '<div class="cal-day-num">' + num + '</div>';
  if (citas.length > 0) {
    var maxDots = 3;
    var dots = citas.slice(0, maxDots);
    html += '<div class="cal-dots">';
    dots.forEach(function(c){
      html += '<span class="cal-dot ' + (c.estado || 'pendiente') + '"></span>';
    });
    html += '</div>';
    if (citas.length > maxDots) {
      html += '<div class="cal-day-count">+' + (citas.length - maxDots) + '</div>';
    }
  }
  div.innerHTML = html;
  
  div.onclick = function() {
    CAL_DIA_SEL = fechaStr;
    // Si es de otro mes, navegamos
    if (esOtroMes) {
      var p = fechaStr.split('-');
      CAL_ANO = parseInt(p[0]);
      CAL_MES = parseInt(p[1]) - 1;
    }
    renderCalendario();
  };
  
  return div;
}

function _renderListaDelDia() {
  var contenedor = document.getElementById('calDayList');
  if (!contenedor) return;
  
  if (!CAL_DIA_SEL) {
    contenedor.innerHTML = '';
    return;
  }

  var citas = _citasDelDia(CAL_DIA_SEL);
  var p = CAL_DIA_SEL.split('-');
  var d = new Date(parseInt(p[0]), parseInt(p[1])-1, parseInt(p[2]));
  var _lc = (typeof TEKPAIR_LANG === 'string' ? TEKPAIR_LANG : 'es');
  var fechaTxt = d.toLocaleDateString(_lc, {weekday:'long', day:'numeric', month:'long'});

  var html = '<div class="cal-day-list-title">';
  html += '<span>📋 ' + fechaTxt + '</span>';
  html += '<span class="badge-count">' + citas.length + ' ' + (citas.length === 1 ? T('cita.cita') : T('cita.citas')) + '</span>';
  html += '</div>';

  if (citas.length === 0) {
    html += '<div class="cal-empty-day">';
    html += T('cita.no_hay_dia') + '<br/>';
    html += '<button onclick="abrirNuevaCitaFecha(\'' + CAL_DIA_SEL + '\')">+ ' + T('cita.crear_el').replace('{d}', d.getDate()).replace('{m}', d.toLocaleDateString(_lc,{month:'long'})) + '</button>';
    html += '</div>';
  } else {
    var iconEstado = {pendiente:'⏳', confirmada:'✓', atendida:'✓✓', cancelada:'✕'};
    var colorEstado = {pendiente:'var(--orange)', confirmada:'var(--blue)', atendida:'var(--green)', cancelada:'var(--muted)'};
    
    citas.forEach(function(c) {
      html += '<div class="card" style="padding:12px;cursor:pointer;margin-bottom:6px;border-left:3px solid ' + colorEstado[c.estado || 'pendiente'] + '" onclick="abrirCita(\'' + c.id + '\')">';
      html += '<div style="display:flex;justify-content:space-between;align-items:start;gap:10px">';
      html += '<div style="flex:1;min-width:0">';
      html += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:4px"><strong style="font-size:14px;font-family:ui-monospace,monospace">' + esc(c.hora||'') + '</strong>';
      html += '<span style="font-size:11px;background:rgba(255,91,31,.08);color:var(--blue);padding:2px 8px;border-radius:10px;font-weight:600">' + esc(c.servicio || T('cita.consulta')) + '</span></div>';
      html += '<div style="font-weight:700;font-size:13px">' + esc(c.cliente_nombre) + '</div>';
      if (c.marca || c.modelo) html += '<div style="font-size:11px;color:var(--muted)">' + esc((c.marca||'') + ' ' + (c.modelo||'')).trim() + '</div>';
      if (c.cliente_tel) html += '<div style="font-size:11px;color:var(--muted)">📞 ' + esc(c.cliente_tel) + '</div>';
      html += '</div>';
      var _citaVencida = c.fecha && c.fecha < hoyLocal() && (c.estado === 'pendiente' || c.estado === 'confirmada');
      html += '<div style="display:flex;flex-direction:column;align-items:flex-end;gap:3px;flex-shrink:0">';
      if (_citaVencida) html += '<div style="font-size:10px;font-weight:800;color:#fff;background:var(--red);padding:2px 7px;border-radius:8px">⚠️ ' + (T('cita.vencida') || 'VENCIDA') + '</div>';
      html += '<div style="font-size:11px;font-weight:700;color:' + colorEstado[c.estado || 'pendiente'] + ';text-transform:uppercase;letter-spacing:.3px">' + iconEstado[c.estado || 'pendiente'] + ' ' + T('cita.est_' + (c.estado || 'pendiente')) + '</div>';
      html += '</div>';
      html += '</div></div>';
    });
    
    html += '<div style="margin-top:10px;text-align:center">';
    html += '<button onclick="abrirNuevaCitaFecha(\'' + CAL_DIA_SEL + '\')" style="background:var(--blue);color:white;border:none;padding:8px 16px;border-radius:8px;font-weight:700;cursor:pointer;font-family:inherit;font-size:13px">+ Otra cita este día</button>';
    html += '</div>';
  }

  contenedor.innerHTML = html;
}

function abrirNuevaCitaFecha(fechaStr) {
  document.getElementById('ncaFecha').value = fechaStr;
  document.getElementById('ncaHora').value = '10:00';
  document.getElementById('ncaNombre').value = '';
  document.getElementById('ncaTel').value = '';
  document.getElementById('ncaServicio').value = 'Diagnóstico';
  document.getElementById('ncaDuracion').value = '30';
  document.getElementById('ncaMarca').value = '';
  document.getElementById('ncaModelo').value = '';
  document.getElementById('ncaNotas').value = '';
  openM('mNuevaCitaAdmin');
}

async function guardarCitaAdmin() {
  var fecha = document.getElementById('ncaFecha').value;
  var hora = document.getElementById('ncaHora').value;
  var nombre = document.getElementById('ncaNombre').value.trim();
  
  if (!fecha || !hora || !nombre) {
    toast('Fecha, hora y nombre son obligatorios', 'err');
    return;
  }
  
  var nuevaCita = {
    id: 'c' + Date.now() + '_' + Math.random().toString(36).slice(2,8),
    tienda_id: TIENDA_ID,
    fecha: fecha,
    hora: hora,
    servicio: document.getElementById('ncaServicio').value,
    duracion_min: parseInt(document.getElementById('ncaDuracion').value) || 30,
    cliente_nombre: nombre,
    cliente_tel: document.getElementById('ncaTel').value.trim() || null,
    cliente_email: null,
    notas: document.getElementById('ncaNotas').value.trim() || null,
    estado: 'confirmada',
    marca: document.getElementById('ncaMarca').value.trim() || null,
    modelo: document.getElementById('ncaModelo').value.trim() || null,
    imei: null,
    created_at: new Date().toISOString()
  };
  
  if (!DB.citas) DB.citas = [];
  DB.citas.push(nuevaCita);
  guardarDatos();
  
  if (SB_KEY && TIENDA_ID) {
    try {
      await sbPost('citas', nuevaCita);
    } catch(e) {
      console.warn('Cita guardada localmente, error sync:', e);
    }
  }
  
  if (typeof audit === 'function') audit('crear', 'cita', nuevaCita.id, nombre + ' ' + fecha + ' ' + hora, null);
  
  toast(T('tst.cita_creada'), 'ok');
  closeM('mNuevaCitaAdmin');
  
  CAL_DIA_SEL = fecha;
  // Si la fecha está en otro mes, navegar
  var p = fecha.split('-');
  CAL_ANO = parseInt(p[0]);
  CAL_MES = parseInt(p[1]) - 1;
  
  renderCalendario();
  renderCitas();
  actualizarBadgeCitas();
}

// === HORARIOS ===
function getHorariosDefault() {
  return [
    {abierto:true, tramos:[{inicio:'09:30', fin:'13:30'}, {inicio:'17:00', fin:'20:00'}]},
    {abierto:true, tramos:[{inicio:'09:30', fin:'13:30'}, {inicio:'17:00', fin:'20:00'}]},
    {abierto:true, tramos:[{inicio:'09:30', fin:'13:30'}, {inicio:'17:00', fin:'20:00'}]},
    {abierto:true, tramos:[{inicio:'09:30', fin:'13:30'}, {inicio:'17:00', fin:'20:00'}]},
    {abierto:true, tramos:[{inicio:'09:30', fin:'13:30'}, {inicio:'17:00', fin:'20:00'}]},
    {abierto:true, tramos:[{inicio:'10:00', fin:'13:30'}]},
    {abierto:false, tramos:[{inicio:'10:00', fin:'13:30'}]}
  ];
}

// Migrar formato viejo {inicio,fin} → {tramos:[{inicio,fin}]}
function migrarHorarios(horarios) {
  if (!Array.isArray(horarios)) return null;
  return horarios.map(function(h){
    if (h && Array.isArray(h.tramos)) return h;
    if (h && (h.inicio || h.fin)) {
      return {abierto: !!h.abierto, tramos:[{inicio:h.inicio || '09:30', fin:h.fin || '13:30'}]};
    }
    return {abierto:false, tramos:[{inicio:'09:30', fin:'13:30'}]};
  });
}

function renderHorarios() {
  var box = document.getElementById('horariosBox');
  if (!box) return;
  var horarios = TIENDA.horarios;
  if (typeof horarios === 'string') { try { horarios = JSON.parse(horarios); } catch(e){ horarios = null; } }
  horarios = migrarHorarios(horarios);
  if (!horarios || horarios.length !== 7) horarios = getHorariosDefault();
  var html = '';
  for (var i = 0; i < 7; i++) {
    var h = horarios[i];
    if (!h.tramos || !h.tramos.length) h.tramos = [{inicio:'09:30', fin:'13:30'}];
    html += '<div style="padding:10px 0;border-bottom:1px solid var(--border)">';
    html += '<div style="display:flex;align-items:center;gap:10px;margin-bottom:6px">';
    var _diaNom = (typeof T === 'function' ? T('ajt.dia' + i) : '') || DIAS_SEMANA[i];
    var _abierto = (typeof T === 'function' ? T('ajt.abierto') : '') || 'Abierto';
    html += '<div style="font-size:13px;font-weight:600;width:90px">' + _diaNom + '</div>';
    html += '<label style="display:flex;align-items:center;gap:6px;font-size:12px;cursor:pointer">';
    html += '<input type="checkbox" data-dia="' + i + '" data-campo="abierto" onchange="actualizarHorario(this)" ' + (h.abierto ? 'checked' : '') + '> ' + _abierto + '</label>';
    html += '</div>';
    if (h.abierto) {
      // Tramo 1
      html += '<div style="display:flex;align-items:center;gap:6px;margin-left:90px;margin-bottom:6px">';
      html += '<input class="fi" type="time" value="' + (h.tramos[0].inicio || '09:30') + '" data-dia="' + i + '" data-tramo="0" data-campo="inicio" onchange="actualizarHorario(this)" style="font-size:12px;padding:5px 8px;width:100px">';
      html += '<span style="color:var(--muted);font-size:12px">a</span>';
      html += '<input class="fi" type="time" value="' + (h.tramos[0].fin || '13:30') + '" data-dia="' + i + '" data-tramo="0" data-campo="fin" onchange="actualizarHorario(this)" style="font-size:12px;padding:5px 8px;width:100px">';
      if (h.tramos.length < 2) {
        html += '<button type="button" onclick="agregarTramo(' + i + ')" style="background:var(--green);color:white;border:none;padding:4px 10px;border-radius:6px;cursor:pointer;font-size:11px;font-family:inherit">' + ((typeof T === 'function' ? T('ajt.tramo_tarde') : '') || '+ tramo tarde') + '</button>';
      }
      html += '</div>';
      // Tramo 2 (si existe)
      if (h.tramos.length >= 2) {
        html += '<div style="display:flex;align-items:center;gap:6px;margin-left:90px">';
        html += '<input class="fi" type="time" value="' + (h.tramos[1].inicio || '17:00') + '" data-dia="' + i + '" data-tramo="1" data-campo="inicio" onchange="actualizarHorario(this)" style="font-size:12px;padding:5px 8px;width:100px">';
        html += '<span style="color:var(--muted);font-size:12px">a</span>';
        html += '<input class="fi" type="time" value="' + (h.tramos[1].fin || '20:00') + '" data-dia="' + i + '" data-tramo="1" data-campo="fin" onchange="actualizarHorario(this)" style="font-size:12px;padding:5px 8px;width:100px">';
        html += '<button type="button" onclick="quitarTramo(' + i + ')" style="background:transparent;color:var(--red);border:1px solid var(--red);padding:4px 8px;border-radius:6px;cursor:pointer;font-size:11px;font-family:inherit">×</button>';
        html += '</div>';
      }
    }
    html += '</div>';
  }
  box.innerHTML = html;
  var sel = document.getElementById('citasDuracion');
  if (sel) {
    var cfg = TIENDA.citas_config;
    if (typeof cfg === 'string') { try { cfg = JSON.parse(cfg); } catch(e){ cfg = null; } }
    sel.value = (cfg && cfg.duracion_min) || 30;
  }
  TIENDA.horarios = horarios;
}

function actualizarHorario(el) {
  if (!Array.isArray(TIENDA.horarios) || TIENDA.horarios.length !== 7) TIENDA.horarios = getHorariosDefault();
  TIENDA.horarios = migrarHorarios(TIENDA.horarios);
  var dia = parseInt(el.dataset.dia);
  var campo = el.dataset.campo;
  if (campo === 'abierto') {
    TIENDA.horarios[dia].abierto = el.checked;
  } else {
    var tramo = parseInt(el.dataset.tramo) || 0;
    if (!TIENDA.horarios[dia].tramos[tramo]) TIENDA.horarios[dia].tramos[tramo] = {};
    TIENDA.horarios[dia].tramos[tramo][campo] = el.value;
  }
  guardarHorariosLocal();
  if (campo === 'abierto') renderHorarios();
}

function agregarTramo(dia) {
  if (!Array.isArray(TIENDA.horarios) || TIENDA.horarios.length !== 7) TIENDA.horarios = getHorariosDefault();
  TIENDA.horarios = migrarHorarios(TIENDA.horarios);
  if (!TIENDA.horarios[dia].tramos) TIENDA.horarios[dia].tramos = [];
  TIENDA.horarios[dia].tramos.push({inicio:'17:00', fin:'20:00'});
  guardarHorariosLocal();
  renderHorarios();
}

function quitarTramo(dia) {
  if (!Array.isArray(TIENDA.horarios) || TIENDA.horarios.length !== 7) return;
  TIENDA.horarios[dia].tramos = (TIENDA.horarios[dia].tramos || []).slice(0,1);
  guardarHorariosLocal();
  renderHorarios();
}

function guardarHorariosLocal() {
  localStorage.setItem('tk_tienda', JSON.stringify(Object.assign({}, JSON.parse(localStorage.getItem('tk_tienda')||'{}'), {horarios: TIENDA.horarios})));
  if (SB_KEY && TIENDA_ID) sbPatch('tiendas', 'id=eq.' + TIENDA_ID, {horarios: TIENDA.horarios});
}
function guardarConfigCitas() {
  var dur = parseInt(document.getElementById('citasDuracion').value) || 30;
  TIENDA.citas_config = {duracion_min: dur};
  localStorage.setItem('tk_tienda', JSON.stringify(Object.assign({}, JSON.parse(localStorage.getItem('tk_tienda')||'{}'), {citas_config: TIENDA.citas_config})));
  if (SB_KEY && TIENDA_ID) sbPatch('tiendas', 'id=eq.' + TIENDA_ID, {citas_config: TIENDA.citas_config});
  toast(T('tst.config_guardada'), 'ok');
}

// Init
setTimeout(function(){
  if (typeof renderHorarios === 'function') renderHorarios();
  if (typeof syncCitas === 'function') syncCitas();
}, 1500);
setInterval(function(){ if (DB.citas !== undefined) syncCitas(); }, 60000);

// ═══ MODO OSCURO ═══
function aplicarTema(tema) {
  var temas = ['light','dark','negro','grafito','naranja','terracota','ambar'];
  if (tema && tema !== 'light') {
    document.body.setAttribute('data-theme', tema);
  } else {
    document.body.removeAttribute('data-theme');
  }
  // Marcar botón activo
  var ids = { light:'btnTemaClaro', dark:'btnTemaOscuro', negro:'btnTemaNegro', grafito:'btnTemaGrafito', naranja:'btnTemaNaranja', terracota:'btnTemaTerracota', ambar:'btnTemaAmbar' };
  temas.forEach(function(t) {
    var btn = document.getElementById(ids[t]);
    if (!btn) return;
    if (t === tema || (t === 'light' && !tema)) {
      btn.style.borderColor = 'var(--green)';
      btn.style.boxShadow = '0 0 0 4px rgba(0,200,150,.2)';
    } else {
      btn.style.boxShadow = 'none';
      // Restaurar borde original por tema
      if (t === 'negro') btn.style.borderColor = '#222';
      else if (t === 'dark') btn.style.borderColor = '#374151';
      else if (t === 'grafito') btn.style.borderColor = '#3A3A3C';
      else if (t === 'naranja') btn.style.borderColor = '#FFD9C9';
      else if (t === 'terracota') btn.style.borderColor = '#FFD9C9';
      else if (t === 'ambar') btn.style.borderColor = '#FED7AA';
      else btn.style.borderColor = 'var(--border)';
    }
  });
}
function setTema(tema) {
  localStorage.setItem('tk_theme', tema);
  aplicarTema(tema);
  var emojisTema = { light:'☀️', dark:'🌙', negro:'🖤', grafito:'🪨', naranja:'🟠', terracota:'🔥', ambar:'🟧' };
  var _tn = (typeof _temaNombres === 'function') ? _temaNombres() : {};
  toast((emojisTema[tema] || '🎨') + ' ' + (_tn[tema] || tema), 'ok');
  if (typeof actualizarSbControls === 'function') actualizarSbControls();
}
// Aplicar tema al cargar
(function() {
  var saved = localStorage.getItem('tk_theme');
  var temaActivo = saved || 'terracota';
  if (temaActivo !== 'light') {
    document.body.setAttribute('data-theme', temaActivo);
  }
  setTimeout(function(){ aplicarTema(temaActivo); }, 100);
})();

// ═══ IMPORTAR FACTURA PDF ═══
if (typeof pdfjsLib !== 'undefined') {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

var IMP_FAC_PRODUCTOS = []; // [{cat, marca, modelo, capacidad, color, imei, coste}]
var IMP_FAC_TEXTO = '';

function abrirImportFactura() {
  if (!checkFeature('importar_pdf')) return;
  if (!tienePerm('stock_crear')) { toast(T('gen.sin_permiso'), 'err'); return; }
  impFacReset();
  openM('mImportFactura');
  impFacAtarListeners();
}

function impFacAtarListeners() {
  var drop = document.getElementById('impFacDrop');
  var input = document.getElementById('impFacInput');
  if (!drop || !input) return;
  if (drop.dataset.listenersAtados === '1') return;
  drop.dataset.listenersAtados = '1';
  drop.addEventListener('click', function(){ input.click(); });
  drop.addEventListener('dragover', function(e){ e.preventDefault(); drop.style.borderColor = 'var(--green)'; drop.style.background = 'rgba(0,200,150,.05)'; });
  drop.addEventListener('dragleave', function(){ drop.style.borderColor = ''; drop.style.background = '#FAFBFC'; });
  drop.addEventListener('drop', function(e){
    e.preventDefault();
    drop.style.borderColor = ''; drop.style.background = '#FAFBFC';
    if (e.dataTransfer.files && e.dataTransfer.files[0]) impFacProcesarPDF(e.dataTransfer.files[0]);
  });
  input.addEventListener('change', function(e){
    if (e.target.files && e.target.files[0]) impFacProcesarPDF(e.target.files[0]);
  });
}

function impFacReset() {
  IMP_FAC_PRODUCTOS = [];
  IMP_FAC_TEXTO = '';
  document.getElementById('impFacPaso1').style.display = '';
  document.getElementById('impFacPaso2').style.display = 'none';
  document.getElementById('impFacPaso3').style.display = 'none';
  document.getElementById('impFacError').style.display = 'none';
  document.getElementById('impFacInput').value = '';
}

function impFacMostrarError(msg) {
  var el = document.getElementById('impFacError');
  el.textContent = msg;
  el.style.display = 'block';
  document.getElementById('impFacPaso1').style.display = '';
  document.getElementById('impFacPaso2').style.display = 'none';
}

// Listeners drop zone: ahora se atan al abrir el modal via impFacAtarListeners()

async function impFacProcesarPDF(file) {
  if (!file || file.type !== 'application/pdf') { impFacMostrarError('Solo se aceptan PDFs.'); return; }

  document.getElementById('impFacPaso1').style.display = 'none';
  document.getElementById('impFacPaso2').style.display = '';
  document.getElementById('impFacLoadingMsg').textContent = 'Extrayendo texto...';

  try {
    // pdf.js se carga bajo demanda (ya no viene en el <head>)
    var pdfjsLib = await _cargarPdfJs();
    var arrBuffer = await file.arrayBuffer();
    var pdf = await pdfjsLib.getDocument({data: arrBuffer}).promise;
    var fullText = '';
    var allLines = [];
    for (var i = 1; i <= pdf.numPages; i++) {
      var page = await pdf.getPage(i);
      var content = await page.getTextContent();
      // Reconstruir líneas usando la posición Y de cada item
      var lineMap = {};
      content.items.forEach(function(item) {
        var y = Math.round(item.transform[5]);
        if (!lineMap[y]) lineMap[y] = [];
        lineMap[y].push({x: item.transform[4], text: item.str});
      });
      var ys = Object.keys(lineMap).map(Number).sort(function(a,b){ return b - a; });
      ys.forEach(function(y) {
        var line = lineMap[y].sort(function(a,b){ return a.x - b.x; }).map(function(p){ return p.text; }).join(' ').replace(/\s+/g, ' ').trim();
        if (line) {
          allLines.push(line);
          fullText += line + '\n';
        }
      });
      fullText += '\n';
    }

    if (!fullText.trim()) {
      impFacMostrarError('No se extrajo texto del PDF. Probablemente sea un PDF escaneado (foto). Necesitarías OCR.');
      return;
    }

    IMP_FAC_TEXTO = fullText;
    document.getElementById('impFacLoadingMsg').textContent = 'Detectando productos...';
    await new Promise(function(r){ setTimeout(r, 100); }); // permite UI update

    IMP_FAC_PRODUCTOS = impFacParsearProductos(allLines, fullText);
    impFacMostrarRevision();
  } catch (e) {
    console.error('Error procesando PDF:', e);
    impFacMostrarError('Error al leer el PDF: ' + (e.message || 'desconocido'));
  }
}

// Parsea líneas para detectar productos
function impFacParsearProductos(lines, fullText) {
  var productos = [];
  // Regex IMEI: 14-15 dígitos consecutivos (algunos proveedores ponen 14, otros 15)
  var imeiRegex = /\b\d{14,16}\b/g;
  // Regex precio: número con separador decimal . o ,
  var precioRegex = /(?:^|\s)([0-9]{1,4}(?:[.,]\d{1,2})?)\s*(?:€|EUR|EURO)?(?:\s|$)/;

  // Marcas comunes
  var marcasComunes = ['Apple','Samsung','Xiaomi','Huawei','Honor','Oppo','OnePlus','Realme','Motorola','Sony','Nokia','LG','Google','Pixel'];

  // Estrategia: buscar líneas con IMEI. Para cada IMEI, intentar extraer marca/modelo de la línea o las anteriores
  lines.forEach(function(line, idx) {
    var imeisEnLinea = line.match(imeiRegex) || [];
    imeisEnLinea.forEach(function(imei) {
      // Validar que sea probable IMEI (15 digitos es el estándar; algunos PDFs ponen 14)
      if (imei.length < 14 || imei.length > 16) return;
      // Excluir si es claramente un total/numero de factura largo
      // Buscar contexto: línea actual + 2 anteriores + 1 siguiente
      var contexto = lines.slice(Math.max(0, idx-2), Math.min(lines.length, idx+2)).join(' ');

      // Detectar marca
      var marca = '';
      for (var i = 0; i < marcasComunes.length; i++) {
        if (contexto.toLowerCase().indexOf(marcasComunes[i].toLowerCase()) !== -1) {
          marca = marcasComunes[i];
          break;
        }
      }

      // Detectar modelo (heurística: palabra "iPhone XX" o "Galaxy XX" o similar)
      var modelo = '';
      var modeloMatch = contexto.match(/(iPhone\s*\d+\s*(?:Pro\s*Max|Pro|Plus|Mini|SE)?)/i)
        || contexto.match(/(Galaxy\s*[A-Z]?\d+\s*(?:Ultra|Plus|FE|Pro)?)/i)
        || contexto.match(/(Redmi\s*(?:Note\s*)?\d+\s*(?:Pro|Plus|S|T)?)/i)
        || contexto.match(/(Pixel\s*\d+\s*(?:Pro|XL|a)?)/i)
        || contexto.match(/(Mi\s*\d+\s*(?:Pro|Plus|T|Ultra)?)/i);
      if (modeloMatch) modelo = modeloMatch[1].replace(/\s+/g, ' ').trim();

      // Detectar capacidad (32GB, 64GB, 128GB, 256GB, 512GB, 1TB)
      var capacidad = '';
      var capMatch = contexto.match(/\b(32|64|128|256|512|1024)\s*GB\b/i) || contexto.match(/\b1\s*TB\b/i);
      if (capMatch) capacidad = capMatch[0].replace(/\s+/g, '');

      // Detectar color (palabras comunes)
      var coloresComunes = ['Negro','Blanco','Gris','Plata','Dorado','Oro','Azul','Verde','Rojo','Rosa','Morado','Violeta','Amarillo','Naranja','Black','White','Gray','Grey','Silver','Gold','Blue','Green','Red','Pink','Purple','Yellow','Midnight','Starlight','Graphite','Sierra'];
      var color = '';
      for (var j = 0; j < coloresComunes.length; j++) {
        var rgx = new RegExp('\\b' + coloresComunes[j] + '\\b', 'i');
        if (rgx.test(contexto)) { color = coloresComunes[j]; break; }
      }

      // Detectar precio: buscar números con decimales en la línea actual o siguiente
      var coste = 0;
      var lineaConPrecio = line + ' ' + (lines[idx+1] || '');
      // Buscar todos los números con formato precio
      var precios = lineaConPrecio.match(/\b(\d{2,4}[.,]\d{2})\b/g) || [];
      if (precios.length > 0) {
        // Tomar el último (suele ser el total línea o coste unitario al final)
        var ultimoPrecio = precios[precios.length - 1].replace(',', '.');
        coste = parseFloat(ultimoPrecio) || 0;
      }

      // Excluir IMEIs duplicados
      if (productos.some(function(p){ return p.imei === imei; })) return;

      productos.push({
        cat: 'Telefono',
        marca: marca,
        modelo: modelo,
        capacidad: capacidad,
        color: color,
        imei: imei,
        coste: coste
      });
    });
  });

  return productos;
}

function impFacMostrarRevision() {
  document.getElementById('impFacPaso2').style.display = 'none';
  document.getElementById('impFacPaso3').style.display = '';
  document.getElementById('impFacTextoCrudo').textContent = IMP_FAC_TEXTO;
  impFacRenderTabla();
}

function impFacRenderTabla() {
  var tbody = document.getElementById('impFacTbody');
  if (!tbody) return;
  if (!IMP_FAC_PRODUCTOS.length) {
    tbody.innerHTML = '<tr><td colspan="8" style="padding:24px;text-align:center;font-size:12px;color:var(--muted)">No se detectaron productos automáticamente. Pulsa "+ Añadir fila manual".</td></tr>';
    document.getElementById('impFacResumen').textContent = '0 productos detectados';
    document.getElementById('impFacTotal').textContent = cur(0);
    return;
  }
  var total = 0;
  tbody.innerHTML = IMP_FAC_PRODUCTOS.map(function(p, i) {
    total += parseFloat(p.coste) || 0;
    var catOpts = ['Telefono','Tablet','Smartwatch','Pantalla','Bateria','Tapa','Flex de Carga','Altavoz','Otro'];
    var catSel = catOpts.map(function(c){ return '<option ' + (p.cat===c?'selected':'') + '>' + c + '</option>'; }).join('');
    return '<tr>' +
      '<td style="padding:5px 6px;border-bottom:1px solid var(--border)"><select class="fi" style="font-size:11px;padding:5px 6px" onchange="impFacUpd(' + i + ',\'cat\',this.value)">' + catSel + '</select></td>' +
      '<td style="padding:5px 6px;border-bottom:1px solid var(--border)"><input class="fi" style="font-size:11px;padding:5px 8px" value="' + esc(p.marca||'') + '" oninput="impFacUpd(' + i + ',\'marca\',this.value)"></td>' +
      '<td style="padding:5px 6px;border-bottom:1px solid var(--border)"><input class="fi" style="font-size:11px;padding:5px 8px" value="' + esc(p.modelo||'') + '" oninput="impFacUpd(' + i + ',\'modelo\',this.value)"></td>' +
      '<td style="padding:5px 6px;border-bottom:1px solid var(--border)"><input class="fi" style="font-size:11px;padding:5px 8px;width:80px" value="' + esc(p.capacidad||'') + '" oninput="impFacUpd(' + i + ',\'capacidad\',this.value)"></td>' +
      '<td style="padding:5px 6px;border-bottom:1px solid var(--border)"><input class="fi" style="font-size:11px;padding:5px 8px;width:90px" value="' + esc(p.color||'') + '" oninput="impFacUpd(' + i + ',\'color\',this.value)"></td>' +
      '<td style="padding:5px 6px;border-bottom:1px solid var(--border)"><input class="fi" style="font-size:11px;padding:5px 8px;font-family:ui-monospace,monospace" value="' + esc(p.imei||'') + '" oninput="impFacUpd(' + i + ',\'imei\',this.value)"></td>' +
      '<td style="padding:5px 6px;border-bottom:1px solid var(--border)"><input class="fi" type="number" step="0.01" style="font-size:11px;padding:5px 8px;width:80px;text-align:right" value="' + (p.coste||0) + '" oninput="impFacUpd(' + i + ',\'coste\',parseFloat(this.value)||0)"></td>' +
      '<td style="padding:5px;border-bottom:1px solid var(--border);text-align:center"><button onclick="impFacQuitar(' + i + ')" style="background:none;border:none;color:var(--muted);cursor:pointer;font-size:14px" title="Quitar">×</button></td>' +
    '</tr>';
  }).join('');
  document.getElementById('impFacResumen').textContent = IMP_FAC_PRODUCTOS.length + ' producto' + (IMP_FAC_PRODUCTOS.length===1?'':'s') + ' detectado' + (IMP_FAC_PRODUCTOS.length===1?'':'s');
  document.getElementById('impFacTotal').textContent = cur(total);
}

function impFacUpd(i, field, value) {
  if (IMP_FAC_PRODUCTOS[i]) {
    IMP_FAC_PRODUCTOS[i][field] = value;
    if (field === 'coste') impFacRenderTabla();
  }
}

function impFacQuitar(i) {
  IMP_FAC_PRODUCTOS.splice(i, 1);
  impFacRenderTabla();
}

function impFacAnadirFila() {
  IMP_FAC_PRODUCTOS.push({cat:'Telefono', marca:'', modelo:'', capacidad:'', color:'', imei:'', coste:0});
  impFacRenderTabla();
}

function impFacVerTextoCrudo() {
  var det = document.querySelector('#mImportFactura details');
  if (det) det.open = true;
}

function impFacAnadirAlStock() {
  // Validar
  var validos = IMP_FAC_PRODUCTOS.filter(function(p){
    return (p.modelo || '').trim() || (p.imei || '').trim() || (p.marca || '').trim();
  });
  if (!validos.length) { toast('No hay productos válidos', 'err'); return; }

  // Preguntar precio de venta sugerido (margen %)
  var margenStr = prompt('¿Qué margen quieres aplicar al precio de venta? (en %)\nEjemplo: 30 = 30% sobre el coste.\nDeja vacío para no calcular precio de venta.', '30');
  var margen = margenStr ? (parseFloat(margenStr) || 0) : 0;

  if (!DB.stock) DB.stock = [];
  var creados = 0;
  validos.forEach(function(p) {
    var coste = parseFloat(p.coste) || 0;
    var precioV = margen > 0 && coste > 0 ? Math.round(coste * (1 + margen/100) * 100) / 100 : 0;
    var item = {
      id: 's' + Date.now() + '_' + Math.random().toString(36).slice(2,8) + '_' + creados,
      categoria: p.cat || 'Telefono',
      marca: (p.marca || '').trim(),
      modelo: (p.modelo || '').trim(),
      capacidad: (p.capacidad || '').trim(),
      color: (p.color || '').trim(),
      imei: (p.imei || '').trim(),
      unidades: 1,
      stockMin: 1,
      stockMax: 5,
      precioC: coste,
      precioV: precioV,
      proveedor: '',
      notas: 'Importado desde factura ' + hoyLocal()
    };
    DB.stock.push(item);
    creados++;
    // Sync Supabase
    if (typeof SB_KEY !== 'undefined' && SB_KEY && TIENDA_ID) {
      sbPost('stock', {
        id: item.id, tienda_id: TIENDA_ID,
        categoria: item.categoria, marca: item.marca, modelo: item.modelo,
        capacidad: item.capacidad, color: item.color, imei: item.imei,
        unidades: item.unidades, stock_min: item.stockMin, stock_max: item.stockMax,
        precio_c: item.precioC, precio_v: item.precioV
      });
    }
  });
  guardarDatos();
  closeM('mImportFactura');
  toast(creados + ' productos añadidos al stock', 'ok');
  if (typeof renderStock === 'function') renderStock();
}

